import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { Skeleton } from "@/components/ui/skeleton";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { AuthProvider } from "@/contexts/AuthContext";

import { ThemeProvider } from "@/contexts/ThemeContext";
import { LanguageProvider } from "@/contexts/LanguageContext";
import { CallProvider } from "@/contexts/CallContext";
import { FeedbackProvider } from "@/contexts/FeedbackContext";
import { StreakProvider } from "@/contexts/StreakContext";
import "@/i18n/config"; // Initialize i18n
import { ProtectedRoute } from "@/components/auth/ProtectedRoute";
import { Suspense, lazy } from "react";
import { AnimatePresence } from "framer-motion";
import { Loader2 } from "lucide-react";
import { OfflineBanner } from "@/components/OfflineBanner";
import { PWAInstallPrompt } from "@/components/PWAInstallPrompt";
import { PushNotificationManager } from "@/components/PushNotificationManager";
import { FCMManager } from "@/components/chat/FCMManager";
import { GlobalCallManager } from "@/components/chat/GlobalCallManager";
import { FeedbackPrompt } from "@/components/feedback/FeedbackPrompt";
import { useFeedback } from "@/hooks/useFeedback";
import { useAuth } from "@/contexts/AuthContext";
import { useEffect } from "react";
import { LayoutProvider } from "@/contexts/LayoutContext";
import { RootLayout } from "@/components/layout/RootLayout";

// ── Eager imports: Core pages users navigate between frequently ──────────────
// These load with the main bundle so page transitions are INSTANT.
import Dashboard from "./pages/Dashboard";
import LecturerDashboard from "./pages/LecturerDashboard";
import ClassFeed from "./pages/ClassFeed";
import Messages from "./pages/Messages";
import Schedule from "./pages/Schedule";
import Notifications from "./pages/Notifications";
import Profile from "./pages/Profile";
import Settings from "./pages/Settings";
import Notes from "./pages/Notes";
import StudentAssignments from "./pages/StudentAssignments";
import StudentQuizzes from "./pages/StudentQuizzes";
import AIChat from "./pages/AIChat";
import AllStudents from "./pages/AllStudents";
import CreateClass from "./pages/CreateClass";
import LecturerTimeTable from "./pages/LecturerTimeTable";
import LecturerClassesAssignments from "./pages/LecturerClassesAssignments";
import LecturerClassesQuizzes from "./pages/LecturerClassesQuizzes";
import CallHistory from "./pages/CallHistory";
import StreakPage from "./pages/StreakPage";
import KnowledgeMap from "@/pages/KnowledgeMap";

// ── Lazy imports: Auth pages & one-off pages (visited rarely) ────────────────
const Index = lazy(() => import("./pages/Index"));
const Login = lazy(() => import("./pages/Login"));
const Register = lazy(() => import("./pages/Register"));
const StudentLogin = lazy(() => import("./pages/StudentLogin"));
const StudentRegister = lazy(() => import("./pages/StudentRegister"));
const LecturerLogin = lazy(() => import("./pages/LecturerLogin"));
const LecturerRegister = lazy(() => import("./pages/LecturerRegister"));
const ForgotPassword = lazy(() => import("./pages/ForgotPassword"));
const UpdatePassword = lazy(() => import("./pages/UpdatePassword"));
const AuthCallback = lazy(() => import("./pages/AuthCallback"));
const PublicProfile = lazy(() => import("./pages/PublicProfile"));
const Assignments = lazy(() => import("./pages/Assignments"));
const AssignmentSubmit = lazy(() => import("./pages/AssignmentSubmit"));
const ClassAssignmentsView = lazy(() => import("./pages/ClassAssignmentsView"));
const AssignmentSubmissionsPage = lazy(() => import("./pages/AssignmentSubmissionsPage"));
const ClassQuizzesView = lazy(() => import("./pages/ClassQuizzesView"));
const QuizResultsView = lazy(() => import("./pages/QuizResultsView"));
const CreateQuiz = lazy(() => import("./pages/CreateQuiz"));
const CreateAIQuiz = lazy(() => import("./pages/CreateAIQuiz"));
const EditQuiz = lazy(() => import("./pages/EditQuiz"));
const TakeQuiz = lazy(() => import("./pages/TakeQuiz"));
const StudentAssignmentDetail = lazy(() => import("./pages/StudentAssignmentDetail"));
const QuizAttemptDetails = lazy(() => import("./pages/QuizAttemptDetails"));
const SharedAIChat = lazy(() => import("./pages/SharedAIChat"));
const NotFound = lazy(() => import("./pages/NotFound"));

const LoadingFallback = () => {
  useEffect(() => {
    const timer = setTimeout(() => {
      console.warn("Loading persists... possible chunk error. Trying to recover.");
    }, 8000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-background">
      {/* Sidebar Skeleton */}
      <div className="hidden md:flex w-72 h-full flex-col border-r border-border/50 p-6 space-y-6 shrink-0">
        <Skeleton className="h-10 w-32 rounded-xl mb-4" />
        <div className="space-y-4">
          {[1, 2, 3, 4, 5, 6].map(i => (
            <div key={i} className="flex items-center gap-3">
              <Skeleton className="size-5 rounded-md" />
              <Skeleton className="h-4 w-24 rounded-md" />
            </div>
          ))}
        </div>
      </div>

      {/* Main Content Skeleton */}
      <div className="flex-1 flex flex-col p-6 md:p-10 space-y-8 min-w-0">
        <header className="flex justify-between items-center shrink-0">
          <div className="space-y-2">
            <Skeleton className="h-8 w-48 rounded-lg" />
            <Skeleton className="h-4 w-64 rounded-lg invisible sm:visible" />
          </div>
          <div className="flex gap-2">
            <Skeleton className="size-9 rounded-full" />
            <Skeleton className="size-9 rounded-full" />
          </div>
        </header>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[1, 2, 3, 4].map(i => (
            <Skeleton key={i} className="h-32 rounded-3xl" />
          ))}
        </div>

        <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-8 min-h-0">
          <div className="lg:col-span-2 space-y-6">
            <Skeleton className="h-[400px] w-full rounded-3xl" />
          </div>
          <div className="space-y-6">
            <Skeleton className="h-[200px] w-full rounded-3xl" />
            <Skeleton className="h-[200px] w-full rounded-3xl" />
          </div>
        </div>
      </div>
    </div>
  );
};

// Global polyfill for chunk errors
window.addEventListener('error', (e) => {
  if (e.message.includes('Loading chunk') || e.message.includes('CSS chunk')) {
    console.warn("Chunk error detected, reloading...");
    window.location.reload();
  }
}, true);

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5, // 5 minutes
      gcTime: 1000 * 60 * 30, // 30 minutes
    },
  },
});

const FeedbackManager = () => {
  const { user, profile } = useAuth();
  const { showPrompt, setShowPrompt, submitFeedback, checkFeedbackStatus } = useFeedback();


  useEffect(() => {
    if (user && profile) {
      checkFeedbackStatus();
    }
  }, [user, profile]);


  return (
    <FeedbackPrompt
      isOpen={showPrompt}
      onClose={() => setShowPrompt(false)}
      onSubmit={submitFeedback}
    />
  );
};

const AnimatedRoutes = () => {
  const location = useLocation();
  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        <Route path="/p/:id" element={<PublicProfile />} />
        <Route path="/badge/:id" element={<PublicProfile />} />
        <Route path="/profile/:id" element={<PublicProfile />} />
        <Route path="/share/:id" element={<PublicProfile />} />
        <Route path="/" element={<Index />} />
        <Route path="/student/login" element={<StudentLogin />} />
        <Route path="/student/register" element={<StudentRegister />} />
        <Route path="/lecturer/login" element={<LecturerLogin />} />
        <Route path="/lecturer/register" element={<LecturerRegister />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/forgot-password" element={<ForgotPassword />} />
        <Route path="/update-password" element={<UpdatePassword />} />
        <Route path="/auth/callback" element={<AuthCallback />} />

        {/* Persistent Layout Wrapper */}
        <Route element={
          <ProtectedRoute allowedRoles={["student", "lecturer", "admin"]}>
            <RootLayout />
          </ProtectedRoute>
        }>
          <Route path="/dashboard" element={<ProtectedRoute allowedRoles={["student", "admin"]}><Dashboard /></ProtectedRoute>} />
          <Route path="/streak" element={<ProtectedRoute allowedRoles={["student"]}><StreakPage /></ProtectedRoute>} />
          <Route path="/achievements" element={<Navigate to="/streak" replace />} />
          <Route path="/student/assignments" element={<ProtectedRoute allowedRoles={["student", "admin"]}><StudentAssignments /></ProtectedRoute>} />
          <Route path="/student/assignments/:id" element={<ProtectedRoute allowedRoles={["student", "admin"]}><StudentAssignmentDetail /></ProtectedRoute>} />
          <Route path="/student/quizzes" element={<ProtectedRoute allowedRoles={["student", "admin"]}><StudentQuizzes /></ProtectedRoute>} />
          <Route path="/student/quizzes/:quizId" element={<ProtectedRoute allowedRoles={["student", "admin"]}><TakeQuiz /></ProtectedRoute>} />
          <Route path="/student/quizzes/:classId/:quizId/results" element={<ProtectedRoute allowedRoles={["student", "admin"]}><QuizResultsView /></ProtectedRoute>} />
          <Route path="/student/quizzes/:quizId/details" element={<ProtectedRoute allowedRoles={["student", "admin"]}><QuizAttemptDetails /></ProtectedRoute>} />
          <Route path="/student/knowledge-map" element={<ProtectedRoute allowedRoles={["student"]}><KnowledgeMap /></ProtectedRoute>} />
          <Route path="/lecturer-dashboard" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><LecturerDashboard /></ProtectedRoute>} />
          <Route path="/all-students" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><CreateClass /></ProtectedRoute>} />
          <Route path="/classes/:classId/students" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><AllStudents /></ProtectedRoute>} />
          <Route path="/lecturer/timetable" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><LecturerTimeTable /></ProtectedRoute>} />
          <Route path="/lecturer/assignments" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><LecturerClassesAssignments /></ProtectedRoute>} />
          <Route path="/lecturer/assignments/:classId" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><ClassAssignmentsView /></ProtectedRoute>} />
          <Route path="/lecturer/assignments/:classId/:assignmentId/submissions" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><AssignmentSubmissionsPage /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><LecturerClassesQuizzes /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes/:classId/create" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><CreateQuiz /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes/:classId/create-ai" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><CreateAIQuiz /></ProtectedRoute>} />
          <Route path="/lecturer/create-ai-quiz" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><CreateAIQuiz /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes/:classId" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><ClassQuizzesView /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes/:classId/:quizId/edit" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><EditQuiz /></ProtectedRoute>} />
          <Route path="/lecturer/quizzes/:classId/:quizId/results" element={<ProtectedRoute allowedRoles={["lecturer", "admin"]}><QuizResultsView /></ProtectedRoute>} />
          <Route path="/assignments" element={<ProtectedRoute><Assignments /></ProtectedRoute>} />
          <Route path="/assignments/:id/submit" element={<ProtectedRoute><AssignmentSubmit /></ProtectedRoute>} />
          <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
          <Route path="/messages" element={<ProtectedRoute><Messages /></ProtectedRoute>} />
          <Route path="/call-history" element={<ProtectedRoute><CallHistory /></ProtectedRoute>} />
          <Route path="/schedule" element={<ProtectedRoute><Schedule /></ProtectedRoute>} />
          <Route path="/notifications" element={<ProtectedRoute><Notifications /></ProtectedRoute>} />
          <Route path="/settings" element={<ProtectedRoute><Settings /></ProtectedRoute>} />
          <Route path="/notes" element={<ProtectedRoute><Notes /></ProtectedRoute>} />
          <Route path="/class-feed" element={<ProtectedRoute allowedRoles={["student", "lecturer", "admin"]}><ClassFeed /></ProtectedRoute>} />
          <Route path="/ai-chat" element={<ProtectedRoute allowedRoles={["student", "lecturer", "admin"]}><AIChat /></ProtectedRoute>} />

        </Route>

        <Route path="/ai-chat/share/:token" element={<SharedAIChat />} />
        <Route path="*" element={<NotFound />} />
      </Routes>
    </AnimatePresence>
  );
};

const App = () => (
  <QueryClientProvider client={queryClient}>
    <AuthProvider>
      <LanguageProvider>
        <ThemeProvider>
          <FeedbackProvider>
            <StreakProvider>
              <LayoutProvider>
                <FeedbackManager />
                <BrowserRouter future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
                  <TooltipProvider>
                    <CallProvider>
                      <GlobalCallManager />
                      <Toaster />
                      <Sonner />
                      <OfflineBanner />
                      <PWAInstallPrompt />
                      <PushNotificationManager />
                      <FCMManager />
                      <Suspense fallback={<LoadingFallback />}>
                        <AnimatedRoutes />
                      </Suspense>
                    </CallProvider>
                  </TooltipProvider>
                </BrowserRouter>
              </LayoutProvider>
            </StreakProvider>
          </FeedbackProvider>
        </ThemeProvider>
      </LanguageProvider>
    </AuthProvider>
  </QueryClientProvider>
);

export default App;

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { X, Download, MonitorSmartphone, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useIsMobile } from '@/hooks/use-mobile';
import { cn } from '@/lib/utils';

export function PWAInstallPrompt() {
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showPrompt, setShowPrompt] = useState(false);
    const [isIOS, setIsIOS] = useState(false);
    const [isStandalone, setIsStandalone] = useState(false);
    const isMobile = useIsMobile();

    useEffect(() => {
        // Check if running as standalone
        const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches ||
            (window.navigator as any).standalone ||
            document.referrer.includes('android-app://');

        setIsStandalone(isStandaloneMode);


        if (isStandaloneMode) return;

        // Detect iOS
        const isIOSDevice = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
        setIsIOS(isIOSDevice);

        // Check dismissed status
        const dismissedAt = localStorage.getItem('eduspace_pwa_dismissed');
        if (dismissedAt) {
            const dismissedDate = new Date(parseInt(dismissedAt));
            const now = new Date();
            // Show again after 3 days
            if ((now.getTime() - dismissedDate.getTime()) < 3 * 24 * 60 * 60 * 1000) {
                return;
            }
        }

        const handleBeforeInstallPrompt = (e: any) => {
            e.preventDefault();
            setDeferredPrompt(e);
            setShowPrompt(true);
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

        // On iOS, we show the prompt regardless of beforeinstallprompt since it's not supported
        if (isIOSDevice) {
            setShowPrompt(true);
        }

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        };
    }, []);

    const handleInstallClick = async () => {
        if (isIOS) {
            // Instructions are already in the UI
            return;
        }

        if (!deferredPrompt) {
            // If we don't have the prompt (e.g. testing), just close it
            setShowPrompt(false);
            return;
        }

        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;

        if (outcome === 'accepted') {
            setDeferredPrompt(null);
            setShowPrompt(false);
        }
    };

    const handleDismiss = () => {
        setShowPrompt(false);
        localStorage.setItem('eduspace_pwa_dismissed', Date.now().toString());
    };

    if (!showPrompt || isStandalone) return null;

    // Mobile: Top Center, Desktop: Bottom Center (Existing)
    const containerClasses = cn(
        "fixed z-[150] left-4 right-4 flex justify-center pointer-events-none",
        isMobile ? "top-4" : "bottom-4"
    );

    // Mobile animation: Slide from top, Desktop animation: Slide from bottom
    const variants = {
        initial: {
            y: isMobile ? -80 : 80,
            opacity: 0,
            scale: 0.9,
            filter: "blur(8px)"
        },
        animate: {
            y: 0,
            opacity: 1,
            scale: 1,
            filter: "blur(0px)",
            transition: {
                type: "spring" as const,
                stiffness: 350,
                damping: 25
            }
        },
        exit: {
            y: isMobile ? -40 : 40,
            opacity: 0,
            scale: 0.95,
            filter: "blur(4px)",
            transition: {
                duration: 0.2
            }
        }
    };

    return (
        <AnimatePresence>
            <motion.div
                key="pwa-prompt"
                variants={variants}
                initial="initial"
                animate="animate"
                exit="exit"
                className={containerClasses}
            >
                <div className="bg-white/95 dark:bg-slate-900/95 backdrop-blur-2xl rounded-2xl shadow-[0_25px_60px_-15px_rgba(0,0,0,0.2)] dark:shadow-[0_25px_60px_-15px_rgba(0,0,0,0.5)] w-full max-w-[340px] border border-white/40 dark:border-slate-800/60 p-3.5 pointer-events-auto flex flex-col gap-3 overflow-hidden relative group">
                    {/* Glass sheen effect */}
                    <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent pointer-none" />

                    {/* Progress line at top */}
                    <div className="absolute top-0 left-0 right-0 h-1 bg-emerald-500/20">
                        <motion.div
                            initial={{ width: 0 }}
                            animate={{ width: "100%" }}
                            transition={{ duration: 0.8, ease: "easeOut" }}
                            className="h-full bg-emerald-500"
                        />
                    </div>

                    <div className="flex items-start gap-3 relative z-10">
                        <div className="bg-emerald-500/10 dark:bg-emerald-500/20 p-2 rounded-xl shrink-0 border border-emerald-500/20">
                            <img
                                src="/pwa-192x192.png"
                                alt="App Icon"
                                className="w-8 h-8 object-contain"
                                onError={(e) => (e.currentTarget.style.display = 'none')}
                            />
                            <MonitorSmartphone className="w-8 h-8 text-emerald-600 hidden peer-onError:block" />
                        </div>
                        <div className="flex-1 min-w-0 pt-0.5">
                            <div className="flex items-center gap-1.5">
                                <h3 className="font-bold text-[15px] text-slate-900 dark:text-white leading-none">Install EduSpace</h3>
                                <Sparkles className="w-3.5 h-3.5 text-emerald-500" />
                            </div>
                            <p className="text-[12px] text-slate-500 dark:text-slate-400 mt-1.5 leading-tight font-medium">
                                {isIOS
                                    ? "Tap 'Share' > 'Add to Home Screen'"
                                    : "Add to home screen for a better experience."
                                }
                            </p>
                        </div>
                        <button
                            onClick={handleDismiss}
                            className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1.5 -mt-1 -mr-1 transition-all rounded-full hover:bg-slate-100 dark:hover:bg-slate-800"
                        >
                            <X className="w-4 h-4" />
                        </button>
                    </div>

                    {!isIOS ? (
                        <div className="flex gap-2 relative z-10">
                            <Button
                                onClick={handleInstallClick}
                                className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl shadow-lg shadow-emerald-600/20 h-9 text-xs"
                            >
                                <Download className="w-3.5 h-3.5 mr-1.5" />
                                Install Now
                            </Button>
                            <Button
                                variant="ghost"
                                onClick={handleDismiss}
                                className="flex-1 h-9 text-[11px] font-bold text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 rounded-xl"
                            >
                                Later
                            </Button>
                        </div>
                    ) : (
                        <div className="relative z-10">
                            <Button
                                variant="outline"
                                onClick={handleDismiss}
                                className="w-full h-9 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-300 rounded-xl font-bold text-xs"
                            >
                                Got it
                            </Button>
                        </div>
                    )}
                </div>
            </motion.div>
        </AnimatePresence>
    );
}

import { useState, useRef, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Upload, X, FileText, Loader2, CheckCircle, Download, ExternalLink, Calendar, Clock, Trophy, AlertCircle, File, MoreVertical, Trash2 } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { uploadAssignmentFile, validateAssignmentFile } from "@/lib/supabaseStorage";
import { useStreak } from "@/contexts/StreakContext";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import { Card, CardContent } from "@/components/ui/card";
import { formatFileSize, getFileTypeDisplay } from "@/lib/fileUtils";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface SubmitAssignmentDialogProps {
    isOpen: boolean;
    onClose: () => void;
    assignment: any;
    onSubmit: (assignmentId: string, data: any) => Promise<{ success: boolean; error?: string }>;
    onDelete?: (submissionId: string) => Promise<void>;
}

export function SubmitAssignmentDialog({ isOpen, onClose, assignment, onSubmit, onDelete }: SubmitAssignmentDialogProps) {
    const { profile, role } = useAuth();
    const [submitting, setSubmitting] = useState(false);
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);

    // Form State
    const [studentName, setStudentName] = useState(profile?.full_name || "");
    const [regNumber, setRegNumber] = useState(profile?.student_id || "");
    const [notes, setNotes] = useState("");
    const [file, setFile] = useState<File | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);

    // Initial load: Check if we are viewing an existing submission
    const existingSubmission = assignment.submission;
    const hasSubmission = !!existingSubmission;
    const isGraded = existingSubmission?.status === 'graded';

    const prevOpenRef = useRef(false);

    // Reset form only when dialog transition from closed to open
    useEffect(() => {
        if (isOpen && !prevOpenRef.current) {
            setStudentName(profile?.full_name || "");
            setRegNumber(profile?.student_id || "");
            setFile(null);
            setNotes("");
        }
        prevOpenRef.current = isOpen;
    }, [isOpen, profile]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (selectedFile) {
            const validation = validateAssignmentFile(selectedFile);
            if (!validation.valid) {
                toast.error(validation.error || 'Invalid file');
                return;
            }
            setFile(selectedFile);
        }
    };

    const { recordAcademicAction } = useStreak();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (submitting) return;

        if (!file && !notes) {
            toast.error("Please upload a file or add submission notes.");
            return;
        }

        setSubmitting(true);
        try {
            let attachmentUrl = undefined;
            let attachmentName = undefined;
            let fileType = undefined;
            let fileSize = undefined;

            console.log('[SubmitAssignmentDialog] Starting submission...');
            console.log('[SubmitAssignmentDialog] Has new file:', !!file);
            console.log('[SubmitAssignmentDialog] Has existing submission:', hasSubmission);
            console.log('[SubmitAssignmentDialog] Existing file:', existingSubmission?.attachment_name);

            if (file) {
                console.log('[SubmitAssignmentDialog] Uploading new file:', file.name);
                const uploadResult = await uploadAssignmentFile(
                    file,
                    profile?.user_id || 'unknown',
                    assignment.id
                );

                if (!uploadResult.success || !uploadResult.url) {
                    throw new Error(uploadResult.error || 'Upload failed');
                }
                attachmentUrl = uploadResult.url;
                attachmentName = file.name;
                fileType = file.type;
                fileSize = file.size;
                console.log('[SubmitAssignmentDialog] File uploaded successfully:', attachmentName);
                console.log('[SubmitAssignmentDialog] New file URL:', attachmentUrl);
            } else if (hasSubmission && !file) {
                // If checking for edit but no new file, keep existing
                attachmentUrl = existingSubmission?.attachment_url;
                attachmentName = existingSubmission?.attachment_name;
                fileType = existingSubmission?.file_type;
                fileSize = existingSubmission?.file_size;
                console.log('[SubmitAssignmentDialog] No new file, keeping existing:', attachmentName);
            }

            console.log('[SubmitAssignmentDialog] Submitting to database with file:', attachmentName);
            const result = await onSubmit(assignment.id, {
                submission_text: notes,
                attachment_url: attachmentUrl,
                attachment_name: attachmentName,
                file_type: fileType,
                file_size: fileSize,
            });

            if (result.success) {
                console.log('[SubmitAssignmentDialog] Submission successful!');

                // Record academic action
                if (role === 'student') {
                    await recordAcademicAction();
                }

                toast.success(hasSubmission ? "Submission updated successfully!" : "Assignment submitted successfully!");

                // Reset form state
                setFile(null);
                setNotes("");

                onClose();
            } else {
                console.error('[SubmitAssignmentDialog] Submission failed:', result.error);
                toast.error(result.error || "Submission failed");
            }

        } catch (error: any) {
            console.error('[SubmitAssignmentDialog] Error:', error);
            toast.error("Error submitting assignment: " + error.message);
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async () => {
        if (!onDelete || !existingSubmission?.id) return;

        try {
            await onDelete(existingSubmission.id);
            toast.success("Submission deleted successfully");
            setDeleteDialogOpen(false);
            onClose();
        } catch (error: any) {
            console.error('[SubmitAssignmentDialog] Delete error:', error);
            toast.error("Failed to delete submission");
        }
    };

    // Render View Mode for submitted assignments
    if (hasSubmission) {
        return (
            <>
                <Dialog open={isOpen} onOpenChange={onClose}>
                    <DialogContent className="sm:max-w-3xl max-h-[90vh] overflow-hidden flex flex-col p-0 gap-0">
                        <div className="p-6 border-b flex items-start justify-between bg-white dark:bg-slate-950 shrink-0 sticky top-0 z-10">
                            <div className="flex-1 pr-12">
                                <div className="flex flex-wrap items-start gap-3 mb-1.5">
                                    <DialogTitle className="text-xl sm:text-2xl font-bold leading-tight">{assignment.title}</DialogTitle>
                                    <Badge variant={isGraded ? "default" : "secondary"} className={cn("mt-1 shrink-0 px-2 py-0.5 text-[10px] sm:text-xs uppercase tracking-wider font-bold", isGraded ? "bg-emerald-600 hover:bg-emerald-700" : "bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700")}>
                                        {isGraded ? "Graded" : "Submitted"}
                                    </Badge>
                                </div>
                                <DialogDescription className="flex flex-wrap items-center gap-x-3 gap-y-1 text-sm">
                                    <span className="font-semibold text-primary">{assignment.course_code}</span>
                                    <span className="text-muted-foreground">•</span>
                                    <span className="text-muted-foreground">{assignment.lecturer_name}</span>
                                </DialogDescription>
                            </div>

                            <div className="flex items-center gap-2">
                                {!isGraded && onDelete && (
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                                                <MoreVertical className="size-4" />
                                                <span className="sr-only">More options</span>
                                            </Button>
                                        </DropdownMenuTrigger>
                                        <DropdownMenuContent align="end">
                                            <DropdownMenuItem
                                                className="text-red-600 focus:text-red-600 focus:bg-red-50 dark:focus:bg-red-950"
                                                onClick={() => setDeleteDialogOpen(true)}
                                            >
                                                <Trash2 className="size-4 mr-2" />
                                                Delete Submission
                                            </DropdownMenuItem>
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                )}

                                <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800" onClick={onClose}>
                                    <X className="size-4" />
                                    <span className="sr-only">Close</span>
                                </Button>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 sm:p-6">
                            {assignment.due_date && (
                                <div className="flex justify-end mb-6">
                                    <span className="text-xs text-muted-foreground flex items-center gap-1.5 bg-muted/50 px-2.5 py-1.5 rounded-md font-medium border border-border/50">
                                        <Clock className="size-3.5" />
                                        Due {format(new Date(assignment.due_date), "MMM d, h:mm a")}
                                    </span>
                                </div>
                            )}

                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 lg:gap-10">
                                {/* LEFT COLUMN: Lecturer's Assignment */}
                                <div className="space-y-6">
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-2 text-sm font-bold uppercase text-slate-500 dark:text-slate-400 tracking-wider">
                                            <FileText className="size-4" /> Assignment Details
                                        </div>

                                        <div className="prose prose-sm dark:prose-invert max-w-none bg-slate-50 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-100 dark:border-white/5">
                                            <p className="whitespace-pre-wrap text-sm leading-relaxed">{assignment.description || assignment.instructions || "No description provided."}</p>
                                        </div>
                                    </div>

                                    {assignment.attachment_url && (
                                        <div className="bg-indigo-50 dark:bg-indigo-900/10 border border-indigo-100 dark:border-indigo-500/10 rounded-2xl p-4 transition-all hover:shadow-md hover:border-indigo-200 dark:hover:border-indigo-500/20 group">
                                            <Label className="text-xs font-bold text-indigo-600 dark:text-indigo-400 mb-3 block uppercase tracking-wider">Resource Material</Label>
                                            <a
                                                href={assignment.attachment_url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="flex items-center gap-4 group/link"
                                            >
                                                <div className="bg-indigo-100 dark:bg-indigo-900/40 p-3 rounded-xl group-hover:bg-indigo-200 dark:group-hover:bg-indigo-800 transition-colors">
                                                    <File className="size-6 text-indigo-600 dark:text-indigo-300" />
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-sm font-bold text-slate-900 dark:text-slate-100 truncate group-hover/link:underline decoration-indigo-500 underline-offset-2">
                                                        {assignment.attachment_name || "Attached Material"}
                                                    </p>
                                                    <p className="text-xs text-indigo-600 dark:text-indigo-400 mt-0.5 flex items-center gap-1">
                                                        Click to view <ExternalLink className="size-3" />
                                                    </p>
                                                </div>
                                            </a>
                                        </div>
                                    )}

                                    <div className="flex items-center gap-3 text-sm text-slate-600 dark:text-slate-400 bg-amber-50 dark:bg-amber-900/10 p-3 rounded-xl border border-amber-100 dark:border-amber-900/20 w-fit">
                                        <div className="p-1.5 bg-amber-100 dark:bg-amber-900/30 rounded-lg text-amber-600 dark:text-amber-500">
                                            <Trophy className="size-4" />
                                        </div>
                                        <span>Max Points: <span className="font-bold text-slate-900 dark:text-white">{assignment.points || 100} Points</span></span>
                                    </div>
                                </div>

                                {/* RIGHT COLUMN: Student's Work */}
                                <div className="space-y-6">
                                    <div className="flex items-center gap-2 text-sm font-bold uppercase text-slate-500 dark:text-slate-400 tracking-wider">
                                        <CheckCircle className="size-4" /> Your Work
                                    </div>

                                    <Card className="overflow-hidden border-emerald-500/20 bg-emerald-500/5 dark:bg-emerald-500/5 shadow-sm">
                                        <CardContent className="p-5 space-y-5">
                                            <div className="flex flex-wrapjustify-between items-start gap-4 border-b border-emerald-500/10 pb-4">
                                                <div>
                                                    <Label className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest mb-1 block">Submitted On</Label>
                                                    <p className="text-sm font-bold text-slate-700 dark:text-slate-300">
                                                        {existingSubmission.submitted_at ? format(new Date(existingSubmission.submitted_at), "MMM d, yyyy 'at' h:mm a") : "Unknown"}
                                                    </p>
                                                </div>
                                                {isGraded && (
                                                    <div className="text-right bg-white dark:bg-slate-950 px-3 py-2 rounded-xl shadow-sm border border-emerald-100 dark:border-emerald-500/20">
                                                        <Label className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest mb-0.5 block">Grade</Label>
                                                        <p className="text-2xl font-black text-emerald-700 dark:text-emerald-300 leading-none">
                                                            {existingSubmission.grade}<span className="text-xs text-muted-foreground font-normal ml-0.5">/{assignment.points || 100}</span>
                                                        </p>
                                                    </div>
                                                )}
                                            </div>

                                            {existingSubmission.submission_text && (
                                                <div>
                                                    <Label className="text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 block uppercase tracking-wider">Your Notes</Label>
                                                    <div className="bg-white/50 dark:bg-black/20 p-3 rounded-xl text-sm italic border border-emerald-500/5 text-slate-700 dark:text-slate-300">
                                                        "{existingSubmission.submission_text}"
                                                    </div>
                                                </div>
                                            )}

                                            {existingSubmission.attachment_url ? (
                                                <div>
                                                    <Label className="text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 block uppercase tracking-wider">Attached File</Label>
                                                    <a
                                                        href={existingSubmission.attachment_url}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="flex items-center gap-3 p-3 rounded-xl border border-emerald-200 dark:border-emerald-500/20 bg-white dark:bg-slate-900 shadow-sm hover:shadow-md hover:border-emerald-300 dark:hover:border-emerald-500/40 transition-all group"
                                                    >
                                                        <div className="bg-emerald-100 dark:bg-emerald-900/30 p-2 rounded-lg text-emerald-600 dark:text-emerald-400 group-hover:bg-emerald-200 dark:group-hover:bg-emerald-800 transition-colors">
                                                            <FileText className="size-5" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <span className="text-sm font-bold text-slate-800 dark:text-white truncate block">{existingSubmission.attachment_name || "Your Submission"}</span>
                                                            <span className="text-[10px] text-emerald-600 dark:text-emerald-400 font-medium uppercase tracking-wide">
                                                                Download {getFileTypeDisplay(existingSubmission.file_type)} {existingSubmission.file_size ? `(${formatFileSize(existingSubmission.file_size)})` : ''}
                                                            </span>
                                                        </div>
                                                        <Download className="size-4 text-slate-400 group-hover:text-emerald-500 transition-colors" />
                                                    </a>
                                                </div>
                                            ) : (
                                                !existingSubmission.submission_text && <p className="text-sm text-muted-foreground italic text-center py-2">No files attached.</p>
                                            )}
                                        </CardContent>
                                    </Card>

                                    {/* Feedback Section */}
                                    {existingSubmission.feedback && (
                                        <div className="bg-gradient-to-br from-amber-50 to-orange-50 dark:from-amber-900/10 dark:to-orange-900/10 border border-amber-200 dark:border-amber-800/30 rounded-2xl p-5 shadow-sm">
                                            <h4 className="text-sm font-black text-amber-800 dark:text-amber-400 mb-3 flex items-center gap-2 uppercase tracking-wide">
                                                <AlertCircle className="size-4" /> Lecturer Feedback
                                            </h4>
                                            <p className="text-sm text-amber-900 dark:text-amber-100 leading-relaxed bg-white/50 dark:bg-black/10 p-3 rounded-xl">
                                                {existingSubmission.feedback}
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </DialogContent>
                </Dialog>

                <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
                    <AlertDialogContent>
                        <AlertDialogHeader>
                            <AlertDialogTitle>Delete Submission?</AlertDialogTitle>
                            <AlertDialogDescription>
                                This will permanently delete your work. This action cannot be undone.
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel>Cancel</AlertDialogCancel>
                            <AlertDialogAction
                                onClick={handleDelete}
                                className="bg-red-600 hover:bg-red-700 focus:ring-red-600"
                            >
                                Delete
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>
            </>
        );
    }

    // Render Form Mode
    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent
                className="sm:max-w-[500px]"
                onPointerDownOutside={(e) => e.preventDefault()}
                onInteractOutside={(e) => e.preventDefault()}
            >
                <DialogHeader>
                    <DialogTitle>{hasSubmission ? "Edit Submission" : "Submit Assignment"}</DialogTitle>
                    <DialogDescription>
                        Submit your work for <strong>{assignment.title}</strong>
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit}>
                    <div className="space-y-4 py-4">
                        {/* Read-only info */}
                        <div className="grid grid-cols-2 gap-4 text-sm">
                            <div>
                                <span className="text-muted-foreground block">Subject</span>
                                <span className="font-medium">{assignment.subject_name || assignment.course_title}</span>
                            </div>
                            <div>
                                <span className="text-muted-foreground block">Lecturer</span>
                                <span className="font-medium">{assignment.lecturer_name}</span>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <Label>Assignment File</Label>
                            <div
                                className="border-2 border-dashed border-border rounded-lg p-6 bg-muted/20 hover:bg-muted/40 transition-colors cursor-pointer flex flex-col items-center justify-center text-center"
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    className="hidden"
                                    accept=".pdf,.doc,.docx,.txt,.zip,.rar"
                                    onChange={handleFileChange}
                                />
                                {file ? (
                                    <div className="flex items-center gap-2 text-primary">
                                        <FileText className="size-6" />
                                        <span className="font-medium truncate max-w-[200px]">{file.name}</span>
                                        <Button
                                            type="button"
                                            variant="ghost"
                                            size="icon"
                                            className="h-8 w-8"
                                            onClick={(e) => { e.stopPropagation(); setFile(null); }}
                                        >
                                            <X className="size-4" />
                                        </Button>
                                    </div>
                                ) : (
                                    <>
                                        <Upload className="size-8 text-muted-foreground mb-2" />
                                        <p className="text-sm font-medium">Click to upload file</p>
                                        <p className="text-xs text-muted-foreground mt-1">PDF, DOC, DOCX, TXT, ZIP, RAR (Max 50MB)</p>
                                    </>
                                )}
                            </div>
                            {hasSubmission && !file && (
                                <p className="text-xs text-muted-foreground text-center mt-2">
                                    Current file: {existingSubmission.attachment_name || "None"}
                                </p>
                            )}
                        </div>

                        <div className="space-y-2">
                            <Label>Additional Notes (Optional)</Label>
                            <Textarea
                                placeholder="Any comments for the lecturer..."
                                value={notes}
                                onChange={(e) => setNotes(e.target.value)}
                            />
                        </div>
                    </div>

                    <DialogFooter>
                        <Button type="button" variant="outline" onClick={onClose} disabled={submitting}>Cancel</Button>
                        <Button type="submit" disabled={submitting || (!file && !hasSubmission)}>
                            {submitting && <Loader2 className="size-4 mr-2 animate-spin" />}
                            {hasSubmission ? "Update Submission" : "Submit Assignment"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import { Dialog, DialogContent } from "@/components/ui/dialog";
import { X, Loader2, Minimize2, Maximize2, Video } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";

interface CallModalProps {
    isOpen: boolean;
    onClose: () => void;
    type: 'audio' | 'video';
    conversationId: string;
    userName: string;
    isMeeting?: boolean;
    isMinimized?: boolean;
    onMinimize?: (minimized: boolean) => void;
}

export function CallModal({ isOpen, onClose, type, conversationId, userName, isMeeting, isMinimized, onMinimize }: CallModalProps) {
    const appId = "vpaas-magic-cookie-f796d7a3ec46435793193a60b0aef396";
    const domain = "8x8.vc";
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (!isOpen) return;

        let api: any = null;

        const initJitsi = async () => {
            try {
                setIsLoading(true);

                const conferenceName = (isMeeting
                    ? `eduspace_meeting_${conversationId}`
                    : `eduspace_secure_${conversationId.replace(/[^a-zA-Z0-9]/g, '_')}`).toLowerCase();

                const { data, error } = await supabase.functions.invoke('generate-jitsi-token', {
                    body: {
                        roomName: conferenceName,
                        userProfile: {
                            id: (await supabase.auth.getUser()).data.user?.id || 'unknown',
                            name: userName
                        }
                    }
                });

                if (error) throw error;

                const script = document.createElement("script");
                script.src = `https://${domain}/${appId}/external_api.js`;
                script.async = true;
                document.body.appendChild(script);

                script.onload = () => {
                    const roomName = `${appId}/${conferenceName}`;

                    if ((window as any).JitsiMeetExternalAPI) {
                        api = new (window as any).JitsiMeetExternalAPI(domain, {
                            roomName: roomName,
                            parentNode: document.querySelector('#jaas-container'),
                            width: '100%',
                            height: '100%',
                            jwt: data.token,
                            configOverwrite: {
                                prejoinPageEnabled: false,
                                startWithAudioMuted: false,
                                startWithVideoMuted: type === 'audio',
                                startAudioOnly: type === 'audio',
                                disableThirdPartyRequests: false,
                                enableNoAudioDetection: true,
                                enableNoNotificationsIsolation: true,
                                p2p: { enabled: true, preferH264: true },
                                audioQuality: { stereo: true },
                                disableDeepLinking: true,
                                doNotStoreRoom: true,
                            },
                            interfaceConfigOverwrite: {
                                SHOW_JITSI_WATERMARK: false,
                                SHOW_WATERMARK_FOR_GUESTS: false,
                                SHOW_BRAND_WATERMARK: false,
                                MOBILE_APP_PROMO: false,
                                TOOLBAR_BUTTONS: [
                                    'microphone', 'camera', 'closedcaptions', 'desktop', 'fullscreen',
                                    'fodeviceselection', 'hangup', 'profile', 'chat', 'recording',
                                    'livestreaming', 'etherpad', 'sharedvideo', 'settings', 'raisehand',
                                    'videoquality', 'filmstrip', 'invite', 'feedback', 'stats', 'shortcuts',
                                    'tileview', 'videobackgroundblur', 'download', 'help', 'mute-everyone',
                                    'security'
                                ],
                            },
                        });

                        api.addEventListener('videoConferenceLeft', () => {
                            onClose();
                        });

                        setIsLoading(false);
                    }
                };
            } catch (err) {
                console.error("Failed to initialize Jitsi:", err);
                setIsLoading(false);
            }
        };

        const container = document.querySelector('#jaas-container');
        if (container) container.innerHTML = '';
        initJitsi();

        return () => {
            if (api) api.dispose();
            const cont = document.querySelector('#jaas-container');
            if (cont) cont.innerHTML = '';
            const scripts = document.querySelectorAll(`script[src*="external_api.js"]`);
            scripts.forEach(s => s.remove());
        };
    }, [isOpen, conversationId, userName, type, isMeeting]);

    return (
        <>
            {/* Backdrop: Only show when NOT minimized to simulate a modal */}
            {isOpen && !isMinimized && (
                <div
                    className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[99998] animate-in fade-in duration-300 pointer-events-none"
                />
            )}

            <div
                className={cn(
                    "fixed transition-all duration-500 ease-in-out overflow-hidden shadow-2xl bg-black border border-white/10",
                    isMinimized
                        ? "bottom-4 right-4 md:bottom-6 md:right-6 w-[180px] h-[110px] md:w-[340px] md:h-[210px] rounded-xl md:rounded-2xl z-[100000] hover:scale-105 active:scale-95 cursor-pointer"
                        : "inset-0 w-full h-[100dvh] rounded-none z-[99999]",
                    !isOpen && "hidden"
                )}
                onClick={() => {
                    if (isMinimized) onMinimize?.(false);
                }}
            >
                <div className="relative w-full h-full bg-black group touch-none">
                    {isLoading && (
                        <div className="absolute inset-0 z-[100001] flex flex-col items-center justify-center bg-slate-950 text-white gap-2 md:gap-4">
                            <Loader2 className="size-6 md:size-12 animate-spin text-emerald-500" />
                        </div>
                    )}

                    <div
                        id="jaas-container"
                        className="w-full h-full bg-black"
                    />

                    {/* Controls Overlay - Always visible on small screens to avoid hover issues */}
                    <div className={cn(
                        "absolute top-2 right-4 md:top-4 md:right-60 z-[100002] flex gap-1000 md:gap-0.5 transition-opacity duration-3000",
                        isMinimized ? "md:opacity-0 md:group-hover:opacity-100" : "opacity-100"
                    )}>
                        {onMinimize && (
                            <Button
                                variant="ghost"
                                size="icon"
                                className="size-7 md:size-10 rounded-full bg-black/60 hover:bg-white/20 text-white backdrop-blur-md border border-white/10 shadow-lg"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    onMinimize(!isMinimized);
                                }}
                                title={isMinimized ? "Full Screen" : "Minimize"}
                            >
                                {isMinimized ? <Maximize2 className="size-3.5 md:size-5" /> : <Minimize2 className="size-3.5 md:size-5" />}
                            </Button>
                        )}
                        <Button
                            variant="ghost"
                            size="icon"
                            className="size-7 md:size-10 rounded-full bg-black/60 hover:bg-white/20 text-white backdrop-blur-md border border-white/10 shadow-lg"
                            onClick={(e) => {
                                e.stopPropagation();
                                onClose();
                            }}
                            title="End Call"
                        >
                            <X className="size-4 md:size-5" />
                        </Button>
                    </div>

                    {/* Redesigned Minimized UI based on user image */}
                    {isMinimized && (
                        <div className="absolute inset-0 z-[100002] flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] p-2 md:p-6 text-center select-none md:opacity-0 md:group-hover:opacity-100 transition-all duration-300">
                            <span className="text-[10px] md:text-xl font-bold text-white mb-1 md:mb-3 drop-shadow-md">
                                In Call
                            </span>

                            <h3 className="text-[12px] md:text-2xl font-bold text-white mb-3 md:mb-6 px-4 leading-tight drop-shadow-lg max-w-full truncate">
                                {isMeeting ? `Eduspace Meeting ${conversationId.slice(-6).toUpperCase()}` : `Private Session`}
                            </h3>

                            <div className="bg-[#333333] px-3 py-1 md:px-12 md:py-3 rounded-lg md:rounded-xl border border-white/5 shadow-2xl mb-4 md:mb-8 flex items-center justify-center min-w-[100px] md:min-w-[240px]">
                                <span className="text-[10px] md:text-base text-[#E5E7EB] font-semibold truncate">
                                    {userName}
                                </span>
                            </div>

                            {/* Maximize Prompt Styled like the 'Join' button */}
                            <div
                                className="hidden md:flex items-center gap-2 bg-[#2563EB] hover:bg-[#1D4ED8] text-white px-8 py-2 md:py-3 rounded-xl font-bold text-sm shadow-xl transition-colors cursor-pointer"
                                onClick={() => onMinimize?.(false)}
                            >
                                <span>Return to Call</span>
                                <Maximize2 className="size-4 ml-2" />
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </>
    );
}

import { useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { useNavigate } from 'react-router-dom';
import { requestFirebaseToken, onForegroundMessage } from '@/lib/firebase';

export function FCMManager() {
    const { user } = useAuth();
    const navigate = useNavigate();

    useEffect(() => {
        if (!user) return;

        let pushListeners: any[] = [];

        const initFCM = async () => {
            try {
                const { Capacitor } = await import('@capacitor/core');

                // Handle Web/PWA Platform
                if (!Capacitor.isNativePlatform()) {
                    console.log("Initializing Web FCM...");
                    requestFirebaseToken(user.id);

                    // Listen for foreground messages
                    const unsubscribe = onForegroundMessage((payload: any) => {
                        console.log('Foreground message received:', payload);
                        if (payload.data?.type === 'incoming_call') {
                            toast.info(`Incoming Call`, {
                                description: `${payload.data.callerName || 'Someone'} is calling you...`,
                                action: {
                                    label: 'Accept',
                                    onClick: () => {
                                        navigate(`/messages?session=${payload.data.sessionId}&action=accept`);
                                    }
                                },
                                duration: 10000
                            });
                        } else if (payload.notification) {
                            toast.info(payload.notification.title || 'New Message', {
                                description: payload.notification.body
                            });
                        }
                    });

                    return unsubscribe;
                }

                // Handle Native Platform (Capacitor)
                const { PushNotifications } = await import('@capacitor/push-notifications');

                if (Capacitor.getPlatform() === 'android') {
                    PushNotifications.createChannel({
                        id: 'calls',
                        name: 'Incoming Calls',
                        description: 'Notifications for incoming video and audio calls',
                        importance: 5, // HIGH
                        visibility: 1, // PUBLIC
                        sound: 'notification_ringtone',
                        vibration: true,
                    }).catch(e => console.error('Error creating channel:', e));
                }

                const registerPush = async () => {
                    try {
                        const result = await PushNotifications.requestPermissions();
                        if (result.receive === 'granted') {
                            await PushNotifications.register();
                        }
                    } catch (e) {
                        console.warn("FCM registration failed:", e);
                    }
                };

                const l1 = await PushNotifications.addListener('registration', async (token) => {
                    console.log('Push registration success, token: ' + token.value);
                    if (user) {
                        await supabase
                            .from('profiles')
                            .update({ fcm_token: token.value })
                            .eq('user_id', user.id);
                    }
                });

                const l2 = await PushNotifications.addListener('pushNotificationReceived', (notification) => {
                    console.log('Push received: ', notification);
                    if (notification.data?.type === 'incoming_call') {
                        toast.info(`Incoming Call`, {
                            description: `${notification.data.callerName || 'Someone'} is calling you...`,
                            action: {
                                label: 'Accept',
                                onClick: () => {
                                    navigate(`/messages?session=${notification.data.sessionId}&action=accept`);
                                }
                            },
                            duration: 10000
                        });
                    } else {
                        toast.info(notification.title || 'New Notification', {
                            description: notification.body
                        });
                    }
                });

                const l3 = await PushNotifications.addListener('pushNotificationActionPerformed', (notification) => {
                    const data = notification.notification.data;
                    if (data?.url) {
                        navigate(data.url);
                    } else if (data?.sessionId) {
                        navigate(`/messages?session=${data.sessionId}${data.type === 'incoming_call' ? '&action=accept' : ''}`);
                    }
                });

                pushListeners = [l1, l2, l3];
                registerPush();

            } catch (err) {
                console.warn("FCM initialization failed", err);
            }
        };

        const result = initFCM();

        return () => {
            result.then(unsubscribe => {
                if (typeof unsubscribe === 'function') unsubscribe();
                import('@capacitor/core').then(({ Capacitor }) => {
                    if (Capacitor.isNativePlatform()) {
                        import('@capacitor/push-notifications').then(({ PushNotifications }) => {
                            PushNotifications.removeAllListeners();
                        }).catch(() => { });
                    }
                }).catch(() => { });
            });
        };

    }, [user]);

    return null;
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { BarChart2, Check, MoreVertical, Users } from 'lucide-react';
import { toast } from "sonner";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useStreak } from '@/contexts/StreakContext';

interface PollData {
    id: string;
    question: string;
    options: { text: string; votes: number; percentage: number }[];
    totalVotes: number;
    userVotes: Set<number>;
    createdBy: string;
    allowMultiple: boolean;
    isClosed: boolean;
}

interface VoterInfo {
    user_id: string;
    full_name: string;
    avatar_url: string;
    option_index: number;
}

export function PollBubble({ pollId }: { pollId: string }) {
    const { user, role } = useAuth();
    const [poll, setPoll] = useState<PollData | null>(null);
    const [loading, setLoading] = useState(true);
    const [voting, setVoting] = useState(false);

    // Editing state
    const [isEditing, setIsEditing] = useState(false);
    const [editQuestion, setEditQuestion] = useState("");
    const [editOptions, setEditOptions] = useState<string[]>([]);
    const [editAllowMultiple, setEditAllowMultiple] = useState(false);
    const [isUpdating, setIsUpdating] = useState(false);

    // Modal state for viewing votes
    const [showVotesModal, setShowVotesModal] = useState(false);
    const [voterDetails, setVoterDetails] = useState<VoterInfo[]>([]);
    const [isLoadingVotes, setIsLoadingVotes] = useState(false);

    useEffect(() => {
        if (!user || !pollId) return;

        const fetchPoll = async () => {
            try {
                const { data: pollData, error } = await supabase
                    .from('chat_polls')
                    .select('*')
                    .eq('id', pollId)
                    .single();

                if (error || !pollData) throw error;

                const { data: votes } = await supabase
                    .from('chat_poll_votes')
                    .select('*')
                    .eq('poll_id', pollId);

                const isMultiple = pollData.allow_multiple ?? false;
                let processedVotes = votes || [];

                // For single-choice polls, ensure we only count one vote per user
                if (!isMultiple) {
                    const latestUserVotes = new Map();
                    processedVotes.forEach(v => {
                        // We keep the latest vote if somehow duplicates exist
                        latestUserVotes.set(v.user_id, v);
                    });
                    processedVotes = Array.from(latestUserVotes.values());
                }

                const userVotes = new Set<number>(
                    processedVotes.filter(v => v.user_id === user.id).map(v => v.option_index)
                );
                const totalVotes = processedVotes.length;

                const pollOptions = (pollData.options as string[]).map((optionText, index) => {
                    const votesForThisOption = processedVotes.filter(v => v.option_index === index).length;
                    const percentage = totalVotes > 0 ? Math.round((votesForThisOption / totalVotes) * 100) : 0;
                    return {
                        text: optionText,
                        votes: votesForThisOption,
                        percentage: percentage
                    };
                });

                setPoll({
                    id: pollData.id,
                    question: pollData.question,
                    options: pollOptions,
                    totalVotes: totalVotes,
                    userVotes,
                    createdBy: pollData.created_by,
                    allowMultiple: pollData.allow_multiple ?? false,
                    isClosed: pollData.is_closed ?? false
                });
            } catch (err) {
                console.error("Error fetching poll:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchPoll();

        const subscription = supabase
            .channel(`poll_${pollId}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_poll_votes', filter: `poll_id=eq.${pollId}` },
                () => fetchPoll()
            )
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'chat_polls', filter: `id=eq.${pollId}` },
                () => fetchPoll()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(subscription);
        };
    }, [pollId, user]);

    const { recordAcademicAction } = useStreak();

    const handleVote = async (optionIndex: number) => {
        if (!user || !poll || voting || isEditing) return;

        // Record academic action (Participating in class interaction)
        if (role === 'student') {
            recordAcademicAction();
        }

        // Restriction: Poll creator cannot vote
        if (user.id === poll.createdBy) {
            toast.info("As the creator, you cannot vote in this poll.", {
                description: "This poll is for gathering student feedback.",
                icon: <BarChart2 className="w-4 h-4 text-emerald-500" />
            });
            return;
        }

        // Check if poll is closed
        if ((poll as any).isClosed) {
            toast.error("This poll has been closed. Voting is no longer allowed.");
            return;
        }

        const isAlreadyVoted = poll.userVotes.has(optionIndex);
        const hasAnyVote = poll.userVotes.size > 0;

        // Optimistic UI Update: Calculate new state before database operation
        const newUserVotes = new Set(poll.userVotes);
        let newOptions = [...poll.options];
        let newTotalVotes = poll.totalVotes;

        if (isAlreadyVoted && poll.allowMultiple) {
            // Multi-choice: Deselect this option
            newUserVotes.delete(optionIndex);
            newTotalVotes = Math.max(0, newTotalVotes - 1);
            newOptions[optionIndex] = {
                ...newOptions[optionIndex],
                votes: Math.max(0, newOptions[optionIndex].votes - 1)
            };
        } else if (isAlreadyVoted && !poll.allowMultiple) {
            // Single-choice: Clicking same option does nothing (already selected)
            return;
        } else {
            // Selecting a new option
            if (!poll.allowMultiple && hasAnyVote) {
                // Single-choice: Remove previous vote from UI
                poll.userVotes.forEach(idx => {
                    if (newOptions[idx]) {
                        newOptions[idx] = {
                            ...newOptions[idx],
                            votes: Math.max(0, newOptions[idx].votes - 1)
                        };
                        newTotalVotes = Math.max(0, newTotalVotes - 1);
                    }
                });
                newUserVotes.clear();
            }

            // Add new vote
            newUserVotes.add(optionIndex);
            newTotalVotes++;
            newOptions[optionIndex] = {
                ...newOptions[optionIndex],
                votes: newOptions[optionIndex].votes + 1
            };
        }

        // Recalculate percentages for all options
        newOptions = newOptions.map(opt => ({
            ...opt,
            percentage: newTotalVotes > 0 ? Math.round((opt.votes / newTotalVotes) * 100) : 0
        }));

        // Update local state immediately for instant feedback
        setPoll(prev => prev ? {
            ...prev,
            userVotes: newUserVotes,
            options: newOptions,
            totalVotes: newTotalVotes
        } : null);
        setVoting(true);

        try {
            // Database operation: Handle vote change atomically
            if (isAlreadyVoted && poll.allowMultiple) {
                // Multi-choice: Delete this specific vote
                const { error } = await supabase
                    .from('chat_poll_votes')
                    .delete()
                    .eq('poll_id', pollId)
                    .eq('user_id', user.id)
                    .eq('option_index', optionIndex);

                if (error) throw error;
            } else if (!isAlreadyVoted) {
                // Adding a new vote
                if (!poll.allowMultiple) {
                    // Single-choice: Delete ALL previous votes first (atomic vote change)
                    const { error: deleteError } = await supabase
                        .from('chat_poll_votes')
                        .delete()
                        .eq('poll_id', pollId)
                        .eq('user_id', user.id);

                    if (deleteError && deleteError.code !== 'PGRST116') {
                        // PGRST116 = no rows to delete, which is fine
                        throw deleteError;
                    }
                }

                // Insert the new vote
                const { error: insertError } = await supabase
                    .from('chat_poll_votes')
                    .insert({
                        poll_id: pollId,
                        user_id: user.id,
                        option_index: optionIndex
                    });

                if (insertError) {
                    // Handle unique constraint violation gracefully
                    if ((insertError as any).code === '23505') {
                        console.warn('Vote already exists, refreshing poll data...');
                        // Let the subscription handle the refresh
                        return;
                    }
                    throw insertError;
                }
            }

            // Success feedback
            if (!poll.allowMultiple && hasAnyVote && !isAlreadyVoted) {
                toast.success("Vote changed successfully!");
            }
        } catch (err) {
            console.error("Error updating vote:", err);
            toast.error("Failed to update vote. Please try again.");

            // Revert optimistic update by triggering a fresh fetch
            // The subscription will handle this automatically
        } finally {
            setVoting(false);
        }
    };

    const startEditing = () => {
        if (!poll) return;
        setEditQuestion(poll.question);
        setEditOptions(poll.options.map(o => o.text));
        setEditAllowMultiple(poll.allowMultiple);
        setIsEditing(true);
    };

    const handleUpdatePoll = async () => {
        if (!user || !poll || !editQuestion.trim() || editOptions.some(o => !o.trim())) {
            return;
        }

        setIsUpdating(true);
        try {
            const { error } = await supabase
                .from('chat_polls')
                .update({
                    question: editQuestion.trim(),
                    options: editOptions.map(o => o.trim()),
                    allow_multiple: editAllowMultiple
                })
                .eq('id', poll.id);

            if (error) throw error;
            setIsEditing(false);
            toast.success("Poll updated successfully!");
        } catch (err) {
            console.error("Error updating poll:", err);
            toast.error("Failed to update poll");
        } finally {
            setIsUpdating(false);
        }
    };

    const fetchVoterDetails = async () => {
        if (!pollId) return;
        setIsLoadingVotes(true);
        try {
            const { data: votesData, error: votesError } = await supabase
                .from('chat_poll_votes')
                .select('user_id, option_index')
                .eq('poll_id', pollId);

            if (votesError) throw votesError;

            if (votesData && votesData.length > 0) {
                const userIds = [...new Set(votesData.map(v => v.user_id))];
                const { data: profilesData, error: profilesError } = await supabase
                    .from('profiles')
                    .select('user_id, full_name, avatar_url')
                    .in('user_id', userIds);

                if (profilesError) throw profilesError;

                const combinedDetails = votesData.map(vote => {
                    const profile = profilesData?.find(p => p.user_id === vote.user_id);
                    return {
                        user_id: vote.user_id,
                        full_name: profile?.full_name || 'Unknown User',
                        avatar_url: profile?.avatar_url || '',
                        option_index: vote.option_index
                    };
                });
                setVoterDetails(combinedDetails);
            } else {
                setVoterDetails([]);
            }
        } catch (err) {
            console.error("Error fetching voter details:", err);
            toast.error("Failed to load voter details");
        } finally {
            setIsLoadingVotes(false);
        }
    };

    if (loading) return <div className="p-4 bg-slate-50 dark:bg-slate-900 rounded-lg animate-pulse w-full h-48" />;
    if (!poll) return null;

    const isCreator = user?.id === poll.createdBy;

    return (
        <div className="w-full max-w-sm">
            {/* Poll Card */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl border-2 border-emerald-400 dark:border-emerald-500 overflow-hidden shadow-sm">
                {/* Header */}
                <div className="px-4 py-3 bg-white dark:bg-slate-900">
                    <div className="flex items-center gap-2 mb-3">
                        <div className="size-5 bg-emerald-500 rounded flex items-center justify-center">
                            <BarChart2 className="w-3 h-3 text-white" />
                        </div>
                        <span className="text-[11px] font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wide">
                            Interactive Poll
                        </span>
                        {poll.isClosed && (
                            <span className="ml-auto px-2 py-0.5 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 text-[9px] font-bold uppercase rounded">
                                Closed
                            </span>
                        )}
                    </div>

                    {/* Question */}
                    {isEditing ? (
                        <div className="space-y-3">
                            <Input
                                value={editQuestion}
                                onChange={(e) => setEditQuestion(e.target.value)}
                                className="text-sm font-semibold"
                                placeholder="Type your question..."
                            />
                            <div className="space-y-2">
                                {editOptions.map((option, idx) => (
                                    <Input
                                        key={idx}
                                        value={option}
                                        onChange={(e) => {
                                            const newOpts = [...editOptions];
                                            newOpts[idx] = e.target.value;
                                            setEditOptions(newOpts);
                                        }}
                                        className="text-sm"
                                        placeholder={`Option ${idx + 1}`}
                                    />
                                ))}
                            </div>
                            <div className="flex items-center justify-between p-2 bg-slate-50 dark:bg-slate-800 rounded">
                                <span className="text-xs font-semibold">Allow Multiple</span>
                                <button
                                    onClick={() => setEditAllowMultiple(!editAllowMultiple)}
                                    className={`w-10 h-5 rounded-full transition-colors relative ${editAllowMultiple ? 'bg-emerald-500' : 'bg-slate-300'}`}
                                >
                                    <div className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full transition-transform ${editAllowMultiple ? 'translate-x-5' : ''}`} />
                                </button>
                            </div>
                            <div className="flex justify-end gap-2">
                                <Button variant="ghost" size="sm" onClick={() => setIsEditing(false)}>Cancel</Button>
                                <Button size="sm" className="bg-emerald-600 hover:bg-emerald-700" onClick={handleUpdatePoll} disabled={isUpdating}>
                                    {isUpdating ? "Saving..." : "Save"}
                                </Button>
                            </div>
                        </div>
                    ) : (
                        <h3 className="text-[15px] font-semibold text-slate-900 dark:text-slate-50 leading-snug">
                            {poll.question}
                        </h3>
                    )}
                </div>

                {/* Options */}
                {!isEditing && (
                    <div className="px-4 pb-4 space-y-2">
                        {poll.options.map((option, index) => {
                            const isSelected = poll.userVotes.has(index);
                            return (
                                <button
                                    key={index}
                                    className={`w-full text-left transition-all duration-200 ${isCreator || poll.isClosed ? 'cursor-not-allowed opacity-50' : 'cursor-pointer hover:opacity-80'
                                        }`}
                                    onClick={() => handleVote(index)}
                                    disabled={voting || isCreator || poll.isClosed}
                                >
                                    {/* Option Text and Percentage */}
                                    <div className="flex items-center justify-between mb-1">
                                        <div className="flex items-center gap-2">
                                            {isSelected && (
                                                <div className="size-4 bg-emerald-500 rounded-full flex items-center justify-center">
                                                    <Check className="w-2.5 h-2.5 text-white stroke-[3px]" />
                                                </div>
                                            )}
                                            <span className={`text-sm font-medium ${isSelected ? 'text-slate-900 dark:text-slate-50' : 'text-slate-700 dark:text-slate-300'}`}>
                                                {option.text}
                                            </span>
                                        </div>
                                        <span className="text-sm font-semibold text-slate-600 dark:text-slate-400">
                                            {option.percentage}%
                                        </span>
                                    </div>

                                    {/* Progress Bar */}
                                    <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                        <div
                                            className={`h-full transition-all duration-500 ${isSelected ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'
                                                }`}
                                            style={{ width: `${option.percentage}%` }}
                                        />
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                )}

                {/* Footer */}
                {!isEditing && (
                    <div className="px-4 py-2 border-t border-slate-100 dark:border-slate-800 flex items-center justify-center">
                        <button
                            onClick={() => {
                                fetchVoterDetails();
                                setShowVotesModal(true);
                            }}
                            className="text-emerald-600 dark:text-emerald-400 text-xs font-semibold hover:underline"
                        >
                            View votes
                        </button>
                        {isCreator && (
                            <>
                                <span className="mx-2 text-slate-300">•</span>
                                <button
                                    onClick={startEditing}
                                    className="text-emerald-600 dark:text-emerald-400 text-xs font-semibold hover:underline"
                                >
                                    Edit
                                </button>
                            </>
                        )}
                    </div>
                )}
            </div>

            {/* Voter Details Modal */}
            <Dialog open={showVotesModal} onOpenChange={setShowVotesModal}>
                <DialogContent className="sm:max-w-md rounded-2xl">
                    <DialogHeader>
                        <DialogTitle className="text-lg font-bold text-emerald-600 flex items-center gap-2">
                            <Users className="w-5 h-5" />
                            Poll Votes
                        </DialogTitle>
                    </DialogHeader>
                    <div className="max-h-[60vh] overflow-y-auto space-y-4">
                        {isLoadingVotes ? (
                            <div className="space-y-3 py-4">
                                {[1, 2, 3].map(i => (
                                    <div key={i} className="flex items-center gap-3 animate-pulse">
                                        <div className="w-8 h-8 bg-slate-100 rounded-full" />
                                        <div className="flex-1 space-y-2">
                                            <div className="h-3 bg-slate-100 rounded w-1/2" />
                                            <div className="h-2 bg-slate-50 rounded w-1/3" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : voterDetails.length === 0 ? (
                            <div className="text-center py-8">
                                <Users className="w-10 h-10 text-slate-200 mx-auto mb-2" />
                                <p className="text-slate-500 text-sm font-medium">No votes yet</p>
                            </div>
                        ) : (
                            poll.options.map((option, optIdx) => {
                                const optionVoters = voterDetails.filter(v => v.option_index === optIdx);
                                if (optionVoters.length === 0) return null;

                                return (
                                    <div key={optIdx} className="space-y-2">
                                        <div className="flex items-center justify-between">
                                            <h4 className="font-bold text-sm text-slate-900 dark:text-slate-100">
                                                {option.text}
                                            </h4>
                                            <span className="px-2 py-0.5 bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 rounded-full text-[10px] font-bold">
                                                {optionVoters.length}
                                            </span>
                                        </div>
                                        <div className="space-y-1.5 pl-3 border-l-2 border-emerald-100 dark:border-emerald-900/30">
                                            {optionVoters.map((voter, vIdx) => (
                                                <div key={vIdx} className="flex items-center gap-2">
                                                    <Avatar className="h-6 w-6">
                                                        <AvatarImage src={voter.avatar_url} />
                                                        <AvatarFallback className="bg-emerald-50 text-emerald-600 text-[9px] font-bold">
                                                            {voter.full_name?.charAt(0) || '?'}
                                                        </AvatarFallback>
                                                    </Avatar>
                                                    <span className="text-xs font-medium text-slate-600 dark:text-slate-400">
                                                        {voter.full_name}
                                                    </span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                );
                            })
                        )}
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { useCall } from '@/contexts/CallContext';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import {
    Phone, PhoneOff, Video, VideoOff, Mic, MicOff,
    Maximize2, Minimize2, X, Loader2,
    ChevronDown, Lock, UserPlus, Volume2, Grid, MessageSquare,
    GripVertical, ChevronUp
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';

export function PrivateCallManager() {
    const { activeCall, endCall, acceptCall, rejectCall, isMinimized, setMinimized } = useCall();
    const { user, profile } = useAuth();

    const [localStream, setLocalStream] = useState<MediaStream | null>(null);
    const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
    const [isMuted, setIsMuted] = useState(false);
    const [isCameraOff, setIsCameraOff] = useState(false);
    const [isSpeakerOn, setIsSpeakerOn] = useState(true); // Default to speaker on for mobile/web calls
    const [isRemoteVideoOff, setIsRemoteVideoOff] = useState(false);
    const [timer, setTimer] = useState(0);

    const peerConnection = useRef<RTCPeerConnection | null>(null);
    const localVideoRef = useRef<HTMLVideoElement>(null);
    const remoteVideoRef = useRef<HTMLVideoElement>(null);
    const remoteAudioRef = useRef<HTMLAudioElement>(null);
    const ringtoneRef = useRef<HTMLAudioElement>(null);
    const timerInterval = useRef<any>(null);

    const iceServers = {
        iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:stun1.l.google.com:19302' },
        ],
    };

    // Notification Permission Warning
    useEffect(() => {
        if (!("Notification" in window)) return;

        if (Notification.permission === 'denied') {
            const hasWarned = sessionStorage.getItem('call_notif_denied_warned');
            if (!hasWarned) {
                toast.warning("Notifications are blocked. You might miss incoming calls when the app is in the background.", {
                    description: "Please enable them in your browser settings.",
                    duration: 10000
                });
                sessionStorage.setItem('call_notif_denied_warned', 'true');
            }
        }
    }, []);

    // Call Duration Timer (Unlimited)
    useEffect(() => {
        if (activeCall?.status === 'active' && activeCall.category === 'private') {
            timerInterval.current = setInterval(() => {
                setTimer(prev => prev + 1);
            }, 1000);
        } else {
            clearInterval(timerInterval.current);
            setTimer(0);
        }

        return () => clearInterval(timerInterval.current);
    }, [activeCall?.status, activeCall?.category]);

    // 1-Minute Unanswered Call Timeout
    useEffect(() => {
        if (activeCall?.status !== 'calling') return;

        const timeout = setTimeout(() => {
            toast.error('No answer', { description: 'The call was not picked up.' });
            endCall();
        }, 60000); // 60 seconds

        return () => clearTimeout(timeout);
    }, [activeCall?.status, endCall]);

    // Ringtone Management & Vibration
    useEffect(() => {
        let vibrationInterval: any = null;
        let ringtoneRetryInterval: any = null;
        const ringtone = ringtoneRef.current;

        const attemptPlayRingtone = async () => {
            if (!ringtone) return;
            try {
                ringtone.volume = 1.0;
                ringtone.currentTime = 0;
                await ringtone.play();
                console.log("[CallManager] Ringtone playing successfully");
                if (ringtoneRetryInterval) clearInterval(ringtoneRetryInterval);
            } catch (e) {
                console.warn("[CallManager] Ringtone blocked by browser:", e);
            }
        };

        if (activeCall?.status === 'incoming') {
            console.log("[CallManager] Incoming call detected, triggering ringtone/vibration...");
            attemptPlayRingtone();

            // Set a retry interval just in case
            ringtoneRetryInterval = setInterval(() => {
                attemptPlayRingtone();
            }, 3000);

            // Start vibration (for supported mobile devices)
            if ("vibrate" in navigator) {
                try {
                    navigator.vibrate([1000, 500, 1000, 500, 1000]);
                    vibrationInterval = setInterval(() => {
                        navigator.vibrate([1000, 500]);
                    }, 1500);
                } catch (e) {
                    console.error("[CallManager] Vibration failed:", e);
                }
            }
        } else {
            console.log("[CallManager] Call status changed, stopping ringtone/vibration.");
            if (ringtone) {
                ringtone.pause();
                ringtone.currentTime = 0;
            }
            if (vibrationInterval) clearInterval(vibrationInterval);
            if (ringtoneRetryInterval) clearInterval(ringtoneRetryInterval);
            if ("vibrate" in navigator) navigator.vibrate(0);
        }

        return () => {
            if (vibrationInterval) clearInterval(vibrationInterval);
            if (ringtoneRetryInterval) clearInterval(ringtoneRetryInterval);
            if ("vibrate" in navigator) navigator.vibrate(0);
        };
    }, [activeCall?.status]);

    // Global interaction listener to unblock audio
    useEffect(() => {
        const handleInteraction = () => {
            if (activeCall?.status === 'incoming' && ringtoneRef.current) {
                ringtoneRef.current.play().catch(() => { });
            }
        };

        window.addEventListener('click', handleInteraction);
        window.addEventListener('touchstart', handleInteraction);
        return () => {
            window.removeEventListener('click', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, [activeCall?.status]);

    // WebRTC Logic
    useEffect(() => {
        if (!activeCall || activeCall.category !== 'private' || !user) return;

        const setupWebRTC = async () => {
            console.log("Setting up WebRTC...", activeCall.type);
            peerConnection.current = new RTCPeerConnection(iceServers);

            peerConnection.current.onconnectionstatechange = () => {
                const state = peerConnection.current?.connectionState;
                console.log("Connection state change:", state);
                if (state === 'connected') {
                    toast.success("Call connected");
                } else if (state === 'failed') {
                    toast.error("Connection failed");
                    endCall();
                } else if (state === 'disconnected') {
                    toast.info("Peer disconnected");
                    endCall();
                }
            };

            // Add local stream tracks to peer connection
            if (activeCall.status === 'active') {
                try {
                    console.log("Requesting user media...");
                    const stream = await navigator.mediaDevices.getUserMedia({
                        video: activeCall.type === 'video',
                        audio: {
                            echoCancellation: true,
                            noiseSuppression: true,
                            autoGainControl: true
                        },
                    });
                    setLocalStream(stream);

                    stream.getTracks().forEach(track => {
                        peerConnection.current?.addTrack(track, stream);
                    });

                    if (localVideoRef.current) localVideoRef.current.srcObject = stream;
                    // Don't play local audio to avoid feedback loop, but visualize?
                } catch (err) {
                    console.error("Error accessing media devices:", err);
                    toast.error("Could not access camera/microphone");
                    return; // Stop setup if media fails
                }
            }

            // Listen for remote tracks
            peerConnection.current.ontrack = (event) => {
                console.log("[CallManager] Remote track received:", event.track.kind);
                if (event.streams && event.streams[0]) {
                    setRemoteStream(event.streams[0]);
                    if (remoteVideoRef.current) {
                        remoteVideoRef.current.srcObject = event.streams[0];
                        remoteVideoRef.current.play().catch(e => console.warn("[CallManager] Video play blocked:", e));
                    }
                    if (remoteAudioRef.current) {
                        remoteAudioRef.current.srcObject = event.streams[0];
                        remoteAudioRef.current.play().catch(e => console.warn("[CallManager] Audio play blocked:", e));
                    }
                }
            };

            // ICE Candidate handling
            peerConnection.current.onicecandidate = (event) => {
                if (event.candidate) {
                    supabase.channel(`calls:${activeCall.peerId}`).send({
                        type: 'broadcast',
                        event: 'call:ice-candidate',
                        payload: { candidate: event.candidate, senderId: user.id },
                    });
                }
            };

            // Negotiation handling
            if (activeCall.isInitiator && activeCall.status === 'active') {
                const offer = await peerConnection.current.createOffer();
                await peerConnection.current.setLocalDescription(offer);
                supabase.channel(`calls:${activeCall.peerId}`).send({
                    type: 'broadcast',
                    event: 'call:sdp-offer',
                    payload: { sdp: offer, senderId: user.id },
                });
            }
        };

        if (activeCall.status === 'active') {
            setupWebRTC();
        }

        // Signaling listeners
        const channel = supabase.channel(`calls:${user.id}`);
        channel
            .on('broadcast', { event: 'call:sdp-offer' }, async ({ payload }) => {
                if (peerConnection.current) {
                    await peerConnection.current.setRemoteDescription(new RTCSessionDescription(payload.sdp));
                    const answer = await peerConnection.current.createAnswer();
                    await peerConnection.current.setLocalDescription(answer);
                    supabase.channel(`calls:${activeCall.peerId}`).send({
                        type: 'broadcast',
                        event: 'call:sdp-answer',
                        payload: { sdp: answer, senderId: user.id },
                    });
                }
            })
            .on('broadcast', { event: 'call:sdp-answer' }, async ({ payload }) => {
                if (peerConnection.current) {
                    await peerConnection.current.setRemoteDescription(new RTCSessionDescription(payload.sdp));
                }
            })
            .on('broadcast', { event: 'call:ice-candidate' }, async ({ payload }) => {
                if (peerConnection.current) {
                    try {
                        await peerConnection.current.addIceCandidate(new RTCIceCandidate(payload.candidate));
                    } catch (e) {
                        console.error("Error adding ice candidate:", e);
                    }
                }
            })
            .on('broadcast', { event: 'call:accepted' }, () => {
                // If we are initiator and they accepted, we move to active
                // (Context already handles state update, but we might need trigger setup here)
            })
            .on('broadcast', { event: 'call:camera-toggle' }, ({ payload }) => {
                if (payload.senderId === activeCall.peerId) {
                    setIsRemoteVideoOff(payload.isCameraOff);
                }
            })
            .on('broadcast', { event: 'call:rejected' }, () => {
                toast.error("Call rejected");
                endCall();
            })
            .on('broadcast', { event: 'call:ended' }, () => {
                toast.info("Call ended by peer");
                endCall();
            })
            .subscribe();

        return () => {
            channel.unsubscribe();
            localStream?.getTracks().forEach(track => track.stop());
            peerConnection.current?.close();
        };
    }, [activeCall?.status, activeCall?.category, user]);

    // Ensure streams are attached when UI elements mount/unmount
    // NOTE: This must be before any early returns to satisfy React's Rules of Hooks
    useEffect(() => {
        if (remoteVideoRef.current && remoteStream) {
            console.log("[CallManager] Attaching remote video stream");
            remoteVideoRef.current.srcObject = remoteStream;
            remoteVideoRef.current.play().catch(e => console.warn("Video play blocked:", e));
        }
        if (remoteAudioRef.current && remoteStream) {
            console.log("[CallManager] Attaching remote audio stream");
            remoteAudioRef.current.srcObject = remoteStream;
            remoteAudioRef.current.play().catch(e => console.warn("Audio play blocked:", e));
        }
        if (localVideoRef.current && localStream) {
            localVideoRef.current.srcObject = localStream;
        }
    }, [remoteStream, localStream, activeCall?.type, activeCall?.status, isRemoteVideoOff, isMinimized]);

    if (!activeCall || activeCall.category !== 'private') return null;

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const toggleSpeaker = () => {
        setIsSpeakerOn(!isSpeakerOn);
        // Note: Switching between earpiece and speaker is not fully supported in standard Web Audio API
        // without native device access or specific browser flags. 
        // We toggle the UI state to indicate preference.
    };

    const toggleMute = () => {
        if (localStream) {
            localStream.getAudioTracks().forEach(track => {
                track.enabled = isMuted;
            });
            setIsMuted(!isMuted);
        }
    };

    const toggleCamera = () => {
        if (localStream) {
            localStream.getVideoTracks().forEach(track => {
                track.enabled = isCameraOff;
            });
            const newStatus = !isCameraOff;
            setIsCameraOff(newStatus);

            // Broadcast camera status to peer
            if (activeCall?.peerId) {
                supabase.channel(`calls:${activeCall.peerId}`).send({
                    type: 'broadcast',
                    event: 'call:camera-toggle',
                    payload: { isCameraOff: newStatus, senderId: user?.id },
                });
            }
        }
    };

    // Final Render Wrapper
    return (
        <>
            {/* Hidden Ringtone Element - Always mounted when a call exists */}
            <audio
                ref={ringtoneRef}
                loop
                src="/notification_ringtone.mp3"
                className="hidden"
                preload="auto"
                playsInline
            />

            {/* UI Fragments based on status */}
            {activeCall.status === 'incoming' && (
                <div className="fixed top-4 left-4 right-4 z-[100000] animate-in slide-in-from-top-full duration-500 ease-out">
                    <div className="bg-slate-900/90 backdrop-blur-xl border border-white/10 rounded-3xl p-4 shadow-2xl flex items-center justify-between gap-4 max-w-lg mx-auto">
                        <div className="flex items-center gap-3">
                            <div className="relative">
                                <Avatar className="h-12 w-12 border-2 border-primary/20">
                                    <AvatarImage src={activeCall.peerAvatar} />
                                    <AvatarFallback>{activeCall.peerName?.charAt(0)}</AvatarFallback>
                                </Avatar>
                                <div className="absolute -bottom-1 -right-1 bg-emerald-500 rounded-full p-1 border-2 border-slate-900 animate-pulse">
                                    {activeCall.type === 'video' ? <Video className="h-2 w-2 text-white" /> : <Phone className="h-2 w-2 text-white" />}
                                </div>
                            </div>
                            <div className="text-left">
                                <h3 className="text-white font-bold text-sm leading-tight">{activeCall.peerName}</h3>
                                <p className="text-slate-400 text-xs">Incoming {activeCall.type} call...</p>
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                            <Button
                                variant="destructive"
                                size="icon"
                                className="h-10 w-10 rounded-full shadow-lg shadow-red-500/20"
                                onClick={rejectCall}
                            >
                                <PhoneOff className="h-4 w-4" />
                            </Button>
                            <Button
                                variant="default"
                                size="icon"
                                className="h-10 w-10 rounded-full bg-emerald-500 hover:bg-emerald-600 shadow-lg shadow-emerald-500/20"
                                onClick={acceptCall}
                            >
                                <Phone className="h-4 w-4" />
                            </Button>
                        </div>
                    </div>
                </div>
            )}

            {activeCall.status === 'calling' && (
                <div className="fixed inset-0 z-[100000] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl">
                    <div className="flex flex-col items-center gap-8 text-center">
                        <Avatar className="h-32 w-32 border-4 border-primary/50">
                            <AvatarImage src={activeCall.peerAvatar} />
                            <AvatarFallback className="text-4xl">{activeCall.peerName?.charAt(0)}</AvatarFallback>
                        </Avatar>
                        <div className="space-y-2">
                            <h2 className="text-3xl font-bold text-white">{activeCall.peerName}</h2>
                            <p className="text-slate-400 animate-pulse">Calling...</p>
                        </div>
                        <Button
                            variant="destructive"
                            size="icon"
                            className="h-16 w-16 rounded-full mt-8"
                            onClick={endCall}
                        >
                            <PhoneOff className="h-6 w-6" />
                        </Button>
                    </div>
                </div>
            )}

            {activeCall.status === 'active' && (() => {
                // AUDIO CALL UI (Also used when Remote Video is Off in Video Call)
                const showAudioLayout = activeCall.type === 'audio' || isRemoteVideoOff;

                if (showAudioLayout) {
                    return (
                        <>
                            {/* Audio Element (Always Active) */}
                            <audio ref={remoteAudioRef} autoPlay playsInline />

                            {/* Minimized View */}
                            {isMinimized && (
                                <div className="fixed bottom-4 right-4 z-[100000] w-auto bg-slate-900/90 backdrop-blur-xl border border-white/10 rounded-2xl p-4 shadow-2xl flex items-center justify-between gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300">
                                    <div className="flex items-center gap-3">
                                        <div className="relative">
                                            <span className="absolute top-0 right-0 h-2.5 w-2.5 rounded-full bg-emerald-500 border-2 border-slate-900 z-10" />
                                            <Avatar className="h-10 w-10 border border-white/20">
                                                <AvatarImage src={activeCall.peerAvatar} />
                                                <AvatarFallback>{activeCall.peerName?.charAt(0)}</AvatarFallback>
                                            </Avatar>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-white font-bold text-sm max-w-[120px] truncate">{activeCall.peerName}</span>
                                            <span className="text-emerald-400 text-xs font-mono">{formatTime(timer)}</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-2">
                                        <Button
                                            size="icon"
                                            variant="ghost"
                                            className="h-8 w-8 rounded-full text-white hover:bg-white/10"
                                            onClick={() => setMinimized(false)}
                                        >
                                            <Maximize2 className="h-4 w-4" />
                                        </Button>
                                        <Button
                                            size="icon"
                                            variant="ghost"
                                            className={cn("h-8 w-8 rounded-full", isMuted ? "text-red-500 bg-red-500/10" : "text-white hover:bg-white/10")}
                                            onClick={toggleMute}
                                        >
                                            {isMuted ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
                                        </Button>
                                        <Button
                                            size="icon"
                                            variant="destructive"
                                            className="h-8 w-8 rounded-full"
                                            onClick={endCall}
                                        >
                                            <PhoneOff className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </div>
                            )}

                            {/* Full Screen Audio UI (Reference Design) */}
                            <div className={cn(
                                "fixed inset-0 z-[99999] flex flex-col bg-gradient-to-b from-slate-900 to-[#0a0a0a] transition-all duration-300",
                                isMinimized ? "opacity-0 pointer-events-none scale-95" : "opacity-100 scale-100"
                            )}>
                                {/* Header */}
                                <div className="flex justify-between items-center p-6 pt-8">
                                    <Button variant="ghost" size="icon" className="text-slate-400 hover:text-white rounded-full bg-white/5 hover:bg-white/10" onClick={() => setMinimized(true)}>
                                        <ChevronDown className="h-6 w-6" />
                                    </Button>
                                    <div className="flex items-center gap-2 text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-full border border-emerald-500/20">
                                        <Lock className="h-3 w-3" />
                                        <span className="text-[10px] font-bold tracking-wider uppercase">End-to-End Encrypted</span>
                                    </div>
                                    <Button variant="ghost" size="icon" className="text-slate-400 hover:text-white rounded-full bg-white/5 hover:bg-white/10">
                                        <UserPlus className="h-5 w-5" />
                                    </Button>
                                </div>

                                {/* Main Content */}
                                <div className="flex-1 flex flex-col items-center justify-center -mt-10">
                                    <div className="relative mb-6 group">
                                        <div className="absolute inset-0 rounded-full bg-gradient-to-tr from-[#dac395] to-[#bfa068] blur-2xl opacity-20 group-hover:opacity-30 transition-opacity duration-1000" />
                                        <div className="absolute inset-0 rounded-full border-[1px] border-[#dac395]/30 animate-[spin_10s_linear_infinite]" />
                                        <Avatar className="h-40 w-40 md:h-56 md:w-56 border-4 border-[#dac395]/60 shadow-2xl z-10">
                                            <AvatarImage src={activeCall.peerAvatar} className="object-cover" />
                                            <AvatarFallback className="text-4xl bg-orange-100 text-orange-800">{activeCall.peerName?.charAt(0)}</AvatarFallback>
                                        </Avatar>
                                    </div>

                                    <h2 className="text-3xl md:text-4xl font-bold text-white mb-2 tracking-tight text-center px-4">{activeCall.peerName}</h2>

                                    <div className="flex items-center gap-2 mb-2">
                                        <div className="h-2 w-2 rounded-full bg-[#dac395] animate-pulse" />
                                        <span className="text-[#dac395] font-mono text-xl font-medium tracking-widest">{formatTime(timer)}</span>
                                    </div>

                                    <p className="text-slate-500 text-sm font-medium tracking-wide border border-slate-800 bg-slate-900/50 px-3 py-1 rounded-md">
                                        {activeCall.type === 'video' ? 'Video Call Ongoing' : 'High Definition Audio'}
                                    </p>
                                </div>

                                {/* Controls Section */}
                                <div className="p-8 md:p-12 pb-16 flex flex-col items-center gap-8 w-full max-w-lg mx-auto">

                                    {/* Control Icons Panel */}
                                    <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-[2rem] p-6 w-full max-w-sm flex items-center justify-center gap-8 shadow-2xl relative overflow-hidden">
                                        <div className="absolute inset-0 bg-gradient-to-b from-white/5 to-transparent pointer-events-none" />

                                        {/* Mute Toggle */}
                                        <div className="flex flex-col items-center gap-2 group cursor-pointer" onClick={toggleMute}>
                                            <div className={cn(
                                                "h-16 w-16 rounded-full flex items-center justify-center transition-all duration-300",
                                                isMuted ? "bg-white text-slate-900 shadow-lg scale-105" : "bg-white/10 text-white group-hover:bg-white/20"
                                            )}>
                                                {isMuted ? <MicOff className="h-7 w-7" /> : <Mic className="h-7 w-7" />}
                                            </div>
                                            <span className="text-xs uppercase font-bold text-slate-400 tracking-wider">Mute</span>
                                        </div>

                                        {/* Speaker Toggle */}
                                        <div className="flex flex-col items-center gap-2 group cursor-pointer" onClick={toggleSpeaker}>
                                            <div className={cn(
                                                "h-16 w-16 rounded-full flex items-center justify-center transition-all duration-300 shadow-[0_0_15px_-3px_rgba(218,195,149,0.5)] active:scale-95",
                                                isSpeakerOn ? "bg-[#dac395] text-slate-900" : "bg-white/10 text-white hover:bg-white/20"
                                            )}>
                                                <Volume2 className={cn("h-7 w-7 fill-current", isSpeakerOn ? "" : "fill-none")} />
                                            </div>
                                            <span className={cn(
                                                "text-xs uppercase font-bold tracking-wider transition-colors",
                                                isSpeakerOn ? "text-[#dac395]" : "text-slate-400"
                                            )}>Speaker</span>
                                        </div>

                                        {/* Video Toggle (Only if video call) */}
                                        {activeCall.type === 'video' && (
                                            <div className="flex flex-col items-center gap-2 group cursor-pointer" onClick={toggleCamera}>
                                                <div className={cn(
                                                    "h-16 w-16 rounded-full flex items-center justify-center transition-all duration-300",
                                                    isCameraOff ? "bg-red-500/20 text-red-500" : "bg-white/10 text-white group-hover:bg-white/20"
                                                )}>
                                                    {isCameraOff ? <VideoOff className="h-7 w-7" /> : <Video className="h-7 w-7" />}
                                                </div>
                                                <span className="text-xs uppercase font-bold text-slate-400 tracking-wider">Video</span>
                                            </div>
                                        )}
                                    </div>

                                    {/* End Call Button */}
                                    <Button
                                        className="w-full h-16 rounded-full bg-red-600 hover:bg-red-500 text-white font-bold text-xl shadow-[0_10px_30px_-10px_rgba(220,38,38,0.5)] transition-all hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-3 border-none"
                                        onClick={endCall}
                                    >
                                        <div className="bg-white/20 p-2 rounded-full">
                                            <PhoneOff className="h-6 w-6 fill-current" />
                                        </div>
                                        End Call
                                    </Button>
                                </div>
                            </div>
                        </>
                    );
                }

                // VIDEO CALL UI (Existing)
                return (
                    <>
                        {/* Backdrop */}
                        {!isMinimized && <div className="fixed inset-0 bg-black z-[99998]" />}

                        <div className={cn(
                            "fixed transition-all duration-500 ease-in-out shadow-2xl bg-slate-900 overflow-hidden",
                            isMinimized
                                ? "bottom-4 right-4 w-[180px] h-[110px] md:w-[340px] md:h-[210px] rounded-2xl z-[100000] border border-white/10"
                                : "inset-0 z-[99999]"
                        )}>
                            {/* Remote Video (Full Screen) */}
                            <video
                                ref={remoteVideoRef}
                                autoPlay
                                playsInline
                                className={cn("w-full h-full object-cover transition-opacity duration-500", !remoteStream && "opacity-0")}
                            />

                            {/* Placeholder if no remote video yet */}
                            {!remoteStream && (
                                <div className="absolute inset-0 flex items-center justify-center bg-slate-950 -z-10">
                                    <div className="flex flex-col items-center gap-4">
                                        <Loader2 className="h-12 w-12 animate-spin text-primary/50" />
                                        <p className="text-white/50 font-medium text-sm animate-pulse">Connecting...</p>
                                    </div>
                                </div>
                            )}

                            {/* Local Video Overlay */}
                            <div className={cn(
                                "absolute rounded-lg border border-white/20 bg-slate-800 shadow-xl overflow-hidden",
                                isMinimized ? "hidden" : "top-6 right-6 w-32 h-44 md:w-48 md:h-64"
                            )}>
                                <video
                                    ref={localVideoRef}
                                    autoPlay
                                    muted
                                    playsInline
                                    className="w-full h-full object-cover mirror"
                                />
                                {isCameraOff && (
                                    <div className="absolute inset-0 flex items-center justify-center bg-slate-800">
                                        <Avatar className="h-12 w-12">
                                            <AvatarImage src={profile?.avatar_url} />
                                            <AvatarFallback>ME</AvatarFallback>
                                        </Avatar>
                                    </div>
                                )}
                            </div>

                            {/* Controls Bar */}
                            <div className={cn(
                                "absolute left-1/2 -translate-x-1/2 bottom-8 flex items-center gap-4 px-6 py-4 rounded-full bg-slate-900/60 backdrop-blur-md border border-white/10 transition-opacity duration-300",
                                isMinimized ? "opacity-0 invisible" : "opacity-100 visible"
                            )}>
                                <div className="text-white font-mono mr-4 border-r border-white/10 pr-4">
                                    {formatTime(timer)}
                                </div>

                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className={cn("h-12 w-12 rounded-full", isMuted ? "bg-red-500/20 text-red-500" : "text-white hover:bg-white/10")}
                                    onClick={toggleMute}
                                >
                                    {isMuted ? <MicOff className="h-6 w-6" /> : <Mic className="h-6 w-6" />}
                                </Button>

                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className={cn("h-12 w-12 rounded-full", isCameraOff ? "bg-red-500/20 text-red-500" : "text-white hover:bg-white/10")}
                                    onClick={toggleCamera}
                                >
                                    {isCameraOff ? <VideoOff className="h-6 w-6" /> : <Video className="h-6 w-6" />}
                                </Button>

                                <Button
                                    variant="destructive"
                                    size="icon"
                                    className="h-12 w-12 rounded-full"
                                    onClick={endCall}
                                >
                                    <PhoneOff className="h-6 w-6" />
                                </Button>

                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-12 w-12 rounded-full text-white hover:bg-white/10"
                                    onClick={() => setMinimized(true)}
                                >
                                    <Minimize2 className="h-6 w-6" />
                                </Button>
                            </div>

                            {/* Minimized Controls Overlay */}
                            {isMinimized && (
                                <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[2px] cursor-pointer group" onClick={() => setMinimized(false)}>
                                    <div className="flex flex-col items-center gap-1">
                                        <span className="text-white text-[10px] font-bold uppercase tracking-wider opacity-70">Active Call</span>
                                        <span className="text-white text-xs font-medium">{formatTime(timer)}</span>
                                        <Button size="icon" variant="ghost" className="h-8 w-8 rounded-full text-white opacity-0 group-hover:opacity-100 transition-opacity">
                                            <Maximize2 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </div>
                    </>
                );
            })()}
        </>
    );
}

import { useNavigate } from 'react-router-dom';
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
    Calendar,
    ClipboardList,
    FileCheck,
    BookOpen,
    Users,
    ArrowRight,
    MoreVertical,
    Edit,
    Trash2
} from "lucide-react";
import { cn } from "@/lib/utils";
import { getCardColor, getCardColorByIndex } from "@/lib/card-styles";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
    DropdownMenuSeparator
} from "@/components/ui/dropdown-menu";

export interface ClassData {
    id: string;
    class_name: string;
    course_code: string;
    lecturer_department?: string;
    student_count?: number;
    [key: string]: any;
}

export interface SectionClassCardProps {
    classData: ClassData;
    variant?: 'assignments' | 'schedule' | 'students' | 'quizzes';
    onAction?: (id: string, actionType?: string) => void;
    index?: number;
    onEdit?: (classData: ClassData) => void;
    onDelete?: (classData: ClassData) => void;
}

export const SectionClassCard = ({
    classData,
    variant = 'assignments',
    onAction,
    index,
    onEdit,
    onDelete
}: SectionClassCardProps) => {
    const colors = index !== undefined ? getCardColorByIndex(index) : getCardColor(classData.id);

    const getIcon = () => {
        switch (variant) {
            case 'assignments': return ClipboardList;
            case 'schedule': return Calendar;
            case 'students': return Users;
            case 'quizzes': return FileCheck;
            default: return BookOpen;
        }
    };

    const VariantIcon = getIcon();

    return (
        <Card
            className={cn(
                "relative overflow-hidden border-none rounded-3xl transition-all duration-500 group cursor-pointer shadow-lg hover:shadow-2xl hover:-translate-y-1",
                colors.bg
            )}
            onClick={() => onAction && onAction(classData.id)}
        >
            {/* Ambient Background Glow */}
            <div className="absolute top-0 right-0 p-4 opacity-[0.03] dark:opacity-10 group-hover:scale-125 transition-transform duration-700 pointer-events-none">
                <VariantIcon className={cn("size-32", colors.accent)} />
            </div>

            {/* Gradient Overlay */}
            <div className={cn(
                "absolute inset-0 bg-gradient-to-br transition-all duration-500",
                "from-white/40 to-transparent dark:from-white/5",
                "group-hover:from-white/60 dark:group-hover:from-white/10",
                "pointer-events-none"
            )} />

            <CardContent className="p-4 md:p-6 relative z-10 flex flex-col h-full min-h-[140px] md:min-h-[180px]">
                {/* Header */}
                <div className="flex justify-between items-start mb-3 md:mb-6">
                    <div className={cn(
                        "p-2 md:p-3 rounded-xl md:rounded-2xl border backdrop-blur-md shadow-inner group-hover:scale-110 transition-transform duration-300",
                        "bg-white/40 dark:bg-white/10 border-white/40 dark:border-white/20"
                    )}>
                        <VariantIcon className={cn("size-4 md:size-6", colors.accent)} />
                    </div>

                    <div className="flex items-center gap-2">
                        <Badge
                            className={cn(
                                "border-0 backdrop-blur-md px-2 md:px-3 font-bold text-[8px] md:text-[10px] tracking-wider py-0.5 md:py-1 rounded-lg shadow-sm",
                                "bg-white/60 dark:bg-white/20 text-slate-700 dark:text-white"
                            )}
                        >
                            {classData.course_code}
                        </Badge>

                        {(onEdit || onDelete) && (
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        className="h-7 w-7 md:h-8 md:w-8 -mr-1 text-slate-400 dark:text-white/70 hover:text-slate-900 dark:hover:text-white hover:bg-white/20 z-40 relative rounded-full"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                        }}
                                    >
                                        <MoreVertical className="size-3.5 md:size-4" />
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end" className="w-48 p-2 rounded-2xl shadow-xl border-none backdrop-blur-xl bg-white/90 dark:bg-slate-900/90">
                                    {onEdit && (
                                        <DropdownMenuItem onClick={(e) => {
                                            e.stopPropagation();
                                            onEdit(classData);
                                        }} className="h-10 rounded-xl cursor-pointer">
                                            <Edit className="size-4 mr-2" />
                                            Edit Class
                                        </DropdownMenuItem>
                                    )}
                                    {onDelete && (
                                        <>
                                            <DropdownMenuSeparator />
                                            <DropdownMenuItem
                                                className="h-10 rounded-xl cursor-pointer text-red-600 focus:text-red-600 focus:bg-red-50 dark:focus:bg-red-950/20"
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    onDelete(classData);
                                                }}
                                            >
                                                <Trash2 className="size-4 mr-2" />
                                                Delete Class
                                            </DropdownMenuItem>
                                        </>
                                    )}
                                </DropdownMenuContent>
                            </DropdownMenu>
                        )}
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1">
                    <h3 className="font-black text-lg md:text-2xl text-slate-800 dark:text-white leading-tight mb-1 md:mb-2 group-hover:translate-x-1 transition-transform line-clamp-2">
                        {classData.class_name}
                    </h3>
                    {classData.lecturer_department && (
                        <p className="text-[10px] md:text-sm font-bold text-slate-500 dark:text-white/60 line-clamp-1 flex items-center gap-1.5 md:gap-2">
                            <span className={cn("size-1.5 md:size-2 rounded-full", colors.accent.replace('text-', 'bg-'), "opacity-40")} />
                            {classData.lecturer_department}
                        </p>
                    )}
                </div>

                {/* Footer */}
                <div className="mt-4 md:mt-8 pt-4 md:pt-6 border-t border-slate-200 dark:border-white/10 flex items-center justify-between">
                    <div className="flex items-center gap-1.5 md:gap-2 text-[10px] md:text-xs font-black text-slate-500 dark:text-white/70 uppercase tracking-tight">
                        <Users className="size-3 md:size-4" />
                        <span>{classData.student_count || 0} <span className="hidden xs:inline">Students</span></span>
                    </div>

                    <div className={cn(
                        "flex items-center gap-1 md:gap-1.5 text-[8px] md:text-[10px] font-black uppercase tracking-widest px-3 md:px-4 py-1.5 md:py-2 rounded-full shadow-lg transition-all",
                        "bg-white/60 dark:bg-white/10 text-slate-700 dark:text-white backdrop-blur-md border border-white/40 dark:border-white/20",
                        "group-hover:scale-105 active:scale-95"
                    )}>
                        {variant === 'assignments' ? 'Assignments' : variant === 'students' ? 'Students' : variant === 'quizzes' ? 'Quizzes' : 'Schedule'}
                        <ArrowRight className="size-2.5 md:size-3 group-hover:translate-x-1 transition-transform" />
                    </div>
                </div>

            </CardContent>
        </Card>
    );
};

export default SectionClassCard;

import { useState } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Loader2, UserPlus } from "lucide-react";

interface AddStudentModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    classId: string;
    onStudentAdded: (studentData: any) => Promise<void>;
}

export function AddStudentModal({
    open,
    onOpenChange,
    classId,
    onStudentAdded,
}: AddStudentModalProps) {
    const { toast } = useToast();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        studentName: "",
        email: "",
        registerNumber: "",
        department: "",
        year: "",
        section: "",
        phone: "",
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        // Validation
        if (!formData.studentName.trim()) {
            toast({
                title: "Validation Error",
                description: "Student name is required",
                variant: "destructive",
            });
            return;
        }

        if (!formData.email.trim()) {
            toast({
                title: "Validation Error",
                description: "Email is required",
                variant: "destructive",
            });
            return;
        }

        // Email validation
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(formData.email)) {
            toast({
                title: "Validation Error",
                description: "Please enter a valid email address",
                variant: "destructive",
            });
            return;
        }

        if (!formData.registerNumber.trim()) {
            toast({
                title: "Validation Error",
                description: "Register number is required",
                variant: "destructive",
            });
            return;
        }

        try {
            setLoading(true);
            await onStudentAdded(formData);

            // Reset form
            setFormData({
                studentName: "",
                email: "",
                registerNumber: "",
                department: "",
                year: "",
                section: "",
                phone: "",
            });

            onOpenChange(false);
        } catch (error) {
            // Error handling is done in parent component
        } finally {
            setLoading(false);
        }
    };

    const handleCancel = () => {
        setFormData({
            studentName: "",
            email: "",
            registerNumber: "",
            department: "",
            year: "",
            section: "",
            phone: "",
        });
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <UserPlus className="size-5" />
                        Add Student Manually
                    </DialogTitle>
                    <DialogDescription>
                        Enter student details to add them to this class. A join request will be sent automatically.
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit}>
                    <div className="grid gap-4 py-4">
                        {/* Student Name */}
                        <div className="grid gap-2">
                            <Label htmlFor="studentName">
                                Student Name <span className="text-destructive">*</span>
                            </Label>
                            <Input
                                id="studentName"
                                placeholder="Enter student's full name"
                                value={formData.studentName}
                                onChange={(e) =>
                                    setFormData({ ...formData, studentName: e.target.value })
                                }
                                disabled={loading}
                                required
                            />
                        </div>

                        {/* Email */}
                        <div className="grid gap-2">
                            <Label htmlFor="email">
                                Email <span className="text-destructive">*</span>
                            </Label>
                            <Input
                                id="email"
                                type="email"
                                placeholder="student@example.com"
                                value={formData.email}
                                onChange={(e) =>
                                    setFormData({ ...formData, email: e.target.value.toLowerCase() })
                                }
                                disabled={loading}
                                required
                            />
                        </div>

                        {/* Register Number */}
                        <div className="grid gap-2">
                            <Label htmlFor="registerNumber">
                                Register Number <span className="text-destructive">*</span>
                            </Label>
                            <Input
                                id="registerNumber"
                                placeholder="Enter register number"
                                value={formData.registerNumber}
                                onChange={(e) =>
                                    setFormData({ ...formData, registerNumber: e.target.value })
                                }
                                disabled={loading}
                                required
                            />
                        </div>

                        {/* Department */}
                        <div className="grid gap-2">
                            <Label htmlFor="department">Department</Label>
                            <Input
                                id="department"
                                placeholder="e.g., Computer Science"
                                value={formData.department}
                                onChange={(e) =>
                                    setFormData({ ...formData, department: e.target.value })
                                }
                                disabled={loading}
                            />
                        </div>

                        {/* Year and Section */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="grid gap-2">
                                <Label htmlFor="year">Year</Label>
                                <Input
                                    id="year"
                                    placeholder="e.g., 2nd Year"
                                    value={formData.year}
                                    onChange={(e) =>
                                        setFormData({ ...formData, year: e.target.value })
                                    }
                                    disabled={loading}
                                />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="section">Section</Label>
                                <Input
                                    id="section"
                                    placeholder="e.g., A"
                                    value={formData.section}
                                    onChange={(e) =>
                                        setFormData({ ...formData, section: e.target.value })
                                    }
                                    disabled={loading}
                                />
                            </div>
                        </div>

                        {/* Phone */}
                        <div className="grid gap-2">
                            <Label htmlFor="phone">Phone Number</Label>
                            <Input
                                id="phone"
                                type="tel"
                                placeholder="Enter phone number"
                                value={formData.phone}
                                onChange={(e) =>
                                    setFormData({ ...formData, phone: e.target.value })
                                }
                                disabled={loading}
                            />
                        </div>
                    </div>

                    <DialogFooter>
                        <Button
                            type="button"
                            variant="outline"
                            onClick={handleCancel}
                            disabled={loading}
                        >
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading}>
                            {loading ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Adding Student...
                                </>
                            ) : (
                                <>
                                    <UserPlus className="mr-2 h-4 w-4" />
                                    Add Student
                                </>
                            )}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import { useState } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useSchedule } from "@/hooks/useSchedule";
import { useClasses } from "@/hooks/useClasses";
import { Loader2 } from "lucide-react";
import { toast } from "sonner";

interface CreateEventDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export function CreateEventDialog({ open, onOpenChange }: CreateEventDialogProps) {
    const { createSchedule } = useSchedule();
    const { classes } = useClasses();
    const [loading, setLoading] = useState(false);

    const [formData, setFormData] = useState({
        title: "",
        type: "lecture",
        day_of_week: "1", // Monday
        start_time: "09:00",
        end_time: "10:00",
        location: "",
        class_id: "none",
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!formData.title || !formData.start_time || !formData.end_time) {
            toast.error("Please fill in all required fields");
            return;
        }

        try {
            setLoading(true);

            const scheduleData: any = {
                title: formData.title,
                type: formData.type as any,
                day_of_week: parseInt(formData.day_of_week),
                start_time: formData.start_time,
                end_time: formData.end_time,
                location: formData.location || null,
                is_recurring: true,
                specific_date: null,
                notes: null,
                color: null,
                class_id: formData.class_id === "none" ? null : formData.class_id,
            };

            const result = await createSchedule(scheduleData);

            if (result.success) {
                toast.success("Event created successfully");
                onOpenChange(false);
                setFormData({
                    title: "",
                    type: "lecture",
                    day_of_week: "1",
                    start_time: "09:00",
                    end_time: "10:00",
                    location: "",
                    class_id: "none",
                });
            } else {
                toast.error(result.error || "Failed to create event");
            }
        } catch (error) {
            console.error(error);
            toast.error("An error occurred");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle>Add to Schedule</DialogTitle>
                    <DialogDescription>
                        Create a new class schedule or event.
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="space-y-2">
                        <Label htmlFor="title">Event Title *</Label>
                        <Input
                            id="title"
                            value={formData.title}
                            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                            placeholder="e.g. Morning Lecture"
                            required
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="type">Type</Label>
                            <Select
                                value={formData.type}
                                onValueChange={(value) => setFormData({ ...formData, type: value })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="lecture">Lecture</SelectItem>
                                    <SelectItem value="lab">Lab</SelectItem>
                                    <SelectItem value="tutorial">Tutorial</SelectItem>
                                    <SelectItem value="exam">Exam</SelectItem>
                                    <SelectItem value="event">Event</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="day">Day</Label>
                            <Select
                                value={formData.day_of_week}
                                onValueChange={(value) => setFormData({ ...formData, day_of_week: value })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="0">Sunday</SelectItem>
                                    <SelectItem value="1">Monday</SelectItem>
                                    <SelectItem value="2">Tuesday</SelectItem>
                                    <SelectItem value="3">Wednesday</SelectItem>
                                    <SelectItem value="4">Thursday</SelectItem>
                                    <SelectItem value="5">Friday</SelectItem>
                                    <SelectItem value="6">Saturday</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="start_time">Start Time *</Label>
                            <Input
                                id="start_time"
                                type="time"
                                value={formData.start_time}
                                onChange={(e) => setFormData({ ...formData, start_time: e.target.value })}
                                required
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="end_time">End Time *</Label>
                            <Input
                                id="end_time"
                                type="time"
                                value={formData.end_time}
                                onChange={(e) => setFormData({ ...formData, end_time: e.target.value })}
                                required
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="location">Location</Label>
                        <Input
                            id="location"
                            value={formData.location}
                            onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                            placeholder="e.g. Room 301 or Online"
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="class">Class (Optional)</Label>
                        <Select
                            value={formData.class_id}
                            onValueChange={(value) => setFormData({ ...formData, class_id: value })}
                        >
                            <SelectTrigger>
                                <SelectValue placeholder="Select a class" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="none">No Class (Personal)</SelectItem>
                                {classes.map((cls) => (
                                    <SelectItem key={cls.id} value={cls.id}>
                                        {cls.course_code} - {cls.class_name || "General"}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <DialogFooter>
                        <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading}>
                            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Create Event
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import { useState, useEffect } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ClassStudent } from "@/hooks/useClassStudents";
import { toast } from "sonner";

interface EditStudentModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    student: ClassStudent | null;
    onSave: (studentId: string, data: any) => Promise<void>;
}

export function EditStudentModal({
    open,
    onOpenChange,
    student,
    onSave,
}: EditStudentModalProps) {
    const [saving, setSaving] = useState(false);
    const [formData, setFormData] = useState({
        student_name: "",
        register_number: "",
        email: "",
        department: "",
        course: "",
        year: "",
        section: "",
        phone: "",
    });

    useEffect(() => {
        if (student) {
            setFormData({
                student_name: student.student_name,
                register_number: student.register_number,
                email: student.email,
                department: student.department || "",
                course: student.course || "",
                year: student.year || "",
                section: student.section || "",
                phone: student.phone || "",
            });
        }
    }, [student, open]);

    const handleChange = (field: string, value: string) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
    };

    const handleSave = async () => {
        // Validation
        if (!formData.student_name || !formData.register_number || !formData.email) {
            toast.error("Please fill in all required fields");
            return;
        }

        if (!student) {
            toast.error("No student selected");
            return;
        }

        setSaving(true);
        try {
            await onSave(student.id, formData);
            toast.success("Student updated successfully");
            onOpenChange(false);
        } catch (error) {
            toast.error("An error occurred while saving");
        } finally {
            setSaving(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Edit Student</DialogTitle>
                    <DialogDescription>
                        Update student information. Changes will be saved immediately.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-4 mt-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="student_name">
                                Student Name <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="student_name"
                                value={formData.student_name}
                                onChange={(e) => handleChange("student_name", e.target.value)}
                                placeholder="Enter student name"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="register_number">
                                Register Number <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="register_number"
                                value={formData.register_number}
                                onChange={(e) => handleChange("register_number", e.target.value)}
                                placeholder="e.g., 2024001"
                                disabled
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="email">
                                Email <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="email"
                                type="email"
                                value={formData.email}
                                onChange={(e) => handleChange("email", e.target.value)}
                                placeholder="student@example.com"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="phone">Phone Number</Label>
                            <Input
                                id="phone"
                                value={formData.phone}
                                onChange={(e) => handleChange("phone", e.target.value)}
                                placeholder="+1234567890"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="department">Department</Label>
                            <Input
                                id="department"
                                value={formData.department}
                                onChange={(e) => handleChange("department", e.target.value)}
                                placeholder="e.g., Computer Science"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="course">Course</Label>
                            <Input
                                id="course"
                                value={formData.course}
                                onChange={(e) => handleChange("course", e.target.value)}
                                placeholder="e.g., B.Tech CS"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="year">Year</Label>
                            <Input
                                id="year"
                                value={formData.year}
                                onChange={(e) => handleChange("year", e.target.value)}
                                placeholder="e.g., 2"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="section">Section</Label>
                            <Input
                                id="section"
                                value={formData.section}
                                onChange={(e) => handleChange("section", e.target.value)}
                                placeholder="e.g., A"
                            />
                        </div>
                    </div>
                </div>

                <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-slate-200 dark:border-slate-700">
                    <Button variant="outline" onClick={() => onOpenChange(false)} disabled={saving}>
                        Cancel
                    </Button>
                    <Button onClick={handleSave} disabled={saving}>
                        {saving ? "Saving..." : "Update Student"}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { useState } from "react";
import { useExcelImport, StudentData, ValidationError } from "@/hooks/useExcelImport";
import { Upload, Download, FileSpreadsheet, AlertCircle, CheckCircle2, Loader2 } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";

interface ImportStudentsModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    classId: string;
    onImport: (students: any[]) => Promise<{ success: number; failed: number; errors: string[] }>;
}

export function ImportStudentsModal({ open, onOpenChange, classId, onImport }: ImportStudentsModalProps) {
    const { toast } = useToast();
    const { parseExcelFile, validateStudentData, generateTemplate } = useExcelImport();
    const [loading, setLoading] = useState(false);
    const [importing, setImporting] = useState(false);
    const [parsedData, setParsedData] = useState<StudentData[]>([]);
    const [parseErrors, setParseErrors] = useState<ValidationError[]>([]);
    const [validationErrors, setValidationErrors] = useState<ValidationError[]>([]);
    const [file, setFile] = useState<File | null>(null);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        // Validate file type
        const validTypes = [
            'application/vnd.ms-excel',
            'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'text/csv'
        ];

        if (!validTypes.includes(selectedFile.type) && !selectedFile.name.match(/\.(xlsx|xls|csv)$/)) {
            toast({
                title: "Invalid File Type",
                description: "Please upload an Excel (.xlsx, .xls) or CSV file",
                variant: "destructive",
            });
            return;
        }

        setFile(selectedFile);
        setLoading(true);

        try {
            const { data, errors } = await parseExcelFile(selectedFile);
            setParsedData(data);
            setParseErrors(errors);

            // Validate parsed data
            const validationErrs = validateStudentData(data);
            setValidationErrors(validationErrs);

            if (data.length === 0) {
                toast({
                    title: "No Data Found",
                    description: "The file appears to be empty or improperly formatted",
                    variant: "destructive",
                });
            } else {
                toast({
                    title: "File Parsed",
                    description: `Found ${data.length} students. Review the data below before importing.`,
                });
            }
        } catch (error) {
            console.error("Error parsing file:", error);
            toast({
                title: "Parse Error",
                description: "Failed to parse the file. Please check the format and try again.",
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    };

    const handleImport = async () => {
        if (parsedData.length === 0) {
            toast({
                title: "No Data",
                description: "Please upload a file first",
                variant: "destructive",
            });
            return;
        }

        if (parseErrors.length > 0 || validationErrors.length > 0) {
            toast({
                title: "Validation Errors",
                description: "Please fix all errors before importing",
                variant: "destructive",
            });
            return;
        }

        try {
            setImporting(true);
            const result = await onImport(parsedData);

            toast({
                title: "Import Complete",
                description: `Successfully imported ${result.success} students. ${result.failed} failed.`,
                variant: result.failed > 0 ? "destructive" : "default",
            });

            if (result.failed === 0) {
                // Reset and close on success
                setParsedData([]);
                setParseErrors([]);
                setValidationErrors([]);
                setFile(null);
                onOpenChange(false);
            }
        } catch (error) {
            console.error("Error importing students:", error);
            toast({
                title: "Import Error",
                description: "Failed to import students. Please try again.",
                variant: "destructive",
            });
        } finally {
            setImporting(false);
        }
    };

    const allErrors = [...parseErrors, ...validationErrors];
    const hasErrors = allErrors.length > 0;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="w-[95vw] sm:max-w-[800px] max-h-[90vh] overflow-y-auto p-4 sm:p-6 rounded-2xl sm:rounded-3xl border-none shadow-2xl">
                <DialogHeader className="mb-4 sm:mb-6">
                    <DialogTitle className="text-xl sm:text-2xl font-bold">Import Students</DialogTitle>
                    <DialogDescription className="text-sm sm:text-base">
                        Upload an Excel file to bulk import students into this class
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-4 sm:space-y-6">
                    {/* Download Template Button */}
                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between p-4 bg-muted/50 rounded-2xl gap-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-primary/10 rounded-xl">
                                <FileSpreadsheet className="size-5 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm font-bold">Need a template?</p>
                                <p className="text-xs text-muted-foreground">Download our Excel template with sample data</p>
                            </div>
                        </div>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={generateTemplate}
                            className="w-full sm:w-auto gap-2 rounded-xl font-bold h-10 border-slate-200 dark:border-slate-800"
                        >
                            <Download className="size-4" />
                            Download Template
                        </Button>
                    </div>

                    {/* File Upload */}
                    <div className="space-y-3">
                        <label
                            htmlFor="file-upload"
                            className="flex flex-col items-center justify-center w-full h-32 sm:h-40 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl cursor-pointer hover:border-primary/50 transition-all bg-slate-50/50 dark:bg-slate-900/50"
                        >
                            <div className="flex flex-col items-center justify-center pt-5 pb-6 px-4 text-center">
                                <div className="p-3 bg-white dark:bg-slate-800 rounded-2xl shadow-sm mb-3">
                                    <Upload className="size-6 text-primary" />
                                </div>
                                <p className="text-sm text-slate-600 dark:text-slate-400">
                                    <span className="font-bold text-primary">Click to upload</span> or drag and drop
                                </p>
                                <p className="text-[10px] sm:text-xs text-muted-foreground mt-1">
                                    Excel (.xlsx, .xls) or CSV files
                                </p>
                            </div>
                            <input
                                id="file-upload"
                                type="file"
                                className="hidden"
                                accept=".xlsx,.xls,.csv"
                                onChange={handleFileChange}
                            />
                        </label>
                        {file && (
                            <div className="flex items-center gap-2 px-1">
                                <FileSpreadsheet className="size-4 text-emerald-500" />
                                <p className="text-xs sm:text-sm font-medium truncate">
                                    Selected: <span className="text-primary">{file.name}</span>
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Loading State */}
                    {loading && (
                        <div className="flex items-center justify-center p-8 bg-slate-50 dark:bg-slate-900 rounded-2xl">
                            <Loader2 className="size-6 animate-spin text-primary" />
                            <span className="ml-3 text-sm font-medium text-muted-foreground">Parsing file...</span>
                        </div>
                    )}

                    {/* Errors */}
                    {hasErrors && !loading && (
                        <Alert variant="destructive" className="rounded-2xl border-red-100 dark:border-red-900/30 bg-red-50/50 dark:bg-red-950/20">
                            <AlertCircle className="size-4" />
                            <AlertDescription>
                                <p className="font-bold mb-2">Found {allErrors.length} error(s):</p>
                                <ul className="list-disc list-inside space-y-1 text-[11px] sm:text-xs opacity-90">
                                    {allErrors.slice(0, 5).map((error, index) => (
                                        <li key={index}>
                                            Row {error.row}: {error.field} - {error.message}
                                        </li>
                                    ))}
                                    {allErrors.length > 5 && (
                                        <li className="font-bold">...and {allErrors.length - 5} more errors</li>
                                    )}
                                </ul>
                            </AlertDescription>
                        </Alert>
                    )}

                    {/* Success Message */}
                    {parsedData.length > 0 && !hasErrors && !loading && (
                        <Alert className="rounded-2xl border-emerald-100 dark:border-emerald-900/30 bg-emerald-50/50 dark:bg-emerald-950/20">
                            <CheckCircle2 className="size-4 text-emerald-500" />
                            <AlertDescription className="text-emerald-700 dark:text-emerald-400 font-medium">
                                Successfully parsed {parsedData.length} students. Ready to import!
                            </AlertDescription>
                        </Alert>
                    )}

                    {/* Preview Table */}
                    {parsedData.length > 0 && !loading && (
                        <div className="border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden shadow-sm">
                            <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-200 dark:border-slate-800">
                                <p className="text-xs sm:text-sm font-bold">Preview ({parsedData.length} students)</p>
                            </div>
                            <div className="max-h-[250px] sm:max-h-[350px] overflow-auto">
                                <div className="min-w-[600px] sm:min-w-0">
                                    <Table>
                                        <TableHeader className="bg-slate-50/50 dark:bg-slate-900/50">
                                            <TableRow>
                                                <TableHead className="text-[11px] uppercase tracking-wider font-bold">ID</TableHead>
                                                <TableHead className="text-[11px] uppercase tracking-wider font-bold">Name</TableHead>
                                                <TableHead className="text-[11px] uppercase tracking-wider font-bold">Email</TableHead>
                                                <TableHead className="text-[11px] uppercase tracking-wider font-bold">Dept</TableHead>
                                                <TableHead className="text-[11px] uppercase tracking-wider font-bold text-right pr-4">Year</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {parsedData.slice(0, 10).map((student, index) => (
                                                <TableRow key={index} className="hover:bg-slate-50/50 dark:hover:bg-slate-900/50 transition-colors">
                                                    <TableCell className="font-mono text-[10px] sm:text-xs">
                                                        {student.registerNumber}
                                                    </TableCell>
                                                    <TableCell className="text-[11px] sm:text-sm font-medium">{student.studentName}</TableCell>
                                                    <TableCell className="text-[11px] sm:text-xs text-muted-foreground">{student.email}</TableCell>
                                                    <TableCell className="text-[11px] sm:text-xs">{student.department}</TableCell>
                                                    <TableCell className="text-[11px] sm:text-xs text-right pr-4">{student.year}</TableCell>
                                                </TableRow>
                                            ))}
                                        </TableBody>
                                    </Table>
                                </div>
                                {parsedData.length > 10 && (
                                    <div className="p-3 text-center text-[10px] sm:text-xs text-muted-foreground bg-slate-50/50 dark:bg-slate-900/50 border-t border-slate-100 dark:border-slate-800">
                                        ...and {parsedData.length - 10} more students
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <DialogFooter className="flex flex-col-reverse sm:flex-row gap-3 mt-6">
                    <Button
                        variant="ghost"
                        onClick={() => {
                            setParsedData([]);
                            setParseErrors([]);
                            setValidationErrors([]);
                            setFile(null);
                            onOpenChange(false);
                        }}
                        disabled={importing}
                        className="w-full sm:w-auto rounded-xl font-bold h-11"
                    >
                        Cancel
                    </Button>
                    <Button
                        onClick={handleImport}
                        disabled={parsedData.length === 0 || hasErrors || importing}
                        className="w-full sm:w-auto rounded-xl font-black h-11 shadow-lg shadow-primary/20 transition-all active:scale-95"
                    >
                        {importing ? (
                            <Loader2 className="mr-2 size-4 animate-spin" />
                        ) : (
                            <CheckCircle2 className="mr-2 size-4" />
                        )}
                        Import {parsedData.length} Students
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import React, { useEffect, useState, useRef } from 'react';
import { toPng } from 'html-to-image';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Share2, Trophy, Sparkles, Star, Medal, Award, Zap, Shield, Sword, Gem, GraduationCap, Target, Download, Infinity as InfinityIcon } from 'lucide-react';
import { BadgeType, BADGE_DETAILS } from '@/services/streakService';
import { Button } from '@/components/ui/button';
import { useAuth } from '@/contexts/AuthContext';
import { cn } from '@/lib/utils';

const IconMap: Record<string, React.ElementType> = {
    Trophy,
    Medal,
    Award,
    Zap,
    GraduationCap,
    Sparkles,
    Shield,
    Sword,
    Gem,
    Target,
    Infinity: InfinityIcon
};

interface StreakBadgeDetailModalProps {
    type: BadgeType | null;
    isOpen: boolean;
    onClose: () => void;
    hideShare?: boolean;
    hideClose?: boolean;
    hideGenerate?: boolean;
    externalProfile?: any;
}

export const StreakBadgeDetailModal: React.FC<StreakBadgeDetailModalProps> = ({
    type,
    isOpen,
    onClose,
    hideShare = false,
    hideClose = false,
    hideGenerate = false,
    externalProfile
}) => {
    const { profile: authProfile } = useAuth();
    const profile = externalProfile || authProfile;
    const [view, setView] = useState<'interactive' | 'result'>('interactive');
    const [randomStars, setRandomStars] = useState<{ top: string; left: string; size: number; delay: number }[]>([]);
    const [isExporting, setIsExporting] = useState(false);
    const badgeRef = useRef<HTMLDivElement>(null);
    const resultCardRef = useRef<HTMLDivElement>(null);



    useEffect(() => {
        if (isOpen) {
            setView('interactive'); // Reset to interactive when opening
            // Generate some random positions for sparkles
            const stars = Array.from({ length: 12 }).map(() => ({
                top: `${Math.random() * 80 + 10}%`,
                left: `${Math.random() * 80 + 10}%`,
                size: Math.random() * 20 + 10,
                delay: Math.random() * 2
            }));
            setRandomStars(stars);
        }
    }, [isOpen]);

    if (!type) return null;
    const details = BADGE_DETAILS[type];
    const IconComponent = IconMap[details.icon] || Trophy;


    const handleGenerateCard = () => {
        setView('result');
    };

    const handleDownload = async () => {
        if (!resultCardRef.current) return;
        setIsExporting(true);
        const toastId = toast.loading('Capturing your achievement card...');

        try {
            const dataUrl = await toPng(resultCardRef.current, {
                cacheBust: true,
                quality: 1,
                pixelRatio: 2, // Higher quality for saving
                backgroundColor: '#050b14',
            });

            const link = document.createElement('a');
            link.download = `eduspace-streak-${details.level}-days.png`;
            link.href = dataUrl;
            link.click();

            toast.success('Card downloaded!', { id: toastId });
        } catch (error) {
            console.error('Error downloading card:', error);
            toast.error('Download failed. Try again.', { id: toastId });
        } finally {
            setIsExporting(false);
        }
    };

    const copyToClipboard = (text: string) => {
        navigator.clipboard.writeText(text).catch((err) => {
            console.error('Could not copy text: ', err);
        });
    };

    const handleShare = async () => {
        if (!profile?.user_id) {
            toast.error("Profile ID not found. Please refresh and try again.");
            return;
        }

        const shareUrl = `${window.location.origin}/badge/${profile.user_id}?badge=${type}`;
        const shareMessage = `I just reached a ${details.level} Days Academic Streak on EduSpace! Check out my live achievement: ${shareUrl}`;

        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Academic Achievement | Eduspace`,
                    text: shareMessage,
                    url: shareUrl,
                });
            } catch (err) {
                if ((err as Error).name !== 'AbortError') {
                    console.error('Error sharing:', err);
                    copyToClipboard(shareUrl);
                }
            }
        } else {
            copyToClipboard(shareUrl);
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/95 overflow-y-auto cursor-pointer"
                >
                    {/* Background Spotlight Effect */}
                    <div className="absolute inset-0 pointer-events-none">
                        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[800px] h-[600px] bg-white/5 blur-[120px] rounded-full" />
                        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[400px] h-[400px] bg-white/10 blur-[80px] rounded-full" />

                        {/* Spotlight Beam */}
                        <div
                            className="absolute top-[-100px] left-1/2 -translate-x-1/2 w-[600px] h-[1000px]"
                            style={{
                                background: 'conic-gradient(from 165deg at 50% 0%, transparent 0%, rgba(255,255,255,0.05) 15%, transparent 30%)',
                                transform: 'rotate(0deg)'
                            }}
                        />
                    </div>

                    {/* Floating Sparkles */}
                    {randomStars.map((star, i) => (
                        <motion.div
                            key={i}
                            initial={{ scale: 0, opacity: 0 }}
                            animate={{
                                scale: [0, 1, 0.5, 1, 0],
                                opacity: [0, 0.8, 0.3, 0.8, 0]
                            }}
                            transition={{
                                duration: 3,
                                repeat: Infinity,
                                delay: star.delay,
                                ease: "easeInOut"
                            }}
                            className="absolute pointer-events-none"
                            style={{ top: star.top, left: star.left }}
                        >
                            <Sparkles className="text-white/40" style={{ width: star.size, height: star.size }} />
                        </motion.div>
                    ))}

                    {/* Main Content Container */}
                    <motion.div
                        initial={{ scale: 0.9, y: 20, opacity: 0 }}
                        animate={{ scale: 1, y: 0, opacity: 1 }}
                        exit={{ scale: 0.9, y: 20, opacity: 0 }}
                        onClick={(e) => e.stopPropagation()}
                        className="relative w-full max-w-2xl flex flex-col items-center text-center text-white cursor-default"
                    >
                        {view === 'interactive' ? (
                            <>
