import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Check, X, GraduationCap, Calendar, User } from "lucide-react";
import { useState } from "react";
import { useAccessRequests } from "@/hooks/useAccessRequests";
import { toast } from "sonner";

interface AccessRequestCardProps {
    request: any;
    onRespond: (requestId: string) => void;
}

export function AccessRequestCard({ request, onRespond }: AccessRequestCardProps) {
    const { respondToAccessRequest, loading } = useAccessRequests();
    const [responding, setResponding] = useState(false);

    const handleAccept = async () => {
        try {
            setResponding(true);
            await respondToAccessRequest(request.id, 'accepted');
            toast.success("Access request accepted! You've been added to the class.");
            onRespond(request.id);
        } catch (error) {
            toast.error("Failed to accept request");
        } finally {
            setResponding(false);
        }
    };

    const handleReject = async () => {
        try {
            setResponding(true);
            await respondToAccessRequest(request.id, 'rejected');
            toast.success("Access request rejected");
            onRespond(request.id);
        } catch (error) {
            toast.error("Failed to reject request");
        } finally {
            setResponding(false);
        }
    };

    const classInfo = request.classes;

    return (
        <Card className="bg-gradient-to-br from-primary/5 to-primary/10 border-primary/20">
            <CardContent className="p-6">
                <div className="flex flex-col gap-4">
                    {/* Header */}
                    <div className="flex items-start justify-between">
                        <div className="flex items-center gap-3">
                            <div className="size-12 rounded-full bg-primary/10 flex items-center justify-center">
                                <GraduationCap className="size-6 text-primary" />
                            </div>
                            <div>
                                <h3 className="font-semibold text-lg">Class Access Request</h3>
                                <p className="text-sm text-muted-foreground">
                                    You've been invited to join a class
                                </p>
                            </div>
                        </div>
                        <Badge variant="secondary" className="bg-yellow-500/10 text-yellow-600 border-yellow-500/20">
                            Pending
                        </Badge>
                    </div>

                    {/* Class Details */}
                    <div className="bg-background/50 rounded-lg p-4 space-y-3">
                        <div className="flex items-center gap-2">
                            <GraduationCap className="size-4 text-muted-foreground" />
                            <span className="font-medium">{classInfo?.course_code || 'Unknown Course'}</span>
                            {classInfo?.class_name && (
                                <>
                                    <span className="text-muted-foreground">•</span>
                                    <span className="text-sm text-muted-foreground">{classInfo.class_name}</span>
                                </>
                            )}
                        </div>

                        {classInfo?.semester && classInfo?.academic_year && (
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                <Calendar className="size-4" />
                                <span>{classInfo.semester} • {classInfo.academic_year}</span>
                            </div>
                        )}

                        {classInfo?.lecturer_name && (
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                <User className="size-4" />
                                <span>Lecturer: {classInfo.lecturer_name}</span>
                                {classInfo.lecturer_department && (
                                    <>
                                        <span>•</span>
                                        <span>{classInfo.lecturer_department}</span>
                                    </>
                                )}
                            </div>
                        )}
                    </div>

                    {/* Message */}
                    <div className="bg-background/50 rounded-lg p-4">
                        <p className="text-sm text-muted-foreground">
                            <strong>{classInfo?.lecturer_name || 'A lecturer'}</strong> has invited you to join this class.
                            By accepting, you'll get access to assignments, schedules, and can communicate with your lecturer.
                        </p>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-3 pt-2">
                        <Button
                            onClick={handleAccept}
                            disabled={responding || loading}
                            className="flex-1 gap-2"
                        >
                            <Check className="size-4" />
                            {responding ? "Accepting..." : "Accept"}
                        </Button>
                        <Button
                            onClick={handleReject}
                            disabled={responding || loading}
                            variant="outline"
                            className="flex-1 gap-2 text-destructive hover:text-destructive"
                        >
                            <X className="size-4" />
                            {responding ? "Rejecting..." : "Reject"}
                        </Button>
                    </div>

                    {/* Timestamp */}
                    <p className="text-xs text-muted-foreground text-center">
                        Sent {new Date(request.sent_at).toLocaleDateString('en-US', {
                            month: 'short',
                            day: 'numeric',
                            year: 'numeric',
                            hour: '2-digit',
                            minute: '2-digit'
                        })}
                    </p>
                </div>
            </CardContent>
        </Card>
    );
}

import { useEffect, useState } from 'react';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { AccessRequestCard } from './AccessRequestCard';
import { GraduationCap } from 'lucide-react';
import { Badge } from '@/components/ui/badge';

interface JoinRequestModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    pendingInvitations: any[];
    onRequestHandled: () => void;
    onRequestMarkedAsHandled?: (requestId: string) => void;
}

export function JoinRequestModal({
    open,
    onOpenChange,
    pendingInvitations,
    onRequestHandled,
    onRequestMarkedAsHandled,
}: JoinRequestModalProps) {
    const [localInvitations, setLocalInvitations] = useState(pendingInvitations);

    useEffect(() => {
        setLocalInvitations(pendingInvitations);
    }, [pendingInvitations]);

    const handleRespond = async (requestId: string) => {
        // Mark request as handled (clears notification)
        if (onRequestMarkedAsHandled) {
            await onRequestMarkedAsHandled(requestId);
        }

        // Refresh the invitations list
        await onRequestHandled();

        // Close modal if no more pending invitations
        if (localInvitations.length <= 1) {
            onOpenChange(false);
        }
    };

    // Don't render if no invitations
    if (!pendingInvitations || pendingInvitations.length === 0) {
        return null;
    }

    return (
        <Dialog
            open={open}
            onOpenChange={(open) => {
                // Prevent closing the modal - only allow programmatic close after handling request
                if (!open) return;
                onOpenChange(open);
            }}
        >
            <DialogContent
                className="max-w-4xl max-h-[90vh] [&>button]:hidden"
                onInteractOutside={(e) => {
                    // Prevent closing when clicking outside
                    e.preventDefault();
                }}
                onEscapeKeyDown={(e) => {
                    // Prevent closing with Escape key
                    e.preventDefault();
                }}
            >
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-3 text-2xl">
                        <div className="size-10 rounded-full bg-primary/10 flex items-center justify-center">
                            <GraduationCap className="size-6 text-primary" />
                        </div>
                        <span>Class Join Requests</span>
                        <Badge variant="secondary" className="ml-2">
                            {localInvitations.length}
                        </Badge>
                    </DialogTitle>
                    <DialogDescription>
                        You have been invited to join {localInvitations.length} class{localInvitations.length > 1 ? 'es' : ''}.
                        Review the details below and accept or reject each invitation.
                    </DialogDescription>
                </DialogHeader>

                <ScrollArea className="max-h-[60vh] pr-4">
                    <div className="space-y-4 mt-4">
                        {localInvitations.map((invitation) => (
                            <AccessRequestCard
                                key={invitation.id}
                                request={invitation}
                                onRespond={handleRespond}
                            />
                        ))}
                    </div>
                </ScrollArea>
            </DialogContent>
        </Dialog>
    );
}

import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { Clock, FileText, Trophy, PlayCircle, CheckCircle, XCircle, Eye, ArrowRight } from 'lucide-react';
import { Quiz } from '@/types/quiz';
import { cn } from '@/lib/utils';

interface QuizCardProps {
    quiz: Quiz & {
        my_submission?: any;
        instructor?: {
            full_name: string | null;
            avatar_url: string | null;
        } | null;
        _count?: {
            questions: number;
        };
        classes?: {
            class_name: string;
            course_code: string;
        } | null;
    };
    onAttempt: (quizId: string) => void;
    onViewDetails: (quizId: string) => void;
    onViewLeaderboard: (quizId: string, classId: string) => void;
    viewMode?: 'grid' | 'list';
    className?: string;
}

export function QuizCard({ quiz, onAttempt, onViewDetails, onViewLeaderboard, viewMode = 'grid', className }: QuizCardProps) {
    // Determine state
    const hasActiveSubmission = !!quiz.my_submission && !quiz.my_submission.is_archived;
    const isCompleted = hasActiveSubmission && quiz.my_submission.status !== 'pending';

    // Reattempt Logic
    const submissionVersion = quiz.my_submission?.quiz_version || 0;
    const currentQuizVersion = (quiz as any).version || 1;
    const canReattempt = isCompleted && currentQuizVersion > submissionVersion;

    // Final decision: Show "Attempted" state if completed AND on current version
    const showAttemptedState = isCompleted && !canReattempt;
    const isPassed = quiz.my_submission?.status === 'passed';

    if (viewMode === 'list') {
        return (
            <Card className={cn(
                "group relative overflow-hidden border shadow-sm hover:shadow-md transition-all duration-300 w-full rounded-xl bg-white dark:bg-[#3c3744] text-slate-900 dark:text-white border-slate-200 dark:border-white/5",
                className
            )}>
                <CardContent className="p-4 flex flex-col md:flex-row gap-4 items-center">
                    {/* Left: Status & Course */}
                    <div className="flex items-center gap-3 md:w-48 shrink-0">
                        <div className={`p-3 rounded-xl ${showAttemptedState
                            ? (isPassed ? 'bg-emerald-100/50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400' : 'bg-red-100/50 text-red-600 dark:bg-red-900/20 dark:text-red-400')
                            : 'bg-blue-100/50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400'
                            }`}>
                            {showAttemptedState ? (
                                isPassed ? <CheckCircle className="size-6" /> : <XCircle className="size-6" />
                            ) : (
                                <PlayCircle className="size-6" />
                            )}
                        </div>
                        <div className="flex flex-col">
                            <Badge variant="secondary" className="w-fit mb-1 bg-blue-400 hover:bg-blue-500 text-blue-950 border-none text-[10px] font-bold">
                                {quiz.classes?.course_code || 'COURSE'}
                            </Badge>
                            <span className="text-xs font-semibold text-slate-500 dark:text-muted-foreground">
                                {showAttemptedState ? quiz.my_submission?.status?.toUpperCase() : 'NOT STARTED'}
                            </span>
                        </div>
                    </div>

                    {/* Middle: Title & Instructor */}
                    <div className="flex-1 min-w-0 text-center md:text-left">
                        <h3 className="font-bold text-lg leading-tight text-slate-900 dark:text-white truncate">
                            {quiz.title}
                        </h3>
                        {quiz.instructor && (
                            <div className="flex items-center justify-center md:justify-start gap-2 mt-1">
                                <span className="text-xs font-medium text-slate-500 dark:text-slate-300">
                                    by {quiz.instructor.full_name}
                                </span>
                            </div>
                        )}
                    </div>

                    {/* Right: Metrics */}
                    <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-300 shrink-0 border-r border-slate-200 dark:border-white/10 pr-4 mr-2 hidden md:flex">
                        <div className="flex items-center gap-1.5" title="Questions">
                            <FileText className="size-4" />
                            <span className="font-medium text-slate-900 dark:text-white">{quiz._count?.questions || 0}</span>
                        </div>
                        <div className="flex items-center gap-1.5" title="Total Points">
                            <Trophy className="size-4" />
                            <span className="font-medium text-slate-900 dark:text-white">{quiz.total_marks} Pts</span>
                        </div>
                        <div className="flex items-center gap-1.5" title="Pass Score">
                            <CheckCircle className="size-4" />
                            <span className="font-medium text-slate-900 dark:text-white">{quiz.pass_percentage}% Pass</span>
                        </div>
                    </div>

                    {/* Action Button */}
                    <div className="shrink-0 w-full md:w-auto">
                        {showAttemptedState ? (
                            <div className="flex gap-2 w-full md:w-auto">
                                <Button
                                    onClick={() => onViewDetails(quiz.id)}
                                    size="sm"
                                    className="flex-1 md:flex-none font-semibold"
                                    variant="outline"
                                >
                                    Details
                                </Button>
                                <Button
                                    onClick={() => onViewLeaderboard(quiz.id, quiz.class_id)}
                                    size="icon"
                                    className="shrink-0"
                                    variant="ghost"
                                >
                                    <Trophy className="size-4 text-amber-500" />
                                </Button>
                            </div>
                        ) : (
                            <Button
                                onClick={() => onAttempt(quiz.id)}
                                size="sm"
                                className="w-full md:w-auto font-bold bg-blue-600 hover:bg-blue-700 text-white shadow-sm"
                            >
                                Start Quiz
                            </Button>
                        )}
                    </div>
                </CardContent>
            </Card>
        );
    }

    return (
        <Card className={cn(
            "group relative overflow-hidden border-none shadow-lg hover:shadow-2xl transition-all duration-500 w-full flex flex-col h-full rounded-2xl bg-white dark:bg-[#1a1625] text-slate-900 dark:text-white",
            className
        )}>
            {/* Header Section - Compact Gradient */}
            <div className="relative h-16 bg-gradient-to-br from-blue-600 to-blue-800 p-3 flex flex-col justify-between overflow-hidden">
                {/* Decorative background circle */}
                <div className="absolute -top-6 -right-6 size-20 bg-white/5 rounded-full blur-2xl group-hover:scale-150 transition-transform duration-700" />

                <div className="flex justify-between items-start relative z-10">
                    <Badge variant="secondary" className="bg-white/20 hover:bg-white/30 text-white border-none backdrop-blur-md font-bold tracking-wider uppercase text-[8px] px-2 py-1 rounded-md truncate max-w-[90px] shrink-0">
                        {quiz.classes?.course_code || 'COURSE'}
                    </Badge>

                    {showAttemptedState ? (
                        <Badge className={cn("border-none font-bold shadow-lg backdrop-blur-md px-2 py-0.5 rounded-md text-[8px]", isPassed ? 'bg-emerald-400 text-emerald-950' : 'bg-red-400 text-red-950')}>
                            {quiz.my_submission?.status?.toUpperCase()}
                        </Badge>
                    ) : (
                        <Badge className="bg-white/20 hover:bg-white/30 text-white border-none backdrop-blur-md font-bold shadow-sm px-2 py-0.5 rounded-md text-[8px]">
                            NOT STARTED
                        </Badge>
                    )}
                </div>
            </div>

            {/* Content Body - Compact */}
            <CardContent className="p-3 flex flex-col h-full gap-3 relative">
                {/* Title */}
                <div>
                    <h3 className="font-black text-sm leading-snug line-clamp-2 mb-2 text-slate-800 dark:text-slate-100 group-hover:text-primary transition-colors" title={quiz.title}>
                        {quiz.title}
                    </h3>

                    {/* Instructor Info */}
                    {quiz.instructor && (
                        <div className="flex items-center gap-1.5">
                            <Avatar className="h-5 w-5 border border-background shadow-sm shrink-0">
                                <AvatarImage src={quiz.instructor.avatar_url || ''} />
                                <AvatarFallback className="bg-primary/10 text-primary font-bold text-[8px]">
                                    {quiz.instructor.full_name?.charAt(0) || 'I'}
                                </AvatarFallback>
                            </Avatar>
                            <span className="text-[10px] font-semibold text-slate-500 dark:text-slate-400 line-clamp-1">
                                {quiz.instructor.full_name}
                            </span>
                        </div>
                    )}
                </div>

                {/* Metrics Grid - Stacked */}
                <div className="flex flex-col gap-1.5">
                    <div className="flex gap-1.5">
                        <div className="flex-1 flex items-center gap-1.5 px-2 py-1.5 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-white/5">
                            <FileText className="size-3 text-blue-500 shrink-0" />
                            <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300">{quiz._count?.questions || 0} Questions</span>
                        </div>
                        <div className="flex-1 flex items-center gap-1.5 px-2 py-1.5 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-white/5">
                            <Trophy className="size-3 text-amber-500 shrink-0" />
                            <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300">{quiz.total_marks} Pts</span>
                        </div>
                    </div>

                    <div className="flex items-center gap-1.5 px-2 py-1.5 rounded-xl bg-indigo-500/5 dark:bg-indigo-500/10 border border-indigo-500/10">
                        <Clock className="size-3 text-indigo-500 shrink-0" />
                        <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400">
                            {quiz.pass_percentage}% Required to Pass
                        </span>
                    </div>
                </div>

                {/* Action Area */}
                <div className="mt-auto">
                    {showAttemptedState ? (
                        <div className="flex gap-2">
                            <Button
                                onClick={() => onViewDetails(quiz.id)}
                                className="flex-1 rounded-xl font-bold text-xs h-8 bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-white/10 shadow transition-all flex items-center justify-center gap-1"
                            >
                                <Eye className="size-3" />
                                Details
                            </Button>
                            <Button
                                onClick={() => onViewLeaderboard(quiz.id, quiz.class_id)}
                                variant="outline"
                                className="rounded-xl h-8 w-8 p-0 border-slate-200 dark:border-white/10"
                                title="Leaderboard"
                            >
                                <Trophy className="size-3.5 text-amber-500" />
                            </Button>
                        </div>
                    ) : (
                        <Button
                            onClick={() => onAttempt(quiz.id)}
                            className="w-full rounded-xl font-bold text-xs h-8 bg-gradient-to-r from-blue-600 to-blue-800 text-white shadow transition-all hover:scale-[1.02] active:scale-95 border-none"
                        >
                            {canReattempt ? 'Retake Quiz' : 'Start Quiz'}
                        </Button>
                    )}
                </div>
            </CardContent>
        
        </Card>
        
    );
}

import { useState, useEffect } from "react";
import { Sheet, SheetContent, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Drawer } from "vaul";
import { useIsMobile } from "@/hooks/use-mobile";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { BookOpen, Plus, Trash2, Edit2, Save, X, Search, MoreVertical } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { format, formatDistanceToNow } from "date-fns";
import { knowledgeService } from "@/lib/knowledgeService";
import { cn } from "@/lib/utils";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface Note {
    id: string;
    title: string;
    content: string;
    created_at: string;
}

export function StudentNotesDrawer() {
    const { user } = useAuth();
    const [notes, setNotes] = useState<Note[]>([]);
    const [loading, setLoading] = useState(true);
    const [isEditing, setIsEditing] = useState<string | null>(null);
    const [newNoteMode, setNewNoteMode] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const isMobile = useIsMobile();
    const [open, setOpen] = useState(false);
    const [showDeleteAllConfirm, setShowDeleteAllConfirm] = useState(false);

    // Form State
    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    const fetchNotes = async () => {
        if (!user) return;
        setLoading(true);
        const { data, error } = await supabase
            .from('student_notes')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("Error fetching notes:", error);
            toast.error("Failed to load notes");
        } else {
            setNotes(data || []);
        }
        setLoading(false);
    };

    useEffect(() => {
        if (user) fetchNotes();
    }, [user]);

    const handleSave = async () => {
        if (!user || !title.trim()) return;

        try {
            if (isEditing) {
                const { error: updateError } = await supabase
                    .from('student_notes')
                    .update({ title, content })
                    .eq('id', isEditing);
                if (updateError) throw updateError;
                toast.success("Note updated");

                knowledgeService.upsertKnowledgeNode({
                    type: 'note',
                    sourceId: isEditing,
                    label: title,
                    text: `${title}\n${content}`
                });
            } else {
                const { data, error: insertError } = await supabase
                    .from('student_notes')
                    .insert({ user_id: user.id, title, content })
                    .select();
                if (insertError) throw insertError;
                toast.success("Note created");

                // Update Knowledge Map with new note
                if (data?.[0]) {
                    knowledgeService.upsertKnowledgeNode({
                        type: 'note',
                        sourceId: data[0].id,
                        label: title,
                        text: `${title}\n${content}`
                    });
                }
            }

            resetForm();
            fetchNotes();
        } catch (error) {
            console.error("Error saving note:", error);
            toast.error("Failed to save note");
        }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const { error } = await supabase.from('student_notes').delete().eq('id', id);
        if (error) {
            toast.error("Failed to delete note");
        } else {
            toast.success("Note deleted");
            setNotes(prev => prev.filter(n => n.id !== id));
            knowledgeService.deleteKnowledgeNode(id);
        }
    };

    const handleDeleteAll = async () => {
        if (!user || notes.length === 0) return;

        try {
            const { error } = await supabase
                .from('student_notes')
                .delete()
                .eq('user_id', user.id);

            if (error) throw error;

            toast.success("All notes deleted");

            // Cleanup knowledge map for all deleted notes
            notes.forEach(note => {
                knowledgeService.deleteKnowledgeNode(note.id);
            });

            setNotes([]);
            setShowDeleteAllConfirm(false);
        } catch (error) {
            console.error("Error deleting all notes:", error);
            toast.error("Failed to delete all notes");
        }
    };

    const startEdit = (note: Note) => {
        setIsEditing(note.id);
        setTitle(note.title);
        setContent(note.content);
        setNewNoteMode(false);
    };

    const resetForm = () => {
        setIsEditing(null);
        setNewNoteMode(false);
        setTitle("");
        setContent("");
    };

    const filteredNotes = notes.filter(n =>
        n.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        n.content.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const renderContent = () => (
        <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900">
            {/* Header Section */}
            <div className={cn(
                "flex flex-col gap-4 shrink-0 px-4",
                isMobile ? "pt-6 pb-2" : "mt-8 mb-6"
            )}>
                <div className="flex items-center justify-between relative min-h-[44px]">
                    <SheetTitle className="font-black text-foreground tracking-tight text-2xl">
                        {isEditing ? "Edit Note" : newNoteMode ? "New Note" : "My Notes"}
                    </SheetTitle>

                    <div className="flex items-center gap-3">
                        {/* New Note Button (Desktop Title Row) */}
                        {!newNoteMode && !isEditing && !isMobile && (
                            <button
                                onClick={() => setNewNoteMode(true)}
                                className="text-[11px] font-black uppercase tracking-widest text-blue-600 hover:text-blue-700 bg-blue-50 dark:bg-blue-500/10 px-4 py-2 rounded-xl active:scale-95 transition-all"
                            >
                                New
                            </button>
                        )}

                        {(newNoteMode || isEditing) && (
                            <button
                                onClick={resetForm}
                                className="text-[11px] font-black uppercase tracking-widest text-muted-foreground hover:text-foreground bg-muted/30 px-4 py-2 rounded-xl active:scale-95 transition-all"
                            >
                                Cancel
                            </button>
                        )}
                    </div>
                </div>

                {/* Search Bar & Delete All - Side by Side */}
                {!newNoteMode && !isEditing && (
                    <div className="flex items-center gap-2">
                        <div className="relative group flex-1">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 size-4 text-muted-foreground/60 transition-colors group-focus-within:text-blue-500" />
                            <Input
                                placeholder="Search notes..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className={cn(
                                    "h-12 pl-11 pr-4 bg-muted/40 border-none rounded-2xl focus-visible:ring-blue-500/20 placeholder:text-muted-foreground/40 font-medium transition-all w-full",
                                    isMobile && "bg-slate-300/40 dark:bg-slate-800/60"
                                )}
                            />
                        </div>
                        {notes.length > 0 && (
                            <AlertDialog open={showDeleteAllConfirm} onOpenChange={setShowDeleteAllConfirm}>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => setShowDeleteAllConfirm(true)}
                                    className="size-12 rounded-2xl bg-red-50/50 dark:bg-red-500/5 text-red-500 hover:bg-red-500 hover:text-white transition-all shrink-0"
                                    title="Delete All Notes"
                                >
                                    <Trash2 className="size-5" />
                                </Button>
                                <AlertDialogContent className="z-[300]">
                                    <AlertDialogHeader>
                                        <AlertDialogTitle>Delete All Notes?</AlertDialogTitle>
                                        <AlertDialogDescription>
                                            This action will permanently delete all your saved notes. This cannot be undone.
                                        </AlertDialogDescription>
                                    </AlertDialogHeader>
                                    <AlertDialogFooter>
                                        <AlertDialogCancel className="rounded-xl">Cancel</AlertDialogCancel>
                                        <AlertDialogAction
                                            onClick={handleDeleteAll}
                                            className="bg-red-600 hover:bg-red-700 text-white rounded-xl"
                                        >
                                            Delete All
                                        </AlertDialogAction>
                                    </AlertDialogFooter>
                                </AlertDialogContent>
                            </AlertDialog>
                        )}
                    </div>
                )}
            </div>

            <div className="flex-1 overflow-hidden flex flex-col pt-4 min-h-0 px-4">
                {(newNoteMode || isEditing) ? (
                    <div className="flex flex-col gap-4 h-full pb-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
                        <div className="space-y-1">
                            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 ml-1">Title</label>
                            <Input
                                placeholder="Note Title"
                                value={title}
                                onChange={e => setTitle(e.target.value)}
                                className="font-bold text-lg h-14 rounded-2xl border-none bg-muted/40 focus-visible:ring-blue-500/10 px-4"
                            />
                        </div>
                        <div className="space-y-1 flex-1 flex flex-col min-h-0">
                            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 ml-1">Content</label>
                            <Textarea
                                placeholder="Start typing your note here..."
                                value={content}
                                onChange={e => setContent(e.target.value)}
                                className="flex-1 resize-none rounded-2xl border-none bg-muted/30 p-4 focus-visible:ring-blue-500/10 leading-relaxed text-base"
                            />
                        </div>
                        <div className="flex justify-end pt-4 pb-2">
                            <Button
                                onClick={handleSave}
                                disabled={!title.trim()}
                                className="bg-blue-600 hover:bg-blue-700 text-white shadow-xl shadow-blue-600/30 font-black rounded-2xl px-8 h-12 w-full active:scale-[0.98] transition-all"
                            >
                                <Save className="h-4 w-4 mr-2" />
                                {isEditing ? "Update Note" : "Save Note"}
                            </Button>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 min-h-0 flex flex-col relative overflow-hidden">
                        <div className="flex-1 overflow-y-auto mb-2 overscroll-contain pb-4">
                            {loading ? (
                                <div className="flex flex-col gap-4 py-4 animate-in fade-in duration-500">
                                    {[1, 2, 3, 4, 5, 6].map((i) => (
                                        <div key={i} className="p-4 rounded-2xl bg-white dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800/30 shadow-sm space-y-3">
                                            <div className="flex justify-between items-start">
                                                <Skeleton className="h-5 w-3/4 rounded-lg" />
                                                <Skeleton className="h-4 w-12 rounded-lg" />
                                            </div>
                                            <div className="space-y-2">
                                                <Skeleton className="h-3 w-full rounded-md" />
                                                <Skeleton className="h-3 w-[90%] rounded-md" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : filteredNotes.length === 0 ? (
                                <div className="text-center text-muted-foreground py-20 flex flex-col items-center gap-6 animate-in fade-in zoom-in-95 duration-500">
                                    <div className="size-24 bg-muted/30 rounded-full flex items-center justify-center">
                                        <BookOpen className="h-12 w-12 opacity-20" />
                                    </div>
                                    <div className="space-y-1">
                                        <p className="font-black text-lg text-foreground">Pocket empty</p>
                                        <p className="text-sm font-medium">Capture your lecture highlights here</p>
                                    </div>
                                </div>
                            ) : (
                                <div className="flex flex-col gap-3 pb-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
                                    {filteredNotes.map(note => (
                                        <div
                                            key={note.id}
                                            onClick={() => startEdit(note)}
                                            className={cn(
                                                "p-4 rounded-2xl border border-transparent transition-all active:scale-[0.97] group relative overflow-hidden",
                                                isMobile
                                                    ? "bg-white dark:bg-slate-800/40 border-slate-200 dark:border-slate-700/30 shadow-sm"
                                                    : "bg-muted/5 border-border/10 hover:border-blue-500/30"
                                            )}
                                        >
                                            <div className="flex flex-col gap-2">
                                                <div className="flex justify-between items-start gap-4">
                                                    <h3 className="font-bold text-[15px] text-foreground group-hover:text-blue-500 transition-colors line-clamp-1 flex-1">
                                                        {note.title}
                                                    </h3>
                                                    <div className="flex items-center gap-4 shrink-0 pl-2">
                                                        <span className="text-[10px] font-black text-muted-foreground/60 tracking-wider">
                                                            {format(new Date(note.created_at), 'HH:mm')}
                                                        </span>
                                                        <button
                                                            onClick={(e) => handleDelete(note.id, e)}
                                                            className="p-1.5 text-muted-foreground/40 hover:text-red-500 active:scale-90 transition-all"
                                                            title="Delete Note"
                                                        >
                                                            <Trash2 className="size-4" />
                                                        </button>
                                                    </div>
                                                </div>
                                                <p className="text-[13px] text-muted-foreground/70 line-clamp-2 leading-relaxed font-medium">
                                                    {note.content}
                                                </p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Large Footer Button for Mobile - Docked at bottom */}
                        {isMobile && !loading && !newNoteMode && !isEditing && (
                            <div className="pt-2 pb-10 shrink-0 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                                <Button
                                    onClick={() => setNewNoteMode(true)}
                                    className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black text-base h-16 rounded-[24px] shadow-2xl shadow-blue-600/20 active:scale-[0.98] transition-all gap-2"
                                >
                                    <Plus className="size-6 stroke-[3px]" />
                                    Create New Note
                                </Button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );

    if (isMobile) {
        return (
            <Drawer.Root open={open} onOpenChange={setOpen}>
                <Drawer.Trigger asChild>
                    <Button variant="ghost" size="icon" className="h-9 w-9 text-slate-500" title="My Notes">
                        <BookOpen className="h-5 w-5" />
                    </Button>
                </Drawer.Trigger>
                <Drawer.Portal>
                    <Drawer.Overlay className="fixed inset-0 z-[150] bg-black/40 backdrop-blur-[2px]" />
                    <Drawer.Content className="fixed bottom-0 left-0 right-0 z-[200] flex flex-col bg-slate-50 dark:bg-slate-900 rounded-t-[32px] outline-none h-[92vh]">
                        {/* Drag handle */}
                        <div className="mx-auto w-12 h-1.5 flex-shrink-0 cursor-grab rounded-full bg-slate-200 dark:bg-slate-800 mt-4 mb-2" />
                        <div className="flex-1 overflow-hidden">
                            {renderContent()}
                        </div>
                    </Drawer.Content>
                </Drawer.Portal>
            </Drawer.Root>
        );
    }

    return (
        <Sheet open={open} onOpenChange={setOpen}>
            <SheetTrigger asChild>
                <Button variant="ghost" size="icon" className="h-9 w-9 text-slate-500" title="My Notes">
                    <BookOpen className="h-5 w-5" />
                </Button>
            </SheetTrigger>
            <SheetContent
                side="right"
                className="flex flex-col p-0 border-none bg-background shadow-2xl transition-all duration-500 ease-in-out h-full w-full sm:max-w-md pt-[var(--safe-top)]"
            >
                {renderContent()}
            </SheetContent>
        </Sheet>
    );
}

import { useState, useEffect, useRef } from "react";
import { useSearchParams } from "react-router-dom";
import { AIChatSidebar } from "./AIChatSidebar";
import { AIChatInput } from "./AIChatInput";
import { AIMessage } from "./AIMessage";
import { AIChatSkeleton, MessagesSkeleton } from "./AIChatSkeleton";
import { aiChatService, AIConversation, AIChatMessage, MessageContent } from "@/lib/aiChatService";
import { ScrollArea } from "@/components/ui/scroll-area";
import { toast } from "sonner";
import { Loader2, MessageSquare, Sparkles, ChevronRight, User, Menu, Bot, MessageCircleDashed, MessageCircle, Link } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { knowledgeService } from "@/lib/knowledgeService";
import { useStreak } from "@/contexts/StreakContext";

export default function AIChatWindow() {
    const [conversations, setConversations] = useState<AIConversation[]>([]);
    const [currentConversation, setCurrentConversation] = useState<AIConversation | null>(null);
    const [messages, setMessages] = useState<AIChatMessage[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isStreaming, setIsStreaming] = useState(false);
    const [streamingMessage, setStreamingMessage] = useState("");
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [userProfile, setUserProfile] = useState<{ full_name?: string; avatar_url?: string; role?: string } | null>(null);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isTemporaryMode, setIsTemporaryMode] = useState(false);
    const scrollAreaRef = useRef<HTMLDivElement>(null);
    const lastMessageRef = useRef<HTMLDivElement>(null);
    const [searchParams, setSearchParams] = useSearchParams();
    const chatIdFromUrl = searchParams.get('id');

    // Typewriter effect for slogans
    // Typewriter effect for slogans with role-specific phrases
    const studentSlogans = [
        "Your Personalized Learning Partner",
        "Learn Smarter with Eduspace",
        "Your Academic Journey, Redefined",
        "Empowering Every Student to Succeed",
        "Where Curiosity Meets Intelligence",
        "Unlock Your Full Potential",
        "The Smartest Way to Study"
    ];

    const lecturerSlogans = [
        "Enhance Your Teaching Experience",
        "Streamline Your Course Management",
        "Empowering Educators with AI",
        "Insightful Analytics for Your Classes",
        "Revolutionize the Way You Teach",
        "Manage Your Students Smarter",
        "Your AI-Powered Teaching Assistant"
    ];

    const slogans = userProfile?.role === 'lecturer' ? lecturerSlogans : studentSlogans;

    const [currentSloganIndex, setCurrentSloganIndex] = useState(0);
    const [displayText, setDisplayText] = useState("");
    const [isDeleting, setIsDeleting] = useState(false);
    const [typingSpeed, setTypingSpeed] = useState(150);

    useEffect(() => {
        if (messages.length > 0) return; // Only animate in empty state

        const handleTyping = () => {
            const fullSlogan = slogans[currentSloganIndex];

            if (!isDeleting) {
                setDisplayText(fullSlogan.substring(0, displayText.length + 1));
                setTypingSpeed(100);

                if (displayText === fullSlogan) {
                    setIsDeleting(true);
                    setTypingSpeed(2000); // Pause at the end
                }
            } else {
                setDisplayText(fullSlogan.substring(0, displayText.length - 1));
                setTypingSpeed(50);

                if (displayText === "") {
                    setIsDeleting(false);
                    setCurrentSloganIndex((prev) => (prev + 1) % slogans.length);
                    setTypingSpeed(500);
                }
            }
        };

        const timer = setTimeout(handleTyping, typingSpeed);
        return () => clearTimeout(timer);
    }, [displayText, isDeleting, currentSloganIndex, slogans.length, typingSpeed, messages.length]);

    useEffect(() => {
        loadConversations();
        loadUserProfile();
    }, []);

    // Sync current conversation with URL id
    useEffect(() => {
        if (conversations.length > 0 && chatIdFromUrl) {
            const conv = conversations.find(c => c.id === chatIdFromUrl);
            if (conv && (!currentConversation || currentConversation.id !== conv.id)) {
                setCurrentConversation(conv);
            }
        } else if (!chatIdFromUrl && currentConversation) {
            setCurrentConversation(null);
        }
    }, [chatIdFromUrl, conversations]);

    useEffect(() => {
        if (currentConversation) {
            loadMessages(currentConversation.id);
        } else {
            setMessages([]);
        }
    }, [currentConversation]);

    useEffect(() => {
        scrollToBottom();
    }, [messages, streamingMessage]);

    const scrollToBottom = () => {
        if (lastMessageRef.current) {
            lastMessageRef.current.scrollIntoView({
                behavior: isStreaming ? 'auto' : 'smooth',
                block: 'end'
            });
        }
    };

    const loadUserProfile = async () => {
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                const { data } = await supabase
                    .from('public_profiles')
                    .select('full_name, avatar_url, role')
                    .eq('user_id', user.id)
                    .maybeSingle();

                if (data) setUserProfile(data);
            }
        } catch (err) {
            console.warn("Failed to load profile:", err);
        }
    };

    const loadConversations = async () => {
        setIsInitialLoading(true);
        try {
            const data = await aiChatService.getConversations();
            setConversations(data);

            // If we have an ID in the URL, select it immediately
            if (chatIdFromUrl) {
                const conv = data.find(c => c.id === chatIdFromUrl);
                if (conv) setCurrentConversation(conv);
            }
        } catch (error) {
            console.error("Failed to load conversations:", error);
        } finally {
            setIsInitialLoading(false);
        }
    };

    const loadMessages = async (id: string) => {
        setIsLoading(true);
        try {
            const data = await aiChatService.getMessages(id);
            setMessages(data);
        } catch (error) {
            console.error("Failed to load messages:", error);
            toast.error("Failed to load messages");
        } finally {
            setIsLoading(false);
        }
    };

    const handleNewChat = () => {
        setCurrentConversation(null);
        setMessages([]);
        setSearchParams({});
    };

    const handleDeleteConversation = async (id: string) => {
        try {
            await aiChatService.deleteConversation(id);
            setConversations(prev => prev.filter(c => c.id !== id));
            if (currentConversation?.id === id) {
                handleNewChat();
            }
            knowledgeService.deleteKnowledgeNode(id);
            toast.success("Conversation deleted");
        } catch (error) {
            toast.error("Failed to delete conversation");
        }
    };

    const handleUpdateTitle = (id: string, newTitle: string) => {
        setConversations(prev => prev.map(c => c.id === id ? { ...c, title: newTitle } : c));
        if (currentConversation?.id === id) {
            setCurrentConversation(prev => prev ? { ...prev, title: newTitle } : null);
        }
    };

    const handleTogglePin = async (id: string) => {
        try {
            const newPinnedStatus = await aiChatService.togglePin(id);
            setConversations(prev => {
                const updated = prev.map(c => c.id === id ? { ...c, is_pinned: newPinnedStatus } : c);
                return [...updated].sort((a, b) => {
                    if (a.is_pinned && !b.is_pinned) return -1;
                    if (!a.is_pinned && b.is_pinned) return 1;
                    return new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime();
                });
            });
        } catch (error) {
            toast.error("Failed to pin conversation");
        }
    };

    const handleToggleShare = async (id: string) => {
        try {
            const shareToken = await aiChatService.toggleShare(id);
            setConversations(prev => prev.map(c => c.id === id ? { ...c, share_token: shareToken || undefined } : c));
        } catch (error) {
            toast.error("Failed to update sharing settings");
        }
    };

    const handleCopyShareLink = (shareToken: string) => {
        const shareUrl = `${window.location.origin}/ai-chat/share/${shareToken}`;
        navigator.clipboard.writeText(shareUrl);
        toast.info("Share link copied to clipboard", {
            icon: <Link className="h-4 w-4" />,
            duration: 2000
        });
    };

    const handleToggleTemporaryMode = () => {
        const nextMode = !isTemporaryMode;
        setIsTemporaryMode(nextMode);

        // Always start fresh when toggling mode to ensure privacy/new session
        setCurrentConversation(null);
        setMessages([]);
        setSearchParams({});
    };

    const handleUpdateMessage = async (id: string, newContent: string) => {
        try {
            await aiChatService.updateMessage(id, newContent);

            // Find the index of the edited message
            const messageIndex = messages.findIndex(m => m.id === id);
            if (messageIndex === -1) return;

            // Keep only messages up to the edited one
            const updatedMessages = messages.slice(0, messageIndex + 1).map(m =>
                m.id === id ? { ...m, content: newContent } : m
            );

            setMessages(updatedMessages);

            // If it's a user message, trigger regeneration
            if (updatedMessages[updatedMessages.length - 1].role === 'user') {
                await regenerateAIResponse(updatedMessages);
            }
        } catch (error) {
            console.error("Failed to update message:", error);
            toast.error("Failed to update message");
        }
    };

    const regenerateAIResponse = async (historyMessages: AIChatMessage[]) => {
        if (!currentConversation) return;

        try {
            setIsLoading(true);
            setIsStreaming(true);
            setStreamingMessage("");

            const history = [
                { role: 'system', content: 'You are EduSpace Assistant, a helpful and professional academic assistant. You help students with their studies, assignments, and questions about the platform. Provide clear, accurate, and supportive answers.' },
                ...historyMessages.map(m => ({
                    role: m.role,
                    content: m.content
                }))
            ];

            const fullAIContent = await aiChatService.streamChat(history, (token) => {
                setStreamingMessage(prev => prev + token);
            });

            const assistantMsg = await aiChatService.saveMessage(currentConversation.id, 'assistant', fullAIContent);
            setMessages(prev => [...prev, assistantMsg]);
            setStreamingMessage("");

            // Update Knowledge Map
            knowledgeService.upsertKnowledgeNode({
                type: 'chat',
                sourceId: currentConversation.id,
                label: currentConversation.title,
                text: `${messages[messages.length - 1]?.content}\n${fullAIContent}`
            });
        } catch (error: any) {
            toast.error(error.message || "Regeneration failed");
        } finally {
            setIsLoading(false);
            setIsStreaming(false);
        }
    };

    const { recordAcademicAction } = useStreak();

    const handleSendMessage = async (content: string, imageUrl?: string) => {
        let conversationId = currentConversation?.id;

        try {
            // Record academic action
            if (userProfile?.role === 'student') {
                recordAcademicAction();
            }
            setIsLoading(true);

            // Construct content for user message
            const messageContent: string | MessageContent[] = imageUrl ? [
                { type: 'text', text: content || "What is in this image?" },
                { type: 'image_url', image_url: { url: imageUrl } }
            ] : content;

            if (isTemporaryMode) {
                // Temporary Mode: Skip DB logic
                const userMsg: AIChatMessage = {
                    id: crypto.randomUUID(),
                    conversation_id: 'temporary',
                    role: 'user',
                    content: messageContent,
                    created_at: new Date().toISOString()
                };
                setMessages(prev => [...prev, userMsg]);

                setIsStreaming(true);
                setStreamingMessage("");

                const history = [
                    { role: 'system', content: 'You are EduSpace Assistant in Temporary Mode. Nothing you say here will be saved or stored in history. Help the user with their quick task.' },
                    ...messages.map(m => ({ role: m.role, content: m.content })),
                    { role: 'user', content: messageContent }
                ];

                const fullAIContent = await aiChatService.streamChat(history, (token) => {
                    setStreamingMessage(prev => prev + token);
                });

                const assistantMsg: AIChatMessage = {
                    id: crypto.randomUUID(),
                    conversation_id: 'temporary',
                    role: 'assistant',
                    content: fullAIContent,
                    created_at: new Date().toISOString()
                };
                setMessages(prev => [...prev, assistantMsg]);
                setStreamingMessage("");
                return;
            }

            // Normal Mode: standard saving logic
            // 1. Create conversation if not exists
            if (!conversationId) {
                const newConv = await aiChatService.createConversation(content.substring(0, 40) || (imageUrl ? "Image Analysis" : "New Chat"));
                conversationId = newConv.id;
                setCurrentConversation(newConv);
                setConversations(prev => [newConv, ...prev]);
                setSearchParams({ id: newConv.id });
            }

            // 2. Save user message
            const userMsg = await aiChatService.saveMessage(conversationId, 'user', messageContent);
            setMessages(prev => {
                if (prev.some(m => m.id === userMsg.id)) return prev;
                return [...prev, userMsg];
            });

            // 3. Start streaming
            setIsStreaming(true);
            setStreamingMessage("");

            const history = [
                { role: 'system', content: 'You are EduSpace Assistant, a helpful and professional academic assistant. You help students with their studies, assignments, and questions about the platform. Provide clear, accurate, and supportive answers.' },
                ...messages.map(m => ({ role: m.role, content: m.content })),
                { role: 'user', content: messageContent }
            ];

            const fullAIContent = await aiChatService.streamChat(history, (token) => {
                setStreamingMessage(prev => prev + token);
            });

            // 4. Save assistant message
            const assistantMsg = await aiChatService.saveMessage(conversationId, 'assistant', fullAIContent);
            setMessages(prev => {
                if (prev.some(m => m.id === assistantMsg.id)) return prev;
                return [...prev, assistantMsg];
            });
            setStreamingMessage("");

            // Update Knowledge Map
            knowledgeService.upsertKnowledgeNode({
                type: 'chat',
                sourceId: conversationId,
                label: currentConversation?.title || content.substring(0, 40),
                text: `${content}\n${fullAIContent}`
            });

            loadConversations();

        } catch (error: any) {
            console.error("Chat error:", error);
            toast.error(error.message || "Something went wrong");
        } finally {
            setIsLoading(false);
            setIsStreaming(false);
        }
    };

    if (isInitialLoading) {
        return <AIChatSkeleton />;
    }

    return (
        <div className="flex h-full overflow-hidden bg-background relative">
            {/* Mobile Sidebar Overlay - Local to this container */}
            <AnimatePresence>
                {isMobileMenuOpen && (
                    <>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="absolute inset-0 bg-background/60 backdrop-blur-sm z-40 md:hidden"
                        />
                        <motion.div
                            initial={{ x: "-100%" }}
                            animate={{ x: 0 }}
                            exit={{ x: "-100%" }}
                            transition={{ type: "spring", damping: 25, stiffness: 200 }}
                            className="absolute inset-y-0 left-0 w-[280px] max-w-[85vw] bg-card z-50 md:hidden border-r border-border/40 shadow-2xl"
                        >
                            <AIChatSidebar
                                conversations={conversations}
                                currentConversationId={currentConversation?.id}
                                onSelectConversation={(id) => {
                                    setSearchParams({ id });
                                    setIsMobileMenuOpen(false);
                                }}
                                onNewChat={() => {
                                    handleNewChat();
                                    setIsMobileMenuOpen(false);
                                }}
                                onDeleteConversation={handleDeleteConversation}
                                onUpdateTitle={handleUpdateTitle}
                                onTogglePin={handleTogglePin}
                                onToggleShare={handleToggleShare}
                                onCopyShareLink={handleCopyShareLink}
                                onClose={() => setIsMobileMenuOpen(false)}
                                isLoading={isInitialLoading}
                            />
                        </motion.div>
                    </>
                )}
            </AnimatePresence>

            {/* Sidebar - Desktop */}
            <div className="hidden md:block w-72 shrink-0 h-full border-r border-border/40 bg-card/10">
                <AIChatSidebar
                    conversations={conversations}
                    currentConversationId={currentConversation?.id}
                    onSelectConversation={(id) => setSearchParams({ id })}
                    onNewChat={handleNewChat}
                    onDeleteConversation={handleDeleteConversation}
                    onUpdateTitle={handleUpdateTitle}
                    onTogglePin={handleTogglePin}
                    onToggleShare={handleToggleShare}
                    onCopyShareLink={handleCopyShareLink}
                    isLoading={isInitialLoading}
                />
            </div>

            {/* Main Chat Area */}
            <div className="flex-1 flex flex-col relative h-full overflow-hidden">
                {/* Chat Header */}
                <div className="min-h-16 shrink-0 border-b border-border/40 bg-background/50 backdrop-blur-md flex items-center justify-between px-4 md:px-6 z-30 pt-[var(--safe-top)]">
                    <div className="flex items-center gap-2 md:gap-3">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="md:hidden -ml-2 h-9 w-9"
                            onClick={() => setIsMobileMenuOpen(true)}
                        >
                            <Menu className="h-5 w-5" />
                        </Button>

                        <div className="size-9 rounded-xl overflow-hidden border border-border/60 shadow-lg shrink-0">
                            <img src="/favicon.png" alt="Eduspace Logo" className="size-full object-cover" />
                        </div>
                        <div>
                            <h2 className="text-xs md:text-sm font-bold tracking-tight text-foreground/90 truncate max-w-[150px] md:max-w-none leading-none">
                                {isTemporaryMode ? "Temporary Chat" : (currentConversation?.title || "AI Tutor Assistant")}
                            </h2>
                            {isTemporaryMode && (
                                <div className="flex items-center gap-1.5 mt-1 leading-none">
                                    <MessageCircleDashed className="h-2.5 w-2.5 text-amber-500 animate-pulse" />
                                    <span className="text-[10px] text-amber-500/80 font-bold uppercase tracking-wider">Off Record</span>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={handleToggleTemporaryMode}
                            className={cn(
                                "h-9 w-9 rounded-xl border transition-all",
                                isTemporaryMode
                                    ? "bg-amber-500/10 border-amber-500/30 text-amber-500 hover:bg-amber-500/20 shadow-sm"
                                    : "text-muted-foreground hover:bg-muted/50 border-transparent"
                            )}
                            title={isTemporaryMode ? "Temporary Chat On" : "Start Temporary Chat"}
                        >
                            {isTemporaryMode ? (
                                <MessageCircleDashed className="h-4 w-4 animate-pulse" />
                            ) : (
                                <MessageCircle className="h-4 w-4" />
                            )}
                        </Button>
                    </div>
                </div>

                <ScrollArea className="flex-1" viewportRef={scrollAreaRef as any}>
                    <div className="max-w-4xl mx-auto w-full min-h-full">
                        {isLoading && messages.length === 0 ? (
                            <MessagesSkeleton />
                        ) : messages.length === 0 && !isStreaming ? (
                            <div className="min-h-[70vh] flex flex-col items-center justify-center p-8 text-center space-y-12">
                                <motion.div
                                    initial={{ scale: 0.9, opacity: 0 }}
                                    animate={{ scale: 1, opacity: 1 }}
                                    className="relative"
                                >
                                    <div className="absolute -inset-4 bg-gradient-to-br from-indigo-500/20 to-purple-600/20 rounded-full blur-2xl animate-pulse" />
                                    <div className="relative h-24 w-24 rounded-3xl overflow-hidden border border-border shadow-2xl mx-auto">
                                        <img src="/favicon.png" alt="Eduspace Logo" className="size-full object-cover" />
                                    </div>
                                </motion.div>

                                <div className="space-y-6 max-w-2xl mx-auto">
                                    <h1 className="text-3xl md:text-5xl font-black tracking-tight text-foreground leading-[1.1] min-h-[3.3em] flex flex-wrap justify-center items-center">
                                        <span className="text-secondary-foreground">{displayText.split(' ').slice(0, -2).join(' ')} </span>
                                        <span className="text-primary ml-2">
                                            {displayText.split(' ').slice(-2).join(' ')}
                                            <span className="inline-block w-1.5 h-8 md:h-12 bg-primary/40 ml-1 animate-pulse align-middle" />
                                        </span>
                                    </h1>
                                </div>

                                <div className="w-full max-w-2xl px-6 mx-auto">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4">
                                        {[
                                            { label: "Summarize notes", icon: "📝", desc: "Get key takeaways" },
                                            { label: "Explain concepts", icon: "⚛️", desc: "Simplify complex topics" },
                                            { label: "Brainstorm ideas", icon: "💡", desc: "Get creative help" },
                                        ].map((item, i) => (
                                            <motion.button
                                                key={i}
                                                initial={{ opacity: 0, y: 20 }}
                                                animate={{ opacity: 1, y: 0 }}
                                                transition={{ delay: 0.2 + i * 0.1 }}
                                                onClick={() => handleSendMessage(item.label)}
                                                className="group flex md:flex-col items-center md:items-start gap-4 p-4 rounded-2xl border border-border/40 bg-card/40 hover:bg-primary/5 hover:border-primary/30 transition-all text-left shadow-sm hover:shadow-md"
                                            >
                                                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-primary/10 text-xl group-hover:scale-110 transition-transform">
                                                    {item.icon}
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-sm font-bold text-foreground/80 group-hover:text-primary transition-colors">
                                                        {item.label}
                                                    </p>
                                                    <p className="hidden md:block text-[11px] font-medium text-muted-foreground mt-1">
                                                        {item.desc}
                                                    </p>
                                                </div>
                                                <ChevronRight className="h-4 w-4 text-muted-foreground/30 md:hidden" />
                                            </motion.button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="pb-32 md:pb-48 px-4 pt-4">
                                <AnimatePresence initial={false}>
                                    {messages.map((msg) => (
                                        <motion.div
                                            key={msg.id}
                                            initial={{ opacity: 0 }}
                                            animate={{ opacity: 1 }}
                                        >
                                            <AIMessage
                                                messageId={msg.id}
                                                role={msg.role}
                                                content={msg.content}
                                                profile={userProfile || undefined}
                                                onUpdateMessage={handleUpdateMessage}
                                            />
                                        </motion.div>
                                    ))}
                                    {isStreaming && (
                                        <motion.div
                                            key="streaming-message"
                                            initial={{ opacity: 0 }}
                                            animate={{ opacity: 1 }}
                                        >
                                            <AIMessage role="assistant" content={streamingMessage} />
                                        </motion.div>
                                    )}
                                </AnimatePresence>

                                {isLoading && !isStreaming && (
                                    <div className="p-8 flex justify-center">
                                        <div className="flex items-center gap-3 px-4 py-2 bg-muted/50 rounded-full border border-border/40 animate-pulse">
                                            <Loader2 className="h-4 w-4 animate-spin text-primary" />
                                            <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">AI is processing...</span>
                                        </div>
                                    </div>
                                )}
                                <div ref={lastMessageRef} className="h-4" />
                            </div>
                        )}
                    </div>
                </ScrollArea>

                <div className="absolute inset-x-0 bottom-0 pointer-events-none z-20">
                    <div className="h-32 bg-gradient-to-t from-background via-background/90 to-transparent" />
                    <div className="bg-background pb-4 md:pb-6 pt-2 px-4 md:px-6 pointer-events-auto">
                        <div className="max-w-4xl mx-auto">
                            <AIChatInput onSendMessage={handleSendMessage} isLoading={isLoading || isStreaming} />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { MessageRole, MessageContent } from "@/lib/aiChatService";
import { cn } from "@/lib/utils";
import { User, Bot, Sparkles, Copy, Check, Pencil, X } from "lucide-react";
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useState, useRef, useEffect } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";

interface AIMessageProps {
    messageId?: string;
    role: MessageRole;
    content: string | MessageContent[];
    profile?: {
        full_name?: string;
        avatar_url?: string;
    };
    onUpdateMessage?: (id: string, newContent: string) => void;
    isReadOnly?: boolean;
}

export function AIMessage({ messageId, role, content, profile, onUpdateMessage, isReadOnly }: AIMessageProps) {
    const [copied, setCopied] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [editValue, setEditValue] = useState(typeof content === 'string' ? content : '');
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const isAssistant = role === 'assistant';

    const getRawText = (c: string | MessageContent[]): string => {
        if (typeof c === 'string') return c;
        return c.map(item => item.type === 'text' ? item.text : '').join(' ');
    };

    const rawText = getRawText(content);

    const processedText = isAssistant
        ? rawText.replace(/<think>[\s\S]*?<\/think>/gi, '').replace(/<think>[\s\S]*$/gi, '').trim()
        : rawText;

    const handleCopy = () => {
        navigator.clipboard.writeText(processedText);
        setCopied(true);
        toast.success("Copied to clipboard");
        setTimeout(() => setCopied(false), 2000);
    };

    const handleSave = () => {
        if (!editValue.trim() || editValue === content) {
            setIsEditing(false);
            return;
        }
        if (messageId && onUpdateMessage) {
            onUpdateMessage(messageId, editValue.trim());
        }
        setIsEditing(false);
    };

    useEffect(() => {
        if (isEditing && textareaRef.current) {
            textareaRef.current.style.height = 'auto';
            textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
            textareaRef.current.focus();
        }
    }, [isEditing]);

    return (
        <div className={cn(
            "group w-full py-6 md:py-8 transition-all duration-300 relative",
            isAssistant ? "bg-accent/5 md:bg-accent/10" : "bg-transparent"
        )}>
            <div className="max-w-4xl mx-auto px-4 md:px-6 flex gap-3 md:gap-6">
                <div className="shrink-0 pt-1">
                    {isAssistant ? (
                        <Avatar className="h-10 w-10 rounded-2xl border border-border/40 shadow-lg ring-1 ring-white/10">
                            <AvatarImage src="/favicon.png" className="object-cover" />
                            <AvatarFallback className="bg-gradient-to-br from-indigo-500 to-purple-600 text-white rounded-2xl">
                                <Sparkles className="h-5 w-5" />
                            </AvatarFallback>
                        </Avatar>
                    ) : (
                        <Avatar className="h-10 w-10 rounded-2xl border border-border/40 shadow-sm ring-1 ring-black/5">
                            <AvatarImage src={profile?.avatar_url || ''} />
                            <AvatarFallback className="bg-muted text-muted-foreground rounded-2xl">
                                {profile?.full_name?.charAt(0) || <User className="h-5 w-5" />}
                            </AvatarFallback>
                        </Avatar>
                    )}
                </div>

                <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-[11px] font-black uppercase tracking-[0.15em] text-foreground/80">
                            {isAssistant ? "EduSpace AI" : (profile?.full_name || "You")}
                        </span>

                        <div className="flex items-center gap-1">
                            {!isAssistant && !isEditing && !isReadOnly && (
                                <Button
                                    size="icon"
                                    variant="ghost"
                                    onClick={() => setIsEditing(true)}
                                    className="h-8 w-8 opacity-30 md:opacity-0 md:group-hover:opacity-100 transition-opacity duration-200 rounded-lg hover:bg-background/80"
                                >
                                    <Pencil className="h-3.5 w-3.5 text-muted-foreground" />
                                </Button>
                            )}
                            {!isEditing && (
                                <Button
                                    size="icon"
                                    variant="ghost"
                                    onClick={handleCopy}
                                    className="h-8 w-8 opacity-30 md:opacity-0 md:group-hover:opacity-100 transition-opacity duration-200 rounded-lg hover:bg-background/80"
                                >
                                    {copied ? (
                                        <Check className="h-3.5 w-3.5 text-emerald-500" />
                                    ) : (
                                        <Copy className="h-3.5 w-3.5 text-muted-foreground" />
                                    )}
                                </Button>
                            )}
                        </div>
                    </div>

                    {isEditing ? (
                        <div className="space-y-3">
                            <Textarea
                                ref={textareaRef}
                                value={editValue}
                                onChange={(e) => {
                                    setEditValue(e.target.value);
                                    e.target.style.height = 'auto';
                                    e.target.style.height = `${e.target.scrollHeight}px`;
                                }}
                                className="min-h-[60px] w-full resize-none bg-background/50 border-primary/20 text-sm font-medium focus-visible:ring-primary/20"
                            />
                            <div className="flex items-center gap-2">
                                <Button
                                    size="sm"
                                    onClick={handleSave}
                                    className="h-8 px-4 rounded-lg bg-primary text-primary-foreground font-bold text-xs flex items-center gap-2 transition-all hover:bg-primary/90 hover:shadow-lg active:scale-95"
                                >
                                    <span>Save & Send</span>
                                    <Sparkles className="h-3 w-3" />
                                </Button>
                                <Button
                                    size="sm"
                                    variant="ghost"
                                    onClick={() => {
                                        setIsEditing(false);
                                        setEditValue(rawText);
                                    }}
                                    className="h-8 px-4 rounded-lg text-xs font-bold"
                                >
                                    Cancel
                                </Button>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {Array.isArray(content) ? (
                                content.map((part, i) => (
                                    <div key={i}>
                                        {part.type === 'text' && (
                                            <div className={cn(
                                                "prose prose-sm dark:prose-invert max-w-none text-foreground/90 leading-relaxed font-medium",
                                                "prose-p:mb-4 last:prose-p:mb-0",
                                                "prose-pre:bg-[#1a1a1a] prose-pre:border prose-pre:border-white/5 prose-pre:rounded-2xl"
                                            )}>
                                                <ReactMarkdown
                                                    components={{
                                                        code({ node, inline, className, children, ...props }: any) {
                                                            const match = /language-(\w+)/.exec(className || '');
                                                            return !inline && match ? (
                                                                <div className="relative group/code my-6 rounded-2xl overflow-hidden border border-white/5 shadow-2xl">
                                                                    <div className="flex items-center justify-between px-4 py-2 bg-white/5 border-b border-white/5">
                                                                        <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                                                                            {match[1]}
                                                                        </span>
                                                                        <div className="flex gap-1.5">
                                                                            <div className="w-2.5 h-2.5 rounded-full bg-rose-500/20" />
                                                                            <div className="w-2.5 h-2.5 rounded-full bg-amber-500/20" />
                                                                            <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/20" />
                                                                        </div>
                                                                    </div>
                                                                    <SyntaxHighlighter
                                                                        style={vscDarkPlus as any}
                                                                        language={match[1]}
                                                                        PreTag="div"
                                                                        className="!bg-transparent !p-5 !m-0 font-mono text-sm leading-relaxed"
                                                                        {...props}
                                                                    >
                                                                        {String(children).replace(/\n$/, '')}
                                                                    </SyntaxHighlighter>
                                                                </div>
                                                            ) : (
                                                                <code className={cn("bg-muted/50 px-1.5 py-0.5 rounded-md text-primary font-mono text-xs border border-border/20", className)} {...props}>
                                                                    {children}
                                                                </code>
                                                            );
                                                        }
                                                    }}
                                                >
                                                    {part.text || ''}
                                                </ReactMarkdown>
                                            </div>
                                        )}
                                        {part.type === 'image_url' && (
                                            <div className="my-4 max-w-lg">
                                                <div className="rounded-2xl overflow-hidden border border-border/40 shadow-xl ring-1 ring-black/5">
                                                    <img src={part.image_url?.url} alt="Uploaded content" className="w-full h-auto object-cover" />
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                ))
                            ) : (
                                <div className={cn(
                                    "prose prose-sm dark:prose-invert max-w-none text-foreground/90 leading-relaxed font-medium",
                                    "prose-p:mb-4 last:prose-p:mb-0",
                                    "prose-pre:bg-[#1a1a1a] prose-pre:border prose-pre:border-white/5 prose-pre:rounded-2xl"
                                )}>
                                    <ReactMarkdown
                                        components={{
                                            code({ node, inline, className, children, ...props }: any) {
                                                const match = /language-(\w+)/.exec(className || '');
                                                return !inline && match ? (
                                                    <div className="relative group/code my-6 rounded-2xl overflow-hidden border border-white/5 shadow-2xl">
                                                        <div className="flex items-center justify-between px-4 py-2 bg-white/5 border-b border-white/5">
                                                            <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                                                                {match[1]}
                                                            </span>
                                                            <div className="flex gap-1.5">
                                                                <div className="w-2.5 h-2.5 rounded-full bg-rose-500/20" />
                                                                <div className="w-2.5 h-2.5 rounded-full bg-amber-500/20" />
                                                                <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/20" />
                                                            </div>
                                                        </div>
                                                        <SyntaxHighlighter
                                                            style={vscDarkPlus as any}
                                                            language={match[1]}
                                                            PreTag="div"
                                                            className="!bg-transparent !p-5 !m-0 font-mono text-sm leading-relaxed"
                                                            {...props}
                                                        >
                                                            {String(children).replace(/\n$/, '')}
                                                        </SyntaxHighlighter>
                                                    </div>
                                                ) : (
                                                    <code className={cn("bg-muted/50 px-1.5 py-0.5 rounded-md text-primary font-mono text-xs border border-border/20", className)} {...props}>
                                                        {children}
                                                    </code>
                                                );
                                            }
                                        }}
                                    >
                                        {processedText}
                                    </ReactMarkdown>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Subtle separator for "manual" feel */}
            <div className="absolute bottom-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-border/10 to-transparent" />
        </div>
    );
}

import { useState } from "react";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Mail, MessageSquare, Send, CheckCircle2, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";

interface ContactSupportDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export function ContactSupportDialog({ open, onOpenChange }: ContactSupportDialogProps) {
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        subject: "",
        message: "",
    });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSubmitted, setIsSubmitted] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!formData.name || !formData.email || !formData.subject || !formData.message) {
            toast.error("Please fill in all fields");
            return;
        }

        setIsSubmitting(true);
        try {
            const { error: fnError } = await supabase.functions.invoke('contact-support', {
                body: {
                    name: formData.name,
                    email: formData.email,
                    subject: formData.subject,
                    message: formData.message,
                },
            });

            if (fnError) throw fnError;

            setIsSubmitting(false);
            setIsSubmitted(true);
            toast.success("Support request sent successfully!");

            // Reset form after 3 seconds
            setTimeout(() => {
                setIsSubmitted(false);
                setFormData({ name: "", email: "", subject: "", message: "" });
                onOpenChange(false);
            }, 3000);

        } catch (error: any) {
            console.error('FAILED...', error);
            toast.error("Failed to send message. Please ensure you are connected to the internet.");
            setIsSubmitting(false);
        }

    };

    const handleChange = (field: string) => (
        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    ) => {
        setFormData(prev => ({ ...prev, [field]: e.target.value }));
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[900px] p-0 overflow-hidden bg-background border-border max-h-[85vh] overflow-y-auto">
                <div className="flex flex-col-reverse md:flex-row h-full">
                    {/* Left Panel - Contact Information */}
                    <div className="w-full md:w-2/5 bg-slate-900 p-6 md:p-8 text-white flex flex-col justify-between relative overflow-hidden shrink-0">
                        {/* Background Decoration */}
                        <div className="absolute top-0 right-0 p-12 opacity-10 hidden md:block">
                            <MessageSquare className="size-64 text-white transform translate-x-1/3 -translate-y-1/3" />
                        </div>

                        <div className="relative z-10 space-y-6">
                            <div>
                                <h3 className="text-xl md:text-2xl font-bold mb-2">Contact Information</h3>
                                <p className="text-slate-300 text-sm md:text-base">
                                    Fill up the form and our team will get back to you within 24 hours.
                                </p>
                            </div>

                            <div className="space-y-4 md:space-y-6 mt-4 md:mt-8">
                                <div className="flex items-start gap-4">
                                    <div className="p-2 bg-white/10 rounded-lg shrink-0">
                                        <Mail className="size-4 md:size-5 text-blue-400" />
                                    </div>
                                    <div>
                                        <div className="font-medium text-blue-200 text-xs md:text-sm mb-1">Email</div>
                                        <div className="text-sm">eduspacelearning8@gmail.com</div>
                                    </div>
                                </div>

                                <div className="flex items-start gap-4">
                                    <div className="p-2 bg-white/10 rounded-lg shrink-0">
                                        <MessageSquare className="size-4 md:size-5 text-purple-400" />
                                    </div>
                                    <div>
                                        <div className="font-medium text-purple-200 text-xs md:text-sm mb-1">Phone</div>
                                        <div className="text-xs md:text-sm">+91 7670895485</div>
                                    </div>
                                </div>

                                <div className="flex items-start gap-4">
                                    <div className="p-2 bg-white/10 rounded-lg shrink-0">
                                        <MessageSquare className="size-4 md:size-5 text-indigo-400" />
                                    </div>
                                    <div>
                                        <div className="font-medium text-indigo-200 text-xs md:text-sm mb-1">Address</div>
                                        <div className="text-xs md:text-sm leading-relaxed text-slate-300">
                                            1-194, Mannam Bazar, SN Padu Mandal, Endluru, Prakasam District,<br />
                                            Andhra Pradesh - 523225, India
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Bottom Decoration */}
                        <div className="relative z-10 mt-8 md:mt-12 hidden md:block">
                            <div className="flex gap-4">
                                <div className="size-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/20 transition-colors cursor-pointer">
                                    <MessageSquare className="size-4" />
                                </div>
                                <div className="size-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/20 transition-colors cursor-pointer">
                                    <Mail className="size-4" />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Right Panel - Form */}
                    <div className="w-full md:w-3/5 p-8 bg-background">
                        <DialogHeader className="mb-6 text-left">
                            <DialogTitle className="text-2xl font-bold text-foreground">Get in Touch</DialogTitle>
                            <DialogDescription>
                                We'd love to hear from you. Please fill out this form.
                            </DialogDescription>
                        </DialogHeader>

                        {isSubmitted ? (
                            <div className="flex flex-col items-center justify-center py-12 space-y-4 h-[400px]">
                                <div className="p-4 rounded-full bg-green-100 dark:bg-green-900/20 animate-in zoom-in duration-300">
                                    <CheckCircle2 className="size-12 text-green-600 dark:text-green-400" />
                                </div>
                                <div className="text-center space-y-2">
                                    <h3 className="text-xl font-semibold text-foreground">Request Submitted!</h3>
                                    <p className="text-muted-foreground max-w-xs mx-auto">
                                        Thank you for contacting us. We'll be in touch shortly.
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <form onSubmit={handleSubmit} className="space-y-5">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="name">Name</Label>
                                        <Input
                                            id="name"
                                            placeholder="John Doe"
                                            value={formData.name}
                                            onChange={handleChange("name")}
                                            disabled={isSubmitting}
                                            className="bg-background border-border focus:ring-blue-500"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="email">Email</Label>
                                        <Input
                                            id="email"
                                            type="email"
                                            placeholder="john@example.com"
                                            value={formData.email}
                                            onChange={handleChange("email")}
                                            disabled={isSubmitting}
                                            className="bg-background border-border focus:ring-blue-500"
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="subject">Subject</Label>
                                    <Input
                                        id="subject"
                                        placeholder="How can we help?"
                                        value={formData.subject}
                                        onChange={handleChange("subject")}
                                        disabled={isSubmitting}
                                        className="bg-background border-border focus:ring-blue-500"
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="message">Message</Label>
                                    <Textarea
                                        id="message"
                                        placeholder="Tell us more about your inquiry..."
                                        className="min-h-[120px] resize-none bg-background border-border focus:ring-blue-500"
                                        value={formData.message}
                                        onChange={handleChange("message")}
                                        disabled={isSubmitting}
                                    />
                                </div>

                                <div className="pt-2 flex gap-3 justify-end">
                                    <Button
                                        type="button"
                                        variant="ghost"
                                        onClick={() => onOpenChange(false)}
                                        disabled={isSubmitting}
                                        className="text-muted-foreground hover:text-foreground"
                                    >
                                        Cancel
                                    </Button>
                                    <Button
                                        type="submit"
                                        disabled={isSubmitting}
                                        className="min-w-[140px]"
                                    >
                                        {isSubmitting ? (
                                            <>
                                                <Loader2 className="size-4 animate-spin mr-2" />
                                                Sending...
                                            </>
                                        ) : (
                                            <>
                                                Send Message
                                                <Send className="size-4 ml-2" />
                                            </>
                                        )}
                                    </Button>
                                </div>
                            </form>
                        )}
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";
import { cn } from "@/lib/utils";
import { useEffect, useRef, useState } from "react";

export const BackgroundGradientAnimation = ({
    gradientBackgroundStart = "rgb(108, 0, 162)",
    gradientBackgroundEnd = "rgb(0, 17, 82)",
    firstColor = "18, 113, 255",
    secondColor = "221, 74, 255",
    thirdColor = "100, 220, 255",
    fourthColor = "200, 50, 50",
    fifthColor = "180, 180, 50",
    pointerColor = "140, 100, 255",
    size = "80%",
    blendingValue = "hard-light",
    children,
    className,
    interactive = true,
    containerClassName,
}: {
    gradientBackgroundStart?: string;
    gradientBackgroundEnd?: string;
    firstColor?: string;
    secondColor?: string;
    thirdColor?: string;
    fourthColor?: string;
    fifthColor?: string;
    pointerColor?: string;
    size?: string;
    blendingValue?: string;
    children?: React.ReactNode;
    className?: string;
    interactive?: boolean;
    containerClassName?: string;
}) => {
    const interactiveRef = useRef<HTMLDivElement>(null);

    const [curX, setCurX] = useState(0);
    const [curY, setCurY] = useState(0);
    const [tgX, setTgX] = useState(0);
    const [tgY, setTgY] = useState(0);
    useEffect(() => {
        document.body.style.setProperty(
            "--gradient-background-start",
            gradientBackgroundStart
        );
        document.body.style.setProperty(
            "--gradient-background-end",
            gradientBackgroundEnd
        );
