  credits_required: number | null;
  advisor: string | null;
  enrollment_date: string | null;
  expected_graduation: string | null;
  avatar_url: string | null;
  street: string | null;
  city: string | null;
  state: string | null;
  zip_code: string | null;
  country: string | null;
  cover_url: string | null;
  linkedin_url: string | null;
  github_url: string | null;
  twitter_url: string | null;
  portfolio_url: string | null;
  verified: boolean | null;
  fcm_token: string | null; // Added
  email_notifications: boolean | null;
  push_notifications: boolean | null;
  sms_notifications: boolean | null;
  assignment_reminders: boolean | null;
  message_notifications: boolean | null; // Added
  grade_updates: boolean | null;
  course_announcements: boolean | null;
  weekly_digest: boolean | null;
  notifications_enabled: boolean | null;
  batch: string | null; // Added
  hod_name: string | null; // Added
  language: string | null;
  timezone: string | null;
  theme: string | null;
  sidebar_mode: 'expanded' | 'collapsed' | 'hover' | null;
  last_selected_class_id: string | null;
  active_call: {
    type: 'audio' | 'video';
    conversationId: string;
    isMeeting?: boolean;
    userName?: string;
  } | null;
  last_feedback_prompt_at: string | null;
  created_at: string;
  updated_at: string;
}


interface AuthContextType {
  user: User | null;
  session: Session | null;
  profile: Profile | null;
  role: AppRole | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  signIn: (email: string, password: string) => Promise<{ success: boolean; error?: string }>;
  signUp: (email: string, password: string, fullName: string, role: AppRole) => Promise<{ success: boolean; error?: string }>;
  signInWithGoogle: (selectedRole: AppRole) => Promise<{ success: boolean; error?: string }>;
  signInWithNotion: (selectedRole: AppRole) => Promise<{ success: boolean; error?: string }>;
  signInWithGitHub: (selectedRole: AppRole) => Promise<{ success: boolean; error?: string }>;
  signOut: () => Promise<void>;
  updateProfile: (data: Partial<Profile>) => Promise<{ success: boolean; error?: string }>;
  refreshProfile: (userId?: string) => Promise<void>;
  resetPassword: (email: string) => Promise<{ success: boolean; error?: string }>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [role, setRole] = useState<AppRole | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const fetchWithRetry = async <T,>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
    try {
      return await fn();
    } catch (err) {
      if (retries > 0) {
        await new Promise(resolve => setTimeout(resolve, delay));
        return fetchWithRetry(fn, retries - 1, delay * 1.5);
      }
      throw err;
    }
  };

  const fetchProfile = async (userId: string) => {
    return fetchWithRetry(async () => {
      const { data, error } = await supabase
        .from("profiles")
        .select("*")
        .eq("user_id", userId)
        .maybeSingle();

      if (error) {
        console.error("Error fetching profile:", error);
        return null;
      }
      return data as any as Profile | null;
    }).catch(err => {
      console.error("Persistent error fetching profile:", err);
      return null;
    });
  };

  const fetchRole = async (userId: string) => {
    return fetchWithRetry(async () => {
      const { data, error } = await supabase
        .from("user_roles")
        .select("role")
        .eq("user_id", userId)
        .maybeSingle();

      if (error) {
        console.error("Error fetching role:", error);
        return null;
      }
      return data?.role as AppRole | null;
    }).catch(err => {
      console.error("Persistent error fetching role:", err);
      return null;
    });
  };

  const refreshProfile = async (userId?: string) => {
    const targetUserId = userId || user?.id;
    if (targetUserId) {
      const [profileData, userRole] = await Promise.all([
        fetchProfile(targetUserId),
        fetchRole(targetUserId)
      ]);

      // Always update state when we have valid data
      if (userRole !== null) {
        setProfile(profileData);
        setRole(userRole);
      }
    }
  };

  useEffect(() => {
    let mounted = true;

    // 1. Define initialization logic
    const initializeAuth = async () => {
      // Safety timeout: don't let the app stay in loading state forever if Supabase is unreachable
      const timeoutId = setTimeout(() => {
        if (mounted && isLoading) {
          console.warn("Auth initialization timed out after 10s, forcing loading to false.");
          setIsLoading(false);
        }
      }, 10000);

      try {
        const { data: { session } } = await supabase.auth.getSession();

        if (mounted) {
          setSession(session);
          setUser(session?.user ?? null);

          if (session?.user) {
            // Await critical data before unblocking UI to prevent redirects
            await Promise.all([
              fetchProfile(session.user.id).then(d => mounted && setProfile(d)),
              fetchRole(session.user.id).then(d => mounted && setRole(d))
            ]);
          } else {
            console.log("No active session found during initialization.");
          }
        }
      } catch (error) {
        console.error("Auth initialization failed:", error);
      } finally {
        clearTimeout(timeoutId);
        if (mounted) setIsLoading(false);
      }
    };

    // 2. Run initialization
    initializeAuth();

    // 3. Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (!mounted) return;

        console.log("Auth state change:", event);
        setSession(session);
        setUser(session?.user ?? null);

        if (session?.user) {
          // Re-fetch on auth events to ensure freshness
          // Note: using void to not block the event loop, as UI might already be rendered
          void fetchProfile(session.user.id).then(d => mounted && setProfile(d));
          void fetchRole(session.user.id).then(d => mounted && setRole(d));
        } else {
          setProfile(null);
          setRole(null);
        }

        // Ensure loading is false after any auth event
        setIsLoading(false);
      }
    );

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const signIn = async (email: string, password: string) => {
    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error) {
        return { success: false, error: error.message };
      }

      return { success: true };
    } catch (error: any) {
      console.error("Sign in exception:", error);
      return { success: false, error: error.message || "Network error. Please check your connection and try again." };
    }
  };

  const signUp = async (email: string, password: string, fullName: string, selectedRole: AppRole) => {
    try {
      const redirectUrl = `${window.location.origin}/`;

      const { error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: redirectUrl,
          data: {
            full_name: fullName,
            role: selectedRole,
          },
        },
      });

      if (error) {
        if (error.message.includes("already registered")) {
          return { success: false, error: "This email is already registered. Please sign in instead." };
        }
        return { success: false, error: error.message };
      }

      // Trigger Welcome Email (Fire and forget, don't block registration)
      try {
        console.log("📧 Triggering welcome email...");

        supabase.functions.invoke("send-welcome-email", {
          body: {
            email,
            fullName,
            role: selectedRole,
          },
        }).then(({ data, error }) => {
          if (error) console.error("❌ Failed to send welcome email:", error);
          else console.log("✅ Welcome email request sent:", data);
        }).catch(err => {
          console.error("❌ Network error triggering welcome email:", err);
        });
      } catch (err) {
        console.error("Error triggering email function:", err);
      }

      return { success: true };
    } catch (error: any) {
      console.error("Sign up exception:", error);
      return { success: false, error: error.message || "Network error. Please check your connection." };
    }
  };

  const signInWithGoogle = async (selectedRole: AppRole) => {
    try {
      // Store the selected role in localStorage for use after OAuth callback
      localStorage.setItem("pendingRole", selectedRole);
      console.log("🔐 Storing role in localStorage for OAuth:", selectedRole);

      const { error } = await supabase.auth.signInWithOAuth({
        provider: "google",
        options: {
          redirectTo: `${window.location.origin}/auth/callback`,
          queryParams: {
            access_type: "offline",
            prompt: "consent",
          },
        },
      });

      if (error) {
        localStorage.removeItem("pendingRole");
        console.error("❌ OAuth initiation failed:", error.message);
        return { success: false, error: error.message };
      }

      console.log("✅ OAuth initiated successfully, redirecting to Google...");
      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Network error. Please check your connection." };
    }
  };

  const signInWithNotion = async (selectedRole: AppRole) => {
    try {
      // Store the selected role in localStorage for use after OAuth callback
      localStorage.setItem("pendingRole", selectedRole);
      console.log("🔐 Storing role in localStorage for Notion OAuth:", selectedRole);

      const { error } = await supabase.auth.signInWithOAuth({
        provider: "notion",
        options: {
          redirectTo: `${window.location.origin}/auth/callback`,
        },
      });

      if (error) {
        localStorage.removeItem("pendingRole");
        console.error("❌ Notion OAuth initiation failed:", error.message);
        return { success: false, error: error.message };
      }

      console.log("✅ Notion OAuth initiated successfully, redirecting to Notion...");
      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Network error." };
    }
  };

  const signInWithGitHub = async (selectedRole: AppRole) => {
    try {
      // Store the selected role in localStorage for use after OAuth callback
      localStorage.setItem("pendingRole", selectedRole);
      console.log("🔐 Storing role in localStorage for GitHub OAuth:", selectedRole);

      const { error } = await supabase.auth.signInWithOAuth({
        provider: "github",
        options: {
          redirectTo: `${window.location.origin}/auth/callback?role=${selectedRole}`,
          scopes: "user:email",
        },
      });

      if (error) {
        localStorage.removeItem("pendingRole");
        console.error("❌ GitHub OAuth initiation failed:", error.message);
        return { success: false, error: error.message };
      }

      console.log("✅ GitHub OAuth initiated successfully, redirecting to GitHub...");
      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Network error." };
    }
  };

  const signOut = async () => {
    try {
      await supabase.auth.signOut();
    } catch (error) {
      console.error("Sign out error:", error);
    } finally {
      setUser(null);
      setSession(null);
      setProfile(null);
      setRole(null);
    }
  };

  const resetPassword = async (email: string) => {
    try {
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: `${window.location.origin}/update-password`,
      });

      if (error) {
        return { success: false, error: error.message };
      }

      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Network error." };
    }
  };

  const updateProfile = async (data: Partial<Profile>) => {
    if (!user) {
      return { success: false, error: "Not authenticated" };
    }

    try {
      const { error } = await supabase
        .from("profiles")
        .update(data)
        .eq("user_id", user.id);

      if (error) {
        return { success: false, error: error.message };
      }

      // Also sync to public_profiles table for sharing
      // Only pick fields that are safe/meant for public viewing
      const publicData = {
        user_id: user.id,
        full_name: data.full_name,
        avatar_url: data.avatar_url,
        bio: data.bio,
        program: data.program,
        year: data.year,
        department: data.department,
        gpa: data.gpa,
        credits_completed: data.credits_completed,
        credits_required: data.credits_required,
        expected_graduation: data.expected_graduation,
        email: data.email,
        phone: data.phone,
        city: data.city,
        country: data.country,
        cover_url: data.cover_url,
        linkedin_url: data.linkedin_url,
        github_url: data.github_url,
        twitter_url: data.twitter_url,
        portfolio_url: data.portfolio_url,
        last_updated: new Date().toISOString()
      };

      // Filter out undefined values to avoid overwriting with null if no change
      const filteredPublicData = Object.fromEntries(
        Object.entries(publicData).filter(([_, v]) => v !== undefined)
      );

      if (Object.keys(filteredPublicData).length > 1) { // More than just user_id
        await supabase
          .from("public_profiles")
          .upsert(filteredPublicData as any, { onConflict: 'user_id' });

      }

      await refreshProfile();
      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Network error. Failed to update profile." };
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        session,
        profile,
        role,
        isAuthenticated: !!user,
        isLoading,
        signIn,
        signUp,
        signInWithGoogle,
        signInWithNotion,
        signInWithGitHub,
        signOut,
        updateProfile,
        refreshProfile,
        resetPassword,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export type CallType = 'audio' | 'video';
export type CallCategory = 'private' | 'meeting';
export type CallStatus = 'idle' | 'calling' | 'ringing' | 'incoming' | 'active' | 'ended';

export interface CallState {
    id?: string;
    type: CallType;
    category: CallCategory;
    conversationId?: string;
    peerId?: string;
    peerName?: string;
    peerAvatar?: string;
    isInitiator: boolean;
    status: CallStatus;
    startTime?: number;
}

interface CallContextType {
    activeCall: CallState | null;
    isMinimized: boolean;
    initiateCall: (peerId: string, peerName: string, peerAvatar: string, type: CallType) => Promise<void>;
    acceptCall: () => void;
    rejectCall: () => void;
    endCall: () => void;
    setMinimized: (minimized: boolean) => void;
    startMeeting: (conversationId: string, meetingName: string, type: CallType) => void;
}

const CallContext = createContext<CallContextType | undefined>(undefined);

export function CallProvider({ children }: { children: React.ReactNode }) {
    const { user, profile } = useAuth();
    const [activeCall, setActiveCall] = useState<CallState | null>(null);
    const [isMinimized, setIsMinimized] = useState(false);
    const channelRef = useRef<any>(null);

    // Unified Session Handler
    const handleSession = async (sessionId: string | null, action: string | null) => {
        if (!sessionId || (activeCall && activeCall.id === sessionId)) return;

        console.log("[CallContext] Checking session:", sessionId, "Action:", action);

        try {
            // Fetch session details from DB
            const { data: session, error } = await supabase
                .from('call_sessions')
                .select(`
                    *,
                    caller:profiles!call_sessions_caller_id_fkey(full_name, avatar_url)
                `)
                .eq('id', sessionId)
                .single();

            if (error || !session) {
                console.error("[CallContext] Failed to fetch session for deep link:", error);
                return;
            }

            console.log("[CallContext] Session fetched successfully. Status:", session.status);

            // Check for stale session (ignore calls older than 5 minutes)
            const sessionTime = new Date(session.created_at).getTime();
            const now = Date.now();
            const fiveMinutes = 5 * 60 * 1000;

            if (now - sessionTime > fiveMinutes && session.status !== 'active') {
                console.warn("[CallContext] Ignoring stale deep link session.");
                return;
            }

            // Only handle if the call is still valid
            const isValidStatus = ['initiated', 'ringing', 'accepted', 'active'].includes(session.status);

            if (isValidStatus) {
                const callState: CallState = {
                    id: session.id,
                    type: session.call_type as CallType,
                    category: 'private',
                    peerId: session.caller_id,
                    peerName: session.caller?.full_name || 'Someone',
                    peerAvatar: session.caller?.avatar_url,
                    isInitiator: false,
                    status: session.status === 'active' || session.status === 'accepted' ? 'active' : 'incoming',
                    startTime: session.status === 'active' ? sessionTime : undefined
                };

                console.log("[CallContext] Setting recovery call state:", callState.status);
                setActiveCall(callState);

                // If the user clicked "Accept"
                if (action === 'accept' && session.status !== 'accepted' && session.status !== 'active') {
                    console.log("[CallContext] Auto-accepting from deep link...");
                    setTimeout(() => {
                        acceptCallFromSession(callState);
                        // Clean up URL
                        if (window.history.pushState) {
                            const newUrl = window.location.protocol + "//" + window.location.host + window.location.pathname;
                            window.history.pushState({ path: newUrl }, '', newUrl);
                        }
                    }, 1500);
                }
            }
        } catch (err) {
            console.error("[CallContext] Critical error in deep link handler:", err);
        }
    };

    // Handle Incoming Call from URL (Deep Linking / Push Notifications)
    useEffect(() => {
        const checkInitialUrl = async () => {
            // CRITICAL: Wait for user AND profile
            if (!user || !profile) return;
            const params = new URLSearchParams(window.location.search);
            handleSession(params.get('session'), params.get('action'));
        };

        checkInitialUrl();

        // Listen for App Resume (Foreground) - Re-check current URL if changed or stale? 
        // Actually simpler to just rely on appUrlOpen for new intents.
        // But if user just minimized and restored, standard resume might trigger check.

        let stateListener: any;
        let urlListener: any;

        const initCapacitor = async () => {
            try {
                const { App } = await import('@capacitor/app');
                stateListener = App.addListener('appStateChange', ({ isActive }) => {
                    if (isActive && user && profile) {
                        // Optional: Re-check window location or just wait for url event
                        const params = new URLSearchParams(window.location.search);
                        if (params.get('session')) {
                            handleSession(params.get('session'), params.get('action'));
                        }
                    }
                });

                // Listen for Deep Links (Custom Scheme / Universal Links)
                urlListener = App.addListener('appUrlOpen', (data) => {
                    console.log("[CallContext] App opened with URL:", data.url);
                    try {
                        // Support both http/https and custom schemes
                        // URL might be "eduspace://call?session=..." or "https://.../?session=..."
                        const urlObj = new URL(data.url);
                        const params = urlObj.searchParams;
                        const sessionId = params.get('session');
                        const action = params.get('action');
                        if (sessionId && user && profile) {
                            handleSession(sessionId, action);
                        }
                    } catch (e) {
                        console.error("Error parsing deep link:", e);
                    }
                });
            } catch (err) {
                console.warn("Capacitor App plugin not available", err);
            }
        };

        initCapacitor();

        return () => {
            if (stateListener) stateListener.then((l: any) => l.remove());
            if (urlListener) urlListener.then((l: any) => l.remove());
        };
    }, [user, profile]); // Depend on profile too

    // Helper for acceptance from deep link
    const acceptCallFromSession = async (call: CallState) => {
        try {
            await supabase
                .from('call_sessions')
                .update({ status: 'accepted', started_at: new Date().toISOString() })
                .eq('id', call.id);

            setActiveCall(prev => prev ? { ...prev, status: 'active', startTime: Date.now() } : null);

            await supabase.channel(`calls:${call.peerId}`).send({
                type: 'broadcast',
                event: 'call:accepted',
                payload: { acceptorId: user?.id, callId: call.id },
            });
        } catch (error) {
            console.error("Error auto-accepting call:", error);
        }
    };

    // Listen for incoming calls via Realtime Broadcast
    useEffect(() => {
        if (!user) return;

        const channel = supabase.channel(`calls:${user.id}`, {
            config: {
                broadcast: { self: false },
            },
        });

        channel
            .on('broadcast', { event: 'call:offer' }, ({ payload }) => {
                if (activeCall) {
                    // Send "busy" message if already in a call
                    channel.send({
                        type: 'broadcast',
                        event: 'call:busy',
                        payload: { callerId: payload.callerId },
                    });
                    return;
                }

                setActiveCall({
                    id: payload.callId,
                    type: payload.type,
                    category: 'private',
                    peerId: payload.callerId,
                    peerName: payload.callerName,
                    peerAvatar: payload.callerAvatar,
                    isInitiator: false,
                    status: 'incoming',
                });
            })
            .on('broadcast', { event: 'call:cancel' }, () => {
                setActiveCall(null);
            })
            .on('broadcast', { event: 'call:accepted' }, ({ payload }) => {
                if (activeCall && activeCall.id === payload.callId) {
                    setActiveCall(prev => prev ? { ...prev, status: 'active', startTime: Date.now() } : null);
                }
            })
            .on('broadcast', { event: 'call:rejected' }, ({ payload }) => {
                if (activeCall && (!payload.callId || activeCall.id === payload.callId)) {
                    toast.error("Call rejected");
                    setActiveCall(null);
                }
            })
            .on('broadcast', { event: 'call:ended' }, ({ payload }) => {
                if (activeCall && activeCall.id === payload.callId) {
                    toast.info("Call ended");
                    setActiveCall(null);
                }
            })
            .on('broadcast', { event: 'call:busy' }, () => {
                toast.error("User is busy");
                setActiveCall(null);
            })
            .subscribe();

        channelRef.current = channel;

        return () => {
            channel.unsubscribe();
        };
    }, [user, activeCall]);

    const initiateCall = async (peerId: string, peerName: string, peerAvatar: string, type: CallType) => {
        if (!user) return;

        try {
            // Call Edge Function to validate and create session
            const { data: session, error: functionError } = await supabase.functions.invoke('initiate-call', {
                body: {
                    caller_id: user.id,
                    receiver_id: peerId,
                    call_type: type,
                },
            });

            if (functionError) throw functionError;

            const call: CallState = {
                id: session.id,
                type: type,
                category: 'private',
                peerId: peerId,
                peerName: peerName,
                peerAvatar: peerAvatar,
                isInitiator: true,
                status: 'calling',
            };

            setActiveCall(call);

            // Signal the peer
            await supabase.channel(`calls:${peerId}`).send({
                type: 'broadcast',
                event: 'call:offer',
                payload: {
                    callId: session.id,
                    callerId: user.id,
                    callerName: profile?.full_name || 'Someone',
                    callerAvatar: profile?.avatar_url,
                    type: type,
                },
            });

        } catch (error: any) {
            console.error("Initiate call error:", error);
            toast.error(error.message || "Failed to initiate call");
        }
    };

    const acceptCall = async () => {
        if (!activeCall || !user) return;

        try {
            // Update session status in DB
            await supabase
                .from('call_sessions')
                .update({ status: 'accepted', started_at: new Date().toISOString() })
                .eq('id', activeCall.id);

            setActiveCall(prev => prev ? { ...prev, status: 'active', startTime: Date.now() } : null);

            // Signal the initiator
            await supabase.channel(`calls:${activeCall.peerId}`).send({
                type: 'broadcast',
                event: 'call:accepted',
                payload: { acceptorId: user.id, callId: activeCall.id },
            });
        } catch (error) {
            console.error("Accept call error:", error);
        }
    };

    const rejectCall = async () => {
        if (!activeCall) return;

        try {
            await supabase
                .from('call_sessions')
                .update({ status: 'rejected' })
                .eq('id', activeCall.id);

            // Signal the peer
            await supabase.channel(`calls:${activeCall.peerId}`).send({
                type: 'broadcast',
                event: 'call:rejected',
                payload: { rejectorId: user?.id },
            });

            setActiveCall(null);
        } catch (error) {
            console.error("Reject call error:", error);
        }
    };

    const endCall = async () => {
        if (!activeCall) return;

        try {
            const endedAt = new Date().toISOString();
            const duration = activeCall.startTime ? Math.floor((Date.now() - activeCall.startTime) / 1000) : 0;
            const finalStatus = activeCall.startTime ? 'completed' : 'cancelled';

            await supabase
                .from('call_sessions')
                .update({
                    status: finalStatus,
                    ended_at: endedAt,
                    duration: duration
                })
                .eq('id', activeCall.id);

            // Signal the peer
            if (activeCall.peerId) {
                await supabase.channel(`calls:${activeCall.peerId}`).send({
                    type: 'broadcast',
                    event: 'call:ended',
                    payload: { callId: activeCall.id },
                });
            }

            setActiveCall(null);
            setIsMinimized(false);
        } catch (error) {
            console.error("End call error:", error);
            setActiveCall(null);
        }
    };

    const startMeeting = (conversationId: string, meetingName: string, type: CallType) => {
        setActiveCall({
            type: type,
            category: 'meeting',
            conversationId: conversationId,
            peerName: meetingName,
            isInitiator: true,
            status: 'active',
            startTime: Date.now(),
        });
    };

    return (
        <CallContext.Provider value={{
            activeCall,
            isMinimized,
            initiateCall,
            acceptCall,
            rejectCall,
            endCall,
            setMinimized: setIsMinimized,
            startMeeting
        }}>
            {children}
        </CallContext.Provider>
    );
}

export function useCall() {
    const context = useContext(CallContext);
    if (context === undefined) {
        throw new Error('useCall must be used within a CallProvider');
    }
    return context;
}

import React, { createContext, useContext, useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

const FEEDBACK_LAST_PROMPTED_KEY = "eduspace_feedback_last_prompted";
const PROMPT_HOUR = 18; // 6:00 PM

interface FeedbackContextType {
    showPrompt: boolean;
    setShowPrompt: (show: boolean) => void;
    checkFeedbackStatus: () => Promise<void>;
    submitFeedback: (rating: number, message: string) => Promise<void>;
    triggerTestPrompt: () => void;
    sendTestEmail: () => Promise<void>;
}

const FeedbackContext = createContext<FeedbackContextType | undefined>(undefined);

export function FeedbackProvider({ children }: { children: React.ReactNode }) {
    const { user, profile, updateProfile, refreshProfile } = useAuth();
    const [showPrompt, setShowPrompt] = useState(false);
    const [hasChecked, setHasChecked] = useState(false);

    const checkFeedbackStatus = async () => {
        if (!user || !profile || hasChecked) return;

        try {
            // 1. Check if it's past the prompt hour (e.g., 6 PM)
            const currentHour = new Date().getHours();
            if (currentHour < PROMPT_HOUR) {
                return;
            }

            // 2. Check Supabase Profile for last prompt date (7-day logic)
            const lastPromptedAt = profile.last_feedback_prompt_at;
            const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
            const now = new Date().getTime();

            if (lastPromptedAt && (now - new Date(lastPromptedAt).getTime() < sevenDaysInMs)) {
                setHasChecked(true);
                return;
            }

            // Show prompt
            setShowPrompt(true);

            // Update profile with current timestamp so it won't show again for 7 days
            await updateProfile({
                last_feedback_prompt_at: new Date().toISOString()
            });

            setHasChecked(true);


        } catch (error) {
            console.error("Error checking feedback status:", error);
        }
    };

    const submitFeedback = async (rating: number, message: string) => {
        if (!user) return;

        try {
            const { error: dbError } = await supabase
                .from("feedbacks")
                .insert({
                    user_id: user.id,
                    rating,
                    message,
                });

            if (dbError) throw dbError;

            const { error: emailError } = await supabase.functions.invoke(
                "send-feedback-email",
                {
                    body: {
                        rating,
                        message,
                        userName: profile?.full_name || user.email || "User",
                        userEmail: user.email || "No Email",
                    },
                }
            );

            if (emailError) throw emailError;

            toast.success("Thank you for your feedback!", {
                description: "Your rating helps us improve Eduspace.",
            });

            setShowPrompt(false);
        } catch (error: any) {
            console.error("Error submitting feedback:", error);
            toast.error("Failed to submit feedback", {
                description: error.message || "Please try again later.",
            });
            throw error;
        }
    };

    const triggerTestPrompt = () => {
        setShowPrompt(true);
    };

    const sendTestEmail = async () => {
        try {
            const { error } = await supabase.functions.invoke("send-feedback-email", {
                body: {
                    rating: 5,
                    message: "This is a test feedback message to verify the email system.",
                    userName: profile?.full_name || user?.email || "Tester",
                    userEmail: user?.email || "test@example.com",
                },
            });
            if (error) throw error;
            toast.success("Test email sent successfully!");
        } catch (error: any) {
            toast.error("Failed to send test email: " + error.message);
        }
    };

    return (
        <FeedbackContext.Provider
            value={{
                showPrompt,
                setShowPrompt,
                checkFeedbackStatus,
                submitFeedback,
                triggerTestPrompt,
                sendTestEmail,
            }}
        >
            {children}
        </FeedbackContext.Provider>
    );
}

export function useFeedbackContext() {
    const context = useContext(FeedbackContext);
    if (context === undefined) {
        throw new Error("useFeedbackContext must be used within a FeedbackProvider");
    }
    return context;
}

import { createContext, useContext, useEffect, ReactNode } from "react";
import { useAuth } from "./AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useTranslation } from "react-i18next";

interface LanguageContextType {
    language: string;
    changeLanguage: (lang: string) => void;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export function LanguageProvider({ children }: { children: ReactNode }) {
    const { user, profile } = useAuth();
    const { i18n } = useTranslation();

    // Load language from profile on mount
    useEffect(() => {
        if (profile?.language) {
            i18n.changeLanguage(profile.language);
        }
    }, [profile?.language, i18n]);

    // Change language and save to database
    const changeLanguage = async (lang: string) => {
        await i18n.changeLanguage(lang);

        // Save to database if user is logged in
        if (user) {
            try {
                await supabase
                    .from("profiles")
                    .update({ language: lang })
                    .eq("user_id", user.id);
            } catch (error) {
                console.error("Error saving language:", error);
            }
        }
    };

    return (
        <LanguageContext.Provider value={{ language: i18n.language, changeLanguage }}>
            {children}
        </LanguageContext.Provider>
    );
}

export function useLanguage() {
    const context = useContext(LanguageContext);
    if (!context) {
        throw new Error("useLanguage must be used within LanguageProvider");
    }
    return context;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from "react";
import { useAuth } from "./AuthContext";

interface LayoutOptions {
    fullHeight?: boolean;
    hideHeaderOnMobile?: boolean;
}

interface LayoutContextType {
    sidebarMode: 'expanded' | 'collapsed' | 'hover';
    setSidebarMode: (mode: 'expanded' | 'collapsed' | 'hover') => void;
    actions: ReactNode;
    setActions: (actions: ReactNode) => void;
    options: LayoutOptions;
    setOptions: (options: LayoutOptions) => void;
    isMobileMenuOpen: boolean;
    setIsMobileMenuOpen: (open: boolean) => void;
}

const LayoutContext = createContext<LayoutContextType | undefined>(undefined);

export function LayoutProvider({ children }: { children: ReactNode }) {
    const { profile, updateProfile } = useAuth();

    // Initialize from localStorage to prevent flicker
    const [sidebarMode, setSidebarModeState] = useState<'expanded' | 'collapsed' | 'hover'>(() => {
        if (typeof window !== 'undefined') {
            const saved = localStorage.getItem('sidebarMode');
            if (saved) return saved as 'expanded' | 'collapsed' | 'hover';
        }
        return 'expanded';
    });

    const [actions, setActions] = useState<ReactNode>(null);
    const [options, setOptions] = useState<LayoutOptions>({});
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    // Sync with profile on load (if not set in localstorage, or just to keep in sync)
    useEffect(() => {
        if (profile?.sidebar_mode) {
            // We only update if it differs, but to avoid visual jumps we trust localStorage first usually.
            // But if localStorage is missing, this helps.
            if (!localStorage.getItem('sidebarMode')) {
                setSidebarModeState(profile.sidebar_mode as any);
            }
        }
    }, [profile]);

    const setSidebarMode = async (mode: 'expanded' | 'collapsed' | 'hover') => {
        setSidebarModeState(mode);
        localStorage.setItem('sidebarMode', mode);
        // Fire and forget update
        if (profile) {
            updateProfile({ sidebar_mode: mode });
        }
    };

    return (
        <LayoutContext.Provider value={{
            sidebarMode,
            setSidebarMode,
            actions,
            setActions,
            options,
            setOptions,
            isMobileMenuOpen,
            setIsMobileMenuOpen
        }}>
            {children}
        </LayoutContext.Provider>
    );
}

export function useLayout() {
    const context = useContext(LayoutContext);
    if (context === undefined) {
        throw new Error("useLayout must be used within a LayoutProvider");
    }
    return context;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { StreakService, BadgeType, UserStreak, UserBadge, BADGE_DETAILS } from '@/services/streakService';
import { StreakCelebrationModal } from '@/components/streak/StreakCelebrationModal';
import { StreakUpdateModal } from '@/components/streak/StreakUpdateModal';
import { format, subDays } from 'date-fns';
import { toast } from 'sonner';

interface StreakContextType {
    streak: UserStreak | null;
    badges: UserBadge[];
    activityLog: string[];
    loading: boolean;
    recordAcademicAction: () => Promise<void>;
    refreshStreakData: () => Promise<void>;
    fetchActivityRange: (start: string, end: string) => Promise<void>;
}

const StreakContext = createContext<StreakContextType | undefined>(undefined);

export const StreakProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, role } = useAuth();
    const [streak, setStreak] = useState<UserStreak | null>(null);
    const [badges, setBadges] = useState<UserBadge[]>([]);
    const [activityLog, setActivityLog] = useState<string[]>([]);
    const [loading, setLoading] = useState(true);
    const [unlockedBadge, setUnlockedBadge] = useState<BadgeType | null>(null);
    const [showCelebration, setShowCelebration] = useState(false);
    const [showStreakUpdate, setShowStreakUpdate] = useState(false);
    const [currentStreakCount, setCurrentStreakCount] = useState(0);

    const isStudent = role === 'student';

    const refreshStreakData = useCallback(async () => {
        if (!user || !isStudent) {
            setStreak(null);
            setBadges([]);
            setActivityLog([]);
            setLoading(false);
            return;
        }

        try {
            const [streakData, badgesData] = await Promise.all([
                StreakService.getStreak(user.id),
                StreakService.getBadges(user.id)
            ]);
            setStreak(streakData);
            setBadges(badgesData);
        } catch (error) {
            console.error('Error refreshing streak data:', error);
        } finally {
            setLoading(false);
        }
    }, [user, isStudent]);

    const fetchActivityRange = useCallback(async (start: string, end: string) => {
        if (!user || !isStudent) return;
        try {
            const logs = await StreakService.getActivityLog(user.id, start, end);
            setActivityLog(logs);
        } catch (error) {
            console.error('Error fetching activity range:', error);
        }
    }, [user, isStudent]);

    useEffect(() => {
        refreshStreakData();
    }, [refreshStreakData]);

    const recordAcademicAction = useCallback(async () => {
        if (!user || !isStudent) return;

        try {
            const result = await StreakService.recordAction(user.id);

            if (result.updated) {
                // Refresh local state
                await refreshStreakData();

                // Also refresh activity log for today to show the flame
                const today = format(new Date(), 'yyyy-MM-dd');
                setActivityLog(prev => prev.includes(today) ? prev : [...prev, today]);

                if (result.unlockedBadge) {
                    setUnlockedBadge(result.unlockedBadge);
                    setShowCelebration(true);
                } else if (result.isNewDay) {
                    setCurrentStreakCount(result.newStreak);
                    setShowStreakUpdate(true);
                }
            }
        } catch (error) {
            console.error('Error recording academic action:', error);
        }
    }, [user, isStudent, refreshStreakData]);



    return (
        <StreakContext.Provider value={{
            streak,
            badges,
            activityLog,
            loading,
            recordAcademicAction,
            refreshStreakData,
            fetchActivityRange,
        }}>
            {children}
            {isStudent && showCelebration && unlockedBadge && (
                <StreakCelebrationModal
                    badgeType={unlockedBadge}
                    streakCount={streak?.current_streak || 0}
                    onClose={() => setShowCelebration(false)}
                />
            )}
            {isStudent && showStreakUpdate && (
                <StreakUpdateModal
                    streakCount={currentStreakCount}
                    onClose={() => setShowStreakUpdate(false)}
                />
            )}
        </StreakContext.Provider>
    );
};

export const useStreak = () => {
    const context = useContext(StreakContext);
    if (context === undefined) {
        throw new Error('useStreak must be used within a StreakProvider');
    }
    return context;
};

import { createContext, useContext, useEffect, useState, ReactNode } from "react";
import { useAuth } from "./AuthContext";
import { supabase } from "@/integrations/supabase/client";

type Theme = "light" | "dark" | "system";

interface ThemeContextType {
    theme: Theme;
    setTheme: (theme: Theme) => void;
    actualTheme: "light" | "dark"; // The actual applied theme (resolves "system")
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export function ThemeProvider({ children }: { children: ReactNode }) {
    const { user, profile } = useAuth();
    const [theme, setThemeState] = useState<Theme>("system");
    const [actualTheme, setActualTheme] = useState<"light" | "dark">("light");

    // Get system theme preference
    const getSystemTheme = (): "light" | "dark" => {
        if (typeof window !== "undefined") {
            return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
        }
        return "light";
    };

    // Update actual theme based on theme setting
    const updateActualTheme = (themeValue: Theme) => {
        const resolved = themeValue === "system" ? getSystemTheme() : themeValue;
        setActualTheme(resolved);

        // Apply theme to document
        const root = window.document.documentElement;
        root.classList.remove("light", "dark");
        root.classList.add(resolved);
    };

    // Load theme from profile on mount
    useEffect(() => {
        if (profile?.theme) {
            const savedTheme = profile.theme as Theme;
            setThemeState(savedTheme);
            updateActualTheme(savedTheme);
        } else {
            // Default to system theme
            updateActualTheme("system");
        }
    }, [profile?.theme]);

    // Listen for system theme changes when theme is set to "system"
    useEffect(() => {
        if (theme !== "system") return;

        const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
        const handleChange = () => {
            updateActualTheme("system");
        };

        mediaQuery.addEventListener("change", handleChange);
        return () => mediaQuery.removeEventListener("change", handleChange);
    }, [theme]);

    // Set theme and save to database
    const setTheme = async (newTheme: Theme) => {
        setThemeState(newTheme);
        updateActualTheme(newTheme);

        // Save to database if user is logged in
        if (user) {
            try {
                await supabase
                    .from("profiles")
                    .update({ theme: newTheme })
                    .eq("user_id", user.id);
            } catch (error) {
                console.error("Error saving theme:", error);
            }
        }
    };

    return (
        <ThemeContext.Provider value={{ theme, setTheme, actualTheme }}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    const context = useContext(ThemeContext);
    if (!context) {
        throw new Error("useTheme must be used within ThemeProvider");
    }
    return context;
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface AssignmentSubmissionDetail {
    student_id: string;
    student_name: string;
    register_number: string;
    email: string;
    status: 'submitted' | 'pending' | 'graded' | 'returned';
    submitted_at?: string;
    file_url?: string;
    file_name?: string;
    file_type?: string;
    file_size?: number;
    submission_id?: string;
    submission_text?: string;
    grade?: string | null;
    feedback?: string | null;
    profile_image?: string | null;
}

export function useAssignmentSubmissions(assignmentId: string, classId: string) {
    const { user } = useAuth();
    const [submissions, setSubmissions] = useState<AssignmentSubmissionDetail[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchData = async () => {
        if (!user || !assignmentId || !classId) return;

        try {
            setLoading(true);

            // 1. Fetch all students in the class
            const { data: students, error: studentsError } = await supabase
                .from('class_students')
                .select('*')
                .eq('class_id', classId);

            if (studentsError) throw studentsError;

            // 2. Fetch all submissions for this assignment directly (RLS protected)
            const { data: submitted, error: submissionsError } = await supabase
                .from('assignment_submissions')
                .select('*')
                .eq('assignment_id', assignmentId);

            if (submissionsError) {
                console.error('Error fetching submissions directly:', submissionsError);
                throw submissionsError;
            }

            // 2.5 Fetch student emails for matching
            const allSubmissionUserIds = [...new Set((submitted || []).map(s => s.student_id).filter(Boolean))] as string[];
            const submittedEmailsMap: Record<string, string> = {}; // user_id -> email

            if (allSubmissionUserIds.length > 0) {
                const { data: profileEmails, error: emailsError } = await supabase
                    .from('profiles')
                    .select('user_id, email')
                    .in('user_id', allSubmissionUserIds);

                if (profileEmails) {
                    profileEmails.forEach(p => {
                        if (p.email) submittedEmailsMap[p.user_id] = p.email;
                    });
                }
            }

            console.log('[useAssignmentSubmissions] Fetched submissions:', submitted?.length, submitted);
            console.log('[useAssignmentSubmissions] Total students:', students?.length);

            // 2.6 Fetch profile images
            const studentIds = (students || []).map(s => s.student_id);
            const profileMap: Record<string, string> = {};

            if (studentIds.length > 0) {
                const { data: profiles, error: profilesError } = await supabase
                    .from('student_profiles')
                    .select('user_id, profile_image')
                    .in('user_id', studentIds);

                if (!profilesError && profiles) {
                    profiles.forEach(p => {
                        if (p.profile_image) {
                            profileMap[p.user_id] = p.profile_image;
                        }
                    });
                }
            }

            // 3. Merge data
            const combinedData: AssignmentSubmissionDetail[] = (students || []).map(student => {
                const submission = submitted?.find(s => {
                    // 1. Match by student_id (UUID)
                    const matchId = (s.student_id && student.student_id && s.student_id === student.student_id);

                    // 2. Match by register_number
                    const matchReg = (s.register_number && student.register_number &&
                        s.register_number.trim().toLowerCase() === student.register_number.trim().toLowerCase());

                    // 3. Match by email (ultimate fallback)
                    const submittedEmail = s.student_id ? submittedEmailsMap[s.student_id] : null;
                    const matchEmail = (submittedEmail && student.email &&
                        submittedEmail.trim().toLowerCase() === student.email.trim().toLowerCase());

                    return matchId || matchReg || matchEmail;
                });

                return {
                    student_id: student.student_id || student.id,
                    student_name: student.student_name,
                    register_number: student.register_number || 'N/A',
                    email: student.email,
                    status: submission ? (submission.status as any) : 'pending',
                    submitted_at: submission?.submitted_at,
                    file_url: submission?.attachment_url,
                    file_name: submission?.attachment_name,
                    file_type: submission?.file_type,
                    file_size: submission?.file_size,
                    submission_id: submission?.id,
                    submission_text: submission?.submission_text,
                    grade: submission?.grade?.toString(),
                    feedback: submission?.feedback,
                    profile_image: profileMap[student.student_id] || null
                };
            });

            // Do not filter here, return all students to allow filtering in the UI
            console.log('[useAssignmentSubmissions] Total students:', combinedData.length);
            console.log('[useAssignmentSubmissions] Students with submissions:', submitted.length);

            setSubmissions(combinedData);

        } catch (error) {
            console.error('Error fetching assignment details:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!user || !assignmentId || !classId) {
            setLoading(false);
            return;
        }

        fetchData();

        // Subscribe to changes
        const subscription = supabase
            .channel(`assignment_subs_${assignmentId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignment_submissions',
                    filter: `assignment_id=eq.${assignmentId}`
                },
                (payload) => {
                    console.log('[useAssignmentSubmissions] Submission change detected:', payload.eventType, payload);
                    if (payload.eventType === 'DELETE') {
                        console.log('[useAssignmentSubmissions] Submission deleted, refreshing list...');
                    }
                    fetchData();
                }
            )
            .subscribe();

        return () => {
            subscription.unsubscribe();
        };
    }, [user, assignmentId, classId]);

    return {
        submissions,
        loading,
        refetch: fetchData
    };
}

import { useEffect, useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getEnrolledClassIds } from '@/lib/studentUtils';
import { notifyGradePosted, notifyAssignmentSubmission } from '@/lib/notificationService';
import { knowledgeService } from '@/lib/knowledgeService';

// ── Module-level cache ───────────────────────────────────────────────────────
const assignmentsCache = new Map<string, Assignment[]>();
const enrolledClassesCache = new Map<string, { id: string, class_name: string, course_code: string }[]>();

export interface Assignment {
    id: string;
    course_id: string;
    class_id?: string;
    subject_id?: string;
    lecturer_id: string;
    title: string;
    description: string | null;
    instructions: string | null;
    due_date: string | null;
    max_points: number;
    attachment_url: string | null;
    attachment_name: string | null;
    status: 'draft' | 'published' | 'closed' | 'active' | 'completed';
    created_at: string;
    updated_at: string;
    course_title?: string;
    course_code?: string;
    class_name?: string;
    subject_name?: string;
    lecturer_name?: string;
    instructor_avatar?: string;
    studentStatus?: 'pending' | 'submitted' | 'graded' | 'overdue';
    submission?: AssignmentSubmission;
    grade?: number;
    earnedPoints?: number;
}

export interface AssignmentSubmission {
    id: string;
    assignment_id: string;
    student_id: string;
    submission_text: string | null;
    attachment_url: string | null;
    attachment_name: string | null;
    submitted_at: string;
    grade: number | null;
    feedback: string | null;
    graded_at: string | null;
    status: 'submitted' | 'graded' | 'returned';
    student_name?: string;
}

interface AssignmentStats {
    total: number;
    completed: number;
    pending: number;
    averageGrade?: number;
}

export function useAssignments(selectedClassId?: string) {
    const { user, role } = useAuth();
    const cacheKey = selectedClassId ? `${role}_${selectedClassId}` : `${role}_all`;

    const [assignments, setAssignments] = useState<Assignment[]>(() => {
        if (assignmentsCache.has(cacheKey)) {
            return assignmentsCache.get(cacheKey) || [];
        }
        return [];
    });
    const [submissions, setSubmissions] = useState<AssignmentSubmission[]>([]);
    const [loading, setLoading] = useState(() => !assignmentsCache.has(cacheKey));
    const [error, setError] = useState<Error | null>(null);
    const [isInitialLoad, setIsInitialLoad] = useState(() => !assignmentsCache.has(cacheKey));
    const [enrolledClasses, setEnrolledClasses] = useState<{ id: string, class_name: string, course_code: string }[]>(() => {
        if (user && enrolledClassesCache.has(user.id)) {
            return enrolledClassesCache.get(user.id) || [];
        }
        return [];
    });

    const fetchEnrolledClasses = useCallback(async () => {
        if (!user || role !== 'student') return;

        try {
            // Use the centralized helper to get robust enrollment IDs
            const classIds = await getEnrolledClassIds(user.id);

            if (classIds.length === 0) {
                setEnrolledClasses([]);
                return;
            }

            const { data: classesData, error: classesError } = await supabase
                .from('classes')
                .select('id, class_name, course_code')
                .in('id', classIds);

            if (classesError) {
                console.error('Error fetching class details:', classesError);
                return;
            }

            setEnrolledClasses(classesData || []);
            enrolledClassesCache.set(user.id, classesData || []);

        } catch (error) {
            console.error('Error in fetchEnrolledClasses:', error);
        }
    }, [user, role]);

    // Initialize enrolled classes for student
    useEffect(() => {
        if (role === 'student') {
            fetchEnrolledClasses();
        }
    }, [fetchEnrolledClasses, role]);

    // silentRefresh: when true, don't trigger loading state (for real-time updates)
    const fetchAssignments = useCallback(async (silentRefresh = false) => {
        if (!user) return;

        try {
            // Only show loading spinner on initial load, not on real-time updates
            if (!silentRefresh && !assignmentsCache.has(cacheKey)) {
                setLoading(true);
            }

            let data: any[] = [];
            let mySubmissions: AssignmentSubmission[] = [];

            if (role === 'lecturer') {
                // Lecturer sees their own assignments
                const { data: assignmentsData, error: fetchError } = await supabase
                    .from('assignments')
                    .select('*')
                    .eq('lecturer_id', user.id)
                    .order('created_at', { ascending: false });

                if (fetchError) throw fetchError;
                data = assignmentsData || [];

            } else {
                // Student View
                let targetClassIds: string[] = [];

                if (selectedClassId) {
                    targetClassIds = [selectedClassId];
                } else {
                    // If no class selected, fetch for all enrolled classes (Dashboard view)
                    targetClassIds = await getEnrolledClassIds(user.id);
                }

                if (targetClassIds.length === 0) {
                    data = [];
                    mySubmissions = [];
                } else {
                    // Fetch assignments for the target classes
                    const { data: classAssignments, error: classError } = await supabase
                        .from('assignments')
                        .select('*')
                        .in('class_id', targetClassIds)
                        .in('status', ['published', 'active', 'completed', 'closed'])
                        .order('due_date', { ascending: true });

                    if (classError) {
                        console.error('Error fetching class assignments:', classError);
                        throw classError;
                    }
                    data = classAssignments || [];
                }

                if (data.length > 0) {
                    // Fetch related data for enrichment
                    // Get unique subject IDs and lecturer IDs
                    const subjectIds = [...new Set(data.map(a => a.subject_id).filter(Boolean))];
                    const lecturerIds = [...new Set(data.map(a => a.lecturer_id).filter(Boolean))];

                    // Fetch subject names
                    let subjectMap = new Map<string, string>();
                    if (subjectIds.length > 0) {
                        const { data: subjects } = await supabase
                            .from('subjects')
                            .select('id, name')
                            .in('id', subjectIds);
                        subjectMap = new Map(subjects?.map(s => [s.id, s.name]) || []);
                    }

                    // Fetch lecturer names and avatars
                    const lecturerMap = new Map<string, { name: string, avatar: string | null }>();
                    if (lecturerIds.length > 0) {
                        const { data: lecturers } = await supabase
                            .from('profiles')
                            .select('user_id, full_name, avatar_url')
                            .in('user_id', lecturerIds);

                        lecturers?.forEach(l => {
                            lecturerMap.set(l.user_id, {
                                name: l.full_name,
                                avatar: l.avatar_url
                            });
                        });
                    }

                    // Enrich assignments with class, subject, and lecturer details
                    data = data.map(a => {
                        const lecturer = lecturerMap.get(a.lecturer_id);
                        const clsInfo = enrolledClasses.find(c => c.id === a.class_id);
                        return {
                            ...a,
                            course_code: clsInfo?.course_code || a.course_code,
                            class_name: clsInfo?.class_name || "Assignment",
                            subject_name: subjectMap.get(a.subject_id) || null,
                            lecturer_name: lecturer?.name || null,
                            instructor_avatar: lecturer?.avatar || null,
                        };
                    });

                    // Fetch My Submissions for these assignments
                    const assignmentIds = data.map(a => a.id);
                    if (assignmentIds.length > 0) {
                        const { data: submissionsData, error: subError } = await supabase
                            .from('assignment_submissions')
                            .select('*')
                            .eq('student_id', user.id)
                            .in('assignment_id', assignmentIds);

                        if (subError) throw subError;
                        mySubmissions = (submissionsData || []) as any[];
                        console.log('[useAssignments] Fetched student submissions:', mySubmissions.length, mySubmissions);
                    }
                }
            }

            const formattedAssignments = data.map((a: any) => {
                const base = {
                    ...a,
                    course_title: a.courses?.title,
                    course_code: a.courses?.course_code,
                    lecturer_name: a.lecturer_name || a.lecturer?.full_name,
                    instructor_avatar: a.instructor_avatar || a.lecturer?.avatar_url,
                };

                if (role === 'student') {
                    // Compute status for student
                    const submission = mySubmissions.find(s => s.assignment_id === a.id);
                    let studentStatus = 'pending';
                    let grade = undefined;
                    let earnedPoints = undefined;

                    console.log(`[useAssignments] Processing assignment "${a.title}":`, {
                        assignmentId: a.id,
                        hasSubmission: !!submission,
                        submissionStatus: submission?.status,
                        submissionId: submission?.id
                    });

                    if (submission) {
                        studentStatus = submission.status === 'graded' ? 'graded' : 'submitted';
                        if (submission.grade !== null) {
                            grade = submission.grade;
                            earnedPoints = submission.grade;
                        }
                        console.log(`[useAssignments] Assignment "${a.title}" status: ${studentStatus}`);
                    } else if (a.due_date && new Date(a.due_date) < new Date()) {
                        studentStatus = 'overdue';
                    }

                    return {
                        ...base,
                        studentStatus,
                        submission,
                        grade,
                        earnedPoints
                    };
                }

                return base;
            });

            console.log('[useAssignments] Final formatted assignments:', formattedAssignments.length);
            setAssignments(formattedAssignments);
            assignmentsCache.set(cacheKey, formattedAssignments);
            setError(null);
        } catch (err) {
            console.error('Error fetching assignments:', err);
            // Don't clear assignments on error during refresh - keep existing data
            if (isInitialLoad) {
                setAssignments([]);
            }
            setError(err as Error);
        } finally {
            setLoading(false);
            setIsInitialLoad(false);
        }
    }, [user, role, isInitialLoad, selectedClassId, cacheKey]);

    // Fetch assignments when selected class changes (for student)
    useEffect(() => {
        if (assignmentsCache.has(cacheKey)) {
            setAssignments(assignmentsCache.get(cacheKey) || []);
            setLoading(false);
            setIsInitialLoad(false);
        } else {
            setAssignments([]);
            setLoading(true);
            setIsInitialLoad(true);
        }

        if (role === 'student' || role === 'lecturer') {
            fetchAssignments();
        }
    }, [fetchAssignments, role, selectedClassId, cacheKey]);

    // Helper function to merge new assignments with existing ones, preserving submission states
    const mergeAssignmentsWithSubmissions = useCallback((
        newAssignments: Assignment[],
        existingAssignments: Assignment[]
    ): Assignment[] => {
        const mergedMap = new Map<string, Assignment>();

        // Start with existing assignments (to preserve submission states)
        existingAssignments.forEach(a => {
            mergedMap.set(a.id, a);
        });

        // Merge in new/updated assignments, preserving submission data from existing
        newAssignments.forEach(newAssignment => {
            const existing = mergedMap.get(newAssignment.id);
            if (existing) {
                // Update assignment but preserve submission-related fields if they exist
                mergedMap.set(newAssignment.id, {
                    ...newAssignment,
                    studentStatus: newAssignment.studentStatus || existing.studentStatus,
                    submission: newAssignment.submission || existing.submission,
                    grade: newAssignment.grade !== undefined ? newAssignment.grade : existing.grade,
                    earnedPoints: newAssignment.earnedPoints !== undefined ? newAssignment.earnedPoints : existing.earnedPoints,
                });
            } else {
                // New assignment - add it
                mergedMap.set(newAssignment.id, newAssignment);
            }
        });

        return Array.from(mergedMap.values());
    }, []);

    useEffect(() => {
        if (!user) {
            setLoading(false);
            return;
        }

        if (role !== 'student') {
            // Initial fetch for non-students (lecturers view all their assignments usually)
            // or handled by the other useEffect
            fetchAssignments();
        }

        // Real-time subscription for assignments table
        const assignmentsSubscription = supabase
            .channel('assignments_changes')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignments',
                },
                async (payload) => {
                    console.log('[useAssignments] Assignment change detected:', payload.eventType, payload);

                    if (payload.eventType === 'INSERT') {
                        // For new assignments, check if it's relevant to this user and add it
                        const newAssignment = payload.new as any;

                        if (role === 'student') {
                            // If a specific class is selected, ignore assignments from other classes
                            if (selectedClassId && newAssignment.class_id !== selectedClassId) {
                                return;
                            }

                            // Check if student is enrolled in this class
                            const enrolledClassIds = await getEnrolledClassIds(user.id);
                            if (newAssignment.class_id && enrolledClassIds.includes(newAssignment.class_id)) {
                                // Add the new assignment with pending status
                                setAssignments(prev => {
                                    // Check if already exists
                                    if (prev.some(a => a.id === newAssignment.id)) {
                                        return prev;
                                    }
                                    const enrichedAssignment: Assignment = {
                                        ...newAssignment,
                                        studentStatus: 'pending' as const,
                                        submission: undefined,
                                        grade: undefined,
                                        earnedPoints: undefined,
                                    };
                                    console.log('[useAssignments] Adding new assignment to list:', enrichedAssignment.title);
                                    return [...prev, enrichedAssignment];
                                });
                            }
                        } else {
                            // Lecturer: add if they own it
                            if (newAssignment.lecturer_id === user.id) {
                                setAssignments(prev => {
                                    if (prev.some(a => a.id === newAssignment.id)) {
                                        return prev;
                                    }
                                    return [newAssignment, ...prev];
                                });
                            }
                        }
                    } else if (payload.eventType === 'UPDATE') {
                        // Update existing assignment without losing submission data
                        const updatedAssignment = payload.new as any;
                        setAssignments(prev => prev.map(a =>
                            a.id === updatedAssignment.id
                                ? { ...updatedAssignment, studentStatus: a.studentStatus, submission: a.submission, grade: a.grade, earnedPoints: a.earnedPoints }
                                : a
                        ));
                    } else if (payload.eventType === 'DELETE') {
                        const deletedId = (payload.old as any).id;
                        setAssignments(prev => prev.filter(a => a.id !== deletedId));
                    }
                }
            )
            .subscribe();

        // Real-time subscription for assignment_submissions table
        // This ensures students see their submission status update instantly
        const submissionsSubscription = supabase
            .channel(`assignment_submissions_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignment_submissions',
                    filter: role === 'student' ? `student_id=eq.${user.id}` : undefined,
                },
                (payload) => {
                    console.log('[useAssignments] Submission change detected:', payload.eventType, payload);

                    if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
                        const submission = payload.new as AssignmentSubmission;
                        // Update only the affected assignment's submission status
                        setAssignments(prev => prev.map(a => {
                            if (a.id === submission.assignment_id) {
                                const studentStatus = submission.status === 'graded' ? 'graded' : 'submitted';
                                console.log(`[useAssignments] Updating assignment ${a.title} status to ${studentStatus}`);
                                return {
                                    ...a,
                                    studentStatus: studentStatus as 'pending' | 'submitted' | 'graded' | 'overdue',
                                    submission: submission,
                                    grade: submission.grade ?? a.grade,
                                    earnedPoints: submission.grade ?? a.earnedPoints,
                                };
                            }
                            return a;
                        }));
                    } else if (payload.eventType === 'DELETE') {
                        // Submission deleted - reset to pending status
                        const deletedSubmission = payload.old as any;
                        setAssignments(prev => prev.map(a => {
                            if (a.id === deletedSubmission.assignment_id) {
                                return {
                                    ...a,
                                    studentStatus: 'pending' as const,
                                    submission: undefined,
                                    grade: undefined,
                                    earnedPoints: undefined,
                                };
                            }
                            return a;
                        }));
                    }
                }
            )
            .subscribe();

        // Real-time subscription for access_requests (enrollment changes)
        // This ensures students see assignments from newly accepted classes immediately
        const enrollmentSubscription = role === 'student' ? supabase
            .channel(`enrollment_changes_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'access_requests',
                    filter: `student_id=eq.${user.id}`,
                },
                () => {
                    // For enrollment changes, do a full refresh to get new class assignments
                    fetchAssignments(true);
                }
            )
            .subscribe() : null;

        return () => {
            assignmentsSubscription.unsubscribe();
            submissionsSubscription.unsubscribe();
            enrollmentSubscription?.unsubscribe();
        };
    }, [user, fetchAssignments, role, mergeAssignmentsWithSubmissions]);

    // Create assignment (lecturer only)
    const createAssignment = async (data: {
        course_id: string;
        title: string;
        description?: string;
        instructions?: string;
        due_date?: string;
        max_points?: number;
        attachment_url?: string;
        attachment_name?: string;
        status?: 'draft' | 'published';
    }) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { data: newAssignment, error } = await supabase
                .from('assignments')
                .insert({
                    ...data,
                    lecturer_id: user.id,
                    status: data.status || 'draft',
                })
                .select()
                .single();

            if (error) throw error;

            await fetchAssignments();
            return { success: true, data: newAssignment };
        } catch (err: any) {
            console.error('Error creating assignment:', err);
            return { success: false, error: err.message };
        }
    };

    // Update assignment (lecturer only)
    const updateAssignment = async (id: string, data: Partial<Assignment>) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { error } = await supabase
                .from('assignments')
                .update(data)
                .eq('id', id)
                .eq('lecturer_id', user.id);

            if (error) throw error;

            await fetchAssignments();
            return { success: true };
        } catch (err: any) {
            console.error('Error updating assignment:', err);
            return { success: false, error: err.message };
        }
    };

    // Delete assignment (lecturer only)
    const deleteAssignment = async (id: string) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { error } = await supabase
                .from('assignments')
                .delete()
                .eq('id', id)
                .eq('lecturer_id', user.id);

            if (error) throw error;

            await fetchAssignments();
            return { success: true };
        } catch (err: any) {
            console.error('Error deleting assignment:', err);
            return { success: false, error: err.message };
        }
    };

    // Fetch submissions for an assignment (lecturer only)
    const fetchSubmissions = async (assignmentId: string) => {
        if (!user || role !== 'lecturer') return [];

        try {
            const { data, error } = await supabase
                .from('assignment_submissions')
                .select('*')
                .eq('assignment_id', assignmentId)
                .order('submitted_at', { ascending: false });

            if (error) throw error;

            // Fetch student names
            const submissionsWithNames = await Promise.all(
                (data || []).map(async (sub) => {
                    const { data: profile } = await supabase
                        .from('profiles')
                        .select('full_name')
                        .eq('user_id', sub.student_id)
                        .single();

                    return {
                        ...sub,
                        student_name: profile?.full_name || 'Unknown Student',
                    };
                })
            );

            setSubmissions(submissionsWithNames as AssignmentSubmission[]);
            return submissionsWithNames;
        } catch (err) {
            console.error('Error fetching submissions:', err);
            return [];
        }
    };

    // Grade submission (lecturer only)
    const gradeSubmission = async (submissionId: string, grade: number, feedback?: string) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { error } = await supabase
                .from('assignment_submissions')
                .update({
                    grade,
                    feedback,
                    graded_at: new Date().toISOString(),
                    status: 'graded',
                })
                .eq('id', submissionId);

            if (error) throw error;

            // Send notification to student about the grade
            try {
                const { data: submission } = await supabase
                    .from('assignment_submissions')
                    .select('student_id, assignment_id')
                    .eq('id', submissionId)
                    .single();

                if (submission) {
                    const { data: assignment } = await supabase
                        .from('assignments')
                        .select('title, class_id')
                        .eq('id', submission.assignment_id)
                        .single();

                    if (assignment) {
                        await notifyGradePosted(
                            submission.student_id,
                            assignment.title,
                            grade.toString(),
                            submission.assignment_id,
                            user.id,
                            assignment.class_id
                        );
                    }
                }
            } catch (notifyErr) {
                console.error("Error sending grade notification:", notifyErr);
                // Non-blocking error
            }

            return { success: true };
        } catch (error) {
            console.error('Error grading submission:', error);
            return { success: false, error };
        }
    };

    // Delete submission (student only)
    const deleteSubmission = async (submissionId: string) => {
        if (!user) return { success: false, error: 'Not authenticated' };

        try {
            const { error } = await supabase
                .from('assignment_submissions')
                .delete()
                .eq('id', submissionId)
                .eq('student_id', user.id); // Security check

            if (error) throw error;

            await knowledgeService.deleteKnowledgeNode(submissionId);

            return { success: true };
        } catch (error) {
            console.error('Error deleting submission:', error);
            return { success: false, error };
        }
    };

    // Submit assignment (student only)
    const submitAssignment = async (assignmentId: string, data: {
        submission_text?: string;
        attachment_url?: string;
        attachment_name?: string;
        file_type?: string;
        file_size?: number;
    }) => {
        if (!user || role !== 'student') return { success: false, error: 'Unauthorized' };

        try {
            // 1. Fetch assignment details and student profile
            const [assignmentResult, profileResult] = await Promise.all([
                supabase
                    .from('assignments')
                    .select('lecturer_id, title, class_id')
                    .eq('id', assignmentId)
                    .single(),
                supabase
                    .from('profiles')
                    .select('full_name, student_id') // student_id is the register number field in profiles
                    .eq('user_id', user.id)
                    .single()
            ]);

            const assignment = assignmentResult.data;
            const studentProfile = profileResult.data;

            // 2. Insert/Update submission including the snapshot fields
            console.log('[useAssignments] Upserting submission with data:', {
                assignment_id: assignmentId,
                student_id: user.id,
                attachment_url: data.attachment_url,
                attachment_name: data.attachment_name,
                file_type: data.file_type,
                file_size: data.file_size
            });

            const { data: subData, error } = await supabase
                .from('assignment_submissions')
                .upsert({
                    assignment_id: assignmentId,
                    student_id: user.id,
                    class_id: assignment?.class_id,
                    register_number: studentProfile?.student_id, // Map student_id to register_number
                    ...data,
                    submitted_at: new Date().toISOString(),
                    status: 'submitted',
                })
                .select('*')
                .single();

            if (error) throw error;

            console.log('[useAssignments] Submission saved to database:', {
                id: subData.id,
                attachment_name: subData.attachment_name,
                attachment_url: subData.attachment_url
            });

            // Manually refresh assignments to ensure UI updates immediately
            console.log('[useAssignments] Triggering manual refresh...');
            await fetchAssignments(true);
            console.log('[useAssignments] Manual refresh complete');

            // 3. Send notification to lecturer
            try {
                if (assignment && assignment.class_id) {
                    // Use notification service for consistent handling
                    await notifyAssignmentSubmission(
                        assignment.lecturer_id,
                        studentProfile?.full_name || 'A student',
                        assignment.title,
                        assignmentId,
                        assignment.class_id,
                        user.id
                    );
                }
            } catch (notifError) {
                console.warn('Failed to send submission notification:', notifError);
            }

            // Sync with Knowledge Map
            try {
                await knowledgeService.upsertKnowledgeNode({
                    type: 'assignment',
                    sourceId: subData.id,
                    label: assignment?.title || 'Assignment',
                    text: assignment?.title || 'Assignment'
                });
            } catch (kmError) {
                console.warn('Failed to sync assignment with Knowledge Map:', kmError);
            }

            return { success: true };
        } catch (err: any) {
            console.error('Error submitting assignment:', err);
            return { success: false, error: err.message };
        }
    };


    // Calculate Average Grade for Students
    let averageGrade = 0;
    if (role === 'student' && assignments.length > 0) {
        let totalWeightedScore = 0;
        let count = 0;

        assignments.forEach(a => {
            const maxPoints = a.max_points || 100;
            let score = 0;
            let shouldCount = false;

            if (a.studentStatus === 'graded' && a.grade !== undefined && a.grade !== null) {
                // 1. Graded: Use actual grade (percentage)
                score = (a.grade / maxPoints) * 100;
                shouldCount = true;
            } else if (a.studentStatus === 'submitted' && a.submission) {
                // 2 & 3. Submitted (Ungraded)
                const submittedAt = new Date(a.submission.submitted_at);
                const dueDate = a.due_date ? new Date(a.due_date) : new Date();

                // Check if late (submitted after due date)
                if (a.due_date && submittedAt > dueDate) {
                    // Late penalty: 10% deduction from full score
                    score = 90;
                } else {
                    // On time: Award full base grade (100%)
                    score = 100;
                }
                shouldCount = true;
            } else if (a.studentStatus === 'overdue') {
                // 4. Overdue (Not submitted): 0%
                score = 0;
                shouldCount = true;
            }
            // Pending/Future assignments are excluded from the denominator

            if (shouldCount) {
                totalWeightedScore += score;
                count++;
            }
        });

        averageGrade = count > 0 ? Math.round(totalWeightedScore / count) : 0;
    }

    const stats: AssignmentStats & { averageGrade: number } = {
        total: assignments.length,
        completed: role === 'student'
            ? assignments.filter((a) => a.studentStatus === 'submitted' || a.studentStatus === 'graded').length
            : assignments.filter((a) => a.status === 'closed').length,
        pending: role === 'student'
            ? assignments.filter((a) => a.studentStatus === 'pending' || a.studentStatus === 'overdue').length
            : assignments.filter((a) => a.status === 'published').length,
        averageGrade
    };

    return {
        assignments,
        submissions,
        loading,
        stats,
        createAssignment,
        updateAssignment,
        deleteAssignment,
        fetchSubmissions,
        gradeSubmission,
        submitAssignment,
        deleteSubmission,
        refreshAssignments: fetchAssignments,
        enrolledClasses
    };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { notifyNewAssignment, notifyAssignmentUpdated } from '@/lib/notificationService';

// ── Module-level cache ───────────────────────────────────────────────────────
const assignmentsCache = new Map<string, ClassAssignment[]>();

export interface ClassAssignment {
    id: string;
    class_id: string;
    subject_id: string | null;
    subject_name?: string;
    topic: string | null;
    title: string;
    description: string | null;
    due_date: string | null;
    attachment_url: string | null;
    attachment_name: string | null;
    status: 'active' | 'closed' | 'completed';
    created_at: string;
    updated_at: string;
    submission_count?: number;
    total_students?: number;
}

export interface CreateClassAssignmentDTO {
    title: string;
    description: string;
    subject_id: string;
    topic?: string;
    due_date: Date;
    attachment_url: string;
    attachment_name: string;
}

export function useClassAssignments(classId: string | null) {
    const { user } = useAuth();
    const [assignments, setAssignments] = useState<ClassAssignment[]>(() => {
        if (classId && assignmentsCache.has(classId)) {
            return assignmentsCache.get(classId) || [];
        }
        return [];
    });
    const [loading, setLoading] = useState(() => {
        return !classId || !assignmentsCache.has(classId);
    });
    const [error, setError] = useState<Error | null>(null);

    // Update state if classId changes and we have cached data
    useEffect(() => {
        if (!classId) {
            setAssignments([]);
            setLoading(false);
        } else if (assignmentsCache.has(classId)) {
            setAssignments(assignmentsCache.get(classId) || []);
            setLoading(false);
        } else {
            setAssignments([]);
            setLoading(true);
        }
    }, [classId]);

    // silentRefresh: when true, don't trigger loading state (for real-time updates)
    const fetchAssignments = useCallback(async (silentRefresh = false) => {
        if (!classId || !user) {
            setAssignments([]);
            setLoading(false);
            return;
        }

        try {
            // Only show loading spinner on initial load, not on real-time updates
            if (!silentRefresh && !assignmentsCache.has(classId)) {
                setLoading(true);
            }

            // Fetch assignments for the class
            const { data: assignmentsData, error: assignmentsError } = await supabase
                .from('assignments')
                .select('*')
                .eq('class_id', classId)
                .order('created_at', { ascending: false });

            if (assignmentsError) {
                console.error('Error fetching assignments:', assignmentsError);
                throw assignmentsError;
            }

            console.log('Fetched assignments:', assignmentsData);

            // Get total accepted students in class (students who have accepted the class invitation)
            const { count: totalStudents } = await supabase
                .from('access_requests')
                .select('*', { count: 'exact', head: true })
                .eq('class_id', classId)
                .eq('status', 'accepted');

            // Fetch submission counts and subject names for each assignment
            const assignmentsWithStats = await Promise.all(
                (assignmentsData || []).map(async (assignment) => {
                    const { count: submissionCount } = await supabase
                        .from('assignment_submissions')
                        .select('*', { count: 'exact', head: true })
                        .eq('assignment_id', assignment.id);

                    // Fetch subject name if subject_id exists
                    let subjectName = null;
                    if (assignment.subject_id) {
                        const { data: subjectData } = await supabase
                            .from('subjects')
                            .select('name')
                            .eq('id', assignment.subject_id)
                            .single();
                        subjectName = subjectData?.name || null;
                    }

                    return {
                        ...assignment,
                        status: assignment.status as 'active' | 'closed' | 'completed',
                        subject_name: subjectName,
                        submission_count: submissionCount || 0,
                        total_students: totalStudents || 0,
                    };
                })
            );

            console.log('Assignments with stats:', assignmentsWithStats);
            setAssignments(assignmentsWithStats);
            assignmentsCache.set(classId, assignmentsWithStats);

            // Auto-complete logic: Check if any active assignment has full submissions
            // We do this check after setting state to avoid blocking the UI, but we trigger the update
            assignmentsWithStats.forEach(async (assignment) => {
                if (
                    assignment.status === 'active' &&
                    assignment.total_students > 0 &&
                    assignment.submission_count === assignment.total_students
                ) {
                    console.log(`Auto-completing assignment ${assignment.id} as all ${assignment.total_students} students have submitted.`);
                    // We call the update directly via Supabase to avoid circular dependency with the hook's updateAssignmentStatus wrapper if it causes issues
                    // But using the wrapper is better for notifications if we add them later. 
                    // To be safe and simple, we'll direct update here or use the internal logic.
                    // For now, let's just use the Supabase call directly to avoid needing the function wrapper in scope if it's defined later.
                    const { error } = await supabase
                        .from('assignments')
                        .update({ status: 'completed', updated_at: new Date().toISOString() })
                        .eq('id', assignment.id);

                    if (error) console.error('Error auto-completing assignment:', error);
                }
            });

            setError(null);
        } catch (err) {
            console.error('Error fetching class assignments:', err);
            setError(err as Error);
            // Only show error for genuine failures, not empty results
            // Set empty array on initial load failure
            if (!assignmentsCache.has(classId)) {
                setAssignments([]);
            }
        } finally {
            setLoading(false);
        }
    }, [classId, user]);

    useEffect(() => {
        fetchAssignments();

        if (!classId || !user) return;

        // Real-time subscription for assignments
        const assignmentsSubscription = supabase
            .channel(`assignments_${classId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignments',
                    filter: `class_id=eq.${classId}`,
                },
                () => {
                    // Silent refresh - don't show loading indicator
                    fetchAssignments(true);
                }
            )
            .subscribe();

        // Real-time subscription for assignment_submissions
        // This ensures submission counts update instantly as students submit
        const submissionsSubscription = supabase
            .channel(`submissions_${classId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignment_submissions',
                },
                (payload) => {
                    console.log('[useClassAssignments] Submission change detected:', payload.eventType, payload);
                    // Refetch assignments to ensure accurate submission counts and status
                    fetchAssignments(true);
                }
            )
            .subscribe();

        // Real-time subscription for access_requests (enrollment changes)
        // This ensures total student counts update when students accept/reject invitations
        const enrollmentSubscription = supabase
            .channel(`enrollments_${classId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'access_requests',
                    filter: `class_id=eq.${classId}`,
                },
                () => {
                    // Silent refresh for enrollment changes
                    fetchAssignments(true);
                }
            )
            .subscribe();

        return () => {
            assignmentsSubscription.unsubscribe();
            submissionsSubscription.unsubscribe();
            enrollmentSubscription.unsubscribe();
        };
    }, [classId, user, fetchAssignments]);

    const createAssignment = async (data: CreateClassAssignmentDTO) => {
        if (!user || !classId) throw new Error('User not authenticated or class not selected');

        try {
            // Insert assignment
            const { data: newAssignment, error: assignmentError } = await supabase
                .from('assignments')
                .insert({
                    lecturer_id: user.id,
                    class_id: classId,
                    subject_id: data.subject_id,
                    topic: data.topic || null,
                    title: data.title,
                    description: data.description,
                    due_date: data.due_date.toISOString(),
                    attachment_url: data.attachment_url,
                    attachment_name: data.attachment_name,
                    status: 'active', // Changed from 'published' to 'active'
                })
                .select()
                .single();

            if (assignmentError) {
                console.error('Assignment creation error:', assignmentError);
                throw assignmentError;
            }

            // Get enrolled students who have accepted the class
            const { data: enrolledStudents, error: studentsError } = await supabase
                .from('class_students')
                .select('student_id')
                .eq('class_id', classId);

            if (!studentsError && enrolledStudents && enrolledStudents.length > 0) {
                // Filter students who have accepted the class
                const { data: acceptedRequests } = await supabase
                    .from('access_requests')
                    .select('student_id')
                    .eq('class_id', classId)
                    .eq('status', 'accepted');

                const acceptedStudentIds = acceptedRequests?.map(r => r.student_id).filter(id => id !== null) || [];

                if (acceptedStudentIds.length > 0) {
                    // Use notification service for consistent handling and preference checking
                    await notifyNewAssignment(
                        acceptedStudentIds,
                        data.title,
                        newAssignment.id,
                        user.id,
                        classId,
                        data.due_date.toISOString()
                    );
                }
            }

            toast.success('Assignment created successfully!');
            await fetchAssignments();
            return { success: true };
        } catch (error: any) {
            console.error('Error creating assignment:', error);
            const errorMessage = error.message || 'Failed to create assignment';
            toast.error(errorMessage);
            return { success: false, error: errorMessage };
        }
    };

    const updateAssignment = async (id: string, data: Partial<CreateClassAssignmentDTO>) => {
        if (!user) throw new Error('User not authenticated');

        try {
            const updates: any = {
                title: data.title,
                description: data.description,
                subject_id: data.subject_id,
                topic: data.topic,
                due_date: data.due_date?.toISOString(),
                attachment_url: data.attachment_url,
                attachment_name: data.attachment_name,
                updated_at: new Date().toISOString(),
            };

            // Remove undefined keys
            Object.keys(updates).forEach(key => updates[key] === undefined && delete updates[key]);

            const { error } = await supabase
                .from('assignments')
                .update(updates)
                .eq('id', id);

            if (error) throw error;

            // Send update notifications to enrolled students
            const { data: assignment } = await supabase
                .from('assignments')
                .select('title, class_id')
                .eq('id', id)
                .single();

            if (assignment && assignment.class_id) {
                const { data: enrolledStudents } = await supabase
                    .from('class_students')
                    .select('student_id')
                    .eq('class_id', assignment.class_id);

                if (enrolledStudents && enrolledStudents.length > 0) {
                    const { data: acceptedRequests } = await supabase
                        .from('access_requests')
                        .select('student_id')
                        .eq('class_id', assignment.class_id)
                        .eq('status', 'accepted');

                    const acceptedStudentIds = acceptedRequests?.map(r => r.student_id).filter(id => id !== null) || [];

                    if (acceptedStudentIds.length > 0) {
                        // Build update details based on what changed
                        let updateDetails = 'Assignment has been updated';
                        if (data.title) updateDetails = 'Title updated';
                        else if (data.due_date) updateDetails = `Due date changed to ${data.due_date.toLocaleDateString()}`;
                        else if (data.description) updateDetails = 'Description updated';

                        // Use notification service for consistent handling
                        await notifyAssignmentUpdated(
                            acceptedStudentIds,
                            assignment.title,
                            id,
                            updateDetails,
                            user.id,
                            assignment.class_id
                        );
                    }
                }
            }

            toast.success('Assignment updated successfully!');
            await fetchAssignments();
            return { success: true };
        } catch (error: any) {
            console.error('Error updating assignment:', error);
            toast.error(error.message || 'Failed to update assignment');
            return { success: false, error: error.message };
        }
    };

    const deleteAssignment = async (id: string) => {
        if (!user) throw new Error('User not authenticated');

        try {
            const { error } = await supabase
                .from('assignments')
                .delete()
                .eq('id', id);

            if (error) throw error;

            toast.success('Assignment deleted successfully');
            await fetchAssignments();
        } catch (error: any) {
            console.error('Error deleting assignment:', error);
            toast.error('Failed to delete assignment');
            throw error;
        }
    };

    const updateAssignmentStatus = async (id: string, status: 'active' | 'closed' | 'completed') => {
        if (!user) throw new Error('User not authenticated');

        try {
            const { error } = await supabase
                .from('assignments')
                .update({ status, updated_at: new Date().toISOString() })
                .eq('id', id);

            if (error) throw error;

            toast.success(`Assignment ${status === 'closed' ? 'closed' : 'activated'} successfully`);
            await fetchAssignments();
        } catch (error: any) {
            console.error('Error updating assignment status:', error);
            toast.error('Failed to update assignment status');
            throw error;
        }
    };

    return {
        assignments,
        loading,
        error,
        createAssignment,
        updateAssignment,
        deleteAssignment,
        updateAssignmentStatus,
        refreshAssignments: fetchAssignments,
    };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getEnrolledClassIds } from '@/lib/studentUtils';
import { notifyClassStudents, sendClassEmail, getLecturerName } from '@/lib/notificationService';

// ── Types ────────────────────────────────────────────────────────────────────

export interface FeedPost {
    id: string;
    class_id: string;
    author_id: string;
    content: string;
    attachment_url: string | null;
    attachment_name: string | null;
    attachment_type: string | null;
    is_pinned: boolean;
    created_at: string;
    updated_at: string;
    // Joined / enriched
    author_name: string;
    author_avatar: string | null;
    author_role: string;
    class_name: string;
    course_code: string;
    reactions: FeedReaction[];
    seen_count: number;
    total_students: number;
}

export interface FeedReaction {
    id: string;
    post_id: string;
    user_id: string;
    emoji: string;
    user_name?: string;
}

export interface ClassOption {
    id: string;
    class_name: string | null;
    course_code: string;
}

// ── Untyped Supabase client for new tables ───────────────────────────────────
// These tables (class_feed_posts, class_feed_reactions, class_feed_seen) are
// not yet in the auto-generated Supabase types. We use `any` to bypass type
// checking for .from() calls targeting these tables.

const db = supabase as any;

// ── Module-level cache ───────────────────────────────────────────────────────
// Persists across component mounts so navigating away and back shows data instantly.
const postsCache = new Map<string, FeedPost[]>();
let classesCache: ClassOption[] | null = null;
let cachedSelectedClassId: string | null = null;

// ── Hook ─────────────────────────────────────────────────────────────────────

export function useClassFeed() {
    const { user, role } = useAuth();
    const [posts, setPosts] = useState<FeedPost[]>(() => {
        // Initialize from cache if available
        if (cachedSelectedClassId && postsCache.has(cachedSelectedClassId)) {
            return postsCache.get(cachedSelectedClassId) || [];
        }
        return [];
    });
    const [classes, setClasses] = useState<ClassOption[]>(() => classesCache || []);
    const [selectedClassId, setSelectedClassId] = useState<string | null>(() => cachedSelectedClassId);
    const [loading, setLoading] = useState(() => {
        // Only show loading if we have NO cached data at all
        return !cachedSelectedClassId || !postsCache.has(cachedSelectedClassId);
    });
    const [posting, setPosting] = useState(false);

    // ── Fetch user's classes ─────────────────────────────────────────────

    const fetchClasses = useCallback(async () => {
        if (!user) return;

        try {
            if (role === 'student') {
                const enrolledIds = await getEnrolledClassIds(user.id);
                if (enrolledIds.length === 0) {
                    setClasses([]);
                    classesCache = [];
                    return;
                }
                const { data } = await supabase
                    .from('classes')
                    .select('id, class_name, course_code')
                    .in('id', enrolledIds)
                    .eq('is_active', true)
                    .order('created_at', { ascending: false });

                setClasses(data || []);
                classesCache = data || [];
                if (data && data.length > 0 && !selectedClassId) {
                    setSelectedClassId(data[0].id);
                    cachedSelectedClassId = data[0].id;
                }
            } else {
                const { data } = await supabase
                    .from('classes')
                    .select('id, class_name, course_code')
                    .eq('lecturer_id', user.id)
                    .eq('is_active', true)
                    .order('created_at', { ascending: false });

                setClasses(data || []);
                classesCache = data || [];
                if (data && data.length > 0 && !selectedClassId) {
                    setSelectedClassId(data[0].id);
                    cachedSelectedClassId = data[0].id;
                }
            }
        } catch (err) {
            console.error('Error fetching classes for feed:', err);
        }
    }, [user, role, selectedClassId]);

    // ── Fetch feed posts for selected class ──────────────────────────────

    const fetchPosts = useCallback(async () => {
        if (!user || !selectedClassId) {
            setPosts([]);
            setLoading(false);
            return;
        }

        // Cache the selected class ID for next mount
        cachedSelectedClassId = selectedClassId;

        try {
            // Only show loading skeleton if there's NO cached data for this class
            const hasCachedPosts = postsCache.has(selectedClassId);
            if (!hasCachedPosts) {
                setLoading(true);
            }
            // If we have cache, show it immediately (already set in state init or previous fetch)

            // 1. Fetch posts
            const { data: postsData, error: postsError } = await db
                .from('class_feed_posts')
                .select('*')
                .eq('class_id', selectedClassId)
                .order('is_pinned', { ascending: false })
                .order('created_at', { ascending: false });

            if (postsError) throw postsError;
            if (!postsData || postsData.length === 0) {
                setPosts([]);
                postsCache.set(selectedClassId, []);
                setLoading(false);
                return;
            }

            const postIds = postsData.map((p: any) => p.id);
            const authorIds = [...new Set(postsData.map((p: any) => p.author_id))] as string[];

            // 2. Fetch author profiles
            const { data: profiles } = await supabase
                .from('profiles')
                .select('user_id, full_name, avatar_url')
                .in('user_id', authorIds);

            const profileMap = new Map<string, { full_name: string; avatar_url: string | null }>();
            profiles?.forEach(p => profileMap.set(p.user_id, { full_name: p.full_name || 'Unknown', avatar_url: p.avatar_url }));

            // 3. Fetch author roles
            const { data: roles } = await supabase
                .from('user_roles')
                .select('user_id, role')
                .in('user_id', authorIds);
            const roleMap = new Map<string, string>();
            roles?.forEach(r => roleMap.set(r.user_id, r.role));

            // 4. Fetch reactions
            const { data: reactions } = await db
                .from('class_feed_reactions')
                .select('*')
                .in('post_id', postIds);

            const reactionsByPost = new Map<string, FeedReaction[]>();
            (reactions || []).forEach((r: any) => {
                const arr = reactionsByPost.get(r.post_id) || [];
                const authorProfile = profileMap.get(r.user_id);
                arr.push({
                    id: r.id,
                    post_id: r.post_id,
                    user_id: r.user_id,
                    emoji: r.emoji,
                    user_name: authorProfile?.full_name || 'Unknown',
                });
                reactionsByPost.set(r.post_id, arr);
            });

            // 5. Fetch seen counts
            const { data: seenData } = await db
                .from('class_feed_seen')
                .select('post_id')
                .in('post_id', postIds);

            const seenCountMap = new Map<string, number>();
            (seenData || []).forEach((s: any) => {
                seenCountMap.set(s.post_id, (seenCountMap.get(s.post_id) || 0) + 1);
            });

            // 6. Total students in class
            const { count: totalStudents } = await supabase
                .from('class_students')
                .select('*', { count: 'exact', head: true })
                .eq('class_id', selectedClassId);

            // 7. Get class info
            const { data: classInfo } = await supabase
                .from('classes')
                .select('class_name, course_code')
                .eq('id', selectedClassId)
                .single();

            // 8. Enrich posts
            const enrichedPosts: FeedPost[] = postsData.map((post: any) => {
                const author = profileMap.get(post.author_id);
                return {
                    id: post.id,
                    class_id: post.class_id,
                    author_id: post.author_id,
                    content: post.content,
                    attachment_url: post.attachment_url,
                    attachment_name: post.attachment_name,
                    attachment_type: post.attachment_type,
                    is_pinned: post.is_pinned,
                    created_at: post.created_at,
                    updated_at: post.updated_at,
                    author_name: author?.full_name || 'Unknown',
                    author_avatar: author?.avatar_url || null,
                    author_role: roleMap.get(post.author_id) || 'student',
                    class_name: classInfo?.class_name || '',
                    course_code: classInfo?.course_code || '',
                    reactions: reactionsByPost.get(post.id) || [],
                    seen_count: seenCountMap.get(post.id) || 0,
                    total_students: totalStudents || 0,
                };
            });

            setPosts(enrichedPosts);
            // Update cache
            postsCache.set(selectedClassId, enrichedPosts);

            // 9. Mark all posts as seen by the current user
            if (postIds.length > 0) {
                const seenRecords = postIds.map((post_id: string) => ({
                    post_id,
                    user_id: user.id,
                }));

                await db
                    .from('class_feed_seen')
                    .upsert(seenRecords, { onConflict: 'post_id,user_id', ignoreDuplicates: true });
            }

        } catch (err) {
            console.error('Error fetching feed posts:', err);
        } finally {
            setLoading(false);
        }
    }, [user, selectedClassId]);

    // ── Create announcement ──────────────────────────────────────────────

    const createPost = useCallback(async (
        content: string,
        attachment?: { url: string; name: string; type: string } | null
    ) => {
        if (!user || !selectedClassId) return false;
        // Require either content or attachment
        if (!content.trim() && !attachment) return false;

        try {
            setPosting(true);

            const postContent = content.trim() || (attachment ? '📎 Shared a file' : '');

            const { data: newPost, error } = await db
                .from('class_feed_posts')
                .insert({
                    class_id: selectedClassId,
                    author_id: user.id,
                    content: postContent,
                    attachment_url: attachment?.url || null,
                    attachment_name: attachment?.name || null,
                    attachment_type: attachment?.type || null,
                    is_pinned: false,
                })
                .select()
                .single();

            if (error) throw error;

            // Send notifications to all class students
            const { data: classInfo } = await supabase
                .from('classes')
                .select('class_name, course_code')
                .eq('id', selectedClassId)
                .single();

            const preview = postContent.length > 80 ? postContent.substring(0, 80) + '...' : postContent;

            await notifyClassStudents(
                selectedClassId,
                'announcement',
                `📢 New Announcement — ${classInfo?.course_code || 'Class'}`,
                preview,
                user.id,
                newPost?.id
            );

            // Send class email
            try {
                const lecturerName = await getLecturerName(user.id);
                sendClassEmail({
                    classId: selectedClassId,
                    type: 'update',
                    title: `New Announcement in ${classInfo?.course_code || 'your class'}`,
                    body: preview,
                    link: `https://eduspaceacademy.online/class-feed`,
                    lecturerName,
                });
            } catch (emailErr) {
                console.warn('Email notification failed (non-critical):', emailErr);
            }

            await fetchPosts();
            return true;
        } catch (err) {
            console.error('Error creating announcement:', err);
            return false;
        } finally {
            setPosting(false);
        }
    }, [user, selectedClassId, fetchPosts]);

    // ── Toggle pin ───────────────────────────────────────────────────────

    const togglePin = useCallback(async (postId: string, currentlyPinned: boolean) => {
        if (!user) return;

        try {
            const { error } = await db
                .from('class_feed_posts')
                .update({ is_pinned: !currentlyPinned, updated_at: new Date().toISOString() })
                .eq('id', postId);

            if (error) throw error;
            await fetchPosts();
        } catch (err) {
            console.error('Error toggling pin:', err);
        }
    }, [user, fetchPosts]);

    // ── Delete post ──────────────────────────────────────────────────────

    const deletePost = useCallback(async (postId: string) => {
        if (!user) return;

        try {
            const { error } = await db
                .from('class_feed_posts')
                .delete()
                .eq('id', postId);

            if (error) throw error;
            await fetchPosts();
        } catch (err) {
            console.error('Error deleting post:', err);
        }
    }, [user, fetchPosts]);

    // ── Toggle reaction ──────────────────────────────────────────────────

    const toggleReaction = useCallback(async (postId: string, emoji: string) => {
        if (!user) return;

        try {
            // Check if user already reacted with this emoji
            const { data: existing } = await db
                .from('class_feed_reactions')
                .select('id')
                .eq('post_id', postId)
                .eq('user_id', user.id)
                .eq('emoji', emoji)
                .maybeSingle();

            if (existing) {
                // Remove reaction
                await db
                    .from('class_feed_reactions')
                    .delete()
                    .eq('id', existing.id);
            } else {
                // Add reaction
                await db
                    .from('class_feed_reactions')
                    .insert({
                        post_id: postId,
                        user_id: user.id,
                        emoji,
                    });
            }

            await fetchPosts();
        } catch (err) {
            console.error('Error toggling reaction:', err);
        }
    }, [user, fetchPosts]);

    // ── Real-time subscription ───────────────────────────────────────────

    useEffect(() => {
        fetchClasses();
    }, [fetchClasses]);

    useEffect(() => {
        fetchPosts();

        if (!selectedClassId) return;

        // Subscribe to changes on posts for this class
        const channel = supabase
            .channel(`class_feed_${selectedClassId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'class_feed_posts',
                    filter: `class_id=eq.${selectedClassId}`,
                },
                () => fetchPosts()
            )
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'class_feed_reactions',
                },
                () => fetchPosts()
            )
            .subscribe();

        return () => {
            channel.unsubscribe();
        };
    }, [selectedClassId, fetchPosts]);

    // ── Wrapped setSelectedClassId — loads cached posts instantly ─────────

    const handleSetSelectedClassId = useCallback((classId: string) => {
        cachedSelectedClassId = classId;
        setSelectedClassId(classId);
        // Instantly load cached posts for the new class (if available)
        if (postsCache.has(classId)) {
            setPosts(postsCache.get(classId) || []);
        }
    }, []);

    return {
        posts,
        classes,
        selectedClassId,
        setSelectedClassId: handleSetSelectedClassId,
        loading,
        posting,
        createPost,
        togglePin,
        deletePost,
        toggleReaction,
        refreshPosts: fetchPosts,
    };
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

// ── Module-level cache ───────────────────────────────────────────────────────
const studentsCache = new Map<string, ClassStudent[]>();

export interface ClassStudent {
    id: string;
    class_id: string;
    student_id: string;
    register_number: string;
    student_name: string;
    email: string;
    department?: string;
    course?: string;
    year?: string;
    section?: string;
    phone?: string;
    student_image_url?: string | null;
    import_source: string;
    added_at: string;
    profile_image?: string;
    status?: 'active' | 'probation' | 'inactive';
    progress?: number;
}

export function useClassStudents(classId?: string) {
    const { user } = useAuth();
    const [students, setStudents] = useState<ClassStudent[]>(() => {
        if (classId && studentsCache.has(classId)) {
            return studentsCache.get(classId) || [];
        }
        return [];
    });
    const [loading, setLoading] = useState(() => {
        return !classId || !studentsCache.has(classId);
    });
    const [error, setError] = useState<string | null>(null);

    // Update state synchronously if classId changes and we have cached data
    useEffect(() => {
        if (!classId) {
            setStudents([]);
            setLoading(false);
        } else if (studentsCache.has(classId)) {
            setStudents(studentsCache.get(classId) || []);
            setLoading(false);
        } else {
            setStudents([]);
            setLoading(true);
        }
    }, [classId]);

    useEffect(() => {
        if (!user || !classId) {
            setLoading(false);
            return;
        }

        fetchStudents();

        // Set up real-time subscription
        const subscription = supabase
            .channel(`class_students_${classId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'class_students',
                    filter: `class_id=eq.${classId}`
                },
                () => {
                    fetchStudents(true);
                }
            )
            .subscribe();

        return () => {
            subscription.unsubscribe();
        };
    }, [user, classId]);

    const fetchStudents = async (silentRefresh = false) => {
        if (!classId) return;

        try {
            if (!silentRefresh && !studentsCache.has(classId)) {
                setLoading(true);
            }
            const { data, error: fetchError } = await supabase
                .from('class_students')
                .select('*')
                .eq('class_id', classId)
                .order('added_at', { ascending: false });

            if (fetchError) throw fetchError;

            setStudents(data || []);
            if (data) studentsCache.set(classId, data);
            setError(null);
        } catch (err) {
            console.error('Error fetching students:', err);
            setError(err instanceof Error ? err.message : 'Failed to fetch students');
        } finally {
            setLoading(false);
        }
    };

    const addStudent = async (studentData: Omit<ClassStudent, 'id' | 'added_at'>) => {
        if (!user || !classId) throw new Error('Not authenticated or no class selected');

        try {
            const { data, error: insertError } = await supabase
                .from('class_students')
                .insert({
                    ...studentData,
                    class_id: classId
                })
                .select()
                .single();

            if (insertError) throw insertError;

            await fetchStudents();
            return { success: true, data };
        } catch (err) {
            console.error('Error adding student:', err);
            return {
                success: false,
                error: err instanceof Error ? err.message : 'Failed to add student'
            };
        }
    };

    const updateStudent = async (studentId: string, updates: Partial<ClassStudent>) => {
        if (!user || !classId) throw new Error('Not authenticated or no class selected');

        try {
            const { error: updateError } = await supabase
                .from('class_students')
                .update(updates)
                .eq('id', studentId)
                .eq('class_id', classId);

            if (updateError) throw updateError;

            await fetchStudents();
        } catch (err) {
            console.error('Error updating student:', err);
            throw err;
        }
    };

    const deleteStudent = async (studentId: string) => {
        if (!user || !classId) throw new Error('Not authenticated or no class selected');

        try {
            const { error: deleteError } = await supabase
                .from('class_students')
                .delete()
                .eq('id', studentId)
                .eq('class_id', classId);

            if (deleteError) throw deleteError;

            await fetchStudents();
        } catch (err) {
            console.error('Error deleting student:', err);
            throw err;
        }
    };

    const importStudents = async (studentsData: any[]) => {
        if (!user || !classId) throw new Error('Not authenticated or no class selected');

        try {
            // Prepare students for insertion
            const studentsToInsert = studentsData.map(student => ({
                class_id: classId,
                student_id: null, // Will be filled when student accepts
                register_number: student.registerNumber,
                student_name: student.studentName,
                email: student.email,
                department: student.department || null,
                course: student.course || null,
                year: student.year || null,
                section: student.section || null,
                phone: student.phone || null,
                import_source: 'excel'
            }));

            // Insert students
            const { data, error: insertError } = await supabase
                .from('class_students')
                .insert(studentsToInsert)
                .select();

            if (insertError) throw insertError;

            await fetchStudents();

            return {
                success: true,
                imported: data?.length || 0,
                skipped: studentsData.length - studentsToInsert.length,
                failed: 0,
                errors: []
            };
        } catch (err) {
            console.error('Error importing students:', err);
            return {
                success: false,
                imported: 0,
                skipped: 0,
                failed: studentsData.length,
                errors: [err instanceof Error ? err.message : 'Failed to import students']
            };
        }
    };

    const updateStudentImage = async (studentId: string, imageUrl: string | null) => {
        if (!user || !classId) throw new Error('Not authenticated or no class selected');

        try {
            const { error: updateError } = await supabase
                .from('class_students')
                .update({ student_image_url: imageUrl })
                .eq('id', studentId)
                .eq('class_id', classId);

            if (updateError) throw updateError;

            await fetchStudents();
        } catch (err) {
            console.error('Error updating student image:', err);
            throw err;
        }
    };

    return {
        students,
        loading,
        error,
        addStudent,
        updateStudent,
        deleteStudent,
        importStudents,
        updateStudentImage,
        refetch: fetchStudents
    };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getEnrolledClassIds } from '@/lib/studentUtils';

// ── Module-level cache ───────────────────────────────────────────────────────
const classesCache = new Map<string, Class[]>();

export interface Class {
    id: string;
    lecturer_id: string;
    lecturer_name: string | null;
    lecturer_department: string | null;
    lecturer_profile_image: string | null;
    class_image_url: string | null;
    course_code: string;
    class_name: string | null;
    semester: string | null;
    academic_year: string | null;
    is_active: boolean;
    created_at: string;
    updated_at: string;
    student_count?: number;
    subjects?: string[]; // Added for student view
}

export interface CreateClassData {
    lecturer_name: string;
    lecturer_department: string;
    course_code: string;
    class_name?: string;
    semester?: string;
    academic_year?: string;
}

export function useClasses() {
    const { user, role } = useAuth();
    const [classes, setClasses] = useState<Class[]>(() => {
        if (user && classesCache.has(user.id)) {
            return classesCache.get(user.id) || [];
        }
        return [];
    });
    const [loading, setLoading] = useState(() => {
        if (!user) return true;
        return !classesCache.has(user.id);
    });
    const [error, setError] = useState<Error | null>(null);

    // Update state synchronously if user changes and we have cached data
    useEffect(() => {
        if (!user) {
            setClasses([]);
            setLoading(false);
        } else if (classesCache.has(user.id)) {
            setClasses(classesCache.get(user.id) || []);
            setLoading(false);
        } else {
            setClasses([]);
            setLoading(true);
        }
    }, [user]);

    // silentRefresh: when true, don't trigger loading state (for real-time updates)
    const fetchClasses = useCallback(async (silentRefresh = false) => {
        if (!user) {
            setLoading(false);
            return;
        }

        try {
            if (!silentRefresh && !classesCache.has(user.id)) {
                setLoading(true);
            }

            if (role === 'student') {
                // STUDENT: Fetch enrolled classes
                const enrolledIds = await getEnrolledClassIds(user.id);

                if (enrolledIds.length === 0) {
                    setClasses([]);
                    setLoading(false);
                    return;
                }

                const { data: classesData, error: classesError } = await supabase
                    .from('classes')
                    .select('*')
                    .in('id', enrolledIds)
                    .eq('is_active', true)
                    .order('created_at', { ascending: false });

                if (classesError) throw classesError;

                // Enrich with subjects and latest lecturer profile info
                const classIds = classesData?.map(c => c.id) || [];
                const lecturerIds = Array.from(new Set(classesData?.map(c => c.lecturer_id) || []));

                // fetch subjects in bulk
                const { data: allSubjects } = await supabase
                    .from('subjects')
                    .select('name, class_id')
                    .in('class_id', classIds);

                // fetch lecturer profiles in bulk
                const { data: allProfiles } = await supabase
                    .from('profiles')
                    .select('user_id, full_name, avatar_url')
                    .in('user_id', lecturerIds);

                // Create maps for easy lookup
                const subjectsMap = new Map<string, string[]>();
                allSubjects?.forEach((s: any) => {
                    const current = subjectsMap.get(s.class_id) || [];
                    current.push(s.name);
                    subjectsMap.set(s.class_id, current);
                });

                const profilesMap = new Map<string, { full_name: string, avatar_url: string }>();
                allProfiles?.forEach((p: any) => {
                    profilesMap.set(p.user_id, {
                        full_name: p.full_name,
                        avatar_url: p.avatar_url
                    });
                });

                const enrichedClasses = (classesData || []).map((classItem) => {
                    const lecturer = profilesMap.get(classItem.lecturer_id);
                    return {
                        ...classItem,
                        lecturer_profile_image: lecturer?.avatar_url || classItem.lecturer_profile_image,
                        lecturer_name: lecturer?.full_name || classItem.lecturer_name || 'Unknown Lecturer',
                        subjects: subjectsMap.get(classItem.id) || []
                    };
                });

                setClasses(enrichedClasses);
                classesCache.set(user.id, enrichedClasses);

            } else {
                // LECTURER: Fetch own classes
                const { data: classesData, error: classesError } = await supabase
                    .from('classes')
                    .select('*')
                    .eq('lecturer_id', user.id)
                    .eq('is_active', true)
                    .order('created_at', { ascending: false });

                if (classesError) throw classesError;

                // Fetch student count for each class
                const classesWithCount = await Promise.all(
                    (classesData || []).map(async (classItem) => {
                        const { count } = await supabase
                            .from('class_students')
                            .select('*', { count: 'exact', head: true })
                            .eq('class_id', classItem.id);

                        return {
                            ...classItem,
                            student_count: count || 0,
                        };
                    })
                );

                setClasses(classesWithCount);
                classesCache.set(user.id, classesWithCount);
            }
            setError(null);
        } catch (err) {
            console.error('Error fetching classes:', err);
            setError(err as Error);
            if (!classesCache.has(user.id)) {
                setClasses([]);
            }
        } finally {
            setLoading(false);
        }
    }, [user, role]);

    useEffect(() => {
        fetchClasses();

        // Real-time subscription for classes
        // Note: For students, we might want to listen to access_requests too, but general class updates are fine for now.
        // Or if the lecturer calls updates.
        const filter = role === 'lecturer' ? `lecturer_id=eq.${user?.id}` : undefined; // Students listen to broad updates or specific? 
        // Broad updates might be too much. Let's stick to basic reload on mount/focus for now or simple subscription.
        // Re-using existing subscription logic but refining filter

        let subscription: any;

        if (role === 'lecturer') {
            subscription = supabase
                .channel('classes_changes')
                .on(
                    'postgres_changes',
                    {
                        event: '*',
                        schema: 'public',
                        table: 'classes',
                        filter: `lecturer_id=eq.${user?.id}`,
                    },
                    () => fetchClasses(true)
                )
                .subscribe();
        }

        return () => {
            if (subscription) subscription.unsubscribe();
        };
    }, [user, role, fetchClasses]);

    const createClass = async (data: CreateClassData) => {
        if (!user) throw new Error('User not authenticated');

        try {
            // Create class with manually entered lecturer details
            const { data: newClass, error: createError } = await supabase
                .from('classes')
                .insert({
                    lecturer_id: user.id,
                    lecturer_name: data.lecturer_name,
                    lecturer_department: data.lecturer_department,
                    lecturer_profile_image: null,
                    course_code: data.course_code,
                    class_name: data.class_name || null,
                    semester: data.semester || null,
                    academic_year: data.academic_year || null,
                    is_active: true,
                })
                .select()
                .single();

            if (createError) throw createError;

            await fetchClasses();
            return newClass;
        } catch (err) {
            console.error('Error creating class:', err);
            throw err;
        }
    };

    const updateClass = async (classId: string, data: Partial<CreateClassData>) => {
        if (!user) throw new Error('User not authenticated');

        try {
            const { error: updateError } = await supabase
                .from('classes')
                .update({
                    course_code: data.course_code,
                    class_name: data.class_name,
                    semester: data.semester,
                    academic_year: data.academic_year,
                    updated_at: new Date().toISOString(),
                })
                .eq('id', classId)
                .eq('lecturer_id', user.id);

            if (updateError) throw updateError;

            await fetchClasses();
        } catch (err) {
            console.error('Error updating class:', err);
            throw err;
        }
    };

    const deleteClass = async (classId: string) => {
        if (!user) throw new Error('User not authenticated');

        try {
            // Soft delete by setting is_active to false
            const { error: deleteError } = await supabase
                .from('classes')
                .update({ is_active: false })
                .eq('id', classId)
                .eq('lecturer_id', user.id);

            if (deleteError) throw deleteError;

            await fetchClasses();
        } catch (err) {
            console.error('Error deleting class:', err);
            throw err;
        }
    };

    const updateClassImage = async (classId: string, imageUrl: string | null) => {
        if (!user) throw new Error('User not authenticated');

        try {
            const { error: updateError } = await supabase
                .from('classes')
                .update({
                    class_image_url: imageUrl,
                    updated_at: new Date().toISOString(),
                })
                .eq('id', classId)
                .eq('lecturer_id', user.id);

            if (updateError) throw updateError;

            await fetchClasses();
        } catch (err) {
            console.error('Error updating class image:', err);
            throw err;
        }
    };

    return {
        classes,
        loading,
        error,
        createClass,
        updateClass,
        deleteClass,
        updateClassImage,
        refreshClasses: fetchClasses,
    };
}

import { useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface EligibleStudent {
    id: string; // This is the user_id (student_id)
    full_name: string;
    email: string;
    avatar_url?: string;
    class_name?: string; // Optional: show which class they are in
}

export interface ClassGroup {
    class_id: string;
    class_name: string;
    students: EligibleStudent[];
}

export function useEligibleStudents() {
    const { user } = useAuth();
    const [students, setStudents] = useState<EligibleStudent[]>([]); // Keep flat list for backward compatibility if needed, or remove if not used elsewhere
    const [classGroups, setClassGroups] = useState<ClassGroup[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!user) return;

        const fetchStudents = async () => {
            try {
                // 1. Get classes owned by this lecturer
                const { data: classes, error: classError } = await supabase
                    .from('classes')
                    .select('id, class_name')
                    .eq('lecturer_id', user.id);

                if (classError) throw classError;
                if (!classes || classes.length === 0) {
                    setStudents([]);
                    setClassGroups([]);
                    setLoading(false);
                    return;
                }

                const classIds = classes.map(c => c.id);

                // 2. Get accepted students directly using denormalized columns in class_students
                // Removed the .not('student_id', 'is', null) filter to catch students added via Excel/Manually who haven't been linked yet
                const { data, error } = await supabase
                    .from('class_students')
                    .select(`
                        student_id,
                        class_id,
                        student_name,
                        email
                    `)
                    .in('class_id', classIds);

                if (error) throw error;

                // 3. Collect IDs and Emails for lookup
                const uniqueStudentIds = new Set<string>();
                const emailsToLookup = new Set<string>();

                data?.forEach((item: any) => {
                    if (item.student_id) {
                        uniqueStudentIds.add(item.student_id);
                    } else if (item.email) {
                        emailsToLookup.add(item.email);
                    }
                });

                // 4. Fetch avatars and resolve missing IDs via Email
                const avatarMap = new Map<string, string>();
                const emailToIdMap = new Map<string, string>();

                // Fetch by ID
                if (uniqueStudentIds.size > 0) {
                    try {
                        const { data: profileData } = await supabase
                            .from('profiles')
                            .select('user_id, avatar_url')
                            .in('user_id', Array.from(uniqueStudentIds));

                        if (profileData) {
                            profileData.forEach((p: any) => {
                                avatarMap.set(p.user_id, p.avatar_url);
                            });
                        }
                    } catch (avatarError) {
                        console.warn('Could not fetch avatars:', avatarError);
                    }
                }

                // Fetch by Email (for those missing IDs)
                if (emailsToLookup.size > 0) {
                    try {
                        const { data: emailProfileData } = await supabase
                            .from('profiles')
                            .select('user_id, email, avatar_url')
                            .in('email', Array.from(emailsToLookup));

                        if (emailProfileData) {
                            emailProfileData.forEach((p: any) => {
                                if (p.email) {
                                    emailToIdMap.set(p.email, p.user_id);
                                    if (p.avatar_url) {
                                        avatarMap.set(p.user_id, p.avatar_url);
                                    }
                                }
                            });
                        }
                    } catch (emailError) {
                        console.warn('Could not resolve students by email:', emailError);
                    }
                }

                // 5. Group by Class
                const groups: ClassGroup[] = classes.map(cls => ({
                    class_id: cls.id,
                    class_name: cls.class_name,
                    students: []
                }));

                const flatList: EligibleStudent[] = [];

                data?.forEach((item: any) => {
                    // Try to resolve ID if missing
                    let studentId = item.student_id;
                    if (!studentId && item.email) {
                        studentId = emailToIdMap.get(item.email);
                    }

                    // Only include if we have a valid ID (either originally present or resolved)
                    if (!studentId) return;

                    const clsGroup = groups.find(g => g.class_id === item.class_id);
                    if (clsGroup) {
                        const student: EligibleStudent = {
                            id: studentId,
                            full_name: item.student_name || item.email?.split('@')[0] || 'Unknown Student',
                            email: item.email || '',
                            avatar_url: avatarMap.get(studentId),
                            class_name: clsGroup.class_name
                        };

                        // Avoid duplicates in the same class (e.g. if Excel had dupes)
                        if (!clsGroup.students.some(s => s.id === student.id)) {
                            clsGroup.students.push(student);
                        }

                        if (!flatList.some(s => s.id === student.id)) {
                            flatList.push(student);
                        }
                    }
                });

                // Filter out empty classes so the UI doesn't render blank space or think we have data when we don't
                const nonEmptyGroups = groups.filter(g => g.students.length > 0);
                setClassGroups(nonEmptyGroups);
                setStudents(flatList);

            } catch (err) {
                console.error('Error fetching eligible students:', err);
            } finally {
                setLoading(false);
            }
        };

        fetchStudents();

        const subscription = supabase
            .channel('eligible_students_changes')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'class_students'
                },
                () => {
                    fetchStudents();
                }
            )
            .subscribe();

        return () => {
            subscription.unsubscribe();
        };

    }, [user]);

    return { students, classGroups, loading };
}

import * as XLSX from 'xlsx';

export interface StudentData {
    registerNumber: string;
    studentName: string;
    email: string;
    department?: string;
    course?: string;
    year?: string;
    section?: string;
    phone?: string;
}

export interface ValidationError {
    row: number;
    field: string;
    message: string;
}

export function useExcelImport() {
    const parseExcelFile = async (file: File): Promise<{ data: StudentData[]; errors: ValidationError[] }> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();

            reader.onload = (e) => {
                try {
                    const data = e.target?.result;
                    const workbook = XLSX.read(data, { type: 'binary' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const jsonData = XLSX.utils.sheet_to_json(worksheet);

                    const students: StudentData[] = [];
                    const errors: ValidationError[] = [];

                    jsonData.forEach((row: any, index: number) => {
                        const rowNumber = index + 2; // +2 because Excel is 1-indexed and has header row

                        // Validate required fields
                        if (!row['Register Number'] && !row['registerNumber']) {
                            errors.push({
                                row: rowNumber,
                                field: 'Register Number',
                                message: 'Register Number is required',
                            });
                        }

                        if (!row['Student Name'] && !row['studentName']) {
                            errors.push({
                                row: rowNumber,
                                field: 'Student Name',
                                message: 'Student Name is required',
                            });
                        }

                        if (!row['Email'] && !row['email']) {
                            errors.push({
                                row: rowNumber,
                                field: 'Email',
                                message: 'Email is required',
                            });
                        } else {
                            const email = row['Email'] || row['email'];
                            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                            if (!emailRegex.test(email)) {
                                errors.push({
                                    row: rowNumber,
                                    field: 'Email',
                                    message: 'Invalid email format',
                                });
                            }
                        }

                        // If no critical errors, add student
                        if (
                            (row['Register Number'] || row['registerNumber']) &&
                            (row['Student Name'] || row['studentName']) &&
                            (row['Email'] || row['email'])
                        ) {
                            students.push({
                                registerNumber: row['Register Number'] || row['registerNumber'],
                                studentName: row['Student Name'] || row['studentName'],
                                email: row['Email'] || row['email'],
                                department: row['Department'] || row['department'] || '',
                                course: row['Course'] || row['course'] || '',
                                year: row['Year'] || row['year'] || '',
                                section: row['Section'] || row['section'] || '',
                                phone: row['Phone'] || row['phone'] || '',
                            });
                        }
                    });

                    resolve({ data: students, errors });
                } catch (error) {
                    reject(error);
                }
            };

            reader.onerror = () => {
                reject(new Error('Failed to read file'));
            };

            reader.readAsBinaryString(file);
        });
    };

    const validateStudentData = (students: StudentData[]): ValidationError[] => {
        const errors: ValidationError[] = [];
        const registerNumbers = new Set<string>();
        const emails = new Set<string>();

        students.forEach((student, index) => {
            const rowNumber = index + 2;

            // Check for duplicate register numbers
            if (registerNumbers.has(student.registerNumber)) {
                errors.push({
                    row: rowNumber,
                    field: 'Register Number',
                    message: `Duplicate register number: ${student.registerNumber}`,
                });
            } else {
                registerNumbers.add(student.registerNumber);
            }

            // Check for duplicate emails
            if (emails.has(student.email)) {
                errors.push({
                    row: rowNumber,
                    field: 'Email',
                    message: `Duplicate email: ${student.email}`,
                });
            } else {
                emails.add(student.email);
            }
        });

        return errors;
    };

    const generateTemplate = () => {
        const template = [
            {
                'Register Number': '2024001',
                'Student Name': 'John Doe',
                'Email': 'john.doe@example.com',
                'Department': 'Computer Science',
                'Course': 'B.Tech',
                'Year': '2024',
                'Section': 'A',
                'Phone': '+1234567890',
            },
        ];

        const worksheet = XLSX.utils.json_to_sheet(template);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, 'Students');

        // Add instructions sheet
        const instructions = [
            { Instruction: 'Fill in student details in the Students sheet' },
            { Instruction: 'Register Number, Student Name, and Email are required fields' },
            { Instruction: 'Other fields are optional' },
            { Instruction: 'Do not modify the column headers' },
            { Instruction: 'Save the file and upload it to import students' },
        ];

        const instructionsSheet = XLSX.utils.json_to_sheet(instructions);
        XLSX.utils.book_append_sheet(workbook, instructionsSheet, 'Instructions');

        // Download file
        XLSX.writeFile(workbook, 'student_import_template.xlsx');
    };

    return {
        parseExcelFile,
        validateStudentData,
        generateTemplate,
    };
}

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { notifyNewAssignment, notifyAssignmentUpdated } from "@/lib/notificationService";

export interface Assignment {
    id: string;
    title: string;
    course_id: string;
    subject_id?: string;
    course_title?: string;
    course_code?: string;
    subject_name?: string;
    description: string | null;
    due_date: string | null;
    max_points: number | null;
    status: string | null;
    attachment_url: string | null;
    attachment_name: string | null;
    created_at: string;
    submission_count?: number;
}

export interface Subject {
    id: string;
    name: string;
    code: string | null;
    class_id: string;
}

export interface CreateAssignmentDTO {
    title: string;
    description: string;
    course_id: string;
    subject_id: string;
    due_date: Date;
    attachment_url: string;  // Now required
    attachment_name: string; // Now required
}

export function useLecturerAssignments() {
    const { user } = useAuth();
    const [rawAssignments, setRawAssignments] = useState<any[]>([]);
    const [courses, setCourses] = useState<{ id: string; title: string; course_code: string }[]>([]);
    const [subjects, setSubjects] = useState<Subject[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchCourses = async () => {
        if (!user) return;
        try {
            const { data, error } = await supabase
                .from("courses")
                .select("id, title, course_code")
                .eq("lecturer_id", user.id);

            if (error) throw error;
            setCourses(data || []);
            return data;
        } catch (error) {
            console.error("Error fetching courses:", error);
            return [];
        }
    };

    const fetchSubjects = async (classId: string): Promise<Subject[]> => {
        try {
            const { data, error } = await supabase
                .from("subjects")
                .select("*")
                .eq("class_id", classId);

            if (error) throw error;
            return (data || []) as Subject[];
        } catch (error) {
            console.error("Error fetching subjects:", error);
            return [];
        }
    };

    const fetchAssignments = async () => {
        if (!user) return;
        try {
            setLoading(true);

            // Fetch Raw Assignments (No Join)
            const { data, error } = await supabase
                .from("assignments")
                .select("*")
                .eq("lecturer_id", user.id)
                .order("created_at", { ascending: false });

            if (error) throw error;
            setRawAssignments(data || []);

        } catch (error: any) {
            console.error("Error fetching assignments:", error);
            toast.error("Failed to load assignments");
        } finally {
            setLoading(false);
        }
    };

    const createAssignment = async (data: CreateAssignmentDTO) => {
        if (!user) return { success: false, error: "Not authenticated" };

        try {
            // Insert assignment with text fields for course and subject
            const { data: newAssignment, error: assignmentError } = await supabase
                .from("assignments")
                .insert({
                    lecturer_id: user.id,
                    title: data.title,
                    description: data.description,
                    course_name: data.course_id, // Using course_id field as course_name (text)
                    subject_name: data.subject_id, // Using subject_id field as subject_name (text)
                    due_date: data.due_date.toISOString(),
                    attachment_url: data.attachment_url,
                    attachment_name: data.attachment_name,
                    status: "active" // Changed from "published" to match database constraint
                } as any) // Type assertion to bypass TypeScript type checking
                .select()
                .single();

            if (assignmentError) {
                console.error("Assignment creation error:", assignmentError);
                throw assignmentError;
            }

            // Get the course to find associated class
            const { data: course } = await supabase
                .from("courses")
                .select("id, course_code")
                .eq("id", data.course_id)
                .single();

            // Find the class associated with this course (by matching course_code)
            let classId: string | null = null;
            if (course) {
                const { data: matchingClass } = await supabase
                    .from("classes")
                    .select("id")
                    .eq("course_code", course.course_code)
                    .eq("lecturer_id", user.id)
                    .eq("is_active", true)
                    .maybeSingle();

                classId = matchingClass?.id || null;
            }

            // Only notify students enrolled in the specific class (if class exists)
            if (classId) {
                // Get enrolled students from class_students table
                const { data: enrolledStudents, error: studentsError } = await supabase
                    .from("class_students")
                    .select("student_id")
                    .eq("class_id", classId)
                    .not("student_id", "is", null); // Only students with accounts

                if (!studentsError && enrolledStudents && enrolledStudents.length > 0) {
                    const studentIds = enrolledStudents.map(s => s.student_id).filter(Boolean) as string[];

                    // Use the centralized notification service
                    await notifyNewAssignment(
                        studentIds,
                        data.title,
                        newAssignment.id,
                        user.id,
                        classId,
                        data.due_date.toISOString()
                    );
                }
            }

            toast.success("Assignment created successfully!");
            fetchAssignments();
            return { success: true };
        } catch (error: any) {
            console.error("Error creating assignment:", error);
            const errorMessage = error.message || error.hint || "Failed to create assignment. Please check the database schema.";
            toast.error(errorMessage);
            return { success: false, error: errorMessage };
        }
    };

    const updateAssignment = async (id: string, data: Partial<CreateAssignmentDTO>) => {
        if (!user) return { success: false, error: "Not authenticated" };

        try {
            const updates: any = {
                title: data.title,
                description: data.description,
                subject_name: data.subject_id, // Using subject_id field as subject_name text
                due_date: data.due_date?.toISOString(),
                attachment_url: data.attachment_url,
                attachment_name: data.attachment_name,
            };

            // Remove undefined keys
            Object.keys(updates).forEach(key => updates[key] === undefined && delete updates[key]);

            const { error } = await supabase
                .from("assignments")
                .update(updates)
                .eq("id", id)
                .eq("lecturer_id", user.id);

            if (error) throw error;

            // Send update notifications to enrolled students
            try {
                // Get assignment details
                const { data: assignment } = await supabase
                    .from("assignments")
                    .select("title, course_name")
                    .eq("id", id)
                    .single();

                if (assignment) {
                    // Find class by course_name (which stores course_code)
                    const { data: matchingClass } = await supabase
                        .from("classes")
                        .select("id")
                        .eq("course_code", assignment.course_name)
                        .eq("lecturer_id", user.id)
                        .eq("is_active", true)
                        .maybeSingle();

                    if (matchingClass) {
                        // Get enrolled students
                        const { data: enrolledStudents } = await supabase
                            .from("class_students")
                            .select("student_id")
                            .eq("class_id", matchingClass.id)
                            .not("student_id", "is", null);

                        if (enrolledStudents && enrolledStudents.length > 0) {
                            const studentIds = enrolledStudents.map(s => s.student_id).filter(Boolean) as string[];

                            // Use the centralized notification service
                            await notifyAssignmentUpdated(
                                studentIds,
                                assignment.title,
                                id,
                                "The assignment details have been updated.",
                                user.id,
                                matchingClass.id
                            );
                        }
                    }
                }
            } catch (notifError) {
                console.warn("Failed to send update notifications:", notifError);
            }

            toast.success("Assignment updated successfully!");
            fetchAssignments();
            return { success: true };
        } catch (error: any) {
            console.error("Error updating assignment:", error);
            toast.error(error.message || "Failed to update assignment");
            return { success: false, error: error.message };
        }
    };

    const deleteAssignment = async (id: string) => {
        try {
            const { error } = await supabase
                .from("assignments")
                .delete()
                .eq("id", id);

            if (error) throw error;

            toast.success("Assignment deleted");
            setRawAssignments(prev => prev.filter(a => a.id !== id));
            return { success: true };
        } catch (error: any) {
            console.error("Error deleting assignment:", error);
            toast.error("Failed to delete assignment");
            return { success: false, error: error.message };
        }
    };

    useEffect(() => {
        // Initial fetch sequence
        const init = async () => {
            setLoading(true);
            await fetchCourses();
            await fetchAssignments();
            setLoading(false);
        };
        init();
    }, [user]);

    // Client-side Join
    const assignments: Assignment[] = rawAssignments.map((item) => {
        const course = courses.find(c => c.id === item.course_id);
        return {
            ...item,
            course_title: course?.title || "Unknown Course",
            course_code: course?.course_code || "N/A",
        };
    });

    return {
        assignments,
        courses,
        subjects,
        loading,
        createAssignment,
        updateAssignment,
        deleteAssignment,
        fetchSubjects,
        refreshParams: fetchAssignments
    };
}

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { format } from "date-fns";
import { toast } from "sonner";

// ── Module-level cache ───────────────────────────────────────────────────────
const lecturerStatsCache = new Map<string, DashboardStats>();
const recentSubmissionsCache = new Map<string, RecentActivity[]>();
const upcomingClassesCache = new Map<string, UpcomingClass[]>();
const activeTasksCache = new Map<string, ActiveTaskSummary[]>();

export interface DashboardStats {
    enrolledStudents: number;
    submissionsReceived: number;
    pendingSubmissions: number;
    totalExpectedSubmissions: number; // For "X / Y" format display
}

export interface ActiveTaskSummary {
    id: string;
    title: string;
    type: 'assignment' | 'quiz';
    courseCode: string;
    className: string;
    submittedCount: number;
    totalStudents: number;
    dueDate?: string | null;
}

export interface RecentActivity {
    id: string;
    studentName: string;
    assignmentTitle: string; // Used for quiz title too
    courseCode: string;
    className: string;
    submittedAt: string;
    status: "pending" | "graded" | "submitted" | "passed" | "failed";
    grade: string | null;
    classId?: string;
    assignmentId?: string; // Used for quizId too
    quizId?: string;
    type: 'assignment' | 'quiz';
    action?: 'submitted' | 'updated' | 'deleted';
}
// ... (keep existing code until line 170)


export interface UpcomingClass {
    id: string;
    title: string;
    courseCode: string; // From joined class
    className: string; // From joined class
    time: string;
    room: string;
    isToday: boolean;
    day: string;
    classId?: string;
}

export function useLecturerData() {
    const { user } = useAuth();
    const [stats, setStats] = useState<DashboardStats>(() => {
        if (user && lecturerStatsCache.has(user.id)) {
            return lecturerStatsCache.get(user.id)!;
        }
        return {
            enrolledStudents: 0,
            submissionsReceived: 0,
            pendingSubmissions: 0,
            totalExpectedSubmissions: 0,
        };
    });
    const [recentSubmissions, setRecentSubmissions] = useState<RecentActivity[]>(() => {
        if (user && recentSubmissionsCache.has(user.id)) {
            return recentSubmissionsCache.get(user.id) || [];
        }
        return [];
    });
    const [upcomingClasses, setUpcomingClasses] = useState<UpcomingClass[]>(() => {
        if (user && upcomingClassesCache.has(user.id)) {
            return upcomingClassesCache.get(user.id) || [];
        }
        return [];
    });
    const [totalTasks, setTotalTasks] = useState<ActiveTaskSummary[]>(() => {
        if (user && activeTasksCache.has(user.id)) {
            return activeTasksCache.get(user.id) || [];
        }
        return [];
    });

    const [loading, setLoading] = useState(() => {
        if (!user) return false;
        return !lecturerStatsCache.has(user.id);
    });
    const [isInitialLoad, setIsInitialLoad] = useState(() => {
        if (!user) return true;
        return !lecturerStatsCache.has(user.id);
    });

    // silentRefresh: when true, don't trigger loading state (for real-time updates)
    const fetchData = async (silentRefresh = false) => {
        if (!user) return;

        try {
            // Only show loading spinner on initial load, not on real-time updates
            if (!silentRefresh && !lecturerStatsCache.has(user.id)) {
                setLoading(true);
            }

            // 1. Fetch Lecturer's Active Classes
            const { data: classes, error: classesError } = await supabase
                .from("classes")
                .select("id, course_code, class_name")
                .eq("lecturer_id", user.id)
                .eq("is_active", true);

            if (classesError) throw classesError;

            const classIds = classes.map(c => c.id);
            const classesMap = new Map(classes.map(c => [c.id, c]));

            let enrolledStudents = 0;
            let submissionsReceived = 0;
            let pendingSubmissions = 0;
            let totalExpectedSubmissions = 0;
            const allActivities: RecentActivity[] = [];

            // Pre-fetch all IDs needed for counts and activity
            let allAssignmentIds: string[] = [];
            const { data: directAssignments } = await (supabase.from("assignments") as any).select("id, class_id").eq("lecturer_id", user.id);
            if (directAssignments) allAssignmentIds = (directAssignments as any[]).map(a => a.id);
            if (classIds.length > 0) {
                const { data: classAssignments } = await (supabase.from("assignments") as any).select("id, class_id").in("class_id", classIds);
                if (classAssignments) allAssignmentIds = [...new Set([...allAssignmentIds, ...(classAssignments as any[]).map(a => a.id)])];
            }

            let lecturerQuizIds: string[] = [];
            if (classIds.length > 0) {
                const { data: classQuizzes, error } = await (supabase.from("quizzes") as any).select("id, class_id").in("class_id", classIds);
                if (!error && classQuizzes) {
                    lecturerQuizIds = classQuizzes.map((q: any) => q.id);
                }
            }

            let taskSummaries: ActiveTaskSummary[] = [];

            if (classIds.length > 0) {
                // A. Enrolled Students
                const { data: acceptedEnrollments } = await supabase.from("access_requests").select("student_id, class_id").in("class_id", classIds).eq("status", "accepted");
                const uniqueStudents = new Set(acceptedEnrollments?.map(e => e.student_id));
                enrolledStudents = uniqueStudents.size;

                const classStudentCounts = new Map<string, number>();
                acceptedEnrollments?.forEach(e => {
                    if (e.class_id) classStudentCounts.set(e.class_id, (classStudentCounts.get(e.class_id) || 0) + 1);
                });

                // B. Assignments Stats
                if (allAssignmentIds.length > 0) {
                    const { count: submissionCount } = await supabase.from("assignment_submissions").select("*", { count: 'exact', head: true }).in("assignment_id", allAssignmentIds);
                    submissionsReceived = (submissionCount || 0);

                    const { data: assignmentDetails } = await supabase.from("assignments").select("id, title, class_id, due_date").in("id", allAssignmentIds).or("status.eq.published,status.eq.active,status.eq.completed,status.eq.closed");

                    for (const a of assignmentDetails || []) {
                        if (a.class_id && classStudentCounts.has(a.class_id)) {
                            totalExpectedSubmissions += classStudentCounts.get(a.class_id) || 0;

                            const { count } = await supabase.from("assignment_submissions").select("*", { count: 'exact', head: true }).eq("assignment_id", a.id);
                            const classInfo = classesMap.get(a.class_id);
                            taskSummaries.push({
                                id: a.id,
                                title: a.title,
                                type: 'assignment',
                                courseCode: classInfo?.course_code || 'N/A',
                                className: classInfo?.class_name || 'Class',
                                submittedCount: count || 0,
                                totalStudents: classStudentCounts.get(a.class_id) || 0,
                                dueDate: a.due_date
                            });
                        }
                    }
                }

                // C. Quizzes Stats (Used only for Active Tasks summary now, not global stats)
                if (lecturerQuizIds.length > 0) {
                    const { data: quizDetails } = await supabase.from("quizzes").select("id, title, class_id").in("id", lecturerQuizIds).eq("status", "published");

                    for (const q of quizDetails || []) {
                        if (q.class_id && classStudentCounts.has(q.class_id)) {
                            const { count } = await supabase.from("quiz_submissions").select("*", { count: 'exact', head: true }).eq("quiz_id", q.id);
                            const classInfo = classesMap.get(q.class_id);
                            taskSummaries.push({
                                id: q.id,
                                title: q.title,
                                type: 'quiz',
                                courseCode: classInfo?.course_code || 'N/A',
                                className: classInfo?.class_name || 'Class',
                                submittedCount: count || 0,
                                totalStudents: classStudentCounts.get(q.class_id) || 0
                            });
                        }
                    }
                }
                setTotalTasks(taskSummaries);
            }

            pendingSubmissions = Math.max(0, totalExpectedSubmissions - submissionsReceived);

            const newStats = {
                enrolledStudents,
                submissionsReceived,
                pendingSubmissions,
                totalExpectedSubmissions
            };
            setStats(newStats);
            lecturerStatsCache.set(user.id, newStats);
            activeTasksCache.set(user.id, taskSummaries);

            // 2. Fetch Recent Activity for Feed
            if (allAssignmentIds.length > 0) {
                const { data: submissionsData } = await supabase.from("assignment_submissions").select(`
                    id, assignment_id, submitted_at, status, grade, student_id
                `).in("assignment_id", allAssignmentIds).order("submitted_at", { ascending: false }).limit(10);

                let submissions: any[] = submissionsData || [];
                if (submissions.length > 0) {
                    const studentIds = [...new Set(submissions.map(s => s.student_id).filter(Boolean))];
                    if (studentIds.length > 0) {
                        const { data: profiles } = await supabase.from('profiles').select('user_id, full_name').in('user_id', studentIds);
                        const profileMap = new Map(profiles?.map(p => [p.user_id, p]) || []);
                        submissions = submissions.map(s => ({
                            ...s,
                            student: profileMap.get(s.student_id) as any
                        }));
                    }

                    const assignmentIds = [...new Set(submissions.map(s => s.assignment_id).filter(Boolean))];
                    if (assignmentIds.length > 0) {
                        const { data: assignments } = await supabase.from('assignments').select('id, title, class_id').in('id', assignmentIds);
                        const assignmentMap = new Map(assignments?.map(a => [a.id, a]) || []);
                        submissions = submissions.map(s => ({
                            ...s,
                            assignment: assignmentMap.get(s.assignment_id) as any
                        }));
                    }
                }

                // Assignment activity only
                submissions?.forEach(sub => {
                    const assignmentData = sub.assignment as any;
                    const classId = assignmentData?.class_id;
                    allActivities.push({
                        id: sub.id,
                        studentName: (sub.student as any)?.full_name || "Unknown Student",
                        assignmentTitle: assignmentData?.title || "Untitled",
                        courseCode: classId && classesMap.has(classId) ? classesMap.get(classId)?.course_code || "N/A" : "N/A",
                        className: classId && classesMap.has(classId) ? classesMap.get(classId)?.class_name || "Unknown Class" : "Unknown Class",
                        submittedAt: sub.submitted_at,
                        status: sub.status === "graded" ? "graded" : "pending",
                        grade: sub.grade ? sub.grade.toString() : null,
                        classId: classId,
                        assignmentId: assignmentData?.id || sub.assignment_id,
                        type: 'assignment'
                    });
                });
            }

            const finalActivities = allActivities
                .sort((a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime())
                .slice(0, 10)
                .map(act => ({ ...act, submittedAt: format(new Date(act.submittedAt), "MMM d, h:mm a") }));

            setRecentSubmissions(finalActivities);
            recentSubmissionsCache.set(user.id, finalActivities);

            // 3. Fetch Upcoming Classes
            const { data: schedules } = await supabase.from("schedules").select(`*, classes:class_id(class_name, course_code)`).eq("lecturer_id", user.id).order("day_of_week", { ascending: true }).order("start_time", { ascending: true });
            if (schedules) {
                const todayIndex = new Date().getDay();
                const days = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
                const mappedClasses: UpcomingClass[] = schedules.map((s: any) => ({
                    id: s.id,
                    title: s.title,
                    courseCode: s.classes?.course_code || "Class",
                    className: s.classes?.class_name || "",
                    time: s.start_time.slice(0, 5),
                    room: s.location || "Online",
                    isToday: s.day_of_week === todayIndex,
                    day: days[s.day_of_week],
                    classId: s.class_id
                })).sort((a, b) => a.isToday === b.isToday ? 0 : a.isToday ? -1 : 1).slice(0, 5);
                setUpcomingClasses(mappedClasses);
                upcomingClassesCache.set(user.id, mappedClasses);
            }

        } catch (error) {
            console.error("Error fetching lecturer data:", error);
        } finally {
            setLoading(false);
            setIsInitialLoad(false);
        }
    };

    useEffect(() => {
        fetchData();
        const silentFetch = () => fetchData(true);

        const assignmentChannel = supabase.channel('dashboard_assignments').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'assignment_submissions' }, async (payload) => {
            const submission = payload.new as any;
            try {
                const { data: studentData } = await supabase.from('profiles').select('full_name').eq('user_id', submission.student_id).single();
                const { data: assignmentData } = await supabase.from('assignments').select('title, class_id').eq('id', submission.assignment_id).single();
                if (assignmentData) {
                    const { data: classData } = await supabase.from('classes').select('class_name, course_code').eq('id', assignmentData.class_id).single();
                    const newActivity: RecentActivity = {
                        id: submission.id,
                        studentName: studentData?.full_name || 'Unknown Student',
                        assignmentTitle: assignmentData?.title || 'Unknown Assignment',
                        courseCode: classData?.course_code || 'N/A',
                        className: classData?.class_name || 'Unknown Class',
                        submittedAt: format(new Date(), "MMM d, h:mm a"),
                        status: submission.status,
                        grade: submission.grade,
                        assignmentId: submission.assignment_id,
                        classId: assignmentData.class_id,
                        type: 'assignment',
                        action: 'submitted'
                    };
                    setStats(prev => ({ ...prev, submissionsReceived: prev.submissionsReceived + 1, pendingSubmissions: Math.max(0, prev.pendingSubmissions - 1) }));
                    setRecentSubmissions(prev => [newActivity, ...prev.slice(0, 9)]);
                    toast.success(`New Submission: ${studentData?.full_name}`, { description: `Submitted ${assignmentData?.title}` });
                }
            } catch (err) { silentFetch(); }
        }).subscribe();

        const quizChannel = supabase.channel('dashboard_quizzes').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'quiz_submissions' }, async (payload) => {
            const submission = payload.new as any;
            try {
                const { data: studentData } = await supabase.from('profiles').select('full_name').eq('user_id', submission.student_id).single();
                const { data: quizData } = await supabase.from('quizzes').select('title, class_id').eq('id', submission.quiz_id).single();
                if (quizData) {
                    const { data: classData } = await supabase.from('classes').select('class_name, course_code').eq('id', quizData.class_id).single();
                    const newActivity: RecentActivity = {
                        id: submission.id,
                        studentName: studentData?.full_name || 'Unknown Student',
                        assignmentTitle: quizData?.title || 'Unknown Quiz',
                        courseCode: classData?.course_code || 'N/A',
                        className: classData?.class_name || 'Unknown Class',
                        submittedAt: format(new Date(), "MMM d, h:mm a"),
                        status: submission.status,
                        grade: submission.total_obtained?.toString() || null,
                        quizId: submission.quiz_id,
                        classId: quizData.class_id,
                        type: 'quiz',
                        action: 'submitted'
                    };
                    toast.success(`Quiz Completed: ${studentData?.full_name}`, { description: `Finished ${quizData?.title}` });
                }
            } catch (err) { silentFetch(); }
        }).subscribe();

        const subs = [
            supabase.channel('dashboard_class_students').on('postgres_changes', { event: '*', schema: 'public', table: 'class_students' }, silentFetch).subscribe(),
            supabase.channel('dashboard_classes').on('postgres_changes', { event: '*', schema: 'public', table: 'classes' }, silentFetch).subscribe(),
            supabase.channel('dashboard_schedules').on('postgres_changes', { event: '*', schema: 'public', table: 'schedules' }, silentFetch).subscribe(),
            supabase.channel('dashboard_access_requests').on('postgres_changes', { event: '*', schema: 'public', table: 'access_requests' }, silentFetch).subscribe()
        ];

        return () => {
            assignmentChannel.unsubscribe();
            quizChannel.unsubscribe();
            subs.forEach(s => s.unsubscribe());
        };
    }, [user]);

    return { stats, recentSubmissions, upcomingClasses, activeTasks: totalTasks, loading };
}

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface EnrolledStudent {
    student_id: string;
    full_name: string;
    email: string | null;
    avatar_url: string | null;
    courses: string[]; // List of course codes this student is taking with this lecturer
}

export function useLecturerStudents() {
    const { user } = useAuth();
    const [students, setStudents] = useState<EnrolledStudent[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStudents = async () => {
            if (!user) return;

            try {
                setLoading(true);

                // 1. Get all courses taught by this lecturer
                const { data: courses, error: courseError } = await supabase
                    .from("courses")
                    .select("id, course_code")
                    .eq("lecturer_id", user.id);

                if (courseError) throw courseError;

                if (!courses || courses.length === 0) {
                    setStudents([]);
                    return;
                }

                const courseIds = courses.map(c => c.id);

                // 2. Get all enrollments for these courses, joined with student profiles
                const { data: enrollments, error: enrollError } = await supabase
                    .from("course_enrollments")
                    .select(`
            student_id,
            course_id,
            profiles:student_id (
              full_name,
              email,
              avatar_url
            )
          `)
                    .in("course_id", courseIds);

                if (enrollError) throw enrollError;

                // 3. Process data to group by student
                const studentMap = new Map<string, EnrolledStudent>();

                enrollments?.forEach((enrollment: any) => {
                    const studentId = enrollment.student_id;
                    const courseCode = courses.find(c => c.id === enrollment.course_id)?.course_code || "Unknown";
                    const profile = enrollment.profiles;

                    if (studentMap.has(studentId)) {
                        studentMap.get(studentId)?.courses.push(courseCode);
                    } else {
                        studentMap.set(studentId, {
                            student_id: studentId,
                            full_name: profile?.full_name || "Unknown Student",
                            email: profile?.email || null,
                            avatar_url: profile?.avatar_url || null,
                            courses: [courseCode]
                        });
                    }
                });

                setStudents(Array.from(studentMap.values()));

            } catch (error) {
                console.error("Error fetching students:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchStudents();
    }, [user]);

    return { students, loading };
}

import { useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { notifyNewMessage } from '@/lib/notificationService';

interface Message {
    id: string;
    conversation_id: string;
    sender_id: string;
    receiver_id: string;
    content: string;
    attachment_name: string | null;
    attachment_url: string | null;
    attachment_type: string | null;
    attachment_size: string | null;
    is_read: boolean;
    read_at?: string | null;
    created_at: string;
    sender_name?: string;
    is_edited?: boolean;
    edit_count?: number;
    last_edited_at?: string;
}

interface Conversation {
    id: string;
    participant_1: string;
    participant_2: string;
    last_message: string | null;
    last_message_at: string | null;
    other_user_name?: string;
    other_user_avatar?: string;
    other_user_role?: string;
    online?: boolean;
    cleared_at?: Record<string, string> | null;
    visible_to?: string[] | null;
    auto_delete_settings?: Record<string, boolean>;
}

interface Attachment {
    name?: string;
    url?: string;
    type?: string;
    size?: string;
    status?: 'started' | 'ended' | 'missed' | 'declined';
}

export function useMessages() {
    const { user, profile } = useAuth();
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [messages, setMessages] = useState<Message[]>([]);
    const [selectedConversationId, setSelectedConversationId] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<Error | null>(null);
    const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());

    // Pagination state
    const [hasMore, setHasMore] = useState(false);
    const PAGE_SIZE = 20;
    const channelRef = useRef<ReturnType<typeof supabase.channel> | null>(null);

    const fetchConversations = useCallback(async () => {
        if (!user) return;

        try {
            const { data, error: fetchError } = await (supabase
                .from('conversations')
                .select('*')
                .or(`participant_1.eq.${user.id},participant_2.eq.${user.id}`)
                .order('last_message_at', { ascending: false }) as any);

            if (fetchError) {
                console.warn('Error fetching conversations:', fetchError);
                setConversations([]);
            } else {
                // Filter conversations where user is in visible_to
                const visibleConversations = (data || []).filter(conv =>
                    !conv.visible_to || conv.visible_to.includes(user.id)
                );

                // Fetch other user details
                const conversationsWithUsers = await Promise.all(
                    visibleConversations.map(async (conv) => {
                        const otherUserId = conv.participant_1 === user.id ? conv.participant_2 : conv.participant_1;

                        const { data: profileData } = await supabase
                            .from('profiles')
                            .select('full_name, avatar_url')
                            .eq('user_id', otherUserId)
                            .maybeSingle();

                        // If no profile data, try class_students table (for imported students who haven't registered)
                        let otherUserName = profileData?.full_name;
                        let otherUserAvatar = profileData?.avatar_url;

                        if (!otherUserName) {
                            const { data: classStudentData } = await supabase
                                .from('class_students')
                                .select('student_name, student_image_url')
                                .eq('student_id', otherUserId)
                                .limit(1)
                                .maybeSingle();

                            if (classStudentData) {
                                otherUserName = classStudentData.student_name;
                                otherUserAvatar = classStudentData.student_image_url || otherUserAvatar;
                            }
                        }

                        const { data: roleData } = await supabase
                            .from('user_roles')
                            .select('role')
                            .eq('user_id', otherUserId)
                            .maybeSingle();

                        return {
                            ...conv,
                            other_user_name: otherUserName || 'Unknown User',
                            other_user_avatar: otherUserAvatar,
                            other_user_role: roleData?.role,
                        };
                    })
                );

                setConversations(conversationsWithUsers);
            }
            setError(null);
        } catch (err) {
            console.error('Error fetching conversations:', err);
            setConversations([]);
        } finally {
            setLoading(false);
        }
    }, [user]);

    // Fetch conversations effect
    useEffect(() => {
        if (!user) {
            setLoading(false);
            return;
        }

        fetchConversations();

        const subscription = supabase
            .channel('conversations_global')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'conversations' },
                () => fetchConversations()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(subscription);
        };
    }, [user, fetchConversations]);

    const markMessagesAsRead = useCallback(async (conversationId: string) => {
        if (!user) return;
        try {
            await supabase
                .from('messages')
                .update({ is_read: true, read_at: new Date().toISOString() })
                .eq('conversation_id', conversationId)
                .eq('receiver_id', user.id)
                .is('read_at', null); // Only update if not already read
        } catch (err) {
            console.error('Error marking messages as read:', err);
        }
    }, [user]);

    // Fetch messages effect
    useEffect(() => {
        if (!selectedConversationId || !user) return;

        const fetchMessages = async (isLoadMore = false) => {
            try {
                const currentLength = isLoadMore ? messages.length : 0;
                const from = currentLength;
                const to = from + PAGE_SIZE - 1;

                const { data, error: fetchError } = await supabase
                    .from('messages')
                    .select('*')
                    .eq('conversation_id', selectedConversationId)
                    .order('created_at', { ascending: false })
                    .range(from, to);

                if (fetchError) throw fetchError;

                let filteredData = data || [];
                const currentConv = conversations.find(c => c.id === selectedConversationId);

                if (currentConv?.cleared_at && currentConv.cleared_at[user.id]) {
                    const clearedTime = new Date(currentConv.cleared_at[user.id]).getTime();
                    filteredData = filteredData.filter(msg => new Date(msg.created_at).getTime() > clearedTime);
                }

                // Apply individual auto-delete filter (15 days rolling window)
                if (currentConv?.auto_delete_settings?.[user.id]) {
                    const fifteenDaysAgo = Date.now() - (15 * 24 * 60 * 60 * 1000);
                    filteredData = filteredData.filter(msg => new Date(msg.created_at).getTime() > fifteenDaysAgo);
                }

                const newMessages = [...filteredData].reverse();
                if (isLoadMore) {
                    setMessages(prev => [...newMessages, ...prev]);
                } else {
                    setMessages(newMessages);
                }
                setHasMore(filteredData.length === PAGE_SIZE);
            } catch (err) {
                console.error('Error in fetchMessages:', err);
            }
        };

        fetchMessages();

        const channel = supabase.channel(`messages_${selectedConversationId}`, {
            config: { broadcast: { self: false } }
        });

        channel
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'messages',
                    filter: `conversation_id=eq.${selectedConversationId}`,
                },
                (payload) => {
                    const newMessage = payload.new as Message;
                    const currentConv = conversations.find(c => c.id === selectedConversationId);

                    setMessages((prev) => {
                        // Filter real-time messages too
                        if (currentConv?.auto_delete_settings?.[user.id]) {
                            const fifteenDaysAgo = Date.now() - (15 * 24 * 60 * 60 * 1000);
                            if (new Date(newMessage.created_at).getTime() <= fifteenDaysAgo) return prev;
                        }

                        if (prev.some(m => m.id === newMessage.id)) return prev;
                        return [...prev, newMessage];
                    });
                    if (newMessage.sender_id !== user.id) {
                        markMessagesAsRead(selectedConversationId);
                    }
                }
            )
            .on(
                'broadcast',
                { event: 'typing' },
                (payload) => {
                    const typerId = payload.payload.userId;
                    if (typerId !== user.id) {
                        setTypingUsers(prev => {
                            const newSet = new Set(prev);
                            newSet.add(typerId);
                            return newSet;
                        });
                        setTimeout(() => {
                            setTypingUsers(prev => {
                                const newSet = new Set(prev);
                                newSet.delete(typerId);
                                return newSet;
                            });
                        }, 3000);
                    }
                }
            )
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'messages',
                    filter: `conversation_id=eq.${selectedConversationId}`,
                },
                (payload) => {
                    const updatedMessage = payload.new as Message;
                    setMessages((prev) =>
                        prev.map(m => m.id === updatedMessage.id ? updatedMessage : m)
                    );
                }
            )
            .subscribe();

        channelRef.current = channel;

        return () => {
            supabase.removeChannel(channel);
            channelRef.current = null;
        };
    }, [selectedConversationId, user, conversations, markMessagesAsRead]);

    const sendTyping = async () => {
        if (!channelRef.current || !user) return;
        await channelRef.current.send({
            type: 'broadcast',
            event: 'typing',
            payload: { userId: user.id }
        });
    };

    const sendMessage = async (receiverId: string, content: string, attachment?: Attachment) => {
        if (!user || (!content.trim() && !attachment)) return;

        const finalContent = content.trim() || (attachment ? 'Sent an attachment' : '');
        const optimisticId = crypto.randomUUID();
        const timestamp = new Date().toISOString();

        try {
            let conversationId: string | null = null;
            if (selectedConversationId) {
                const currentConv = conversations.find(c => c.id === selectedConversationId);
                if (currentConv && (currentConv.participant_1 === receiverId || currentConv.participant_2 === receiverId)) {
                    conversationId = selectedConversationId;
                }
            }

            const optimisticMessage: Message = {
                id: optimisticId,
                conversation_id: conversationId || 'temp-id',
                sender_id: user.id,
                receiver_id: receiverId,
                content: finalContent,
                attachment_name: attachment?.name || null,
                attachment_url: attachment?.url || null,
                attachment_type: attachment?.type || null,
                attachment_size: attachment?.size || null,
                is_read: false,
                created_at: timestamp,
                sender_name: 'You'
            };

            if (conversationId) {
                setMessages(prev => [...prev, optimisticMessage]);
            }

            if (!conversationId) {
                const { data: existingConv } = await supabase
                    .from('conversations')
                    .select('*')
                    .or(`and(participant_1.eq.${user.id},participant_2.eq.${receiverId}),and(participant_1.eq.${receiverId},participant_2.eq.${user.id})`)
                    .maybeSingle();

                if (existingConv) {
                    conversationId = existingConv.id;
                } else {
                    const { data: newConv, error: convError } = await supabase
                        .from('conversations')
                        .insert({
                            participant_1: user.id,
                            participant_2: receiverId,
                            last_message: content,
                            last_message_at: timestamp,
                            visible_to: [user.id, receiverId] // Critical: set visibility on creation
                        })
                        .select()
                        .single();

                    if (convError) throw convError;
                    conversationId = newConv.id;
                    optimisticMessage.conversation_id = conversationId;
                    setSelectedConversationId(conversationId);
                    setMessages(prev => [...prev, optimisticMessage]);
                }
            } else {
                optimisticMessage.conversation_id = conversationId;
            }

            // Insert real message
            const { error: messageError } = await supabase
                .from('messages')
                .insert({
                    id: optimisticId,
                    conversation_id: conversationId,
                    sender_id: user.id,
                    receiver_id: receiverId,
                    content: finalContent,
                    attachment_name: attachment?.name || null,
                    attachment_url: attachment?.url || null,
                    attachment_type: attachment?.type || null,
                    attachment_size: attachment?.size || null,
                });

            if (messageError) {
                // Retry without attachment_size if error
                const { error: retryError } = await supabase
                    .from('messages')
                    .insert({
                        id: optimisticId,
                        conversation_id: conversationId,
                        sender_id: user.id,
                        receiver_id: receiverId,
                        content: finalContent,
                        attachment_name: attachment?.name || null,
                        attachment_url: attachment?.url || null,
                        attachment_type: attachment?.type || null,
                    });
                if (retryError) {
                    setMessages(prev => prev.filter(m => m.id !== optimisticId));
                    throw retryError;
                }
            }

            // Update conversation and ENSURE VISIBILITY (Resurrection)
            // This is critical for messages "reaching" the other person if they hidden it
            await supabase
                .from('conversations')
                .update({
                    last_message: finalContent,
                    last_message_at: timestamp,
                    visible_to: [user.id, receiverId] // Always reset visibility for both
                })
                .eq('id', conversationId);

            // Trigger Notification (Push + In-App if enabled)
            if (user && profile && conversationId) {
                notifyNewMessage(
                    receiverId,
                    profile.full_name || 'New Message',
                    finalContent,
                    conversationId!,
                    user.id,
                    profile.avatar_url || undefined
                ).catch(err => console.error("Failed to notify message:", err));
            }

            // Manual notification fallback if needed (Optional, but DB trigger is better)
            // We'll skip manual here to avoid double-notification if DB trigger works.

        } catch (err) {
            console.error('Error sending message:', err);
            setMessages(prev => prev.filter(m => m.id !== optimisticId));
            throw err;
        }
    };

    const startConversation = async (otherUserId: string) => {
        if (!user) return null;
        try {
            const { data: existingConv } = await supabase
                .from('conversations')
                .select('id')
                .or(`and(participant_1.eq.${user.id},participant_2.eq.${otherUserId}),and(participant_1.eq.${otherUserId},participant_2.eq.${user.id})`)
                .maybeSingle();

            if (existingConv) {
                setSelectedConversationId(existingConv.id);
                return existingConv.id;
            }

            const { data: newConv, error } = await supabase
                .from('conversations')
                .insert({
                    participant_1: user.id,
                    participant_2: otherUserId,
                    visible_to: [user.id, otherUserId]
                })
                .select()
                .single();

            if (error) throw error;
            await fetchConversations();
            setSelectedConversationId(newConv.id);
            return newConv.id;
        } catch (err) {
            console.error('Error starting conversation:', err);
            return null;
        }
    };

    const deleteMessage = async (messageId: string) => {
        if (!user) return;
        try {
            const { error } = await supabase
                .from('messages')
                .delete()
                .eq('id', messageId)
                .eq('sender_id', user.id);
            if (error) throw error;
            setMessages(prev => prev.filter(m => m.id !== messageId));
        } catch (err) {
            console.error('Error deleting message:', err);
            throw err;
        }
    };

    const clearChat = async (conversationId: string) => {
        if (!user) return;
        try {
            const conversation = conversations.find(c => c.id === conversationId);
            const updatedClearedAt = {
                ...(conversation?.cleared_at || {}),
                [user.id]: new Date().toISOString()
            };
            const { error } = await supabase
                .from('conversations')
                .update({ cleared_at: updatedClearedAt })
                .eq('id', conversationId);
            if (error) throw error;
            setMessages([]);
            setConversations(prev => prev.map(c =>
                c.id === conversationId ? { ...c, cleared_at: updatedClearedAt } : c
            ));
        } catch (err) {
            console.error('Error clearing chat:', err);
            throw err;
        }
    };

    const hideChat = async (conversationId: string) => {
        if (!user) return;
        try {
            const conversation = conversations.find(c => c.id === conversationId);
            if (!conversation) return;
            const updatedVisibleTo = (conversation.visible_to || [conversation.participant_1, conversation.participant_2])
                .filter(id => id !== user.id);
            const { error } = await supabase
                .from('conversations')
                .update({ visible_to: updatedVisibleTo })
                .eq('id', conversationId);
            if (error) throw error;
            setConversations(prev => prev.filter(c => c.id !== conversationId));
            if (selectedConversationId === conversationId) setSelectedConversationId(null);
        } catch (err) {
            console.error('Error hiding chat:', err);
            throw err;
        }
    };

    const unhideChat = async (conversationId: string) => {
        if (!user) return;
        try {
            const { data: conversation } = await supabase
                .from('conversations')
                .select('*')
                .eq('id', conversationId)
                .maybeSingle();

            if (!conversation) return;
            const currentVisible = conversation.visible_to || [conversation.participant_1, conversation.participant_2];
            if (!currentVisible.includes(user.id)) {
                await supabase
                    .from('conversations')
                    .update({ visible_to: [...currentVisible, user.id] })
                    .eq('id', conversationId);
            }
            await fetchConversations();
        } catch (err) {
            console.error('Error unhiding chat:', err);
        }
    };

    const editMessage = async (messageId: string, newContent: string) => {
        if (!user) return;
        try {
            const timestamp = new Date().toISOString();
            // Optimistic
            setMessages(prev => prev.map(m =>
                m.id === messageId ? { ...m, content: newContent, is_edited: true, last_edited_at: timestamp } : m
            ));
            const { error } = await supabase.rpc('edit_message', {
                message_id: messageId,
                new_content: newContent,
                editing_user_id: user.id
            });
            if (error) throw error;
        } catch (err) {
            console.error('Error editing message:', err);
            // Revert
            const { data: original } = await supabase.from('messages').select('*').eq('id', messageId).single();
            if (original) setMessages(prev => prev.map(m => m.id === messageId ? (original as Message) : m));
        }
    };

    const loadMoreMessages = async () => {
        if (!selectedConversationId || !hasMore) return;
        const from = messages.length;
        const to = from + PAGE_SIZE - 1;
        try {
            const { data, error: fetchError } = await supabase
                .from('messages')
                .select('*')
                .eq('conversation_id', selectedConversationId)
                .order('created_at', { ascending: false })
                .range(from, to);
            if (fetchError) throw fetchError;
            const newMessages = [...(data || [])].reverse();
            setMessages(prev => [...newMessages, ...prev]);
            setHasMore(data?.length === PAGE_SIZE);
        } catch (err) {
            console.error("Error in loadMoreMessages:", err);
        }
    };

    return {
        conversations,
        messages,
        selectedConversationId,
        setSelectedConversationId,
        sendMessage,
        startConversation,
        deleteMessage,
        markMessagesAsRead,
        loading,
        error,
        refreshConversations: fetchConversations,
        typingUsers,
        sendTyping,
        clearChat,
        toggleAutoDelete: async (conversationId: string, enabled: boolean) => {
            if (!user) return;
            try {
                const conversation = conversations.find(c => c.id === conversationId);
                const updatedSettings = {
                    ...(conversation?.auto_delete_settings || {}),
                    [user.id]: enabled
                };

                const { error } = await supabase
                    .from('conversations')
                    .update({ auto_delete_settings: updatedSettings })
                    .eq('id', conversationId);

                if (error) throw error;

                // Update local state
                setConversations(prev => prev.map(c =>
                    c.id === conversationId ? { ...c, auto_delete_settings: updatedSettings } : c
                ));
            } catch (err) {
                console.error('Error toggling auto-delete:', err);
                throw err;
            }
        },
        deleteChat: hideChat, // Soft delete compatibility
        hideChat,
        unhideChat,
        finalizeDeleteChat: clearChat,
        editMessage,
        hasMore,
        loadMoreMessages
    };
}

import { useEffect, useState, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

export interface Notification {
    id: string;
    type: string;
    title: string;
    message: string;
    is_read: boolean;
    created_at: string;
    link?: string;
    related_id?: string; // ID of related entity (assignment, message, etc.)
    metadata?: any;
    class_id?: string; // Class association for filtering
}

/**
 * Helper function to check if a notification should be visible to the user
 * Students only see notifications from enrolled classes, access requests, or general notifications
 */
const shouldShowNotification = (
    notification: Notification,
    enrolledClassIds: string[],
    isStudent: boolean
): boolean => {
    // Non-students (lecturers) see all their notifications
    if (!isStudent) return true;

    // Always show access_request notifications (invitations)
    if (notification.type === 'access_request') return true;

    // Always show notifications without class_id (general notifications)
    if (!notification.class_id) return true;

    // For class-scoped notifications, only show if enrolled in that class
    return enrolledClassIds.includes(notification.class_id);
};

import { getEnrolledClassIds } from "@/lib/studentUtils";

export function useNotifications() {
    const { user, role } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [loading, setLoading] = useState(true);
    const [unreadCount, setUnreadCount] = useState(0);

    // Cache enrolled class IDs to avoid refetching on every real-time update
    const enrolledClassIdsRef = useRef<string[]>([]);
    const isStudent = role === 'student';

    useEffect(() => {
        if (!user) return;

        // Fetch initial notifications with enrollment filtering
        const fetchNotifications = async () => {
            try {
                // For students, first get their enrolled class IDs
                let enrolledClassIds: string[] = [];

                if (isStudent) {
                    enrolledClassIds = await getEnrolledClassIds(user.id);
                    enrolledClassIdsRef.current = enrolledClassIds;
                }

                // Fetch notifications for the user
                const { data, error } = await supabase
                    .from("notifications")
                    .select("*")
                    .eq("recipient_id", user.id)
                    .order("created_at", { ascending: false })
                    .limit(50); // Fetch more to account for filtering

                if (error) throw error;

                // Filter notifications based on enrollment status
                const filteredData = (data || []).filter(n =>
                    shouldShowNotification(n as Notification, enrolledClassIds, isStudent)
                ).slice(0, 20); // Limit to 20 after filtering

                setNotifications(filteredData);
                setUnreadCount(filteredData.filter(n => !n.is_read).length);
            } catch (error) {
                console.error("Error fetching notifications:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchNotifications();

        // Subscribe to real-time updates
        const subscription = supabase
            .channel(`notifications-${user.id}`) // Unique channel per user
            .on(
                "postgres_changes",
                {
                    event: "INSERT",
                    schema: "public",
                    table: "notifications",
                    filter: `recipient_id=eq.${user.id}`,
                },
                async (payload) => {
                    const newNotification = payload.new as Notification;

                    // For students, check if notification should be shown
                    if (isStudent) {
                        // Refresh enrolled class IDs if needed (e.g., after accepting invitation)
                        const enrolledClassIds = await getEnrolledClassIds(user.id);
                        enrolledClassIdsRef.current = enrolledClassIds;

                        // Check if this notification should be visible
                        if (!shouldShowNotification(newNotification, enrolledClassIdsRef.current, true)) {
                            // Don't show this notification - student is not enrolled in this class
                            return;
                        }
                    }

                    // Check for duplicates before adding
                    setNotifications((prev) => {
                        if (prev.some(n => n.id === newNotification.id)) {
                            return prev;
                        }
                        return [newNotification, ...prev];
                    });
                    setUnreadCount((prev) => prev + 1);

                    toast(newNotification.title, {
                        description: newNotification.message,
                    });
                }
            )
            .on(
                "postgres_changes",
                {
                    event: "UPDATE",
                    schema: "public",
                    table: "notifications",
                    filter: `recipient_id=eq.${user.id}`,
                },
                (payload) => {
                    const updatedNotification = payload.new as Notification;

                    // Update the notification in state
                    setNotifications((prev) =>
                        prev.map((n) =>
                            n.id === updatedNotification.id ? updatedNotification : n
                        )
                    );

                    // Recalculate unread count
                    setNotifications((prev) => {
                        setUnreadCount(prev.filter(n => !n.is_read).length);
                        return prev;
                    });
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(subscription);
        };
    }, [user, isStudent]);

    const markAsRead = async (id: string) => {
        try {
            const { error } = await supabase
                .from("notifications")
                .update({ is_read: true })
                .eq("id", id);

            if (error) throw error;

            setNotifications((prev) =>
                prev.map((n) => (n.id === id ? { ...n, is_read: true } : n))
            );
            setUnreadCount((prev) => Math.max(0, prev - 1));
        } catch (error) {
            console.error("Error marking notification as read:", error);
        }
    };

    const markAllAsRead = async () => {
        try {
            const { error } = await supabase
                .from("notifications")
                .update({ is_read: true })
                .eq("recipient_id", user?.id)
                .eq("is_read", false);

            if (error) throw error;

            setNotifications((prev) => prev.map((n) => ({ ...n, is_read: true })));
            setUnreadCount(0);
        } catch (error) {
            console.error("Error marking all notifications as read:", error);
        }
    };

    const clearAllNotifications = async () => {
        try {
            const { error } = await supabase
                .from("notifications")
                .delete()
                .eq("recipient_id", user?.id);

            if (error) throw error;

            setNotifications([]);
            setUnreadCount(0);
        } catch (error) {
            console.error("Error clearing all notifications:", error);
        }
    };

    return {
        notifications,
        loading,
        unreadCount,
        markAsRead,
        markAllAsRead,
        clearAllNotifications,
    };
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { startOfWeek, endOfWeek, subWeeks, format, isWithinInterval } from 'date-fns';

export interface TrendData {
    week: string;
    score: number;
    fullDate: Date;
}

export function usePerformanceTrend() {
    const { user } = useAuth();
    const [data, setData] = useState<TrendData[]>([]);
    const [loading, setLoading] = useState(true);
    const [trendPercentage, setTrendPercentage] = useState(0);

    const fetchTrendData = async () => {
        if (!user) return;

        try {
            setLoading(true);

            // 1. Get lecturer's classes
            const { data: classes } = await supabase
                .from('classes')
                .select('id')
                .eq('lecturer_id', user.id);

            if (!classes || classes.length === 0) {
                setData([]);
                setLoading(false);
                return;
            }

            const classIds = classes.map(c => c.id);

            // 2. Fetch quizzes for these classes
            const { data: quizzes } = await supabase
                .from('quizzes')
                .select('id, total_marks')
                .in('class_id', classIds);

            if (!quizzes || quizzes.length === 0) {
                setData([]);
                setLoading(false);
                return;
            }

            const quizIds = quizzes.map(q => q.id);
            const quizMarksMap = new Map(quizzes.map(q => [q.id, q.total_marks]));

            // 3. Fetch submissions for these quizzes from the last 8 weeks
            const eightWeeksAgo = subWeeks(new Date(), 8);
            const { data: submissions } = await supabase
                .from('quiz_submissions')
                .select('quiz_id, total_obtained, submitted_at')
                .in('quiz_id', quizIds)
                .gte('submitted_at', eightWeeksAgo.toISOString())
                .order('submitted_at', { ascending: true });

            if (!submissions || submissions.length === 0) {
                // Return empty but structured data if no submissions
                const emptyData = Array.from({ length: 8 }).map((_, i) => ({
                    week: `Week ${8 - i}`,
                    score: 0,
                    fullDate: subWeeks(new Date(), 7 - i)
                }));
                setData(emptyData);
                setLoading(false);
                return;
            }

            // 4. Aggregate data by week
            const weeklyData: TrendData[] = [];
            for (let i = 7; i >= 0; i--) {
                const weekStart = startOfWeek(subWeeks(new Date(), i));
                const weekEnd = endOfWeek(subWeeks(new Date(), i));

                const weekSubmissions = submissions.filter(s =>
                    isWithinInterval(new Date(s.submitted_at), { start: weekStart, end: weekEnd })
                );

                let avgPercentage = 0;
                if (weekSubmissions.length > 0) {
                    const percentages = weekSubmissions.map(s => {
                        const totalMarks = quizMarksMap.get(s.quiz_id) || 100;
                        return (s.total_obtained / totalMarks) * 100;
                    });
                    avgPercentage = percentages.reduce((a, b) => a + b, 0) / percentages.length;
                }

                weeklyData.push({
                    week: `Week ${8 - i}`,
                    score: Math.round(avgPercentage),
                    fullDate: weekStart
                });
            }

            // 5. Calculate trend percentage (comparing last week to the one before)
            if (weeklyData.length >= 2) {
                const lastWeek = weeklyData[weeklyData.length - 1].score;
                const prevWeek = weeklyData[weeklyData.length - 2].score;
                if (prevWeek > 0) {
                    const diff = ((lastWeek - prevWeek) / prevWeek) * 100;
                    setTrendPercentage(Number(diff.toFixed(1)));
                } else if (lastWeek > 0) {
                    setTrendPercentage(100);
                }
            }

            setData(weeklyData);
        } catch (error) {
            console.error('Error fetching trend data:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchTrendData();
    }, [user]);

    return { data, loading, trendPercentage, refresh: fetchTrendData };
}

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Quiz, QuizQuestion } from '@/types/quiz';
import { toast } from 'sonner';
import { notifyQuizPublished } from '@/lib/notificationService';

// ── Module-level cache ───────────────────────────────────────────────────────
const quizzesCache = new Map<string, Quiz[]>();

export function useQuizzes(classId?: string) {
    const { user } = useAuth();
    const [quizzes, setQuizzes] = useState<Quiz[]>(() => {
        if (classId && quizzesCache.has(classId)) {
            return quizzesCache.get(classId) || [];
        }
        return [];
    });
    const [loading, setLoading] = useState(() => {
        return !classId || !quizzesCache.has(classId);
    });

    // Update state synchronously if classId changes and we have cached data
    useEffect(() => {
        if (!classId) {
            setQuizzes([]);
            setLoading(false);
        } else if (quizzesCache.has(classId)) {
            setQuizzes(quizzesCache.get(classId) || []);
            setLoading(false);
        } else {
            setQuizzes([]);
            setLoading(true);
        }
    }, [classId]);

    const fetchQuizzes = useCallback(async (silentRefresh = false) => {
        if (!user || !classId) {
            setLoading(false);
            return;
        }
        try {
            if (!silentRefresh && !quizzesCache.has(classId)) {
                setLoading(true);
            }
            const { data, error } = await supabase
                .from('quizzes')
                .select(`
                    *,
                    classes(class_name, course_code),
                    quiz_questions(count),
                    quiz_submissions(count)
                `)
                .eq('class_id', classId)
                .order('created_at', { ascending: false });

            if (error) throw error;

            // Transform count to number
            const transformedQuizzes = data.map(q => ({
                ...q,
                _count: {
                    questions: q.quiz_questions?.[0]?.count || 0,
                    submissions: q.quiz_submissions?.[0]?.count || 0
                }
            }));

            setQuizzes(transformedQuizzes as unknown as Quiz[]);
            quizzesCache.set(classId, transformedQuizzes as unknown as Quiz[]);
        } catch (error: any) {
            console.error('Error fetching quizzes:', JSON.stringify(error, null, 2));
            toast.error(`Error loading quizzes: ${error.message || 'Unknown error'}`);
            if (!quizzesCache.has(classId)) {
                setQuizzes([]);
            }
        } finally {
            setLoading(false);
        }
    }, [user, classId]);

    // React to changes
    useEffect(() => {
        fetchQuizzes();

        if (!classId) return;

        const channel = supabase
            .channel(`quizzes_channel_${classId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'quizzes',
                    filter: `class_id=eq.${classId}`
                },
                () => {
                    fetchQuizzes(true);
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [fetchQuizzes, classId]);


    const createQuiz = async (quizData: Partial<Quiz>) => {
        if (!user) throw new Error('User not authenticated');

        try {
            const { data, error } = await supabase
                .from('quizzes')
                .insert([quizData as any])
                .select()
                .single();

            if (error) throw error;

            // Send notifications to enrolled students if quiz is published
            if (quizData.status === 'published' && quizData.class_id) {
                await notifyQuizPublished(
                    data.id,
                    quizData.class_id,
                    quizData.title || 'New Quiz',
                    user.id
                );
            }

            toast.success('Quiz created successfully');
            fetchQuizzes();
            return data;
        } catch (error) {
            console.error('Error creating quiz:', error);
            toast.error('Failed to create quiz');
            throw error;
        }
    };

    const updateQuizStatus = async (quizId: string, status: 'published' | 'closed') => {
        if (!user) return;

        try {
            // If publishing, we want to increment the version to allow re-attempts
            let versionUpdate = {};
            if (status === 'published') {
                const { data: currentQuiz } = await supabase.from('quizzes').select('version').eq('id', quizId).single();
                const newVersion = (currentQuiz?.version || 1) + 1;
                versionUpdate = { version: newVersion };
            }

            const { error } = await supabase
                .from('quizzes')
                .update({ status, ...versionUpdate })
                .eq('id', quizId);

            if (error) throw error;

            // Send notifications when publishing
            if (status === 'published') {
                const quiz = quizzes.find(q => q.id === quizId);
                if (quiz?.class_id) {
                    await notifyQuizPublished(
                        quizId,
                        quiz.class_id,
                        quiz.title || 'Quiz',
                        user.id
                    );
                }
            }

            toast.success(`Quiz ${status === 'published' ? 'published (v' + (versionUpdate as any).version + ')' : 'closed'} successfully`);
            fetchQuizzes();
        } catch (error) {
            console.error('Error updating quiz status:', error);
            toast.error('Failed to update quiz status');
        }
    };

    const deleteQuiz = async (quizId: string) => {
        try {
            const { error } = await supabase
                .from('quizzes')
                .delete()
                .eq('id', quizId);

            if (error) throw error;
            toast.success('Quiz deleted');
            fetchQuizzes();
        } catch (error) {
            console.error('Error deleting quiz:', error);
            toast.error('Failed to delete quiz');
        }
    };

    return {
        quizzes,
        loading,
        fetchQuizzes,
        createQuiz,
        updateQuizStatus,
        deleteQuiz
    };
}

import { useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface RejectionNotification {
    id: string;
    class_id: string;
    student_email: string;
    status: 'rejected';
    responded_at: string;
}

export function useRealtimeRejections() {
    const { user } = useAuth();
    const [rejections, setRejections] = useState<RejectionNotification[]>([]);

    useEffect(() => {
        if (!user?.id) return;

        // Set up real-time subscription for rejection events
        const channel = supabase
            .channel(`rejections_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'access_requests',
                    filter: `lecturer_id=eq.${user.id}`
                },
                async (payload) => {
                    const updated = payload.new as any;

                    // Only process rejections
                    if (updated.status === 'rejected' && payload.old.status === 'pending') {
                        console.log('Student rejected invitation:', updated);

                        // Fetch class and student details
                        const { data: classData } = await supabase
                            .from('classes')
                            .select('course_code, class_name')
                            .eq('id', updated.class_id)
                            .single();

                        const { data: studentData } = await supabase
                            .from('class_students')
                            .select('student_name')
                            .eq('class_id', updated.class_id)
                            .eq('email', updated.student_email)
                            .single();

                        const studentName = studentData?.student_name || updated.student_email;
                        const courseInfo = classData
                            ? `${classData.course_code}${classData.class_name ? ` - ${classData.class_name}` : ''}`
                            : 'your class';

                        // Show toast notification
                        toast.error(
                            'Class Invitation Rejected',
                            {
                                description: `${studentName} has declined the invitation to join ${courseInfo}`,
                                duration: 6000
                            }
                        );

                        setRejections(prev => [updated as RejectionNotification, ...prev]);
                    }
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user?.id]);

    return { rejections };
}

import { useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getEnrolledClassIds } from '@/lib/studentUtils';
import { toast } from 'sonner';
import { notifyScheduleCreated, notifyScheduleUpdated } from '@/lib/notificationService';

// ── Module-level cache ───────────────────────────────────────────────────────
const scheduleCache = new Map<string, Schedule[]>();

export interface Schedule {
    id: string;
    course_id?: string | null;
    class_id: string | null;
    lecturer_id: string;
    title: string;
    type: 'lecture' | 'lab' | 'tutorial' | 'exam' | 'office_hours' | 'event';
    day_of_week: number;
    start_time: string;
    end_time: string;
    location: string | null;
    is_recurring: boolean;
    specific_date: string | null;
    notes: string | null;
    color: string | null;
    created_at: string;
    updated_at: string;
    lecturer_name?: string;
    subject_name?: string;
    class_name?: string;
    course_code?: string;
}

export function useSchedule(classId?: string) {
    const { user, role } = useAuth();
    const cacheKey = classId ? `${role}_${classId}` : `${role}_all`;

    const [schedules, setSchedules] = useState<Schedule[]>(() => {
        if (scheduleCache.has(cacheKey)) {
            return scheduleCache.get(cacheKey) || [];
        }
        return [];
    });
    const [assignments, setAssignments] = useState<any[]>([]); // Kept for compatibility if needed, but primary focus is schedules
    const [loading, setLoading] = useState(() => !scheduleCache.has(cacheKey));
    // Cache enrolled class IDs for real-time filtering updates
    const enrolledClassIdsRef = useRef<string[]>([]);

    const fetchSchedules = useCallback(async () => {
        if (!user) {
            setLoading(false);
            return;
        }

        if (!scheduleCache.has(cacheKey)) {
            setLoading(true);
        }

        try {
            let query = supabase
                .from('schedules')
                .select(`
                    *,
                    classes:class_id (class_name, course_code)
                `);

            if (role === 'lecturer') {
                // If a specific class is selected, filter by it
                if (classId) {
                    query = query.eq('class_id', classId);
                } else {
                    // Otherwise show all schedules created by this lecturer
                    query = query.eq('lecturer_id', user.id);
                }
            } else if (role === 'student') {
                // Students see schedules for ALL their enrolled classes
                const enrolledClassIds = await getEnrolledClassIds(user.id);
                enrolledClassIdsRef.current = enrolledClassIds;

                if (enrolledClassIds.length === 0) {
                    setSchedules([]);
                    setLoading(false);
                    return;
                }

                query = query.in('class_id', enrolledClassIds);
            }

            const { data, error } = await query.order('start_time', { ascending: true });

            if (error) throw error;

            // Transform data to ensure display fields are present
            const formattedData: Schedule[] = (data || []).map((item: any) => ({
                ...item,
                class_name: item.classes?.class_name,
                course_code: item.classes?.course_code,
                // Ensure legacy fields don't break if present
                lecturer_name: item.lecturer_name || user?.user_metadata?.full_name || 'Unknown',
                subject_name: item.subject_name || item.title
            }));

            setSchedules(formattedData);
            scheduleCache.set(cacheKey, formattedData);
        } catch (err) {
            console.error('Error fetching schedules:', err);
            // toast.error('Failed to load schedule'); // Optional: don't spam toasts on load
        } finally {
            setLoading(false);
        }
    }, [user, role, classId]);

    // Set up Real-time Subscription
    useEffect(() => {
        if (scheduleCache.has(cacheKey)) {
            setSchedules(scheduleCache.get(cacheKey) || []);
            setLoading(false);
        } else {
            setSchedules([]);
            setLoading(true);
        }

        fetchSchedules();

        if (!user) return;

        const channel = supabase
            .channel(`schedules-${role}-${user.id}-${classId || 'all'}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'schedules'
                },
                async (payload) => {
                    // Logic to determine if we should refresh based on the payload
                    let shouldRefresh = false;

                    const newItem = payload.new as any; // Cast to any to access dynamic fields
                    const oldItem = payload.old as any;

                    if (role === 'lecturer') {
                        // Lecturer cares if they are the owner OR if it's in the viewed class
                        if (classId) {
                            // Viewing specific class
                            if (newItem?.class_id === classId || oldItem?.class_id === classId) {
                                shouldRefresh = true;
                            }
                        } else {
                            // Viewing all their schedules
                            if (newItem?.lecturer_id === user.id || oldItem?.lecturer_id === user.id) {
                                shouldRefresh = true;
                            }
                        }
                    } else {
                        // Student cares if the schedule is for one of their enrolled classes
                        // We use the ref to check against the list we fetched earlier
                        const relevantClassId = newItem?.class_id || oldItem?.class_id;
                        if (relevantClassId && enrolledClassIdsRef.current.includes(relevantClassId)) {
                            shouldRefresh = true;
                        }
                    }

                    if (shouldRefresh) {
                        await fetchSchedules();
                    }
                }
            )
            .subscribe();

        // Real-time subscription for access_requests (enrollment changes)
        // This ensures students see schedules from newly accepted classes immediately
        const enrollmentChannel = role === 'student' ? supabase
            .channel(`schedule_enrollment_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'access_requests',
                    filter: `student_id=eq.${user.id}`,
                },
                async () => {
                    // Refetch schedules when enrollment status changes
                    await fetchSchedules();
                }
            )
            .subscribe() : null;

        return () => {
            supabase.removeChannel(channel);
            if (enrollmentChannel) supabase.removeChannel(enrollmentChannel);
        };
    }, [fetchSchedules, user, role, classId]);

    // Helper function to get day name
    const getDayName = (dayOfWeek: number): string => {
        const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        return days[dayOfWeek] || 'Unknown';
    };

    const createSchedule = async (scheduleData: Omit<Schedule, 'id' | 'created_at' | 'updated_at' | 'lecturer_id'>) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { data, error } = await supabase
                .from('schedules')
                .insert({
                    ...scheduleData,
                    lecturer_id: user.id
                })
                .select('*, classes(class_name, course_code)')
                .single();

            if (error) throw error;

            // Send Notifications
            if (scheduleData.class_id) {
                // Get accepted students for this class
                const { data: acceptedRequests } = await supabase
                    .from('access_requests')
                    .select('student_id')
                    .eq('class_id', scheduleData.class_id)
                    .eq('status', 'accepted');

                const studentIds = acceptedRequests?.map(r => r.student_id).filter(id => id !== null) as string[] || [];

                if (studentIds.length > 0) {
                    await notifyScheduleCreated(
                        studentIds,
                        scheduleData.title,
                        `New ${scheduleData.type} scheduled for ${scheduleData.specific_date ? new Date(scheduleData.specific_date).toLocaleDateString() : getDayName(scheduleData.day_of_week)} at ${scheduleData.start_time}`,
                        data.id,
                        user.id,
                        scheduleData.class_id
                    );
                }
            }

            return { success: true, data };
        } catch (err: any) {
            console.error('Error creating schedule:', err);
            return { success: false, error: err.message };
        }
    };

    const updateSchedule = async (id: string, updates: Partial<Omit<Schedule, 'id' | 'created_at' | 'updated_at'>>) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { data, error } = await supabase
                .from('schedules')
                .update(updates)
                .eq('id', id)
                .select('*, classes(class_name, course_code)')
                .single();

            if (error) throw error;

            // Send Notifications
            if (data.class_id) {
                const { data: acceptedRequests } = await supabase
                    .from('access_requests')
                    .select('student_id')
                    .eq('class_id', data.class_id)
                    .eq('status', 'accepted');

                const studentIds = acceptedRequests?.map(r => r.student_id).filter(id => id !== null) as string[] || [];

                if (studentIds.length > 0) {
                    // Build update details
                    let updateDetails = 'Schedule updated';
                    if (updates.start_time) updateDetails = `Time changed to ${updates.start_time}`;
                    else if (updates.location) updateDetails = `Location changed to ${updates.location}`;
                    else if (updates.specific_date) updateDetails = `Date changed to ${new Date(updates.specific_date).toLocaleDateString()}`;

                    await notifyScheduleUpdated(
                        studentIds,
                        data.title,
                        updateDetails,
                        data.id,
                        user.id,
                        data.class_id
                    );
                }
            }

            return { success: true, data };
        } catch (err: any) {
            console.error('Error updating schedule:', err);
            return { success: false, error: err.message };
        }
    };

    const deleteSchedule = async (id: string) => {
        if (!user || role !== 'lecturer') return { success: false, error: 'Unauthorized' };

        try {
            const { error } = await supabase
                .from('schedules')
                .delete()
                .eq('id', id)
                .eq('lecturer_id', user.id);

            if (error) throw error;
            return { success: true };
        } catch (err: any) {
            console.error('Error deleting schedule:', err);
            return { success: false, error: err.message };
        }
    };

    const getSchedulesForDay = (dayOfWeek: number) => {
        return schedules.filter(s => s.day_of_week === dayOfWeek);
    };

    const getUpcomingSchedules = () => {
        const today = new Date().getDay();
        return schedules
            .filter(s => s.day_of_week >= today)
            .sort((a, b) => a.day_of_week - b.day_of_week)
            .slice(0, 5);
    };

    return {
        schedules,
        assignments,
        loading,
        createSchedule,
        updateSchedule,
        deleteSchedule,
        refreshSchedules: fetchSchedules,
        getSchedulesForDay,
        getUpcomingSchedules
    };
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getStudentPendingInvitations, linkEmailToAccount } from '@/lib/classInvitationService';
import { checkPendingInvitations } from '@/lib/accessControlService';
import { notifyPendingAccessRequest, clearAccessRequestNotification } from '@/lib/notificationService';

export interface PendingInvitation {
    id: string;
    class_id: string;
    student_email: string;
    sent_at: string;
    classes: {
        course_code: string;
        class_name?: string;
        semester?: string;
        academic_year?: string;
        lecturer_name?: string;
        lecturer_department?: string;
    };
}

const DISMISSED_REQUESTS_KEY = 'dismissedJoinRequests';

// Helper to get dismissed requests from session storage
const getDismissedRequests = (): Set<string> => {
    try {
        const stored = sessionStorage.getItem(DISMISSED_REQUESTS_KEY);
        return stored ? new Set(JSON.parse(stored)) : new Set();
    } catch {
        return new Set();
    }
};

// Helper to save dismissed requests to session storage
const saveDismissedRequests = (requests: Set<string>) => {
    try {
        sessionStorage.setItem(DISMISSED_REQUESTS_KEY, JSON.stringify([...requests]));
    } catch (err) {
        console.error('Error saving dismissed requests:', err);
    }
};

export function useStudentOnboarding() {
    const { user } = useAuth();
    const [pendingInvitations, setPendingInvitations] = useState<PendingInvitation[]>([]);
    const [loading, setLoading] = useState(true);
    const [hasPending, setHasPending] = useState(false);
    const [isOnboarding, setIsOnboarding] = useState(false);
    const [showModal, setShowModal] = useState(false);
    const [dismissedRequests, setDismissedRequests] = useState<Set<string>>(getDismissedRequests());

    useEffect(() => {
        if (!user?.email) {
            setLoading(false);
            return;
        }

        checkAndLinkAccount();
    }, [user]);

    const checkAndLinkAccount = async () => {
        if (!user?.email) return;

        try {
            setLoading(true);
            setIsOnboarding(true);

            // Check if there are pending invitations for this email
            const { hasPending: hasInvitations, count } = await checkPendingInvitations(user.email);
            setHasPending(hasInvitations);

            if (hasInvitations) {
                console.log(`Found ${count} pending invitations for ${user.email}`);

                // Link email-based records to this account
                const { success, linkedCount } = await linkEmailToAccount(user.email, user.id);

                if (success) {
                    console.log(`Linked ${linkedCount} email-based records to account`);
                }

                // Fetch pending invitations
                await fetchPendingInvitations();
            }
        } catch (err) {
            console.error('Error during onboarding check:', err);
        } finally {
            setLoading(false);
            setIsOnboarding(false);
        }
    };

    const fetchPendingInvitations = async () => {
        if (!user?.email) return;

        try {
            const { success, data } = await getStudentPendingInvitations(user.email);

            if (success && data) {
                setPendingInvitations(data as PendingInvitation[]);
                setHasPending(data.length > 0);

                // Check if there are new requests that haven't been dismissed
                const dismissed = getDismissedRequests();
                const hasNewRequests = data.some((inv: PendingInvitation) => !dismissed.has(inv.id));

                // Show modal only if there are new requests
                if (hasNewRequests && data.length > 0) {
                    setShowModal(true);
                }
            }
        } catch (err) {
            console.error('Error fetching pending invitations:', err);
        }
    };

    const refreshInvitations = async () => {
        await fetchPendingInvitations();
    };

    const dismissModal = async () => {
        setShowModal(false);

        // Create notifications for all pending invitations
        if (user?.id && pendingInvitations.length > 0) {
            for (const invitation of pendingInvitations) {
                await notifyPendingAccessRequest(
                    user.id,
                    invitation.classes.lecturer_name || 'A lecturer',
                    invitation.classes.course_code,
                    invitation.classes.class_name,
                    invitation.id
                );
            }
        }

        // Mark all current invitations as dismissed
        const newDismissed = new Set(dismissedRequests);
        pendingInvitations.forEach(inv => newDismissed.add(inv.id));
        setDismissedRequests(newDismissed);
        saveDismissedRequests(newDismissed);
    };

    const markRequestAsHandled = async (requestId: string) => {
        // Clear notification for this request
        if (user?.id) {
            await clearAccessRequestNotification(user.id, requestId);
        }

        // Don't add to dismissed list - handled requests should not prevent new requests from showing
        // The request will be removed from pendingInvitations by the refresh
    };

    const showModalForNewRequest = () => {
        setShowModal(true);
    };

    const reopenModalForRequest = (requestId: string) => {
        // Remove from dismissed list to allow modal to show
        const newDismissed = new Set(dismissedRequests);
        newDismissed.delete(requestId);
        setDismissedRequests(newDismissed);
        saveDismissedRequests(newDismissed);

        // Show the modal
        setShowModal(true);
    };

    return {
        pendingInvitations,
        loading,
        hasPending,
        isOnboarding,
        showModal,
        setShowModal,
        dismissModal,
        markRequestAsHandled,
        showModalForNewRequest,
        reopenModalForRequest,
        refreshInvitations
    };
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { RealtimeChannel } from '@supabase/supabase-js';

// ── Module-level cache ───────────────────────────────────────────────────────
const studentQuizzesCache = new Map<string, any[]>();
const enrolledClassesCache = new Map<string, { id: string, class_name: string, course_code: string }[]>();

export function useStudentQuizzes(selectedClassId?: string) {
    const { user } = useAuth();
    const [quizzes, setQuizzes] = useState<any[]>(() => {
        if (selectedClassId && studentQuizzesCache.has(selectedClassId)) {
            return studentQuizzesCache.get(selectedClassId) || [];
        }
        return [];
    });
    const [loading, setLoading] = useState(() => {
        return !selectedClassId || !studentQuizzesCache.has(selectedClassId);
    });
    const [enrolledClasses, setEnrolledClasses] = useState<{ id: string, class_name: string, course_code: string }[]>(() => {
        // user might not be available initially due to context rendering, but let's try
        if (user && enrolledClassesCache.has(user.id)) {
            return enrolledClassesCache.get(user.id) || [];
        }
        return [];
    });
    const [enrolledClassIds, setEnrolledClassIds] = useState<string[]>([]); // Keep this for real-time subscriptions

    // Use ref to track active channels for cleanup
    const channelsRef = useRef<RealtimeChannel[]>([]);

    const fetchEnrolledClasses = useCallback(async () => {
        if (!user) {
            setLoading(false);
            return;
        }

        try {
            // Get student email for fallback matching
            const studentEmail = user.email || '';
            const emailFilter = studentEmail ? `,email.ilike.${studentEmail}` : '';

            // Get enrolled class IDs first
            const { data: enrollments, error: enrollmentError } = await supabase
                .from('class_students')
                .select('class_id')
                .or(`student_id.eq.${user.id}${emailFilter}`);

            if (enrollmentError) {
                console.error('Error fetching enrollments:', enrollmentError);
                setLoading(false);
                return;
            }

            const classIds = enrollments?.map(e => e.class_id).filter(Boolean) as string[] || [];
            setEnrolledClassIds(classIds); // Update the internal list of IDs

            if (classIds.length === 0) {
                setEnrolledClasses([]);
                setLoading(false);
                return;
            }

            // Fetch class details
            const { data: classesData, error: classesError } = await supabase
                .from('classes')
                .select('id, class_name, course_code')
                .in('id', classIds);

            if (classesError) {
                console.error('Error fetching class details:', classesError);
                setLoading(false);
                return;
            }

            setEnrolledClasses(classesData || []);
            enrolledClassesCache.set(user.id, classesData || []);

        } catch (error) {
            console.error('Error in fetchEnrolledClasses:', error);
            setLoading(false);
        }
    }, [user]);

    const fetchStudentQuizzes = useCallback(async (overrideClassId?: string, silentRefresh = false) => {
        const targetClassId = overrideClassId || selectedClassId;
        if (!user) return;
        if (!targetClassId) {
            setQuizzes([]);
            setLoading(false);
            return;
        }

        try {
            console.log(`[useStudentQuizzes] Fetching quizzes for class: ${targetClassId}`);
            if (!silentRefresh && !studentQuizzesCache.has(targetClassId)) {
                setLoading(true);
            }

            // 2. Fetch published quizzes for THIS class only - BASIC INFO ONLY
            const { data: quizzesData, error } = await supabase
                .from('quizzes')
                .select('*')
                .eq('class_id', targetClassId)
                .in('status', ['published', 'closed'])
                .order('created_at', { ascending: false });

            if (error) {
                console.error('[useStudentQuizzes] Error fetching quizzes data:', error.message || error);
                throw error;
            }

            console.log(`[useStudentQuizzes] Found ${quizzesData?.length || 0} quizzes for class ${targetClassId}`);

            if (!quizzesData || quizzesData.length === 0) {
                setQuizzes([]);
                studentQuizzesCache.set(targetClassId, []);
                setLoading(false);
                return;
            }

            // Fetch Related Data Separately to avoid RLS join issues
            // Fetch Class Details
            const classIds = [...new Set(quizzesData.map(q => q.class_id))];
            const { data: classesData } = await supabase
                .from('classes')
                .select('id, class_name, course_code')
                .in('id', classIds);

            const classMap = new Map(classesData?.map(c => [c.id, c]) || []);

            // Fetch Question Counts
            const quizIds = quizzesData.map(q => q.id);
            const { data: questionCounts } = await supabase
                .from('quiz_questions')
                .select('quiz_id')
                .in('quiz_id', quizIds);

            // Calculate counts manually since we just got IDs
            const questionCountMap = new Map<string, number>();
            if (questionCounts) {
                questionCounts.forEach((q: { quiz_id: string }) => {
                    questionCountMap.set(q.quiz_id, (questionCountMap.get(q.quiz_id) || 0) + 1);
                });
            }


            // 3. Fetch Instructor Profiles separately (to avoid join failures)
            const instructorIds = [...new Set(quizzesData?.map(q => q.created_by).filter(Boolean))];
            let instructorMap: Record<string, any> = {};

            if (instructorIds.length > 0) {
                const { data: instructors } = await supabase
                    .from('profiles')
                    .select('user_id, full_name, avatar_url')
                    .in('user_id', instructorIds);

                if (instructors) {
                    instructorMap = instructors.reduce((acc, curr) => ({
                        ...acc,
                        [curr.user_id]: curr
                    }), {});
                }
            }

            // For each quiz, fetch the student's submission status
            const processedQuizzes = await Promise.all(quizzesData?.map(async (q) => {
                // Fetch student's active submission for this quiz
                const { data: submissionData } = await supabase
                    .from('quiz_submissions')
                    .select('id, status, total_obtained, is_archived, quiz_version, submitted_at, time_taken, started_at')
                    .eq('quiz_id', q.id)
                    .eq('student_id', user.id)
                    .eq('is_archived', false)
                    .maybeSingle();

                // DEBUG LOGGING - Temporary
                console.log(`[DEBUG] Quiz '${q.title}' (ID: ${q.id}):`, {
                    hasSubmission: !!submissionData,
                    submissionStatus: submissionData?.status,
                    isArchived: submissionData?.is_archived,
                    quizVersion: submissionData?.quiz_version,
                    currentQuizVersion: q.version
                });

                // Transform the count to a number and extract instructor details
                const instructor = instructorMap[q.created_by] || null;
                const relatedClass = classMap.get(q.class_id);

                return {
                    ...q,
                    classes: relatedClass ? {
                        class_name: relatedClass.class_name,
                        course_code: relatedClass.course_code
                    } : null,
                    _count: {
                        questions: questionCountMap.get(q.id) || 0
                    },
                    instructor: instructor ? {
                        full_name: instructor.full_name,
                        avatar_url: instructor.avatar_url
                    } : null,
                    my_submission: submissionData || null,
                };
            }) || []);

            setQuizzes(processedQuizzes);
            studentQuizzesCache.set(targetClassId, processedQuizzes);

        } catch (error: any) {
            console.error('Error fetching student quizzes:', error.message || JSON.stringify(error, null, 2));
        } finally {
            setLoading(false);
        }
    }, [user, selectedClassId]);

    // Initial fetch of classes
    useEffect(() => {
        fetchEnrolledClasses();
    }, [fetchEnrolledClasses]);

    // Fetch quizzes when selectedClassId changes
    useEffect(() => {
        if (selectedClassId) {
            if (studentQuizzesCache.has(selectedClassId)) {
                setQuizzes(studentQuizzesCache.get(selectedClassId) || []);
                setLoading(false);
            } else {
                setQuizzes([]);
                setLoading(true);
            }
            fetchStudentQuizzes(); // Fetch new data
        } else {
            setQuizzes([]);
            // Ensure loading is false if no class is selected
            setLoading(false);
        }
    }, [selectedClassId, fetchStudentQuizzes]);

    const refreshQuizzes = useCallback(() => {
        fetchStudentQuizzes();
    }, [fetchStudentQuizzes]);

    // Real-time subscriptions - needing selectedClassId to be passed in from component potentially?
    // Actually, we can subscribe to changes for the *selected* class if we moved state up, 
    // OR just subscribe to all enrolled classes and selectively refresh.
    // Ideally, the hook should know the selected class. 
    // Let's change the hook signature to accept `selectedClassId`.


    // Real-time subscriptions
    useEffect(() => {
        if (!user || enrolledClassIds.length === 0) return;

        // Cleanup previous subscriptions
        channelsRef.current.forEach(channel => supabase.removeChannel(channel));
        channelsRef.current = [];

        console.log('Setting up quiz subscriptions for classes:', enrolledClassIds);

        const channel = supabase
            .channel(`student_quizzes_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'quizzes'
                    // We can't easily filter by class_id list here
                },
                (payload) => {
                    const newRecord = payload.new as any;
                    const oldRecord = payload.old as any;

                    if (payload.eventType === 'DELETE') {
                        // For deletes, we might not know the class_id easily without querying, 
                        // but we should refresh if the deleted quiz was in our list or just refresh to be safe.
                        // Since we can't check class_id on DELETE payloads easily (unless replica identity is full),
                        // we'll optimistically refresh if we have a selected class.
                        console.log('Quiz deleted, refreshing...', payload);
                        fetchStudentQuizzes(selectedClassId, true);
                    } else if (newRecord?.class_id && enrolledClassIds.includes(newRecord.class_id)) {
                        // Filter for INSERT/UPDATE: Only refresh if the affected quiz belongs to an enrolled class
                        console.log('Relevant quiz update detected:', payload);
                        fetchStudentQuizzes(selectedClassId, true);
                    }
                }
            )
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'quiz_submissions',
                    filter: `student_id=eq.${user.id}`
                },
                (payload) => {
                    console.log('Submission update detected:', payload);
                    fetchStudentQuizzes(selectedClassId, true);
                }
            )
            .subscribe();

        channelsRef.current.push(channel);

        return () => {
            channelsRef.current.forEach(channel => supabase.removeChannel(channel));
            channelsRef.current = [];
        };
    }, [user, enrolledClassIds, fetchStudentQuizzes]);

    return {
        quizzes,
        loading,
        enrolledClasses,
        fetchStudentQuizzes
    };
}

import { supabase } from "@/integrations/supabase/client";

/**
 * Permanently deletes all user data and resets the profile to default values.
 * This effectively "factory resets" the account while keeping the login credentials.
 */
export const deleteUserAccount = async (userId: string) => {
    try {
        // 1. Delete all notifications
        const { error: notificationsError } = await supabase
            .from("notifications")
            .delete()
            .eq("recipient_id", userId);

        if (notificationsError) throw new Error(`Notifications deletion failed: ${notificationsError.message}`);

        // 2. Delete all messages (sent by user) & received messages
        // Note: This might leave "ghost" messages for other users if we just delete rows.
        // However, for a full wipe, deleting rows is the cleaner approach for the user.
        // Ideally, we'd replace content with "Message deleted", but user wants "data removed".
        const { error: sentMessagesError } = await supabase
            .from("messages")
            .delete()
            .eq("sender_id", userId);

        if (sentMessagesError) throw new Error(`Sent messages deletion failed: ${sentMessagesError.message}`);

        // We also delete received messages to clear their inbox
        const { error: receivedMessagesError } = await supabase
            .from("messages")
            .delete()
            .eq("receiver_id", userId);

        if (receivedMessagesError) throw new Error(`Received messages deletion failed: ${receivedMessagesError.message}`);

        // 3. Delete course enrollments
        try {
            const { error: enrollmentsError } = await supabase
                .from("course_enrollments" as any) // Cast to any to bypass type check for missing table
                .delete()
                .eq("student_id", userId);

            if (enrollmentsError) {
                // Only throw if it's NOT a "table missing" error
                if (!enrollmentsError.message.includes("Could not find the table") &&
                    !enrollmentsError.message.includes("does not exist")) {
                    throw new Error(`Enrollments deletion failed: ${enrollmentsError.message}`);
                } else {
                    console.warn("Skipping enrollments deletion: Table does not exist.");
                }
            }
        } catch (err) {
            // If the Supabase client throws synchronously (validation), catch it here
            console.warn("Skipping enrollments deletion: Table likely missing.", err);
        }

        // 4. Delete from conversations (participation)
        // This is tricky as it affects others. We'll skip deleting the conversation row itself
        // to avoid breaking the other person's view, but the messages are gone.
        // If we wanted to go further, we could delete conversations where they are the ONLY participant?
        // For now, let's leave conversation rows. They will just show empty history.

        // 5. Reset Profile
        // We update the profile to remove all personal identifiers
        const { error: profileError } = await supabase
            .from("profiles")
            .update({
                full_name: "User", // Generic name
                phone: null,
                date_of_birth: null,
                bio: null,
                student_id: null,
                program: null,
                year: null,
                department: null,
                gpa: null,
                credits_completed: null,
                credits_required: null,
                advisor: null,
                enrollment_date: null,
                expected_graduation: null,
                avatar_url: null,
                street: null,
                city: null,
                state: null,
                zip_code: null,
                country: null,
                // Reset preferences
                email_notifications: true,
                push_notifications: true,
                sms_notifications: false,
                assignment_reminders: true,
                grade_updates: true,
                course_announcements: true,
                weekly_digest: false,
                language: "en",
                timezone: "America/New_York",
                theme: "system",
            })
            .eq("user_id", userId);

        if (profileError) throw new Error(`Profile reset failed: ${profileError.message}`);

        // 6. Delete User Role?
        // If we delete the role, they will be prompted to select one again on next login (via AuthCallback).
        // This supports the "fresh account" feel.
        const { error: roleError } = await supabase
            .from("user_roles")
            .delete()
            .eq("user_id", userId);

        if (roleError) throw new Error(`Role deletion failed: ${roleError.message}`);

        return { success: true };

    } catch (error: any) {
        console.error("Delete account error:", error);
        return { success: false, error: error.message };
    }
};

import { supabase } from "@/integrations/supabase/client";

export type MessageRole = 'user' | 'assistant' | 'system';

export interface MessageContent {
    type: 'text' | 'image_url';
    text?: string;
    image_url?: {
        url: string;
    };
}

export interface AIChatMessage {
    id: string;
    conversation_id: string;
    role: MessageRole;
    content: string | MessageContent[];
    created_at: string;
}

export interface AIConversation {
    id: string;
    user_id: string;
    title: string;
    created_at: string;
    updated_at: string;
    is_pinned?: boolean;
    share_token?: string;
}

export const aiChatService = {
    async getConversations() {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return [];

        const { data, error } = await supabase
            .from('ai_conversations')
            .select('*')
            .eq('user_id', user.id)
            .order('is_pinned', { ascending: false })
            .order('updated_at', { ascending: false });

        if (error) throw error;
        return data as AIConversation[];
    },

    async getMessages(conversationId: string) {
        const { data, error } = await supabase
            .from('ai_messages')
            .select('*')
            .eq('conversation_id', conversationId)
            .order('created_at', { ascending: true });

        if (error) throw error;
        return data as AIChatMessage[];
    },

    async createConversation(title: string = 'New Chat') {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error('User not authenticated');

        const { data, error } = await supabase
            .from('ai_conversations')
            .insert({
                user_id: user.id,
                title,
            })
            .select()
            .single();

        if (error) throw error;
        return data as AIConversation;
    },

    async deleteConversation(id: string) {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error('User not authenticated');

        const { error } = await supabase
            .from('ai_conversations')
            .delete()
            .eq('id', id)
            .eq('user_id', user.id);

        if (error) throw error;
    },

    async saveMessage(conversationId: string, role: MessageRole, content: string | MessageContent[]) {
        const { data, error } = await supabase
            .from('ai_messages')
            .insert({
                conversation_id: conversationId,
                role,
                content,
            })
            .select()
            .single();

        if (error) throw error;

        // Also update the conversation's updated_at
        await supabase
            .from('ai_conversations')
            .update({ updated_at: new Date().toISOString() })
            .eq('id', conversationId);

        return data as AIChatMessage;
    },

    async updateConversationTitle(id: string, title: string) {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error('User not authenticated');

        const { error } = await supabase
            .from('ai_conversations')
            .update({ title })
            .eq('id', id)
            .eq('user_id', user.id);

        if (error) throw error;
    },

    async togglePin(id: string) {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error('User not authenticated');

        const { data, error } = await supabase
            .rpc('toggle_ai_conversation_pin', {
                conv_id: id
            });

        if (error) throw error;
        return data as boolean;
    },

    async toggleShare(id: string) {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error('User not authenticated');

        const { data, error } = await supabase
            .rpc('toggle_ai_conversation_share', {
                conv_id: id
            });

        if (error) throw error;
        return data as string | null;
    },

    async getSharedConversation(shareToken: string) {
        // 1. Get the conversation
        const { data: conv, error: convError } = await supabase
            .from('ai_conversations')
            .select('*')
            .eq('share_token', shareToken)
            .single();

        if (convError) throw convError;

        // 2. Get the owner's profile separately to avoid relationship errors
        const { data: profile } = await supabase
            .from('profiles')
            .select('full_name, avatar_url')
            .eq('user_id', conv.user_id)
            .single();

        // 3. Get the messages
        const { data: messages, error: msgError } = await supabase
            .from('ai_messages')
            .select('*')
            .eq('conversation_id', conv.id)
            .order('created_at', { ascending: true });

        if (msgError) throw msgError;

        return {
            conversation: { ...conv, profiles: profile } as (AIConversation & { profiles: { full_name: string, avatar_url: string } }),
            messages: messages as AIChatMessage[]
        };
    },

    async updateMessage(id: string, content: string) {
        const { error } = await supabase
            .from('ai_messages')
            .update({ content })
            .eq('id', id);

        if (error) throw error;
    },

    async transcribeAudio(audioBlob: Blob) {
        const formData = new FormData();
        formData.append('file', audioBlob, 'recording.wav');

        const { data, error } = await supabase.functions.invoke('ai-transcribe', {
            body: formData,
        });

        if (error) {
            console.error('Transcription function error:', error);
            throw new Error(`Transcription failed: ${error.message}`);
        }

        return data.text as string;
    },

    async streamChat(messages: { role: string; content: string | MessageContent[] }[], onToken: (token: string) => void) {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('Authentication required for AI chat.');

            const functionUrl = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ai-chat`;

            const response = await fetch(functionUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`,
                },
                body: JSON.stringify({ messages, stream: true }),
            });

            if (!response.ok) {
                const errorText = await response.text();
                let errorData;
                try {
                    errorData = JSON.parse(errorText);
                } catch {
                    errorData = { error: errorText };
                }
                console.error('AI Chat Error Details:', errorData);
                throw new Error(errorData.details || errorData.error || 'AI Service Error');
            }

            const reader = response.body?.getReader();
            if (!reader) throw new Error('Response body is null');

            const decoder = new TextDecoder();
            let fullContent = "";

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                const chunk = decoder.decode(value);
                const lines = chunk.split('\n');

                for (const line of lines) {
                    if (line.trim().startsWith('data: ')) {
                        const dataStr = line.replace('data: ', '').trim();
                        if (dataStr === '[DONE]') break;
                        try {
                            const parsed = JSON.parse(dataStr);
                            const token = parsed.choices?.[0]?.delta?.content || "";
                            if (token) {
                                fullContent += token;
                                onToken(token);
                            }
                        } catch (e) {
                            // Partial chunk
                        }
                    }
                }
            }

            return fullContent;

        } catch (error: any) {
            console.error('Chat error:', error);
            throw error;
        }
    },
};

