        <DashboardLayout>
            <div className="flex flex-col gap-6">
                {/* Breadcrumb */}
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => navigate("/all-students")}
                        className="gap-2"
                    >
                        <ChevronLeft className="size-4" />
                        Back to Classes
                    </Button>
                </div>

                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <div className="flex flex-col gap-1">
                        <h1 className="text-2xl sm:text-3xl font-bold text-foreground">
                            {currentClass?.course_code || "Class"} - Student Management
                        </h1>
                        <p className="text-sm text-muted-foreground">
                            {currentClass?.class_name && `${currentClass.class_name} • `}
                            {currentClass?.semester} {currentClass?.academic_year}
                        </p>
                    </div>
                    <div className="flex items-center gap-2">
                        {/* Desktop View Buttons */}
                        <Button
                            variant="outline"
                            onClick={() => setShowAddStudentModal(true)}
                            className="hidden sm:flex rounded-xl h-10 px-4 md:h-12 border-slate-200 dark:border-slate-800 font-bold transition-all hover:bg-slate-50 dark:hover:bg-slate-800 shadow-sm gap-2"
                        >
                            <UserPlus className="size-4" />
                            Add Student
                        </Button>

                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button className="hidden sm:flex rounded-xl h-10 px-4 md:h-12 border-none font-bold transition-all shadow-lg hover:shadow-primary/20 bg-primary text-white gap-2">
                                    <Plus className="size-5" />
                                    <span>Manage Students</span>
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end" className="w-56 p-2 rounded-2xl shadow-xl border-none backdrop-blur-xl bg-white/95 dark:bg-slate-900/95">
                                <DropdownMenuItem onClick={() => setShowImportModal(true)} className="h-12 rounded-xl cursor-pointer gap-3">
                                    <div className="p-2 bg-emerald-500/10 rounded-lg">
                                        <FileSpreadsheet className="size-4 text-emerald-600" />
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="font-bold text-sm">Import Excel</span>
                                        <span className="text-[10px] text-muted-foreground">Bulk upload data</span>
                                    </div>
                                </DropdownMenuItem>
                                <DropdownMenuSeparator className="bg-slate-100 dark:bg-slate-800" />
                                <DropdownMenuItem onClick={handleSendAllRequests} disabled={students.length === 0 || sendingRequests} className="h-12 rounded-xl cursor-pointer gap-3">
                                    <div className="p-2 bg-blue-500/10 rounded-lg">
                                        <Send className="size-4 text-blue-600" />
                                    </div>
                                    <div className="flex flex-col text-left">
                                        <span className="font-bold text-sm">Send Requests</span>
                                        <span className="text-[10px] text-muted-foreground">Invite all students</span>
                                    </div>
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={handleResendAllRequests} disabled={students.length === 0 || sendingRequests} className="h-12 rounded-xl cursor-pointer gap-3">
                                    <div className="p-2 bg-amber-500/10 rounded-lg">
                                        <Users className="size-4 text-amber-600" />
                                    </div>
                                    <div className="flex flex-col text-left">
                                        <span className="font-bold text-sm">Resend Requests</span>
                                        <span className="text-[10px] text-muted-foreground">Remind pending students</span>
                                    </div>
                                </DropdownMenuItem>
                            </DropdownMenuContent>
                        </DropdownMenu>

                        {/* Mobile view handled by FAB or simple header icon could remain here if specifically asked */}
                    </div>
                </div>

                {/* Stats Cards - Premium Design */}
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                    <Card className="border-none bg-gradient-to-br from-blue-600 to-indigo-700 shadow-xl rounded-2xl overflow-hidden group">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative text-white">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <Users className="size-12 sm:size-20" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <Users className="size-5 sm:size-7" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-blue-100/80 font-semibold uppercase tracking-wider truncate">
                                    Total Students
                                </p>
                                <p className="text-xl sm:text-3xl font-black">{totalStudents}</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-none bg-gradient-to-br from-emerald-600 to-teal-700 shadow-xl rounded-2xl overflow-hidden group">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative text-white">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <Users className="size-12 sm:size-20" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <Users className="size-5 sm:size-7" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-emerald-100/80 font-semibold uppercase tracking-wider truncate">
                                    Accepted
                                </p>
                                <p className="text-xl sm:text-3xl font-black">{acceptedStudents}</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-none bg-gradient-to-br from-amber-500 to-orange-600 shadow-xl rounded-2xl overflow-hidden group col-span-2 sm:col-span-1">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative text-white">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <Send className="size-12 sm:size-20" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <Send className="size-5 sm:size-7" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-amber-100/80 font-semibold uppercase tracking-wider truncate">
                                    Pending Requests
                                </p>
                                <p className="text-xl sm:text-3xl font-black">{pendingRequests}</p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Search and Filters */}
                <Card className="bg-card border-border">
                    <CardContent className="p-6">
                        <div className="flex flex-col gap-4">
                            <div className="flex flex-col sm:flex-row gap-4">
                                <div className="flex-1 relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
                                    <Input
                                        placeholder="Search by name, email, or register number..."
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        className="pl-10"
                                    />
                                </div>
                                <Select value={statusFilter} onValueChange={setStatusFilter}>
                                    <SelectTrigger className="w-full sm:w-[200px]">
                                        <SelectValue placeholder="Filter by status" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">All Status</SelectItem>
                                        <SelectItem value="accepted">Accepted</SelectItem>
                                        <SelectItem value="pending">Pending</SelectItem>
                                        <SelectItem value="rejected">Rejected</SelectItem>
                                        <SelectItem value="not_sent">Not Sent</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Students Table */}
                <Card className="bg-card border-border">
                    <CardContent className="p-0">
                        {loading ? (
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Student</TableHead>
                                        <TableHead>Register #</TableHead>
                                        <TableHead>Email</TableHead>
                                        <TableHead>Department</TableHead>
                                        <TableHead>Year</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableSkeleton columns={7} rows={10} />
                            </Table>
                        ) : filteredStudents.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-96 gap-4">
                                <FileSpreadsheet className="size-12 text-muted-foreground" />
                                <div className="text-center">
                                    <p className="text-lg font-semibold text-foreground">No Students Yet</p>
                                    <p className="text-sm text-muted-foreground">
                                        Import students using Excel or add them manually
                                    </p>
                                </div>
                                <Button onClick={() => setShowImportModal(true)} className="gap-2">
                                    <Upload className="size-4" />
                                    Import Students
                                </Button>
                            </div>
                        ) : (
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Student</TableHead>
                                        <TableHead>Register #</TableHead>
                                        <TableHead>Email</TableHead>
                                        <TableHead>Department</TableHead>
                                        <TableHead>Year</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {filteredStudents.map((student) => {
                                        const status = getAccessStatus(student);
                                        const imageUrl = student.student_image_url
                                            ? getOptimizedImageUrl(student.student_image_url, { width: 100, height: 100 })
                                            : null;

                                        return (
                                            <TableRow key={student.id}>
                                                <TableCell>
                                                    <div className="flex items-center gap-3">
                                                        <div className="relative">
                                                            <Avatar className="size-10">
                                                                <AvatarImage src={imageUrl || undefined} />
                                                                <AvatarFallback className="bg-primary/10 text-primary">
                                                                    {student.student_name.slice(0, 2).toUpperCase()}
                                                                </AvatarFallback>
                                                            </Avatar>
                                                            <div className="absolute -bottom-1 -right-1">
                                                                <ImageUploadButton
                                                                    currentImageUrl={student.student_image_url}
                                                                    onImageUpload={(url) => handleImageUpload(student.id, url)}
                                                                    onImageRemove={() => handleImageRemove(student.id)}
                                                                    size="sm"
                                                                />
                                                            </div>
                                                        </div>
                                                        <span className="font-medium">{student.student_name}</span>
                                                    </div>
                                                </TableCell>
                                                <TableCell className="font-mono text-sm">{student.register_number}</TableCell>
                                                <TableCell className="text-sm">{student.email}</TableCell>
                                                <TableCell>{student.department || "-"}</TableCell>
                                                <TableCell>{student.year || "-"}</TableCell>
                                                <TableCell>{getStatusBadge(status)}</TableCell>
                                                <TableCell className="text-right">
                                                    <DropdownMenu>
                                                        <DropdownMenuTrigger asChild>
                                                            <Button variant="ghost" size="icon" className="h-8 w-8 p-0">
                                                                <span className="sr-only">Open menu</span>
                                                                <MoreVertical className="h-4 w-4" />
                                                            </Button>
                                                        </DropdownMenuTrigger>
                                                        <DropdownMenuContent align="end">
                                                            {status === "not_sent" && (
                                                                <DropdownMenuItem onClick={() => handleSendIndividualRequest(student.student_id, student.email)}>
                                                                    <Send className="mr-2 h-4 w-4" />
                                                                    Send Request
                                                                </DropdownMenuItem>
                                                            )}
                                                            {(status === "rejected" || status === "pending") && (
                                                                <DropdownMenuItem onClick={() => handleResendRequest(student.email)}>
                                                                    <Send className="mr-2 h-4 w-4" />
                                                                    Resend Request
                                                                </DropdownMenuItem>
                                                            )}
                                                            <DropdownMenuItem onClick={() => handleEditStudent(student)}>
                                                                <Edit className="mr-2 h-4 w-4" />
                                                                Edit Details
                                                            </DropdownMenuItem>
                                                            <DropdownMenuSeparator />
                                                            <DropdownMenuItem
                                                                onClick={() => handleDeleteClick(student)}
                                                                className="text-destructive focus:text-destructive"
                                                            >
                                                                <Trash2 className="mr-2 h-4 w-4" />
                                                                Remove Student
                                                            </DropdownMenuItem>
                                                        </DropdownMenuContent>
                                                    </DropdownMenu>
                                                </TableCell>
                                            </TableRow>
                                        );
                                    })}
                                </TableBody>
                            </Table>
                        )}
                    </CardContent>
                </Card>
            </div>

            {/* Modals */}
            <AddStudentModal
                open={showAddStudentModal}
                onOpenChange={setShowAddStudentModal}
                classId={classId}
                onStudentAdded={handleAddStudent}
            />

            <ImportStudentsModal
                open={showImportModal}
                onOpenChange={setShowImportModal}
                classId={classId}
                onImport={handleImport}
            />

            <EditStudentModal
                open={showEditModal}
                onOpenChange={setShowEditModal}
                student={selectedStudent}
                onSave={handleSaveStudent}
            />

            {/* Delete Confirmation */}
            <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Delete Student</AlertDialogTitle>
                        <AlertDialogDescription>
                            Are you sure you want to remove <strong>{studentToDelete?.student_name}</strong> from this class?
                            This action cannot be undone.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleDeleteConfirm}
                            className="bg-destructive hover:bg-destructive/90"
                        >
                            Delete
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

            {/* Mobile FAB for Add Student */}
            <div className="fixed bottom-6 right-6 sm:hidden z-40 animate-in fade-in slide-in-from-bottom-4 duration-300">
                <Button
                    onClick={() => setShowAddStudentModal(true)}
                    size="icon"
                    className="size-16 rounded-full shadow-2xl bg-primary hover:bg-primary/90 transition-all active:scale-95 border-4 border-background text-primary-foreground"
                    title="Add Student"
                >
                    <Plus className="size-8 text-white" />
                </Button>
            </div>
            {/* Mobile FAB Menu */}
            <div className="fixed bottom-6 right-6 sm:hidden z-40 animate-in fade-in slide-in-from-bottom-4 duration-300">
                <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                        <Button
                            size="icon"
                            className="size-16 rounded-full shadow-2xl bg-primary hover:bg-primary/90 transition-all active:scale-95 border-4 border-background text-primary-foreground"
                            title="Actions"
                        >
                            <Plus className="size-8 text-white" />
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end" side="top" className="w-64 p-2 rounded-2xl shadow-2xl border-none backdrop-blur-xl bg-white/95 dark:bg-slate-900/95 mb-4">
                        <DropdownMenuItem onClick={() => setShowAddStudentModal(true)} className="h-14 rounded-xl cursor-pointer gap-3 px-4">
                            <div className="p-2.5 bg-primary/10 rounded-xl">
                                <UserPlus className="size-5 text-primary" />
                            </div>
                            <div className="flex flex-col">
                                <span className="font-bold text-base">Add Student</span>
                                <span className="text-[11px] text-muted-foreground leading-tight">Add a single student manually</span>
                            </div>
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setShowImportModal(true)} className="h-14 rounded-xl cursor-pointer gap-3 px-4">
                            <div className="p-2.5 bg-emerald-500/10 rounded-xl">
                                <FileSpreadsheet className="size-5 text-emerald-600" />
                            </div>
                            <div className="flex flex-col">
                                <span className="font-bold text-base">Import Excel</span>
                                <span className="text-[11px] text-muted-foreground leading-tight">Bulk upload student data</span>
                            </div>
                        </DropdownMenuItem>
                        <DropdownMenuSeparator className="bg-slate-100 dark:bg-slate-800" />
                        <DropdownMenuItem onClick={handleSendAllRequests} disabled={students.length === 0 || sendingRequests} className="h-14 rounded-xl cursor-pointer gap-3 px-4">
                            <div className="p-2.5 bg-blue-500/10 rounded-xl">
                                <Send className="size-5 text-blue-600" />
                            </div>
                            <div className="flex flex-col">
                                <span className="font-bold text-base">Send All Requests</span>
                                <span className="text-[11px] text-muted-foreground leading-tight">Invite all pending students</span>
                            </div>
                        </DropdownMenuItem>
                    </DropdownMenuContent>
                </DropdownMenu>
            </div>
        </DashboardLayout>
    );
}

import { useState, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { useAssignmentSubmissions } from '@/hooks/useAssignmentSubmissions';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent } from '@/components/ui/card';
import {
    ArrowLeft,
    Search,
    Loader2,
    CheckCircle2,
    Clock,
    FileText,
    MoreVertical,
    Download,
    AlertCircle,
    Eye,
    ChevronLeft,
    ChevronRight
} from 'lucide-react';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { cn } from '@/lib/utils';
import { useEffect } from 'react';
import { format } from 'date-fns';
import { formatFileSize, getFileExtension, getFileTypeDisplay } from '@/lib/fileUtils';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export default function AssignmentSubmissionsPage() {
    const { classId, assignmentId } = useParams<{ classId: string; assignmentId: string }>();
    const navigate = useNavigate();
    const { submissions, loading: submissionsLoading } = useAssignmentSubmissions(assignmentId!, classId!);
    const [searchQuery, setSearchQuery] = useState("");
    const [filter, setFilter] = useState<'all' | 'submitted' | 'not_submitted'>('all');
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 5;

    // Reset to page 1 when search or filter changes
    useEffect(() => {
        setCurrentPage(1);
    }, [searchQuery, filter]);

    // Fetch assignment details for the header
    const { data: assignment, isLoading: assignmentLoading } = useQuery({
        queryKey: ['assignment', assignmentId],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('assignments')
                .select('*')
                .eq('id', assignmentId)
                .single();
            if (error) throw error;
            return data;
        },
        enabled: !!assignmentId
    });

    // Stats Calculation
    const stats = useMemo(() => {
        const total = submissions.length;
        const pending = submissions.filter(s => s.status === 'pending').length;

        // Calculate average score for graded assignments
        const gradedSubs = submissions.filter(s => s.grade !== null && s.grade !== undefined);
        const totalScore = gradedSubs.reduce((acc, curr) => acc + (parseInt(curr.grade || '0') || 0), 0);
        const avgScore = gradedSubs.length > 0 ? Math.round(totalScore / gradedSubs.length) : 0;

        return { total, pending, avgScore };
    }, [submissions]);

    // Filtering
    const filteredSubmissions = useMemo(() => {
        return submissions.filter(student => {
            const matchesSearch =
                student.student_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                student.register_number.toLowerCase().includes(searchQuery.toLowerCase());

            if (!matchesSearch) return false;

            if (filter === 'all') return true;
            if (filter === 'submitted') return student.status !== 'pending';
            if (filter === 'not_submitted') return student.status === 'pending';

            return true;
        });
    }, [submissions, searchQuery, filter]);

    // Pagination Logic
    const paginatedSubmissions = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return filteredSubmissions.slice(startIndex, startIndex + itemsPerPage);
    }, [filteredSubmissions, currentPage]);

    const totalPages = Math.ceil(filteredSubmissions.length / itemsPerPage);
    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = Math.min(startIndex + itemsPerPage, filteredSubmissions.length);

    const getStatusBadge = (student: any) => {
        const statusMap = {
            graded: {
                label: `GRADED (${student.grade || '0'}/100)`,
                dot: "bg-blue-500",
                bg: "bg-blue-500/10",
                text: "text-blue-500",
                border: "border-blue-500/20"
            },
            submitted: {
                label: "ON TIME",
                dot: "bg-emerald-500",
                bg: "bg-emerald-500/10",
                text: "text-emerald-500",
                border: "border-emerald-500/20"
            },
            returned: {
                label: "LATE",
                dot: "bg-amber-500",
                bg: "bg-amber-500/10",
                text: "text-amber-500",
                border: "border-amber-500/20"
            },
            pending: {
                label: "NOT SUBMITTED",
                dot: "bg-slate-400",
                bg: "bg-slate-400/10",
                text: "text-slate-400",
                border: "border-slate-400/20"
            }
        };

        const config = statusMap[student.status as keyof typeof statusMap] || statusMap.pending;

        return (
            <Badge
                variant="outline"
                className={cn(
                    "gap-2 px-3 py-1.5 font-bold text-[10px] uppercase tracking-wider rounded-full border shadow-sm",
                    config.bg, config.text, config.border
                )}
            >
                <span className={cn("size-1.5 rounded-full shrink-0", config.dot)} />
                {config.label}
            </Badge>
        );
    };

    if (submissionsLoading || assignmentLoading) {
        return (
            <div className="h-screen w-full flex items-center justify-center">
                <Loader2 className="size-8 animate-spin text-primary" />
            </div>
        );
    }

    return (
        <DashboardLayout>
            <div className="flex flex-col gap-8 w-full">

                {/* Header Section */}
                <div className="flex flex-col gap-6">
                    <Button
                        variant="ghost"
                        onClick={() => navigate(`/lecturer/assignments/${classId}`)}
                        className="w-fit text-muted-foreground hover:text-foreground pl-0 gap-2"
                    >
                        <ArrowLeft className="size-4" />
                        Back to Courses
                    </Button>

                    <div className="flex flex-col lg:flex-row lg:items-start justify-between gap-6">
                        <div className="space-y-1">
                            <h1 className="text-2xl sm:text-3xl lg:text-4xl font-black tracking-tight text-foreground leading-tight">
                                Assignment Submissions
                            </h1>
                            <p className="text-base sm:text-lg text-slate-500 font-bold uppercase tracking-tight">
                                {assignment?.title || "Assignment Review"}
                            </p>
                        </div>

                        <div className="grid grid-cols-2 gap-3 w-full lg:w-auto">
                            <Card className="border-none bg-gradient-to-br from-blue-600 to-indigo-700 shadow-lg rounded-2xl overflow-hidden group">
                                <CardContent className="p-3 flex items-center gap-2 relative">
                                    <div className="absolute top-0 right-0 p-3 opacity-10 group-hover:scale-110 transition-transform">
                                        <FileText className="size-10 text-white" />
                                    </div>
                                    <div className="p-2 bg-white/10 rounded-xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                        <FileText className="size-4 text-white" />
                                    </div>
                                    <div className="relative z-10 min-w-0">
                                        <p className="text-[10px] text-blue-100/80 font-semibold uppercase tracking-wider truncate">
                                            Total
                                        </p>
                                        <p className="text-xl font-black text-white">{stats.total}</p>
                                    </div>
                                </CardContent>
                            </Card>

                            <Card className="border-none bg-gradient-to-br from-amber-500 to-orange-600 shadow-lg rounded-2xl overflow-hidden group">
                                <CardContent className="p-3 flex items-center gap-2 relative">
                                    <div className="absolute top-0 right-0 p-3 opacity-10 group-hover:scale-110 transition-transform">
                                        <Clock className="size-10 text-white" />
                                    </div>
                                    <div className="p-2 bg-white/10 rounded-xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                        <Clock className="size-4 text-white" />
                                    </div>
                                    <div className="relative z-10 min-w-0">
                                        <p className="text-[10px] text-amber-100/80 font-semibold uppercase tracking-wider truncate">
                                            Pending
                                        </p>
                                        <p className="text-xl font-black text-white">{stats.pending}</p>
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    </div>
                </div>

                {/* Filter Bar - Mockup Style */}
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div className="relative w-full md:w-[350px] group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 size-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                        <Input
                            placeholder="Search students..."
                            className="h-12 pl-11 pr-4 bg-[#1a1625]/50 dark:bg-[#1a1625]/50 border-white/5 focus:border-primary/50 focus:ring-primary/20 rounded-xl text-sm font-medium transition-all"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>

                    <div className="flex items-center gap-1.5 bg-[#1a1625]/50 backdrop-blur-md p-1.5 rounded-2xl border border-white/5 w-full md:w-fit overflow-x-auto no-scrollbar ml-auto">
                        <Button
                            variant={filter === 'all' ? 'default' : 'ghost'}
                            size="sm"
                            className={cn(
                                "flex-1 md:flex-none rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest px-4 md:px-6 h-9 transition-all shrink-0",
                                filter === 'all'
                                    ? "bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-500/30 md:px-8"
                                    : "text-slate-400 hover:text-slate-200"
                            )}
                            onClick={() => setFilter('all')}
                        >
                            All
                        </Button>
                        <Button
                            variant={filter === 'submitted' ? 'default' : 'ghost'}
                            size="sm"
                            className={cn(
                                "flex-1 md:flex-none rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest px-4 md:px-6 h-9 transition-all shrink-0",
                                filter === 'submitted'
                                    ? "bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-500/30 md:px-8"
                                    : "text-slate-400 hover:text-slate-200"
                            )}
                            onClick={() => setFilter('submitted')}
                        >
                            Submitted
                        </Button>
                        <Button
                            variant={filter === 'not_submitted' ? 'default' : 'ghost'}
                            size="sm"
                            className={cn(
                                "flex-1 md:flex-none rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest px-4 md:px-6 h-9 transition-all shrink-0",
                                filter === 'not_submitted'
                                    ? "bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-500/30 md:px-8"
                                    : "text-slate-400 hover:text-slate-200"
                            )}
                            onClick={() => setFilter('not_submitted')}
                        >
                            Pending
                        </Button>
                    </div>
                </div>

                {/* Submissions List Container */}
                <div className="bg-[#1a1625]/30 backdrop-blur-xl rounded-[2rem] border border-white/5 shadow-2xl overflow-hidden flex flex-col">
                    {/* Header Row - Desktop Only */}
                    <div className="hidden md:grid md:grid-cols-[250px,1fr,200px,120px] gap-8 px-10 py-6 border-b border-white/5">
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Student</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Submission</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 text-center">Status</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 text-right">Actions</span>
                    </div>

                    <div className="divide-y divide-white/5">
                        {paginatedSubmissions.length > 0 ? (
                            paginatedSubmissions.map((student) => (
                                <div key={student.student_id} className="group">
                                    {/* Desktop Row View */}
                                    <div className="hidden md:grid md:grid-cols-[250px,1fr,200px,120px] items-center gap-8 px-10 py-6 hover:bg-white/[0.02] transition-all">
                                        <div className="flex items-center gap-4">
                                            <div className="relative">
                                                <Avatar className="size-10 border-2 border-indigo-500/20 shadow-lg bg-indigo-500/10">
                                                    <AvatarImage src={student.profile_image || undefined} />
                                                    <AvatarFallback className="bg-transparent text-indigo-400 text-[10px] font-black line-height-none">
                                                        {student.student_name.substring(0, 2).toUpperCase()}
                                                    </AvatarFallback>
                                                </Avatar>
                                                <div className="absolute -bottom-0.5 -right-0.5 size-2.5 bg-emerald-500 border-2 border-[#1a1625] rounded-full" />
                                            </div>
                                            <div className="min-w-0">
                                                <h4 className="font-bold text-sm text-slate-100 truncate group-hover:text-indigo-400 transition-colors">{student.student_name}</h4>
                                                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mt-0.5">
                                                    {student.register_number || "711523BAD303"}
                                                </p>
                                            </div>
                                        </div>

                                        <div className="w-full">
                                            {student.file_url ? (
                                                <div className="inline-flex items-center gap-4 bg-white/[0.03] border border-white/5 hover:border-indigo-500/30 hover:bg-white/[0.05] p-3 rounded-xl transition-all max-w-sm w-full">
                                                    <div className="p-2 rounded-lg bg-indigo-500/10 text-indigo-400">
                                                        <FileText className="size-4" />
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <p className="text-xs font-bold text-slate-200 truncate">{student.file_name || "Assignment File.pdf"}</p>
                                                        <p className="text-[9px] text-slate-500 font-bold uppercase tracking-wider mt-0.5">
                                                            {student.file_type?.toUpperCase() || "PDF"} • {formatFileSize(student.file_size) || "114.9 KB"}
                                                        </p>
                                                    </div>
                                                </div>
                                            ) : (
                                                <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.1em] italic">No Submission</span>
                                            )}
                                        </div>

                                        <div className="flex justify-center">
                                            {getStatusBadge(student)}
                                        </div>

                                        <div className="flex items-center justify-end gap-3">
                                            {student.file_url ? (
                                                <>
                                                    <Button variant="ghost" size="icon" className="size-8 rounded-lg hover:bg-white/5 text-slate-400 hover:text-indigo-400 transition-all" asChild>
                                                        <a href={student.file_url} target="_blank" rel="noopener noreferrer">
                                                            <Eye className="size-4" />
                                                        </a>
                                                    </Button>
                                                    <Button variant="ghost" size="icon" className="size-8 rounded-lg hover:bg-white/5 text-slate-400 hover:text-indigo-400 transition-all" asChild>
                                                        <a href={student.file_url} target="_blank" rel="noopener noreferrer" download>
                                                            <Download className="size-4" />
                                                        </a>
                                                    </Button>
                                                </>
                                            ) : (
                                                <span className="text-[10px] font-black text-slate-700 tracking-wider">N/A</span>
                                            )}
                                        </div>
                                    </div>

                                    {/* Mobile Card View - Easy to use design */}
                                    <div className="md:hidden p-5 flex flex-col gap-4 hover:bg-white/[0.02]">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-3">
                                                <Avatar className="size-11 border-2 border-indigo-500/20">
                                                    <AvatarFallback className="bg-indigo-500/10 text-indigo-400 text-xs font-black">
                                                        {student.student_name.substring(0, 2).toUpperCase()}
                                                    </AvatarFallback>
                                                </Avatar>
                                                <div>
                                                    <h4 className="font-bold text-sm text-slate-100">{student.student_name}</h4>
                                                    <p className="text-[10px] text-slate-500 font-bold">{student.register_number}</p>
                                                </div>
                                            </div>
                                            {getStatusBadge(student)}
                                        </div>

                                        {student.file_url ? (
                                            <div className="bg-white/[0.03] border border-white/5 p-3 rounded-2xl flex items-center gap-3 active:scale-95 transition-transform">
                                                <div className="p-2.5 rounded-xl bg-indigo-500/10 text-indigo-400">
                                                    <FileText className="size-5" />
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-xs font-bold text-slate-200 truncate">{student.file_name}</p>
                                                    <p className="text-[9px] text-slate-500 font-bold uppercase tracking-wider">{student.file_type?.toUpperCase()} • {formatFileSize(student.file_size)}</p>
                                                </div>
                                                <div className="flex gap-1.5">
                                                    <Button variant="ghost" size="icon" className="size-9 bg-white/5 rounded-full" asChild>
                                                        <a href={student.file_url} target="_blank" rel="noopener noreferrer"><Download className="size-4" /></a>
                                                    </Button>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="bg-red-500/5 border border-red-500/10 p-3 rounded-2xl text-center">
                                                <p className="text-[10px] text-red-400 font-black uppercase tracking-widest">No Submission recorded</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="py-24 text-center">
                                <AlertCircle className="size-10 text-slate-700 mx-auto mb-4" />
                                <p className="text-sm font-bold text-slate-500">No students found matching your filters.</p>
                            </div>
                        )}
                    </div>

                    {/* Pagination Footer - Mockup Style */}
                    <div className="px-10 py-6 border-t border-white/5 bg-white/[0.01] flex flex-col sm:flex-row items-center justify-between gap-4">
                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">
                            Showing <span className="text-indigo-400">{filteredSubmissions.length === 0 ? 0 : startIndex + 1} - {endIndex}</span> of <span className="text-slate-300">{filteredSubmissions.length}</span> students
                        </p>

                        <div className="flex items-center gap-4">
                            <div className="flex gap-2">
                                <Button
                                    variant="outline"
                                    size="icon"
                                    onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                                    disabled={currentPage === 1}
                                    className="size-10 rounded-xl border-white/5 bg-white/[0.03] text-slate-500 hover:text-white transition-all disabled:opacity-20 shadow-lg shadow-black/20"
                                >
                                    <ChevronLeft className="size-4" />
                                </Button>
                                <Button
                                    variant="outline"
                                    size="icon"
                                    onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                                    disabled={currentPage >= totalPages || totalPages === 0}
                                    className="size-10 rounded-xl border-white/5 bg-white/[0.03] text-slate-500 hover:text-white transition-all disabled:opacity-20 shadow-lg shadow-black/20"
                                >
                                    <ChevronRight className="size-4" />
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </DashboardLayout >
    );
}

import React, { useState } from 'react';
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import {
    Phone, PhoneIncoming, PhoneOutgoing, PhoneMissed, PhoneOff,
    Video, VideoOff, Clock, Calendar, Search, Filter,
    MoreVertical, Trash2, ArrowLeft, ArrowUpRight, ArrowDownLeft,
    ChevronDown, Plus, X, MessageSquare, Settings
} from 'lucide-react';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Card, CardContent, CardHeader, CardTitle, CardDescription
} from '@/components/ui/card';
import {
    DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger
} from '@/components/ui/dropdown-menu';
import { format, isToday, isYesterday, isThisWeek, parseISO } from 'date-fns';
import { cn } from '@/lib/utils';
import { ChatSkeleton } from '@/components/skeletons/ChatSkeleton';
import { toast } from 'sonner';
import { useQueryClient } from '@tanstack/react-query';
import { useCall } from '@/contexts/CallContext';
import { useEligibleStudents } from '@/hooks/useEligibleStudents';
import { useInstructors } from '@/hooks/useInstructors';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";

export default function CallHistory() {
    const { user } = useAuth();
    const { initiateCall } = useCall();
    const navigate = useNavigate();
    const queryClient = useQueryClient();
    const [searchQuery, setSearchQuery] = useState("");
    const [filter, setFilter] = useState<'all' | 'missed'>('all');
    const [isNewCallOpen, setIsNewCallOpen] = useState(false);
    const [isMobileSearchOpen, setIsMobileSearchOpen] = useState(false);
    const [contactSearch, setContactSearch] = useState("");
    const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
    const [expandedLogId, setExpandedLogId] = useState<string | null>(null);

    const { students } = useEligibleStudents();
    const { instructors } = useInstructors();

    const allContacts = [
        ...(instructors || []).map(i => ({ ...i, role: 'Instructor' })),
        ...(students || []).map(s => ({ ...s, role: 'Student' }))
    ];

    const filteredContacts = allContacts.filter(c =>
        c.full_name?.toLowerCase().includes(contactSearch.toLowerCase())
    );

    const { data: calls, isLoading } = useQuery({
        queryKey: ['call_history', user?.id],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('call_sessions')
                .select(`
                    *,
                    caller:profiles!call_sessions_caller_profiles_fkey(user_id, full_name, avatar_url, department),
                    receiver:profiles!call_sessions_receiver_profiles_fkey(user_id, full_name, avatar_url, department)
                `)
                .or(`caller_id.eq.${user?.id},receiver_id.eq.${user?.id}`)
                .order('created_at', { ascending: false });

            if (error) throw error;

            // Client-side visibility filter as a safety layer over RLS
            return (data || []).filter((call: any) => {
                if (call.caller_id === user?.id && call.is_hidden_by_caller) return false;
                if (call.receiver_id === user?.id && call.is_hidden_by_receiver) return false;
                return true;
            });
        },
        enabled: !!user?.id
    });

    // Grouping logic for Sidebar (Unique contacts)
    // List of unique contacts for Desktop Sidebar
    const desktopContacts = React.useMemo(() => {
        const groups: Record<string, any> = {};
        (calls || []).forEach((call: any) => {
            const isOutgoing = call.caller_id === user?.id;
            const otherUser = isOutgoing ? call.receiver : call.caller;
            if (!otherUser) return;

            const otherId = otherUser.user_id;

            // Apply global filters
            const name = otherUser.full_name || 'User';
            if (!name.toLowerCase().includes(searchQuery.toLowerCase())) return;
            if (filter === 'missed' && !(call.status === 'missed' || call.status === 'rejected')) return;

            if (!groups[otherId]) {
                groups[otherId] = {
                    contact: otherUser,
                    latestCall: call,
                    isOutgoing
                };
            }
        });
        return Object.values(groups);
    }, [calls, searchQuery, filter, user?.id]);

    // Flat log for Mobile view (grouped only if consecutive same-day same-type)
    const mobileLogs = React.useMemo(() => {
        const logs: any[] = [];
        (calls || []).forEach((call: any) => {
            const isOutgoing = call.caller_id === user?.id;
            const otherUser = isOutgoing ? call.receiver : call.caller;
            if (!otherUser) return;

            // Filters
            const name = otherUser.full_name || 'User';
            if (!name.toLowerCase().includes(searchQuery.toLowerCase())) return;
            if (filter === 'missed' && !(call.status === 'missed' || call.status === 'rejected')) return;

            // Consecutive grouping logic
            const prev = logs[logs.length - 1];
            const isSameUser = prev && prev.contact.user_id === otherUser.user_id;
            const isSameType = prev && prev.latestCall.call_type === call.call_type;
            const isSameStatus = prev && (
                (prev.latestCall.status === 'missed' || prev.latestCall.status === 'rejected') ===
                (call.status === 'missed' || call.status === 'rejected')
            );
            const isSameDay = prev && isSameDayDate(new Date(prev.latestCall.created_at), new Date(call.created_at));

            if (isSameUser && isSameType && isSameStatus && isSameDay) {
                prev.count = (prev.count || 1) + 1;
            } else {
                logs.push({
                    contact: otherUser,
                    latestCall: call,
                    isOutgoing,
                    count: 1
                });
            }
        });
        return logs;
    }, [calls, searchQuery, filter, user?.id]);

    function isSameDayDate(d1: Date, d2: Date) {
        return d1.getFullYear() === d2.getFullYear() &&
            d1.getMonth() === d2.getMonth() &&
            d1.getDate() === d2.getDate();
    }

    // Grouping logic for Detail View (Dates for selected contact)
    const detailLogs = React.useMemo(() => {
        if (!selectedContactId) return [];
        const contactCalls = (calls || []).filter((call: any) =>
            call.caller_id === selectedContactId || call.receiver_id === selectedContactId
        );

        const dateGroups: Record<string, any[]> = {};
        contactCalls.forEach(call => {
            const date = format(new Date(call.created_at), 'dd/MM/yyyy');
            if (!dateGroups[date]) dateGroups[date] = [];
            dateGroups[date].push(call);
        });

        return Object.entries(dateGroups).map(([date, calls]) => ({ date, calls }));
    }, [calls, selectedContactId]);

    const activeDetailContact = selectedContactId
        ? allContacts.find(c => c.id === selectedContactId) ||
        desktopContacts.find(i => i.contact.user_id === selectedContactId)?.contact ||
        mobileLogs.find(i => i.contact.user_id === selectedContactId)?.contact
        : null;

    const formatDuration = (seconds: number) => {
        if (!seconds) return '';
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return mins > 0 ? `${mins} minute${mins > 1 ? 's' : ''} ${secs} seconds` : `${secs} seconds`;
    };

    const handleDeleteCall = async (callId: string, isCaller: boolean) => {
        try {
            console.log('Attempting to delete call:', { callId, isCaller, userId: user?.id });
            const updateData = isCaller ? { is_hidden_by_caller: true } : { is_hidden_by_receiver: true };

            const { error } = await supabase
                .from('call_sessions')
                .update(updateData as any)
                .eq('id', callId);

            if (error) {
                console.error('Supabase update error details:', {
                    message: error.message,
                    details: error.details,
                    hint: error.hint,
                    code: error.code
                });
                throw error;
            }

            await queryClient.invalidateQueries({ queryKey: ['call_history', user?.id] });
            toast.success("Call removed from history");
        } catch (error: any) {
            console.error('Delete call failure:', error);
            const msg = error.message || "Failed to remove call";
            toast.error(msg);
        }
    };

    if (isLoading) return <DashboardLayout fullHeight={true}><ChatSkeleton /></DashboardLayout>;

    return (
        <DashboardLayout fullHeight={true}>
            <div className="flex bg-slate-50 dark:bg-[#0b141a] text-slate-900 dark:text-slate-200 h-full overflow-hidden">
                {/* Sidebar Pane */}
                <div className={cn(
                    "w-full md:w-[400px] flex flex-col min-h-0 border-r border-slate-200 dark:border-slate-800/50 bg-white dark:bg-[#111b21]",
                    selectedContactId && "hidden md:flex"
                )}>
                    <div className="p-4 space-y-4">
                        <div className="flex items-center justify-between">
                            {isMobileSearchOpen ? (
                                <div className="flex items-center gap-2 w-full animate-in slide-in-from-left-2 duration-200">
                                    <Button
                                        variant="ghost" size="icon"
                                        className="rounded-full text-slate-400"
                                        onClick={() => setIsMobileSearchOpen(false)}
                                    >
                                        <ArrowLeft className="size-5" />
                                    </Button>
                                    <Input
                                        autoFocus
                                        placeholder="Search..."
                                        className="bg-slate-100 dark:bg-[#202c33] border-none rounded-lg h-10 text-slate-900 dark:text-slate-200 focus-visible:ring-0 placeholder:text-slate-500"
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                    />
                                </div>
                            ) : (
                                <>
                                    <h2 className="text-2xl font-semibold text-slate-900 dark:text-white md:text-xl md:font-bold">Calls</h2>
                                    <div className="flex items-center gap-1 md:gap-0">
                                        <Button
                                            variant="ghost" size="icon"
                                            className="rounded-full text-slate-700 dark:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 flex md:hidden"
                                            onClick={() => setIsMobileSearchOpen(true)}
                                        >
                                            <Search className="size-5" />
                                        </Button>
                                        <Button
                                            variant="ghost" size="icon"
                                            className="rounded-full text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hidden md:flex"
                                            onClick={() => setIsNewCallOpen(true)}
                                        >
                                            <Plus className="size-6" />
                                        </Button>
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button
                                                    variant="ghost" size="icon"
                                                    className="rounded-full text-slate-700 dark:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 flex md:hidden"
                                                >
                                                    <MoreVertical className="size-5" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end" className="bg-white dark:bg-[#233138] border-slate-200 dark:border-none text-slate-800 dark:text-slate-200 min-w-[200px] shadow-2xl">
                                                <DropdownMenuItem
                                                    className="focus:bg-slate-100 dark:focus:bg-[#111b21] focus:text-slate-900 dark:focus:text-white flex items-center gap-3 py-3 cursor-pointer"
                                                    onClick={() => setIsNewCallOpen(true)}
                                                >
                                                    <Plus className="size-4" />
                                                    <span>New Call</span>
                                                </DropdownMenuItem>
                                                <DropdownMenuItem
                                                    className="focus:bg-slate-100 dark:focus:bg-[#111b21] focus:text-slate-900 dark:focus:text-white flex items-center gap-3 py-3 cursor-pointer"
                                                    onClick={() => navigate('/messages')}
                                                >
                                                    <MessageSquare className="size-4" />
                                                    <span>Messages</span>
                                                </DropdownMenuItem>
                                                <DropdownMenuItem
                                                    className="focus:bg-slate-100 dark:focus:bg-[#111b21] focus:text-slate-900 dark:focus:text-white flex items-center gap-3 py-3 cursor-pointer"
                                                    onClick={() => setFilter(filter === 'all' ? 'missed' : 'all')}
                                                >
                                                    <Filter className="size-4" />
                                                    <span>{filter === 'all' ? 'Show Missed Calls' : 'Show All Calls'}</span>
                                                </DropdownMenuItem>
                                                <DropdownMenuItem
                                                    className="focus:bg-slate-100 dark:focus:bg-[#111b21] focus:text-slate-900 dark:focus:text-white flex items-center gap-3 py-3 cursor-pointer"
                                                    onClick={() => navigate('/settings')}
                                                >
                                                    <Settings className="size-4" />
                                                    <span>Settings</span>
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </div>
                                </>
                            )}
                        </div>

                        <div className="relative hidden md:block">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-slate-500" />
                            <Input
                                placeholder="Search name or number"
                                className="pl-10 h-10 bg-slate-100 dark:bg-[#202c33] border-none rounded-lg text-sm text-slate-900 dark:text-slate-200 focus-visible:ring-0 placeholder:text-slate-500"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>

                        {/* Tabs - Hidden on mobile as per requirement for clean log look */}
                        <div className="hidden md:flex gap-2">
                            <Button
                                variant="ghost"
                                className={cn(
                                    "rounded-full px-4 h-8 text-xs font-semibold hover:bg-slate-200 dark:hover:bg-slate-800",
                                    filter === 'all' ? "bg-slate-200 dark:bg-slate-700 text-slate-900 dark:text-white" : "text-slate-600 dark:text-slate-400"
                                )}
                                onClick={() => setFilter('all')}
                            >
                                All
                            </Button>
                            <Button
                                variant="ghost"
                                className={cn(
                                    "rounded-full px-4 h-8 text-xs font-semibold hover:bg-slate-200 dark:hover:bg-slate-800",
                                    filter === 'missed' ? "bg-slate-200 dark:bg-slate-700 text-slate-900 dark:text-white" : "text-slate-600 dark:text-slate-400"
                                )}
                                onClick={() => setFilter('missed')}
                            >
                                Missed
                            </Button>
                        </div>
                    </div>

                    <ScrollArea className="flex-1">
                        <div className="px-0 md:px-2 pb-10">
                            {/* Mobile Flat Log vs Desktop Grouped List */}
                            <div className="md:hidden">
                                {mobileLogs.length === 0 ? (
                                    <div className="py-20 text-center text-slate-500 px-10">
                                        <PhoneOff className="size-12 mx-auto mb-4 opacity-20" />
                                        <p className="text-sm">No recent calls found</p>
                                    </div>
                                ) : (
                                    mobileLogs.map((item: any, idx) => {
                                        const contact = item.contact;
                                        const call = item.latestCall;
                                        const isMissed = call.status === 'missed' || call.status === 'rejected';

                                        const dateStr = isToday(new Date(call.created_at)) ? format(new Date(call.created_at), 'h:mm a') :
                                            isYesterday(new Date(call.created_at)) ? 'Yesterday, ' + format(new Date(call.created_at), 'h:mm a') :
                                                format(new Date(call.created_at), 'd MMMM, h:mm a');

                                        const logKey = `${contact.user_id}-${call.id}`;
                                        const isExpanded = expandedLogId === logKey;

                                        return (
                                            <div key={logKey} className="px-0 py-0 animate-in fade-in duration-300">
                                                <div
                                                    onClick={() => setExpandedLogId(isExpanded ? null : logKey)}
                                                    className={cn(
                                                        "flex items-center gap-4 p-4 cursor-pointer hover:bg-slate-100 dark:hover:bg-[#1f2c33] transition-colors border-b border-slate-200 dark:border-white/5 active:bg-slate-200 dark:active:bg-[#202c33]",
                                                        isExpanded && "bg-slate-50 dark:bg-[#1f2c33] border-b-0"
                                                    )}
                                                >
                                                    <Avatar className="h-14 w-14 border-none shrink-0 pointer-events-none">
                                                        <AvatarImage src={contact.avatar_url} />
                                                        <AvatarFallback className="bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold uppercase text-lg">
                                                            {contact.full_name?.[0]}
                                                        </AvatarFallback>
                                                    </Avatar>

                                                    <div className="flex-1 min-w-0 pointer-events-none">
                                                        <p className="font-medium text-[17px] truncate mb-0.5 text-slate-900 dark:text-white">
                                                            {contact.full_name}{item.count > 1 ? `(${item.count})` : ''}
                                                        </p>
                                                        <div className="flex items-center gap-1.5">
                                                            {item.isOutgoing ? (
                                                                <ArrowUpRight className={cn("size-3.5", isMissed ? "text-red-500" : "text-emerald-500")} />
                                                            ) : (
                                                                <ArrowDownLeft className={cn("size-3.5", isMissed ? "text-red-500" : "text-emerald-500")} />
                                                            )}
                                                            <p className="text-[14px] text-slate-500 dark:text-slate-400 truncate font-light">
                                                                {dateStr}
                                                            </p>
                                                        </div>
                                                    </div>

                                                    <div
                                                        className="shrink-0 ml-2 p-2 rounded-full active:bg-slate-200 dark:active:bg-white/10"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            initiateCall(contact.user_id, contact.full_name, contact.avatar_url || '', call.call_type || 'audio');
                                                        }}
                                                    >
                                                        {call.call_type === 'video' ? (
                                                            <Video className="size-6 text-slate-700 dark:text-slate-200" />
                                                        ) : (
                                                            <Phone className="size-5 text-slate-700 dark:text-slate-200" />
                                                        )}
                                                    </div>
                                                </div>

                                                {isExpanded && (
                                                    <div className="bg-slate-50 dark:bg-[#1f2c33] flex items-center justify-around py-3 border-t border-slate-200 dark:border-white/5 animate-in slide-in-from-top-1 duration-200 border-b border-slate-200 dark:border-white/5">
                                                        <button
                                                            className="flex flex-col items-center gap-1.5 px-4 py-1 active:bg-slate-200 dark:active:bg-white/5 rounded-xl transition-colors"
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                setSelectedContactId(contact.user_id);
                                                            }}
                                                        >
                                                            <Clock className="size-5 text-slate-500 dark:text-slate-400" />
                                                            <span className="text-[11px] text-slate-500 dark:text-slate-400">Info</span>
                                                        </button>
                                                        <button
                                                            className="flex flex-col items-center gap-1.5 px-4 py-1 active:bg-slate-200 dark:active:bg-white/5 rounded-xl transition-colors"
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                navigate('/messages', { state: { contactId: contact.user_id } });
                                                            }}
                                                        >
                                                            <MessageSquare className="size-5 text-slate-500 dark:text-slate-400" />
                                                            <span className="text-[11px] text-slate-500 dark:text-slate-400">Message</span>
                                                        </button>
                                                        <button
                                                            className="flex flex-col items-center gap-1.5 px-4 py-1 active:bg-slate-200 dark:active:bg-white/5 rounded-xl transition-colors"
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                initiateCall(contact.user_id, contact.full_name, contact.avatar_url || '', 'video');
                                                                setExpandedLogId(null);
                                                            }}
                                                        >
                                                            <Video className="size-5 text-slate-500 dark:text-slate-400" />
                                                            <span className="text-[11px] text-slate-500 dark:text-slate-400">Video Call</span>
                                                        </button>
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })
                                )}
                            </div>

                            <div className="hidden md:block">
                                {desktopContacts.length === 0 ? (
                                    <div className="py-20 text-center text-slate-500 px-10">
                                        <PhoneOff className="size-12 mx-auto mb-4 opacity-20" />
                                        <p className="text-sm">No recent calls found</p>
                                    </div>
                                ) : (
                                    desktopContacts.map((item: any) => {
                                        const contact = item.contact;
                                        const call = item.latestCall;
                                        const isMissed = call.status === 'missed' || call.status === 'rejected';
                                        const dateStr = isToday(new Date(call.created_at)) ? format(new Date(call.created_at), 'h:mm a') :
                                            isYesterday(new Date(call.created_at)) ? 'Yesterday' :
                                                format(new Date(call.created_at), 'EEEE');

                                        return (
                                            <div
                                                key={contact.user_id}
                                                onClick={() => setSelectedContactId(contact.user_id)}
                                                className={cn(
                                                    "flex items-center gap-4 p-3 rounded-xl cursor-pointer hover:bg-slate-100 dark:hover:bg-[#202c33] transition-colors group",
                                                    selectedContactId === contact.user_id && "bg-slate-200 dark:bg-[#2a3942]"
                                                )}
                                            >
                                                <Avatar className="h-12 w-12 border-none">
                                                    <AvatarImage src={contact.avatar_url} />
                                                    <AvatarFallback className="bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold uppercase">
                                                        {contact.full_name?.[0]}
                                                    </AvatarFallback>
                                                </Avatar>

                                                <div className="flex-1 min-w-0">
                                                    <div className="flex justify-between items-baseline mb-0.5">
                                                        <p className="font-semibold text-slate-900 dark:text-white truncate text-sm">
                                                            {contact.full_name}
                                                        </p>
                                                        <span className="text-[10px] text-slate-500 font-medium">
                                                            {dateStr}
                                                        </span>
                                                    </div>
                                                    <div className="flex items-center gap-1.5">
                                                        {isMissed ? (
                                                            <ArrowDownLeft className="size-3 text-red-500" />
                                                        ) : item.isOutgoing ? (
                                                            <ArrowUpRight className="size-3 text-emerald-500" />
                                                        ) : (
                                                            <ArrowDownLeft className="size-3 text-blue-500" />
                                                        )}
                                                        <p className={cn(
                                                            "text-[12px] truncate",
                                                            isMissed ? "text-red-500" : "text-slate-500 dark:text-slate-400"
                                                        )}>
                                                            {isMissed ? 'Missed' : item.isOutgoing ? 'Outgoing' : 'Incoming'}
                                                        </p>
                                                    </div>
                                                </div>

                                                <div className="hidden group-hover:flex items-center gap-1">
                                                    <Button variant="ghost" size="icon" className="size-8 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white">
                                                        <Phone className="size-4" />
                                                    </Button>
                                                    <Button variant="ghost" size="icon" className="size-8 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white">
                                                        <Video className="size-4" />
                                                    </Button>
                                                </div>
                                            </div>
                                        );
                                    })
                                )}
                            </div>
                        </div>
                    </ScrollArea>
                </div>

                {/* Detail Pane */}
                <div className={cn(
                    "flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0b141a] relative",
                    !selectedContactId && "hidden md:flex items-center justify-center"
                )}>
                    {activeDetailContact ? (
                        <>
                            {/* Header */}
                            <div className="h-16 border-b border-slate-200 dark:border-slate-800/50 flex items-center justify-between px-6 bg-slate-50 dark:bg-[#111b21] shrink-0">
                                <div className="flex items-center gap-3">
                                    <Button
                                        variant="ghost" size="icon"
                                        className="md:hidden -ml-2 text-slate-500 dark:text-slate-400"
                                        onClick={() => setSelectedContactId(null)}
                                    >
                                        <ArrowLeft className="size-5" />
                                    </Button>
                                    <h2 className="text-xl font-bold text-slate-900 dark:text-white">Call info</h2>
                                </div>
                                <Button
                                    variant="ghost" size="icon"
                                    className="text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full"
                                    onClick={() => setSelectedContactId(null)}
                                >
                                    <X className="size-5" />
                                </Button>
                            </div>

                            <ScrollArea className="flex-1">
                                <div className="w-full max-w-[1400px] mx-auto p-4 md:p-8 lg:p-10 space-y-8">
                                    {/* Contact Hero Area */}
                                    <div className="relative group overflow-hidden md:bg-gradient-to-br md:from-white md:to-slate-50 dark:md:from-[#111b21] dark:md:to-[#182229] md:border border-slate-200 dark:border-slate-800/50 md:rounded-[2rem] py-4 px-2 md:p-8 md:shadow-2xl">
                                        <div className="hidden md:block absolute top-0 right-0 p-8 opacity-5 text-slate-900 dark:text-inherit">
                                            <Phone className="size-48 rotate-12" />
                                        </div>

                                        <div className="relative flex flex-col md:flex-row items-center justify-between gap-6 md:gap-8">
                                            <div className="flex flex-col md:flex-row items-center gap-4 md:gap-8 text-center md:text-left">
                                                <div className="relative shrink-0">
                                                    <Avatar className="h-28 w-28 lg:h-32 lg:w-32 border-none md:border-solid md:border-4 md:border-white dark:md:border-slate-800 shadow-xl md:shadow-2xl transition-transform group-hover:scale-105 duration-500">
                                                        <AvatarImage src={activeDetailContact.avatar_url || (activeDetailContact as any).contact?.avatar_url} />
                                                        <AvatarFallback className="bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-200 text-4xl font-black uppercase">
                                                            {activeDetailContact.full_name?.[0]}
                                                        </AvatarFallback>
                                                    </Avatar>
                                                    <div className="absolute -bottom-2 -right-2 bg-emerald-500 p-2 rounded-2xl border-4 border-white dark:border-[#0b141a] md:border-slate-50 dark:md:border-[#111b21]">
                                                        <div className="size-3 bg-white rounded-full animate-pulse" />
                                                    </div>
                                                </div>
                                                <div className="min-w-0">
                                                    <h3 className="text-2xl lg:text-3xl xl:text-4xl font-black text-slate-900 dark:text-white tracking-tight leading-tight mb-2 md:mb-3">
                                                        {activeDetailContact.full_name}
                                                    </h3>
                                                    <div className="flex flex-wrap items-center justify-center md:justify-start gap-2 lg:gap-3">
                                                        <Badge className="bg-emerald-50 dark:bg-emerald-500/10 text-emerald-600 dark:text-emerald-500 border-none px-3 py-1 font-bold uppercase tracking-widest text-[10px]">
                                                            {activeDetailContact.role || 'Contact'}
                                                        </Badge>
                                                        <p className="text-slate-500 dark:text-slate-400 font-medium text-[13px] lg:text-sm flex items-center gap-2">
                                                            <span className="size-1 bg-slate-300 dark:bg-slate-700 rounded-full shrink-0" />
                                                            <span className="truncate">{activeDetailContact.department || 'Education Space'}</span>
                                                        </p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex items-center justify-center gap-4 lg:gap-3 shrink-0 mt-2 md:mt-0 w-full md:w-auto">
                                                <Button
                                                    variant="secondary"
                                                    className="rounded-full size-12 lg:size-12 p-0 bg-slate-100 dark:bg-[#202c33] hover:bg-slate-200 dark:hover:bg-[#2a3942] text-slate-900 dark:text-white border-none shadow-lg group/btn transition-transform hover:-translate-y-1 shrink-0"
                                                    onClick={() => navigate('/messages', { state: { contactId: selectedContactId } })}
                                                    title="Message"
                                                >
                                                    <MessageSquare className="size-5 text-emerald-500 group-hover/btn:scale-110 transition-transform" />
                                                </Button>
                                                <Button
                                                    variant="secondary"
                                                    className="rounded-full size-12 lg:size-12 p-0 bg-slate-100 dark:bg-[#202c33] hover:bg-slate-200 dark:hover:bg-[#2a3942] text-slate-900 dark:text-white border-none shadow-lg group/btn transition-transform hover:-translate-y-1 shrink-0"
                                                    onClick={() => initiateCall(selectedContactId!, activeDetailContact!.full_name, activeDetailContact!.avatar_url || '', 'video')}
                                                    title="Video Call"
                                                >
                                                    <Video className="size-5 text-blue-500 group-hover/btn:scale-110 transition-transform" />
                                                </Button>
                                                <Button
                                                    variant="secondary"
                                                    className="rounded-full size-12 lg:size-12 p-0 bg-slate-100 dark:bg-[#202c33] hover:bg-slate-200 dark:hover:bg-[#2a3942] text-slate-900 dark:text-white border-none shadow-lg group/btn transition-transform hover:-translate-y-1 shrink-0"
                                                    onClick={() => initiateCall(selectedContactId!, activeDetailContact!.full_name, activeDetailContact!.avatar_url || '', 'audio')}
                                                    title="Audio Call"
                                                >
                                                    <Phone className="size-5 text-emerald-500 group-hover/btn:scale-110 transition-transform" />
                                                </Button>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Logs List Area */}
                                    <div className="space-y-10">
                                        <div className="flex items-center gap-4 px-2">
                                            <div className="h-px flex-1 bg-slate-200 dark:bg-slate-800/50" />
                                            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">Communication Logs</span>
                                            <div className="h-px flex-1 bg-slate-200 dark:bg-slate-800/50" />
                                        </div>

                                        <div className="space-y-12">
                                            {detailLogs.map((group) => (
                                                <div key={group.date} className="space-y-6">
                                                    <div className="flex items-center gap-4">
                                                        <div className="size-2 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
                                                        <h5 className="text-xs font-black uppercase tracking-[0.15em] text-slate-600 dark:text-slate-400">
                                                            {group.date}
                                                        </h5>
                                                    </div>

                                                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
                                                        {group.calls.map((log: any) => {
                                                            const isOutgoing = log.caller_id === user?.id;
                                                            const isMissed = log.status === 'missed' || log.status === 'rejected';
                                                            const timeStr = format(new Date(log.created_at), 'h:mm a');

                                                            return (
                                                                <div key={log.id} className="relative group/log overflow-hidden bg-white dark:bg-[#111b21] border border-slate-200 dark:border-slate-800/50 rounded-2xl p-4 hover:border-slate-300 dark:hover:border-slate-700 transition-all shadow-sm">
                                                                    <div className="flex items-center justify-between gap-4">
                                                                        <div className="flex items-center gap-4">
                                                                            <div className={cn(
                                                                                "size-12 rounded-xl flex items-center justify-center shadow-inner transition-transform group-hover/log:scale-110",
                                                                                log.call_type === 'video' ? "bg-blue-50 dark:bg-blue-500/10" : "bg-emerald-50 dark:bg-emerald-500/10"
                                                                            )}>
                                                                                {log.call_type === 'video' ?
                                                                                    <Video className="size-5 text-blue-500 dark:text-blue-400" /> :
                                                                                    <Phone className="size-5 text-emerald-500 dark:text-emerald-400" />
                                                                                }
                                                                            </div>
                                                                            <div className="min-w-0">
                                                                                <div className="flex items-center gap-2 mb-1">
                                                                                    <p className="text-sm font-bold text-slate-900 dark:text-white truncate">
                                                                                        {isOutgoing ? 'Outgoing' : 'Incoming'} Call
                                                                                    </p>
                                                                                    {isMissed && (
                                                                                        <Badge variant="secondary" className="h-5 bg-red-500/10 text-red-500 border-none text-[9px] font-black uppercase px-2 hover:bg-red-500/20">
                                                                                            Missed
                                                                                        </Badge>
                                                                                    )}
                                                                                </div>
                                                                                <div className="flex items-center gap-3 text-[11px] font-medium text-slate-500">
                                                                                    <span className="flex items-center gap-1.5 lowercase">
                                                                                        <Clock className="size-3" />
                                                                                        {timeStr}
                                                                                    </span>
                                                                                    {log.duration > 0 && (
                                                                                        <>
                                                                                            <span className="size-1 bg-slate-300 dark:bg-slate-800 rounded-full" />
                                                                                            <span className="text-emerald-600 dark:text-emerald-500/80">{formatDuration(log.duration)}</span>
                                                                                        </>
                                                                                    )}
                                                                                </div>
                                                                            </div>
                                                                        </div>

                                                                        <div className="flex items-center gap-2">
                                                                            {/* Options removed as requested */}
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            );
                                                        })}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </ScrollArea>
                        </>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center space-y-4 opacity-40 grayscale pointer-events-none">
                            <div className="size-20 rounded-3xl bg-slate-200 dark:bg-slate-800 flex items-center justify-center">
                                <Search className="size-8 text-slate-500" />
                            </div>
                            <p className="text-sm font-medium text-slate-500 max-w-[200px] text-center">
                                Select a contact to see detailed communication history
                            </p>
                        </div>
                    )}
                </div>
            </div>

            {/* New Call Dialog */}
            <Dialog open={isNewCallOpen} onOpenChange={setIsNewCallOpen}>
                <DialogContent className="max-w-md p-0 overflow-hidden bg-white dark:bg-[#1f2c33] border-none shadow-2xl rounded-2xl">
                    <DialogHeader className="p-6 pb-2 text-slate-900 dark:text-white">
                        <DialogTitle className="text-xl font-bold">New Call</DialogTitle>
                        <DialogDescription className="text-slate-500 dark:text-slate-400">
                            Search for people in your workspace
                        </DialogDescription>
                    </DialogHeader>

                    <div className="p-4 space-y-4">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-slate-500" />
                            <Input
                                placeholder="Name or email..."
                                className="pl-10 bg-slate-100 dark:bg-[#111b21] border-none rounded-xl text-slate-900 dark:text-white h-11"
                                value={contactSearch}
                                onChange={(e) => setContactSearch(e.target.value)}
                            />
                        </div>

                        <ScrollArea className="h-[400px] pr-2">
                            <div className="space-y-1">
                                {filteredContacts.map(contact => (
                                    <div
                                        key={contact.id}
                                        className="flex items-center gap-3 p-3 rounded-xl hover:bg-slate-100 dark:hover:bg-[#2a3942] cursor-pointer group transition-colors"
                                    >
                                        <Avatar className="h-10 w-10 border-none">
                                            <AvatarImage src={contact.avatar_url || (contact as any).avatar_url} />
                                            <AvatarFallback className="bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                                                {contact.full_name?.[0]}
                                            </AvatarFallback>
                                        </Avatar>
                                        <div className="flex-1 min-w-0">
                                            <p className="font-bold text-slate-900 dark:text-white text-sm truncate">{contact.full_name}</p>
                                            <p className="text-[10px] text-slate-500 uppercase tracking-widest leading-none font-bold truncate">
                                                {contact.role}
                                            </p>
                                        </div>
                                        <div className="flex gap-1 opacity-100 md:opacity-0 group-hover:opacity-100">
                                            <Button
                                                variant="ghost" size="icon" className="size-8 rounded-full text-emerald-500"
                                                onClick={() => {
                                                    initiateCall(contact.id, contact.full_name, contact.avatar_url || '', 'audio');
                                                    setIsNewCallOpen(false);
                                                }}
                                            >
                                                <Phone className="size-4" />
                                            </Button>
                                            <Button
                                                variant="ghost" size="icon" className="size-8 rounded-full text-blue-400"
                                                onClick={() => {
                                                    initiateCall(contact.id, contact.full_name, contact.avatar_url || '', 'video');
                                                    setIsNewCallOpen(false);
                                                }}
                                            >
                                                <Video className="size-4" />
                                            </Button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </ScrollArea>
                    </div>
                </DialogContent>
            </Dialog>

        </DashboardLayout>
    );
}

import { useState, useRef, useCallback, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { QuestionEditor } from '@/components/quizzes/QuestionEditor';
import { QuizQuestion } from '@/types/quiz';
import { DeleteConfirmDialog } from '@/components/layout/DeleteConfirmDialog';
import { notifyQuizPublished } from '@/lib/notificationService';
import { useClasses } from '@/hooks/useClasses';
import { SectionClassCard } from '@/components/common/SectionClassCard';
import {
    ArrowLeft,
    Sparkles,
    BookOpen,
    FileUp,
    Loader2,
    Edit2,
    Trash2,
    Plus,
    CheckCircle,
    AlertTriangle,
    Upload,
    RefreshCw,
    Save,
    Zap,
    Brain,
    FileText,
    ShieldCheck,
    Lock,
    ArrowRight,
    Shield,
    Check,
    Search,
    ChevronRight,
    Book,
    Users,
    Bot
} from 'lucide-react';
import {
    generateFromTopic,
    generateFromFile,
    extractTextFromPDF,
    type Difficulty,
} from '@/lib/aiQuizService';
import { motion, AnimatePresence } from 'framer-motion';

type InputMethod = 'topic' | 'file';
type Step = 'select-class' | 'input' | 'generating' | 'review';

const MAX_FILE_SIZE_MB = 5;

export default function CreateAIQuiz() {
    const { classId } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const { classes } = useClasses();
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Step state
    const [step, setStep] = useState<Step>(classId ? 'input' : 'select-class');

    // Input method
    const [inputMethod, setInputMethod] = useState<InputMethod>('topic');

    // Topic inputs
    const [topic, setTopic] = useState('');
    const [difficulty, setDifficulty] = useState<Difficulty>('medium');
    const [questionCount, setQuestionCount] = useState(10);

    // File inputs
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [fileQuestionCount, setFileQuestionCount] = useState(10);

    // Generation
    const [isGenerating, setIsGenerating] = useState(false);
    const [generationProgress, setGenerationProgress] = useState('');

    // Generated questions
    const [questions, setQuestions] = useState<QuizQuestion[]>([]);

    // Quiz metadata
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [passPercentage, setPassPercentage] = useState(50);

    // Editing
    const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);
    const [questionToDelete, setQuestionToDelete] = useState<string | null>(null);

    // Publishing
    const [saving, setSaving] = useState(false);

    // Filter classes for selection
    const [classSearch, setClassSearch] = useState('');
    const filteredClassesSelection = classes.filter(cls =>
        cls.class_name?.toLowerCase().includes(classSearch.toLowerCase()) ||
        cls.course_code.toLowerCase().includes(classSearch.toLowerCase())
    );

    useEffect(() => {
        if (classId) {
            setStep('input');
        } else {
            setStep('select-class');
        }
    }, [classId]);

    const calculateTotalMarks = () => questions.reduce((sum, q) => sum + q.marks, 0);

    // ---------- FILE HANDLING ----------
    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > MAX_FILE_SIZE_MB * 1024 * 1024) {
            toast.error(`File too large. Maximum size is ${MAX_FILE_SIZE_MB} MB.`);
            return;
        }

        if (file.type !== 'application/pdf') {
            toast.error('Only PDF files are supported.');
            return;
        }

        setSelectedFile(file);
    };

    // ---------- ACTIONS ----------
    const handleGenerate = async () => {
        setIsGenerating(true);
        setStep('generating');
        setGenerationProgress('Reading input data...');

        try {
            let generatedQuestions: QuizQuestion[] = [];

            if (inputMethod === 'topic') {
                setGenerationProgress(`Analyzing topic: ${topic}...`);
                generatedQuestions = await generateFromTopic({ topic, difficulty, count: questionCount });
            } else if (selectedFile) {
                setGenerationProgress('Extracting text from PDF...');
                const pdfText = await extractTextFromPDF(selectedFile);
                setGenerationProgress('Generating questions from content...');
                generatedQuestions = await generateFromFile({ fileText: pdfText, count: fileQuestionCount });
            }

            setQuestions(generatedQuestions);
            setStep('review');
            toast.success('Successfully generated quiz questions!');
        } catch (error: any) {
            console.error('Generation Error:', error);
            toast.error(error.message || 'Failed to generate questions. Please try again.');
            setStep('input');
        } finally {
            setIsGenerating(false);
        }
    };

    const handleSaveQuestion = (updatedQuestion: QuizQuestion) => {
        setQuestions(questions.map(q => q.id === updatedQuestion.id ? updatedQuestion : q));
        setEditingQuestionId(null);
        toast.success('Question updated');
    };

    const handleDeleteQuestion = (id: string) => {
        setQuestions(questions.filter(q => q.id !== id));
        toast.info('Question removed');
    };

    const handlePublishQuiz = async () => {
        if (!classId) {
            toast.error('No class context found. You can generate and preview quizes, but you must select a class from the list to publish.');
            return;
        }

        if (!title.trim()) {
            toast.error('Please enter a quiz title');
            return;
        }

        try {
            setSaving(true);
            const totalMarks = calculateTotalMarks();

            // 1. Create Quiz Record
            const { data: quizData, error: quizError } = await supabase
                .from('quizzes')
                .insert({
                    class_id: classId,
                    title,
                    description,
                    total_marks: totalMarks,
                    pass_percentage: passPercentage,
                    status: 'published',
                    created_by: user?.id
                })
                .select()
                .single();

            if (quizError) throw quizError;

            // 2. Create Questions
            const questionsToInsert = questions.map((q, index) => ({
                quiz_id: quizData.id,
                question_text: q.question_text,
                question_type: q.question_type,
                marks: q.marks,
                options: q.options as any,
                correct_answer: q.correct_answer,
                order_index: index
            }));

            const { error: questionsError } = await supabase
                .from('quiz_questions')
                .insert(questionsToInsert);

            if (questionsError) throw questionsError;

            // 3. Send notifications
            if (classId) {
                try {
                    await notifyQuizPublished(quizData.id, classId, title, user?.id || '');
                } catch (notifError) {
                    console.error('Notification failed:', notifError);
                }
            }

            toast.success('AI-generated quiz published successfully!');
            navigate(`/lecturer/quizzes/${classId}`);
        } catch (error: any) {
            console.error('Error publishing quiz:', error);
            toast.error('Failed to publish quiz. Please try again.');
        } finally {
            setSaving(false);
        }
    };



    return (
        <DashboardLayout>
            <div className={step === 'select-class' && !classId
                ? "w-full flex flex-col gap-10 animate-in fade-in duration-500"
                : "w-full min-h-[calc(100vh-4rem)] bg-background text-foreground p-3 md:p-10 animate-in fade-in duration-500 rounded-3xl overflow-hidden shadow-none md:shadow-sm filter-none"
            }>
                <div className="relative w-full">

                    {/* Header - Only show for wizard steps */}
                    {step !== 'select-class' && (
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                            <div className="flex items-center gap-4">
                                <div className="flex flex-col gap-1">
                                    <div className="flex flex-col md:flex-row md:items-center gap-2 md:gap-3">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 sm:p-2.5 bg-indigo-500/10 rounded-xl dark:bg-indigo-500/20 shadow-inner">
                                                <Brain className="size-6 sm:size-7 text-indigo-600 dark:text-indigo-400" />
                                            </div>
                                            <h1 className="text-xl sm:text-3xl font-black tracking-tight text-slate-900 dark:text-white">
                                                AI Quiz <span className="text-indigo-600 dark:text-indigo-400">Generator</span>
                                            </h1>
                                        </div>
                                        <Badge
                                            variant="secondary"
                                            className="w-fit px-3 py-1 bg-indigo-50 text-indigo-700 dark:bg-indigo-950/50 dark:text-indigo-300 border border-indigo-100 dark:border-indigo-800 font-bold uppercase tracking-tighter text-[10px]"
                                        >
                                            <Sparkles className="size-3 mr-1.5 fill-current" />
                                            Llama-3 Powered
                                        </Badge>
                                        {!classId && (
                                            <Badge variant="outline" className="w-fit px-3 py-1 bg-amber-500/10 text-amber-600 border-amber-200 dark:border-amber-800 font-bold uppercase tracking-tighter text-[10px]">
                                                Class Selection Mode
                                            </Badge>
                                        )}
                                    </div>
                                    <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400 font-medium md:pl-14">Create professional assessments in seconds using artificial intelligence</p>
                                </div>
                            </div>

                            {step === 'input' && (
                                <div className="hidden md:flex items-center gap-3 px-6 py-3 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                                    <div className="flex -space-x-3">
                                        {[1, 2, 3].map((i) => (
                                            <div key={i} className="size-8 rounded-full border-2 border-white dark:border-slate-900 bg-slate-200 dark:bg-slate-800 flex items-center justify-center overflow-hidden">
                                                <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${i + 10}`} alt="User" />
                                            </div>
                                        ))}
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">Powering</span>
                                        <span className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-tighter">5,000+ Educators</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {/* ============ STEP: SELECT CLASS (MATCHING QUIZZES PAGE DESIGN) ============ */}
                    {step === 'select-class' && (
                        <div className="w-full flex flex-col gap-10 animate-in fade-in duration-500">
                            {/* Header */}
                            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
                                <div>
                                    <h1 className="text-4xl font-bold tracking-tight text-foreground flex items-center gap-3">
                                        <Bot className="size-8 text-blue-600 dark:text-blue-400 fill-blue-500/10" />
                                        Generate AI Quiz
                                    </h1>
                                    <p className="text-muted-foreground mt-2 text-lg">
                                        Select a class to generate a new quiz using AI.
                                    </p>
                                </div>

                                {/* Search Bar - Wider on Desktop */}
                                <div className="relative w-full lg:w-96 group">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground group-focus-within:text-primary transition-colors" />
                                    <Input
                                        placeholder="Search class or course code..."
                                        value={classSearch}
                                        onChange={(e) => setClassSearch(e.target.value)}
                                        className="pl-11 h-12 bg-white dark:bg-slate-900 border-none shadow-sm focus-visible:ring-2 focus-visible:ring-primary/20 text-lg rounded-xl"
                                    />
                                </div>
                            </div>

                            {/* Stats Overview - Premium Look */}
                            <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-4 gap-6">
                                <Card className="border-none bg-gradient-to-br from-blue-600 to-indigo-700 shadow-xl rounded-2xl overflow-hidden group">
                                    <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative">
                                        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                            <BookOpen className="size-12 sm:size-20 text-white" />
                                        </div>
                                        <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                            <BookOpen className="size-5 sm:size-7 text-white" />
                                        </div>
                                        <div className="relative z-10 min-w-0">
                                            <p className="text-[10px] sm:text-sm text-blue-100/80 font-semibold uppercase tracking-wider truncate">
                                                Total Classes
                                            </p>
                                            <p className="text-xl sm:text-3xl font-black text-white">{classes.length}</p>
                                        </div>
                                    </CardContent>
                                </Card>

                                <Card className="border-none bg-gradient-to-br from-emerald-600 to-teal-700 shadow-xl rounded-2xl overflow-hidden group">
                                    <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative">
                                        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                            <CheckCircle className="size-12 sm:size-20 text-white" />
                                        </div>
                                        <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                            <CheckCircle className="size-5 sm:size-7 text-white" />
                                        </div>
                                        <div className="relative z-10 min-w-0">
                                            <p className="text-[10px] sm:text-sm text-emerald-100/80 font-semibold uppercase tracking-wider truncate">
                                                AI Tokens
                                            </p>
                                            <p className="text-xl sm:text-3xl font-black text-white">Unlimited</p>
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>

                            {/* Classes Grid */}
                            <div>
                                <div className="flex items-center justify-between mb-6">
                                    <h2 className="text-2xl font-bold">Your Academic Classes</h2>
                                    <Badge variant="outline" className="px-4 py-1.5 rounded-full text-base font-medium">
                                        {filteredClassesSelection.length} Results
                                    </Badge>
                                </div>

                                {filteredClassesSelection.length === 0 ? (
                                    <div className="py-20 text-center bg-slate-50/50 dark:bg-slate-900/50 rounded-[2.5rem] border-2 border-dashed border-slate-100 dark:border-slate-800">
                                        <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">No matching classes</p>
                                    </div>
                                ) : (
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-3 gap-6">
                                        {filteredClassesSelection.map((cls, index) => (
                                            <SectionClassCard
                                                key={cls.id}
                                                classData={cls}
                                                variant="quizzes"
                                                onAction={() => navigate(`/lecturer/quizzes/${cls.id}/create-ai`)}
                                                index={index}
                                            />
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Stepper */}
                    {step !== 'generating' && step !== 'select-class' && (
                        <div className="grid grid-cols-3 gap-2 md:flex md:items-center md:gap-4 mb-6 md:mb-10 w-full">
                            {[
                                { key: 'input', label: 'Configure', icon: Zap },
                                { key: 'generating', label: 'Generate', icon: Brain },
                                { key: 'review', label: 'Review', icon: CheckCircle },
                            ].map((s) => (
                                <div key={s.key} className="flex items-center justify-center shrink-0 w-full md:w-auto">
                                    <div
                                        className={`flex items-center justify-center gap-1.5 md:gap-2 px-2 md:px-4 py-2.5 rounded-xl md:rounded-full text-[10px] md:text-xs font-bold transition-all border w-full md:w-auto ${step === s.key
                                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-600/20'
                                            : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-500'
                                            }`}
                                    >
                                        <s.icon className="size-3.5 shrink-0" />
                                        <span className="truncate">{s.label}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* ============ STEP: INPUT ============ */}
                    {step === 'input' && (
                        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 max-w-7xl mx-auto">
                            {/* LEFT COLUMN: Generation Method */}
                            <div className="lg:col-span-4 space-y-6">
                                <Card className="shadow-lg border-slate-200 dark:border-slate-800">
                                    <CardHeader className="pb-4">
                                        <CardTitle className="text-lg flex items-center gap-2">
                                            <Brain className="size-5 text-indigo-600" />
                                            Generation Method
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent className="space-y-4">
                                        <button
                                            onClick={() => setInputMethod('topic')}
                                            className={`w-full p-4 rounded-2xl border text-left transition-all ${inputMethod === 'topic'
                                                ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-500/10'
                                                : 'border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50'
                                                }`}
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className={`p-3 rounded-xl ${inputMethod === 'topic' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                                                    <BookOpen className="size-6" />
                                                </div>
                                                <div>
                                                    <p className="font-bold text-sm">Topic-Based</p>
                                                    <p className="text-xs text-slate-500 mt-0.5 tracking-tight">Enter any subject or topic</p>
                                                </div>
                                            </div>
                                        </button>

                                        <button
                                            onClick={() => setInputMethod('file')}
                                            className={`w-full p-4 rounded-2xl border text-left transition-all ${inputMethod === 'file'
                                                ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-500/10'
                                                : 'border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50'
                                                }`}
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className={`p-3 rounded-xl ${inputMethod === 'file' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                                                    <FileUp className="size-6" />
                                                </div>
                                                <div>
                                                    <p className="font-bold text-sm">File-Based</p>
                                                    <p className="text-xs text-slate-500 mt-0.5 tracking-tight">Generate from your PDF documents</p>
                                                </div>
                                            </div>
                                        </button>
                                    </CardContent>
                                </Card>
                            </div>

                            {/* RIGHT COLUMN: Configuration */}
                            <div className="lg:col-span-8">
                                <Card className="shadow-lg border-slate-200 dark:border-slate-800 h-full">
                                    <CardHeader className="pb-6">
                                        <CardTitle className="text-xl flex items-center gap-2">
                                            {inputMethod === 'topic' ? <BookOpen className="size-5 text-indigo-600" /> : <FileUp className="size-5 text-indigo-600" />}
                                            Generation Settings
                                        </CardTitle>
                                        <CardDescription>
                                            Configure how you want the AI to create your assessment.
                                        </CardDescription>
                                    </CardHeader>
                                    <CardContent className="space-y-8">
                                        {inputMethod === 'topic' ? (
                                            <div className="space-y-6">
                                                <div className="space-y-3">
                                                    <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Target Topic</Label>
                                                    <Input
                                                        placeholder="e.g., Photosynthesis in Plants, Quantum Mechanics Basics..."
                                                        value={topic}
                                                        onChange={(e) => setTopic(e.target.value)}
                                                        className="h-14 text-base font-semibold bg-slate-50/50 dark:bg-slate-900/50 rounded-xl"
                                                    />
                                                </div>
                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                                    <div className="space-y-3">
                                                        <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Difficulty</Label>
                                                        <Select value={difficulty} onValueChange={(v) => setDifficulty(v as Difficulty)}>
                                                            <SelectTrigger className="h-14 px-4 bg-slate-50/50 dark:bg-slate-900/50 rounded-xl">
                                                                <SelectValue />
                                                            </SelectTrigger>
                                                            <SelectContent>
                                                                <SelectItem value="easy">Easy — Basic Concepts</SelectItem>
                                                                <SelectItem value="medium">Medium — Application</SelectItem>
                                                                <SelectItem value="hard">Hard — Synthesis</SelectItem>
                                                            </SelectContent>
                                                        </Select>
                                                    </div>
                                                    <div className="space-y-3">
                                                        <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Question Count</Label>
                                                        <Input
                                                            type="number"
                                                            min={1}
                                                            max={15}
                                                            value={questionCount}
                                                            onChange={(e) => setQuestionCount(Math.min(15, Math.max(1, parseInt(e.target.value) || 1)))}
                                                            className="h-14 font-bold text-lg bg-slate-50/50 dark:bg-slate-900/50 rounded-xl"
                                                        />
                                                    </div>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="space-y-6">
                                                <div className="space-y-3">
                                                    <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">PDF Selection</Label>
                                                    <div
                                                        onClick={() => fileInputRef.current?.click()}
                                                        className={`border-2 border-dashed rounded-3xl p-10 text-center cursor-pointer transition-all hover:bg-slate-50 dark:hover:bg-slate-800/30 ${selectedFile ? 'border-indigo-500 bg-indigo-50/10' : 'border-slate-200 dark:border-slate-800'}`}
                                                    >
                                                        <input
                                                            ref={fileInputRef}
                                                            type="file"
                                                            accept=".pdf"
                                                            className="hidden"
                                                            onChange={handleFileChange}
                                                        />
                                                        {selectedFile ? (
                                                            <div className="flex flex-col items-center gap-4">
                                                                <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-xl">
                                                                    <FileText className="size-10" />
                                                                </div>
                                                                <div>
                                                                    <p className="font-black text-xl">{selectedFile.name}</p>
                                                                    <p className="text-xs text-slate-500 font-bold uppercase mt-1 tracking-widest">
                                                                        {(selectedFile.size / (1024 * 1024)).toFixed(2)} MB • Click to change
                                                                    </p>
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="flex flex-col items-center gap-4">
                                                                <div className="p-4 bg-slate-100 dark:bg-slate-800 rounded-2xl">
                                                                    <Upload className="size-10 text-slate-400" />
                                                                </div>
                                                                <div>
                                                                    <p className="font-bold text-lg">Click to select PDF</p>
                                                                    <p className="text-xs text-slate-500 mt-1 uppercase tracking-widest font-semibold font-mono">Max size 5MB</p>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                </div>
                                                <div className="space-y-3">
                                                    <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Amount of Questions</Label>
                                                    <Input
                                                        type="number"
                                                        min={1}
                                                        max={15}
                                                        value={fileQuestionCount}
                                                        onChange={(e) => setFileQuestionCount(Math.min(15, Math.max(1, parseInt(e.target.value) || 1)))}
                                                        className="h-14 font-bold text-lg w-32 bg-slate-50/50 dark:bg-slate-900/50 rounded-xl"
                                                    />
                                                </div>
                                            </div>
                                        )}

                                        <div className="pt-6">
                                            <Button
                                                onClick={handleGenerate}
                                                disabled={isGenerating}
                                                className="w-full h-16 text-xl font-black rounded-2xl bg-indigo-600 hover:bg-indigo-700 text-white shadow-[0_12px_24px_-8px_rgba(79,70,229,0.5)] transition-all active:scale-[0.98]"
                                            >
                                                <Zap className="size-6 mr-3 fill-current" />
                                                Generate Assessment
                                            </Button>
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>
                        </div>
                    )}

                    {/* ============ STEP: GENERATING ============ */}
                    {step === 'generating' && (
                        <div className="flex flex-col items-center justify-center py-20 px-4">
                            <div className="size-32 relative mb-10">
                                <div className="absolute inset-0 rounded-full bg-indigo-500/10 animate-ping" />
                                <div className="absolute inset-2 rounded-full bg-indigo-500/20 animate-pulse" />
                                <div className="relative z-10 size-full bg-gradient-to-br from-indigo-500 to-purple-600 rounded-full flex items-center justify-center shadow-2xl">
                                    <Brain className="size-16 text-white" />
                                </div>
                            </div>
                            <h1 className="text-3xl font-black tracking-tight mb-2">Engines Firing...</h1>
                            <p className="text-lg text-slate-500 font-medium mb-10">{generationProgress}</p>
                            <div className="flex items-center gap-3 px-5 py-3 bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm animate-bounce">
                                <Loader2 className="size-5 animate-spin text-indigo-600" />
                                <span className="text-sm font-bold">Llama-3 is analyzing content...</span>
                            </div>
                        </div>
                    )}

                    {/* ============ STEP: REVIEW ============ */}
                    {step === 'review' && (
                        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 max-w-7xl mx-auto">
                            <div className="lg:col-span-4 space-y-6">
                                <Card className="shadow-xl rounded-3xl border-slate-200 dark:border-slate-800 overflow-hidden">
                                    <div className="h-2 bg-gradient-to-r from-indigo-500 to-purple-600" />
                                    <CardHeader>
                                        <CardTitle className="text-xl">Finalize Details</CardTitle>
                                        <CardDescription>Give your quiz a name and description before students take it.</CardDescription>
                                    </CardHeader>
                                    <CardContent className="space-y-6">
                                        <div className="space-y-2.5">
                                            <Label className="text-[10px] font-black uppercase text-slate-400">Quiz Title</Label>
                                            <Input
                                                value={title}
                                                onChange={(e) => setTitle(e.target.value)}
                                                className="h-12 font-bold rounded-xl"
                                            />
                                        </div>
                                        <div className="space-y-2.5">
                                            <Label className="text-[10px] font-black uppercase text-slate-400">Description</Label>
                                            <Textarea
                                                value={description}
                                                onChange={(e) => setDescription(e.target.value)}
                                                className="min-h-[120px] rounded-xl font-medium"
                                            />
                                        </div>
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-2">
                                                <Label className="text-[10px] font-black uppercase text-slate-400">Pass Score (%)</Label>
                                                <Input
                                                    type="number"
                                                    value={passPercentage}
                                                    onChange={(e) => setPassPercentage(parseInt(e.target.value) || 0)}
                                                    className="h-12 font-bold rounded-xl"
                                                />
                                            </div>
                                            <div className="space-y-2">
                                                <Label className="text-[10px] font-black uppercase text-slate-400">Total Points</Label>
                                                <div className="h-12 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-xl font-black text-xl">
                                                    {calculateTotalMarks()}
                                                </div>
                                            </div>
                                        </div>
                                        <Button
                                            onClick={handlePublishQuiz}
                                            disabled={saving || questions.length === 0}
                                            className="w-full h-14 bg-emerald-500 hover:bg-emerald-600 text-white font-black text-lg rounded-2xl shadow-xl shadow-emerald-500/20"
                                        >
                                            {saving ? <Loader2 className="animate-spin mr-2" /> : <Save className="mr-2" />}
                                            Publish to Class
                                        </Button>
                                        <Button
                                            variant="outline"
                                            onClick={() => { setStep('input'); setQuestions([]); }}
                                            className="w-full h-12 rounded-2xl"
                                        >
                                            <RefreshCw className="mr-2 size-4" />
                                            Start Over
                                        </Button>
                                    </CardContent>
                                </Card>
                            </div>

                            <div className="lg:col-span-8 space-y-6">
                                <div className="flex items-center justify-between mb-2">
                                    <h3 className="text-2xl font-black tracking-tight">Review Content</h3>
                                    <Badge className="bg-indigo-600 text-white border-none py-1.5 px-4 font-black rounded-full text-[10px] uppercase">
                                        {questions.length} Questions
                                    </Badge>
                                </div>
                                <div className="space-y-4">
                                    {questions.map((q, i) => (
                                        <Card key={q.id} className="group border-slate-200 dark:border-slate-800 hover:border-indigo-500 transition-all rounded-3xl overflow-hidden shadow-sm hover:shadow-xl">
                                            <CardContent className="p-6 flex gap-6">
                                                <div className="size-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center font-black text-xl text-indigo-600 shrink-0">
                                                    {i + 1}
                                                </div>
                                                <div className="flex-1">
                                                    <p className="font-bold text-lg mb-4">{q.question_text}</p>
                                                    <div className="flex items-center gap-4">
                                                        <Badge variant="outline" className="rounded-full px-3 py-1 font-bold text-[10px] uppercase bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800">
                                                            {q.marks} Points
                                                        </Badge>
                                                        <span className="text-xs font-bold text-slate-400 tracking-widest uppercase">
                                                            {q.options.length} Options
                                                        </span>
                                                    </div>
                                                </div>
                                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <Button variant="ghost" size="icon" className="size-10 rounded-xl hover:bg-indigo-500 hover:text-white" onClick={() => setEditingQuestionId(q.id)}>
                                                        <Edit2 className="size-5" />
                                                    </Button>
                                                    <Button variant="ghost" size="icon" className="size-10 rounded-xl hover:bg-rose-500 hover:text-white" onClick={() => setQuestionToDelete(q.id)}>
                                                        <Trash2 className="size-5" />
                                                    </Button>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>



            <DeleteConfirmDialog
                open={!!questionToDelete}
                onOpenChange={(open) => !open && setQuestionToDelete(null)}
                onConfirm={() => {
                    if (questionToDelete) {
                        handleDeleteQuestion(questionToDelete);
                        setQuestionToDelete(null);
                    }
                }}
                title="Delete Question?"
                description="This will remove the question from the generated set. This action cannot be undone."
            />
        </DashboardLayout >
    );
}

import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { useClasses } from "@/hooks/useClasses";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import {
    Users,
    Plus,
    BookOpen,
    GraduationCap,
} from "lucide-react";
import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { CreateClassModal } from "@/components/lecturer/CreateClassModal";
import { EditClassModal } from "@/components/lecturer/EditClassModal";
import { SectionClassCard } from "@/components/common/SectionClassCard";
import { GridSkeleton } from "@/components/skeletons/GridSkeleton";
import { useToast } from "@/hooks/use-toast";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export default function CreateClass() {
    const navigate = useNavigate();
    const { classes, loading, deleteClass } = useClasses();
    const { toast } = useToast();

    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [classToEdit, setClassToEdit] = useState<any>(null);
    const [classToDelete, setClassToDelete] = useState<any>(null);

    // Calculate stats
    const totalClasses = classes.length;
    const totalStudents = classes.reduce((sum, cls) => sum + (cls.student_count || 0), 0);
    const activeClasses = classes.filter(cls => cls.is_active).length;

    const handleViewStudents = (classId: string, actionType?: string) => {
        if (!classId) return;
        const url = `/classes/${classId}/students${actionType === 'import' ? '?action=import' : ''}`;
        navigate(url);
    };

    const handleEditClass = (classData: any) => {
        setClassToEdit(classData);
        setIsEditModalOpen(true);
    };

    const handleDeleteClass = (classData: any) => {
        setClassToDelete(classData);
    };

    const confirmDelete = async () => {
        if (!classToDelete) return;
        try {
            await deleteClass(classToDelete.id);
            toast({
                title: "Class Deleted",
                description: `${classToDelete.course_code} has been successfully deleted`,
            });
        } catch (error) {
            toast({
                title: "Error",
                description: "Failed to delete class",
                variant: "destructive",
            });
        } finally {
            setClassToDelete(null);
        }
    };

    return (
        <DashboardLayout>
            <div className="flex flex-col gap-6">
                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div className="flex flex-col gap-1">
                        <h1 className="text-2xl sm:text-3xl font-bold text-foreground">Student Management</h1>
                        <p className="text-sm text-muted-foreground">Manage students across your classes</p>
                    </div>
                    <Button
                        onClick={() => setIsCreateModalOpen(true)}
                        className="hidden sm:flex bg-primary hover:bg-primary/90 gap-2"
                    >
                        <Plus className="size-4" />
                        Create New Class
                    </Button>
                </div>

                {/* Stats Cards - Premium Design */}
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                    <Card className="border-none bg-gradient-to-br from-blue-600 to-indigo-700 shadow-xl rounded-2xl overflow-hidden group">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <BookOpen className="size-12 sm:size-20 text-white" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <BookOpen className="size-5 sm:size-7 text-white" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-blue-100/80 font-semibold uppercase tracking-wider truncate">
                                    Total Classes
                                </p>
                                <p className="text-xl sm:text-3xl font-black text-white">{totalClasses}</p>
                                <p className="text-[10px] text-blue-100/60 mt-0.5">{activeClasses} active</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-none bg-gradient-to-br from-violet-600 to-purple-700 shadow-xl rounded-2xl overflow-hidden group">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <Users className="size-12 sm:size-20 text-white" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <Users className="size-5 sm:size-7 text-white" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-violet-100/80 font-semibold uppercase tracking-wider truncate">
                                    Total Students
                                </p>
                                <p className="text-xl sm:text-3xl font-black text-white">{totalStudents}</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-none bg-gradient-to-br from-emerald-600 to-teal-700 shadow-xl rounded-2xl overflow-hidden group col-span-2 sm:col-span-1">
                        <CardContent className="p-3 sm:p-6 flex items-center gap-2 sm:gap-5 relative">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                                <GraduationCap className="size-12 sm:size-20 text-white" />
                            </div>
                            <div className="p-2 sm:p-4 bg-white/10 rounded-xl sm:rounded-2xl border border-white/20 relative z-10 backdrop-blur-sm shrink-0">
                                <GraduationCap className="size-5 sm:size-7 text-white" />
                            </div>
                            <div className="relative z-10 min-w-0">
                                <p className="text-[10px] sm:text-sm text-emerald-100/80 font-semibold uppercase tracking-wider truncate">
                                    Avg. Class Size
                                </p>
                                <p className="text-xl sm:text-3xl font-black text-white">
                                    {totalClasses > 0 ? Math.round(totalStudents / totalClasses) : 0}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Classes Grid */}
                {loading ? (
                    <GridSkeleton count={6} />
                ) : classes.length === 0 ? (
                    <Card className="bg-gradient-to-br from-slate-900 to-slate-800 border-slate-700/50 shadow-xl rounded-2xl">
                        <CardContent className="p-12">
                            <div className="flex flex-col items-center justify-center text-center gap-4">
                                <div className="p-4 bg-slate-800 rounded-full">
                                    <BookOpen className="size-8 text-slate-400" />
                                </div>
                                <div className="flex flex-col gap-2">
                                    <h3 className="text-lg font-semibold text-white">No classes yet</h3>
                                    <p className="text-sm text-slate-400 max-w-sm">
                                        Get started by creating your first class. You can then add students and manage course materials.
                                    </p>
                                </div>
                                <Button
                                    onClick={() => setIsCreateModalOpen(true)}
                                    className="bg-primary hover:bg-primary/90 gap-2 mt-2"
                                >
                                    <Plus className="size-4" />
                                    Create Your First Class
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {classes.map((classItem, index) => (
                            <SectionClassCard
                                key={classItem.id}
                                classData={classItem}
                                variant="students"
                                onAction={handleViewStudents}
                                index={index}
                                onEdit={handleEditClass}
                                onDelete={handleDeleteClass}
                            />
                        ))}
                    </div>
                )}
            </div>

            {/* Create Class Modal */}
            <CreateClassModal
                open={isCreateModalOpen}
                onOpenChange={setIsCreateModalOpen}
            />

            {/* Edit Class Modal */}
            <EditClassModal
                open={isEditModalOpen}
                onOpenChange={setIsEditModalOpen}
                classData={classToEdit}
            />

            {/* Delete Confirmation Dialog */}
            <AlertDialog open={!!classToDelete} onOpenChange={() => setClassToDelete(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Are you sure?</AlertDialogTitle>
                        <AlertDialogDescription>
                            This action cannot be undone. This will permanently delete the class
                            <span className="font-semibold text-foreground"> {classToDelete?.course_code} </span>
                            and all associated data.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={confirmDelete}
                            className="bg-red-600 hover:bg-red-700 text-white"
                        >
                            Delete
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

            {/* Mobile FAB */}
            <div className="fixed bottom-6 right-6 sm:hidden z-40 animate-in fade-in slide-in-from-bottom-4 duration-300">
                <Button
                    onClick={() => setIsCreateModalOpen(true)}
                    size="icon"
                    className="size-16 rounded-full shadow-2xl bg-primary hover:bg-primary/90 transition-all active:scale-95 border-4 border-background text-primary-foreground"
                    title="Create New Class"
                >
                    <Plus className="size-8 text-white" />
                </Button>
            </div>
        </DashboardLayout>
    );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { ArrowLeft, Save, Plus, Trash2, Edit2, Loader2 } from 'lucide-react';
import { useQuizzes } from '@/hooks/useQuizzes';
import { QuestionEditor } from '@/components/quizzes/QuestionEditor';
import { QuizQuestion } from '@/types/quiz';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import { Badge } from "@/components/ui/badge";
import { useAuth } from '@/contexts/AuthContext';
import { DeleteConfirmDialog } from '@/components/layout/DeleteConfirmDialog';
import { FormSkeleton } from '@/components/skeletons/FormSkeleton';

// Simple UUID generator to avoid external dependency
const generateId = () => {
    return Math.random().toString(36).substring(2) + Date.now().toString(36);
}

export default function CreateQuiz() {
    const { classId } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const { createQuiz } = useQuizzes(classId);

    // Quiz Details State
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [passPercentage, setPassPercentage] = useState(50);

    // Questions State
    const [questions, setQuestions] = useState<QuizQuestion[]>([]);
    const [isEditingQuestion, setIsEditingQuestion] = useState(false);
    const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);
    const [saving, setSaving] = useState(false);
    const [draftId, setDraftId] = useState<string | null>(null);
    const [lastSaved, setLastSaved] = useState<Date | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isAutoSaving, setIsAutoSaving] = useState(false);
    const [questionToDelete, setQuestionToDelete] = useState<string | null>(null);

    const calculateTotalMarks = () => {
        return questions.reduce((sum, q) => sum + q.marks, 0);
    };

    // Load draft from DB on mount
    useEffect(() => {
        const loadDraft = async () => {
            if (!classId || !user) {
                setIsLoading(false);
                return;
            }

            try {
                // Check quiz_drafts table
                const { data: draft, error } = await supabase
                    .from('quiz_drafts')
                    .select('*')
                    .eq('class_id', classId)
                    .eq('user_id', user.id)
                    .single();

                if (error && error.code !== 'PGRST116') { // PGRST116 is "no rows returned"
                    console.error('Error fetching draft:', error);
                } else if (draft) {
                    setDraftId(draft.id);
                    const data = draft.data as any;

                    if (data) {
                        setTitle(data.title || '');
                        setDescription(data.description || '');
                        setPassPercentage(data.passPercentage || 50);
                        setQuestions(data.questions || []);
                    }
                }
            } catch (error) {
                console.error('Error loading draft:', error);
            } finally {
                setIsLoading(false);
            }
        };

        loadDraft();
    }, [classId, user]);

    // Unified Auto-Save Logic (Supabase only)
    useEffect(() => {
        // Skip if still loading initial data or empty state
        if (isLoading) return;
        if (!title && questions.length === 0 && !description) return;

        const saveEverything = async () => {
            if (!classId || !user) return;
            setIsAutoSaving(true);

            try {
                const draftData = {
                    title,
                    description,
                    passPercentage,
                    questions
                };

                const { data: savedDraft, error } = await supabase
                    .from('quiz_drafts')
                    .upsert({
                        class_id: classId,
                        user_id: user.id,
                        data: draftData,
                        updated_at: new Date().toISOString(),
                        ...(draftId ? { id: draftId } : {})
                    })
                    .select()
                    .single();

                if (error) throw error;

                if (!draftId && savedDraft) {
                    setDraftId(savedDraft.id);
                }

                setLastSaved(new Date());

            } catch (error) {
                console.error('Auto-save failed:', error);
            } finally {
                setIsAutoSaving(false);
            }
        };

        const timeoutId = setTimeout(saveEverything, 1000); // 1s debounce
        return () => clearTimeout(timeoutId);
    }, [title, description, passPercentage, questions, classId, user, draftId, isLoading]);


    const handleSaveQuestion = (question: QuizQuestion) => {
        if (editingQuestionId) {
            setQuestions(questions.map(q => q.id === editingQuestionId ? question : q));
        } else {
            setQuestions([...questions, { ...question, id: generateId() }]);
        }
        setIsEditingQuestion(false);
        setEditingQuestionId(null);
    };

    const handleEditQuestion = (question: QuizQuestion) => {
        setEditingQuestionId(question.id);
        setIsEditingQuestion(true);
    };

    const handleDeleteQuestion = (id: string) => {
        setQuestions(questions.filter(q => q.id !== id));
    };

    const handlePublishQuiz = async () => {
        if (!title.trim()) {
            toast.error('Please enter a quiz title');
            return;
        }
        if (questions.length === 0) {
            toast.error('Please add at least one question');
            return;
        }

        try {
            setSaving(true);
            const totalMarks = calculateTotalMarks();

            // 1. Create Quiz Record in REAL table
            const { data: quizData, error: quizError } = await supabase
                .from('quizzes')
                .insert({
                    class_id: classId,
                    title,
                    description,
                    total_marks: totalMarks,
                    pass_percentage: passPercentage,
                    status: 'published',
                    created_by: user?.id
                })
                .select()
                .single();

            if (quizError) throw quizError;

            // 2. Create Questions
            const questionsToInsert = questions.map((q, index) => ({
                quiz_id: quizData.id,
                question_text: q.question_text,
                question_type: q.question_type,
                marks: q.marks,
                options: q.options,
                correct_answer: q.correct_answer,
                order_index: index
            }));

            const { error: questionsError } = await supabase
                .from('quiz_questions')
                .insert(questionsToInsert);

            if (questionsError) throw questionsError;

            // 3. Delete Draft
            if (draftId) {
                await supabase.from('quiz_drafts').delete().eq('id', draftId);
            }

            toast.success('Quiz created and published successfully!');
            navigate(`/lecturer/quizzes/${classId}`);

        } catch (error) {
            console.error('Error publishing quiz:', error);
            toast.error('Failed to publish quiz');
        } finally {
            setSaving(false);
        }
    };

    if (isLoading) {
        return (
            <DashboardLayout>
                <FormSkeleton />
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout>
            <div className="w-full pb-10 animate-in fade-in duration-500">
                {/* Header */}
                <div className="flex flex-col gap-6 mb-8">
                    <div className="flex items-start justify-between gap-4">
                        <div className="flex items-start gap-4">
                            <Button variant="ghost" size="icon" onClick={() => navigate(-1)} className="h-10 w-10 rounded-full hover:bg-muted transition-colors shrink-0 mt-1 hidden md:flex">
                                <ArrowLeft className="size-6" />
                            </Button>
                            <div>
                                <div className="flex flex-col gap-2">
                                    <div className="flex items-center gap-3 flex-wrap">
                                        <h1 className="text-xl md:text-3xl font-bold tracking-tight">Create New Quiz</h1>
                                        {isAutoSaving && (
