import { FileText, CheckCircle, AlertCircle, Calendar, Loader2, Clock, UserPlus, Heart, Send, Megaphone, Flame, Award, ChevronRight, Sparkles } from "lucide-react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";

import { DashboardHero } from "@/components/dashboard/DashboardHero";
import { UpcomingTask } from "@/components/dashboard/UpcomingTask";
import { useAssignments } from "@/hooks/useAssignments";
import { DashboardAssignmentList } from "@/components/dashboard/DashboardAssignmentList";
import { useSchedule } from "@/hooks/useSchedule";
import { useNavigate } from "react-router-dom";
import SEO from "@/components/SEO";
import { StatsCard } from "@/components/dashboard/StatsCard";
import { PremiumStatsCard } from "@/components/dashboard/PremiumStatsCard";
import { parseISO, format, isAfter, isBefore, addDays } from "date-fns";
import { Button } from "@/components/ui/button";
import { InviteUserDialog } from "@/components/lecturer/InviteUserDialog";
import { PendingInvitationsPanel } from "@/components/student/PendingInvitationsPanel";
import { JoinRequestModal } from "@/components/student/JoinRequestModal";
import { useState, useEffect } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { useStudentOnboarding } from "@/hooks/useStudentOnboarding";
import { useRealtimeInvitations } from "@/hooks/useRealtimeInvitations";
import { DashboardSkeleton } from "@/components/skeletons/DashboardSkeleton";
import { useStreak } from "@/contexts/StreakContext";
import { DashboardStreakWeekly } from "@/components/dashboard/DashboardStreakWeekly";

const days = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

export default function Dashboard() {
  const { assignments, stats, loading: assignmentsLoading } = useAssignments();
  const { schedules, loading: scheduleLoading } = useSchedule();
  const { streak, loading: streakLoading } = useStreak();
  const navigate = useNavigate();
  const { profile, user, role } = useAuth();
  const [inviteDialogOpen, setInviteDialogOpen] = useState(false);
  const { recordAcademicAction } = useStreak();

  // Record daily visit streak
  useEffect(() => {
    if (user?.id && role === 'student') {
      recordAcademicAction();
    }
  }, [user?.id, role, recordAcademicAction]);

  // Student onboarding and real-time invitations
  const {
    hasPending,
    isOnboarding,
    pendingInvitations,
    showModal,
    dismissModal,
    refreshInvitations,
    showModalForNewRequest,
    markRequestAsHandled
  } = useStudentOnboarding();

  // Set up real-time invitations with modal trigger
  useRealtimeInvitations(
    () => {
      // Refresh invitations when new one arrives
      refreshInvitations();
    },
    () => {
      // Show modal when new invitation arrives
      showModalForNewRequest();
    }
  );

  const loading = assignmentsLoading || scheduleLoading || isOnboarding || streakLoading;

  if (loading) {
    return (
      <DashboardLayout>
        <DashboardSkeleton />
      </DashboardLayout>
    );
  }

  // Process upcoming assignments
  const upcomingTasks = assignments
    .filter(a => {
      // Include both 'published' (legacy) and 'active' (new system) statuses
      const isActiveOrPublished = a.status === 'published' || a.status === 'active';
      const isNotSubmitted = a.studentStatus ? (a.studentStatus === 'pending' || a.studentStatus === 'overdue') : true;
      return isActiveOrPublished && isNotSubmitted && a.due_date;
    })
    .sort((a, b) => new Date(a.due_date!).getTime() - new Date(b.due_date!).getTime())
    .slice(0, 3) // Limit to 3 to save space
    .map(a => {
      const dateDate = parseISO(a.due_date!);
      const isUrgent = isBefore(dateDate, addDays(new Date(), 2)) && isAfter(dateDate, new Date());

      return {
        id: a.id,
        title: a.title,
        course: a.course_title || "General Course",
        dueDate: format(dateDate, "MMM d"),
        dueTime: format(dateDate, "h:mm a"),
        type: "assignment" as const,
        isUrgent
      };
    });

  // Process upcoming classes
  const todayIndex = new Date().getDay(); // 0 is Sunday
  const upcomingClasses = schedules
    .filter(s => s.day_of_week >= todayIndex) // Today onwards
    .sort((a, b) => {
      if (a.day_of_week !== b.day_of_week) return a.day_of_week - b.day_of_week;
      return a.start_time.localeCompare(b.start_time);
    })
    .slice(0, 4) // Limit to 4
    .map(s => ({
      id: s.id,
      title: s.title,
      course: s.location || "Room TBD", // Using location as subtitle context
      dueDate: s.day_of_week === todayIndex ? "Today" : days[s.day_of_week],
      dueTime: s.start_time.slice(0, 5),
      type: s.type as any, // 'lecture' | 'lab' etc
      isUrgent: s.day_of_week === todayIndex // Highlight today's classes
    }));

  return (
    <DashboardLayout
      actions={
        <div className="flex items-center gap-2">
          <SEO
            title="Student Dashboard"
            description="View your active assignments, tracking streaks, and upcoming classes all from your EduSpace student dashboard."
          />

          <Button
            variant="default"
            size="sm"
            onClick={() => setInviteDialogOpen(true)}
            className="gap-2"
          >
            <UserPlus className="size-4" />
            <span className="hidden sm:inline">Invite User</span>
          </Button>
        </div>
      }
    >
      <div className="space-y-8">
        {/* Hero Section */}
        <DashboardHero />

        {/* Stats Grid */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
          <PremiumStatsCard
            title="ASSIGNED"
            value={stats.total}
            subtitle="Total active tasks"
            icon={FileText}
            backgroundColor="bg-gradient-to-br from-blue-600 to-indigo-700"
            iconBackgroundColor="bg-white/10"
            onClick={() => navigate("/student/assignments")}
          />
          <PremiumStatsCard
            title="STREAK"
            value={streak?.current_streak || 0}
            subtitle="Day blaze"
            icon={Flame}
            backgroundColor="bg-gradient-to-br from-orange-500 to-red-600"
            iconBackgroundColor="bg-white/10"
            onClick={() => navigate("/streak")}
          />
          <PremiumStatsCard
            title="COMPLETED"
            value={stats.completed}
            subtitle="Tasks finished"
            icon={CheckCircle}
            backgroundColor="bg-gradient-to-br from-green-600 to-emerald-700"
            iconBackgroundColor="bg-white/10"
          />
          <PremiumStatsCard
            title="PENDING"
            value={stats.pending}
            subtitle="Require attention"
            icon={AlertCircle}
            backgroundColor="bg-gradient-to-br from-amber-500 to-orange-600"
            iconBackgroundColor="bg-white/10"
          />
          <PremiumStatsCard
            title="SCHEDULE"
            value="View"
            subtitle="Weekly plan"
            icon={Calendar}
            backgroundColor="bg-gradient-to-br from-purple-600 to-violet-700"
            iconBackgroundColor="bg-white/10"
            onClick={() => navigate("/schedule")}
            className="hidden"
          />
        </div>

        {/* Main Content Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* Left Column (Main Content) */}
          <div className="lg:col-span-2 space-y-8">
            {/* Daily Streak Weekly Visual - MOBILE ONLY (at top of main content) */}
            <div className="space-y-3 lg:hidden">
              <div className="flex items-center justify-between px-1">
                <h3 className="font-black text-[10px] text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                  <Flame className="size-3.5 text-orange-500" />
                  Momentum Tracker
                </h3>
              </div>
              <DashboardStreakWeekly />
            </div>

            <div>
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold text-foreground">Current Assignments</h2>
              </div>
              <DashboardAssignmentList assignments={assignments} />
            </div>
          </div>

          {/* Right Column (Sidebar) */}
          <div className="space-y-6">
            {/* Daily Streak Weekly Visual - DESKTOP ONLY (top of sidebar) */}
            <div className="space-y-3 hidden lg:block">
              <div className="flex items-center justify-between px-1">
                <h3 className="font-black text-[10px] text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                  <Flame className="size-3.5 text-orange-500" />
                  Momentum Tracker
                </h3>
              </div>
              <DashboardStreakWeekly />
            </div>

            {/* Upcoming Classes Widget */}
            <div className="bg-surface rounded-xl border border-border p-5 shadow-sm">
              <h3 className="font-semibold text-foreground mb-4 flex items-center gap-2">
                <Clock className="size-4 text-purple-500" />
                Upcoming Classes
              </h3>
              <div className="space-y-3">
                {upcomingClasses.length > 0 ? (
                  upcomingClasses.map(cls => (
                    <UpcomingTask
                      key={cls.id}
                      {...cls}
                      onClick={() => navigate("/schedule")}
                    />
                  ))
                ) : (
                  <p className="text-sm text-muted-foreground text-center py-4">No upcoming classes</p>
                )}
              </div>
              <Button
                variant="ghost"
                onClick={() => navigate("/schedule")}
                className="w-full mt-2 text-xs"
              >
                View Full Schedule
              </Button>
            </div>

            {/* Upcoming Assignments Widget */}
            <div className="bg-surface rounded-xl border border-border p-5 shadow-sm">
              <h3 className="font-semibold text-foreground mb-4 flex items-center gap-2">
                <Calendar className="size-4 text-primary" />
                Assignments Due
              </h3>
              <div className="space-y-3">
                {upcomingTasks.length > 0 ? (
                  upcomingTasks.map(task => (
                    <UpcomingTask
                      key={task.id}
                      {...task}
                      onClick={() => navigate('/student/assignments')}
                    />
                  ))
                ) : (
                  <p className="text-sm text-muted-foreground text-center py-4">No pending deadlines</p>
                )}
              </div>
            </div>


          </div>

        </div>
      </div>

      {/* Invite User Dialog */}
      <InviteUserDialog
        open={inviteDialogOpen}
        onOpenChange={setInviteDialogOpen}
        lecturerName={profile?.full_name || "Student"}
        lecturerEmail={profile?.email || ""}
      />

      {/* Join Request Modal */}
      <JoinRequestModal
        open={showModal}
        onOpenChange={dismissModal}
        pendingInvitations={pendingInvitations}
        onRequestHandled={refreshInvitations}
        onRequestMarkedAsHandled={markRequestAsHandled}
      />
    </DashboardLayout>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { ArrowLeft, Save, Plus, Trash2, Edit2, Loader2, AlertCircle } from 'lucide-react';
import { QuestionEditor } from '@/components/quizzes/QuestionEditor';
import { QuizQuestion } from '@/types/quiz';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import type { Json } from '@/integrations/supabase/types';
import { Badge } from "@/components/ui/badge";
import { useAuth } from '@/contexts/AuthContext';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { DeleteConfirmDialog } from '@/components/layout/DeleteConfirmDialog';
import { FormSkeleton } from '@/components/skeletons/FormSkeleton';

// Simple UUID generator
// Robust UUID generator for client-side IDs
const generateUUID = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
        const r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
}

export default function EditQuiz() {
    const { classId, quizId } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    // Quiz Details State
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [passPercentage, setPassPercentage] = useState(50);
    const [status, setStatus] = useState('draft');

    // Questions State
    const [questions, setQuestions] = useState<QuizQuestion[]>([]);
    const [isEditingQuestion, setIsEditingQuestion] = useState(false);
    const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);
    const [saving, setSaving] = useState(false);
    const [lastSaved, setLastSaved] = useState<Date | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [hasSubmissions, setHasSubmissions] = useState(false);
    const [questionToDelete, setQuestionToDelete] = useState<string | null>(null);

    const calculateTotalMarks = () => {
        return questions.reduce((sum, q) => sum + q.marks, 0);
    };

    // Load quiz from DB on mount
    useEffect(() => {
        const loadQuiz = async () => {
            if (!quizId || !user) {
                setIsLoading(false);
                return;
            }

            try {
                // Fetch quiz data
                const { data: quiz, error: quizError } = await supabase
                    .from('quizzes')
                    .select('*, questions:quiz_questions(*)')
                    .eq('id', quizId)
                    .single();

                if (quizError) throw quizError;

                if (quiz) {
                    setTitle(quiz.title || '');
                    setDescription(quiz.description || '');
                    setPassPercentage(quiz.pass_percentage || 50);
                    setStatus(quiz.status || 'draft');

                    // Sort questions by order_index
                    const sortedQuestions = (quiz.questions || []).sort((a: any, b: any) => a.order_index - b.order_index);
                    setQuestions(sortedQuestions.map((q: any) => ({
                        id: q.id,
                        quiz_id: q.quiz_id,
                        question_text: q.question_text,
                        question_type: q.question_type,
                        marks: q.marks,
                        options: q.options,
                        correct_answer: q.correct_answer,
                        order_index: q.order_index
                    })));
                }

                // Check if quiz has submissions
                const { count } = await supabase
                    .from('quiz_submissions')
                    .select('*', { count: 'exact', head: true })
                    .eq('quiz_id', quizId);

                setHasSubmissions((count || 0) > 0);

            } catch (error) {
                console.error('Error loading quiz:', error);
                toast.error('Failed to load quiz');
                navigate(`/lecturer/quizzes/${classId}`);
            } finally {
                setIsLoading(false);
            }
        };

        loadQuiz();
    }, [quizId, user, classId, navigate]);

    // Auto-save logic
    useEffect(() => {
        if (isLoading) return;
        if (!title && questions.length === 0 && !description) return;

        const saveEverything = async () => {
            if (!classId || !user || !quizId) return;

            try {
                // Update Quiz Metadata
                const { error: quizError } = await supabase
                    .from('quizzes')
                    .update({
                        title: title || 'Untitled Quiz',
                        description,
                        total_marks: calculateTotalMarks(),
                        pass_percentage: passPercentage,
                    })
                    .eq('id', quizId);

                if (quizError) throw quizError;

                // Smart Sync Questions: Upsert all current, Delete missing
                if (questions.length > 0) {
                    const questionsToUpsert = questions.map((q, index) => ({
                        id: q.id, // Include ID for upsert
                        quiz_id: quizId,
                        question_text: q.question_text,
                        question_type: q.question_type,
                        marks: q.marks,
                        options: q.options as unknown as Json,
                        correct_answer: q.correct_answer,
                        order_index: index
                    }));

                    const { error: upsertError } = await supabase
                        .from('quiz_questions')
                        .upsert(questionsToUpsert);

                    if (upsertError) throw upsertError;

                    // Delete questions that are no longer in the list
                    const currentIds = questions.map(q => q.id);
                    const { error: deleteError } = await supabase
                        .from('quiz_questions')
                        .delete()
                        .eq('quiz_id', quizId)
                        .not('id', 'in', currentIds);

                    if (deleteError) console.error("Error deleting removed questions:", deleteError);
                } else {
                    // If no questions, delete all
                    await supabase.from('quiz_questions').delete().eq('quiz_id', quizId);
                }

                setLastSaved(new Date());

            } catch (error) {
                console.error('Auto-save failed:', error);
            }
        };

        const timeoutId = setTimeout(saveEverything, 1000); // 1s debounce
        return () => clearTimeout(timeoutId);
    }, [title, description, passPercentage, questions, classId, user, quizId, isLoading]);

    const handleSaveQuestion = (question: QuizQuestion) => {
        if (editingQuestionId) {
            setQuestions(questions.map(q => q.id === editingQuestionId ? question : q));
        } else {
            setQuestions([...questions, { ...question, id: generateUUID() }]);
        }
        setIsEditingQuestion(false);
        setEditingQuestionId(null);
    };

    const handleEditQuestion = (question: QuizQuestion) => {
        setEditingQuestionId(question.id);
        setIsEditingQuestion(true);
    };

    const handleDeleteQuestion = (id: string) => {
        setQuestions(questions.filter(q => q.id !== id));
    };

    const handleSaveAndClose = async () => {
        if (!title.trim()) {
            toast.error('Please enter a quiz title');
            return;
        }

        try {
            setSaving(true);
            const totalMarks = calculateTotalMarks();

            // Update Quiz
            const { error: quizError } = await supabase
                .from('quizzes')
                .update({
                    title,
                    description,
                    total_marks: totalMarks,
                    pass_percentage: passPercentage,
                })
                .eq('id', quizId);

            if (quizError) throw quizError;

            // Smart Sync Questions (same as auto-save)
            if (questions.length > 0) {
                const questionsToUpsert = questions.map((q, index) => ({
                    id: q.id,
                    quiz_id: quizId,
                    question_text: q.question_text,
                    question_type: q.question_type,
                    marks: q.marks,
                    options: q.options as unknown as Json,
                    correct_answer: q.correct_answer,
                    order_index: index
                }));

                const { error: upsertError } = await supabase
                    .from('quiz_questions')
                    .upsert(questionsToUpsert);

                if (upsertError) throw upsertError;

                // Delete missing
                const currentIds = questions.map(q => q.id);
                await supabase
                    .from('quiz_questions')
                    .delete()
                    .eq('quiz_id', quizId)
                    .not('id', 'in', currentIds);

            } else {
                await supabase.from('quiz_questions').delete().eq('quiz_id', quizId);
            }

            // If republishing, archive existing submissions to allow retake
            if (status === 'published') {
                const { error: archiveError } = await supabase
                    .from('quiz_submissions')
                    .update({ is_archived: true })
                    .eq('quiz_id', quizId)
                    .eq('is_archived', false);

                if (archiveError) console.error("Error archiving submissions:", archiveError);
            }

            toast.success('Quiz updated successfully!');
            navigate(`/lecturer/quizzes/${classId}`);

        } catch (error) {
            console.error('Error saving quiz:', error);
            toast.error('Failed to update quiz');
        } finally {
            setSaving(false);
        }
    };

    if (isLoading) {
        return (
            <DashboardLayout>
                <FormSkeleton />
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout>
            <div className="w-full pb-10 animate-in fade-in duration-500">
                {/* Header */}
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                    <div className="flex items-center gap-4">
                        <Button variant="ghost" size="icon" onClick={() => navigate(-1)} className="h-12 w-12 rounded-full hover:bg-muted transition-colors">
                            <ArrowLeft className="size-6" />
                        </Button>
                        <div>
                            <div className="flex items-center gap-3">
                                <h1 className="text-3xl font-bold tracking-tight">Edit Quiz</h1>
                                <Badge variant={status === 'published' ? 'default' : status === 'closed' ? 'destructive' : 'secondary'}>
                                    {status}
                                </Badge>
                                {lastSaved && (
                                    <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-500/10 text-emerald-500 text-xs font-medium animate-in zoom-in">
                                        <Save className="size-3" />
                                        Auto-saved at {lastSaved.toLocaleTimeString()}
                                    </div>
                                )}
                            </div>
                            <p className="text-muted-foreground text-lg mt-1">Modify your quiz questions and settings</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <Button variant="outline" onClick={() => navigate(-1)} className="h-11 px-6">Cancel</Button>
                        <Button
                            onClick={handleSaveAndClose}
                            disabled={saving || questions.length === 0}
                            className="h-11 px-8 shadow-lg shadow-primary/20 transition-all hover:scale-105 active:scale-95"
                        >
                            {saving ? (status === 'published' ? 'Republishing...' : 'Saving...') : (status === 'published' ? 'Republish Quiz' : 'Save Changes')}
                        </Button>
                    </div>
                </div>

                {hasSubmissions && (
                    <Alert className="mb-6 border-amber-500/50 bg-amber-500/10">
                        <AlertCircle className="size-4 text-amber-500" />
                        <AlertDescription className="text-amber-700 dark:text-amber-400">
                            <strong>Note:</strong> This quiz has student submissions. Editing questions may affect the grading consistency.
                            Consider creating a new quiz instead if major changes are needed.
                        </AlertDescription>
                    </Alert>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* Sidebar: Basic Info & Criteria */}
                    <div className="lg:col-span-4 space-y-6">
                        <Card className="shadow-md border-none bg-gradient-to-br from-card to-card/50">
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <Edit2 className="size-5 text-primary" />
                                    Quiz Overview
                                </CardTitle>
                                <CardDescription>Basic information and passing rules</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                <div className="space-y-2.5">
                                    <Label className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Quiz Title</Label>
                                    <Input
                                        placeholder="e.g., Mid-Term Physics Assessment"
                                        value={title}
                                        onChange={(e) => setTitle(e.target.value)}
                                        className="h-11 text-lg font-medium"
                                    />
                                </div>
                                <div className="space-y-2.5">
                                    <Label className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Detailed Description</Label>
                                    <Textarea
                                        placeholder="Add instructions, rules, or learning objectives..."
                                        value={description}
                                        onChange={(e) => setDescription(e.target.value)}
                                        className="min-h-[120px] resize-none"
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-6 pt-2">
                                    <div className="space-y-2.5">
                                        <Label className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Pass Score (%)</Label>
                                        <div className="relative">
                                            <Input
                                                type="number"
                                                min={0}
                                                max={100}
                                                value={passPercentage}
                                                onChange={(e) => setPassPercentage(parseInt(e.target.value) || 0)}
                                                className="h-11 pr-8 font-bold"
                                            />
                                            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground font-bold">%</span>
                                        </div>
                                    </div>
                                    <div className="space-y-2.5">
                                        <Label className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Total Points</Label>
                                        <div className="h-11 px-4 bg-muted/50 rounded-md border-2 border-dashed border-muted text-foreground font-bold flex items-center justify-center text-xl">
                                            {calculateTotalMarks()}
                                        </div>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Main Section: Questions List */}
                    <div className="lg:col-span-8 space-y-6">
                        <Card className="shadow-md border-none">
                            <CardHeader className="flex flex-row items-center justify-between pb-4">
                                <div>
                                    <CardTitle className="text-2xl">Exam Questions</CardTitle>
                                    <CardDescription>Manage and organize your question bank</CardDescription>
                                </div>
                                <Button
                                    onClick={() => setIsEditingQuestion(true)}
                                    disabled={isEditingQuestion}
                                    variant="outline"
                                    className="gap-2 border-primary text-primary hover:bg-primary hover:text-white"
                                >
                                    <Plus className="size-4" />
                                    New Question
                                </Button>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                {isEditingQuestion && (
                                    <div className="bg-muted/30 p-6 rounded-xl border-2 border-dashed border-primary/20 animate-in slide-in-from-top-4 duration-300">
                                        <QuestionEditor
                                            question={editingQuestionId ? questions.find(q => q.id === editingQuestionId) : undefined}
                                            onSave={handleSaveQuestion}
                                            onCancel={() => {
                                                setIsEditingQuestion(false);
                                                setEditingQuestionId(null);
                                            }}
                                            questionNumber={editingQuestionId ? questions.findIndex(q => q.id === editingQuestionId) + 1 : questions.length + 1}
                                        />
                                    </div>
                                )}

                                <div className="space-y-4">
                                    {questions.map((question, index) => (
                                        <Card key={question.id} className="relative group hover:border-primary/50 transition-colors shadow-sm bg-muted/20">
                                            <CardContent className="p-5 flex gap-6">
                                                <div className="flex flex-col items-center justify-center p-3 bg-white dark:bg-slate-900 rounded-xl w-14 h-14 shrink-0 shadow-sm border font-bold text-xl text-primary">
                                                    {index + 1}
                                                </div>
                                                <div className="flex-1 space-y-3">
                                                    <p className="font-semibold text-lg leading-tight">{question.question_text}</p>
                                                    <div className="flex flex-wrap items-center gap-4">
                                                        <Badge variant="outline" className="bg-white dark:bg-slate-900 px-3 py-1 border-primary/20 shadow-sm">
                                                            {question.marks} Points
                                                        </Badge>
                                                        <span className="text-sm text-muted-foreground flex items-center gap-1.5">
                                                            <div className="size-1.5 rounded-full bg-muted-foreground" />
                                                            {question.options.length} Choices
                                                        </span>
                                                        <span className="text-sm text-emerald-600 font-medium flex items-center gap-1.5">
                                                            <div className="size-1.5 rounded-full bg-emerald-600" />
                                                            Answer Set
                                                        </span>
                                                    </div>
                                                </div>
                                                <div className="flex flex-col gap-2">
                                                    <Button variant="ghost" size="icon" onClick={() => handleEditQuestion(question)} className="h-10 w-10 hover:bg-white dark:hover:bg-slate-900 shadow-sm border border-transparent hover:border-border">
                                                        <Edit2 className="size-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-10 w-10 text-destructive hover:bg-destructive/10 hover:text-destructive border border-transparent hover:border-destructive/20"
                                                        onClick={() => setQuestionToDelete(question.id)}
                                                    >
                                                        <Trash2 className="size-4" />
                                                    </Button>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>

                                {questions.length === 0 && !isEditingQuestion && (
                                    <div className="text-center py-20 border-2 border-dashed rounded-2xl bg-muted/10 opacity-60">
                                        <div className="p-4 rounded-full bg-muted w-16 h-16 flex items-center justify-center mx-auto mb-4">
                                            <Plus className="size-8 text-muted-foreground" />
                                        </div>
                                        <h4 className="text-lg font-bold">No questions yet</h4>
                                        <p className="text-muted-foreground mt-1">Start building your quiz by adding your first question.</p>
                                        <Button onClick={() => setIsEditingQuestion(true)} className="mt-6" variant="secondary">
                                            Add First Question
                                        </Button>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    </div>
                </div>
            </div>

            <DeleteConfirmDialog
                open={!!questionToDelete}
                onOpenChange={(open) => !open && setQuestionToDelete(null)}
                onConfirm={() => {
                    if (questionToDelete) {
                        handleDeleteQuestion(questionToDelete);
                        setQuestionToDelete(null);
                    }
                }}
                title="Delete Question?"
                description="This will remove the question from your quiz. You'll need to save your changes to make this permanent."
            />
        </DashboardLayout>
    );
}

import { useRef, useEffect, useState, useCallback } from "react";
import * as THREE from "three";
import ForceGraph3D from "react-force-graph-3d";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Card } from "@/components/ui/card";
import { Loader2, Orbit, Info, RefreshCw, Search, Hand, Target } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { knowledgeService } from "@/lib/knowledgeService";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";

interface Node {
    id: string;
    label: string;
    type: 'chat' | 'note' | 'quiz' | 'assignment';
    keywords: string[];
    val: number;
}

interface Link {
    source: string;
    target: string;
}

interface GraphData {
    nodes: Node[];
    links: Link[];
}

export default function KnowledgeMap() {
    const fgRef = useRef<any>();
    const { user } = useAuth();
    const [loading, setLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [graphData, setGraphData] = useState<GraphData>({ nodes: [], links: [] });
    const [originalData, setOriginalData] = useState<GraphData>({ nodes: [], links: [] });
    const [activeFilter, setActiveFilter] = useState<'all' | 'chat' | 'note' | 'quiz' | 'assignment'>('all');
    const [dimensions, setDimensions] = useState({ width: 0, height: 400 });
    const containerRef = useRef<HTMLDivElement>(null);

    const fetchKnowledgeData = useCallback(async () => {
        if (!user) return;

        try {
            setLoading(true);
            const { data: nodes, error } = await supabase
                .from('knowledge_nodes')
                .select('*')
                .eq('user_id', user.id);

            if (error) throw error;

            // Process actual data (if no data, graph will be empty)
            const formattedNodes: Node[] = (nodes || []).map(n => ({
                id: n.id,
                label: n.label,
                type: n.entity_type as any,
                keywords: n.keywords || [],
                val: 10 + (n.keywords?.length || 0) * 2
            }));

            // Basic linking logic: link nodes that share keywords
            const links: Link[] = [];
            for (let i = 0; i < formattedNodes.length; i++) {
                for (let j = i + 1; j < formattedNodes.length; j++) {
                    const shared = formattedNodes[i].keywords.filter(k =>
                        formattedNodes[j].keywords.includes(k)
                    );
                    if (shared.length > 0) {
                        links.push({
                            source: formattedNodes[i].id,
                            target: formattedNodes[j].id
                        });
                    }
                }
            }

            setOriginalData({ nodes: formattedNodes, links });
            setGraphData({ nodes: formattedNodes, links });
        } catch (error: any) {
            console.error('Detailed Knowledge Map Error:', error);
            const message = error.message || 'Unknown database error';
            toast.error(`Map Error: ${message}`);
        } finally {
            setLoading(false);
        }
    }, [user]);

    useEffect(() => {
        if (!containerRef.current) return;

        const resizeObserver = new ResizeObserver((entries) => {
            for (let entry of entries) {
                if (entry.contentRect) {
                    setDimensions({
                        width: entry.contentRect.width,
                        height: Math.max(entry.contentRect.height, 400)
                    });
                }
            }
        });

        resizeObserver.observe(containerRef.current);
        return () => resizeObserver.disconnect();
    }, []);

    useEffect(() => {
        if (activeFilter === 'all') {
            setGraphData(originalData);
        } else {
            const filteredNodes = originalData.nodes.filter(n => n.type === activeFilter);
            const nodeIds = new Set(filteredNodes.map(n => n.id));
            const filteredLinks = originalData.links.filter(l =>
                nodeIds.has(typeof l.source === 'object' ? (l.source as any).id : l.source) &&
                nodeIds.has(typeof l.target === 'object' ? (l.target as any).id : l.target)
            );
            setGraphData({ nodes: filteredNodes, links: filteredLinks });
        }
    }, [activeFilter, originalData]);

    useEffect(() => {
        fetchKnowledgeData();

        // Subscribe to real-time updates for knowledge nodes
        if (!user) return;

        const channel = supabase
            .channel('knowledge_nodes_changes')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'knowledge_nodes',
                    filter: `user_id=eq.${user.id}`
                },
                () => {
                    fetchKnowledgeData();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [fetchKnowledgeData, user]);

    const syncExistingData = async () => {
        if (!user) return;

        try {
            setIsSyncing(true);
            toast.info("Scanning your learning history...", { duration: 3000 });

            // 1. Fetch existing notes
            const { data: notes } = await supabase
                .from('student_notes')
                .select('id, title, content')
                .eq('user_id', user.id);

            // 2. Fetch existing chats
            const { data: chats } = await supabase
                .from('ai_conversations')
                .select('id, title')
                .eq('user_id', user.id);

            // 3. Fetch existing quiz submissions
            const { data: quizSubs } = await supabase
                .from('quiz_submissions')
                .select('id, quiz:quizzes(title)')
                .eq('student_id', user.id)
                .neq('status', 'pending');

            // 4. Fetch existing assignment submissions
            const { data: assignmentSubs } = await supabase
                .from('assignment_submissions')
                .select('id, assignment:assignments(title)')
                .eq('student_id', user.id);

            // 5. Process each
            const syncPromises = [];

            if (notes) {
                for (const note of notes) {
                    syncPromises.push(knowledgeService.upsertKnowledgeNode({
                        type: 'note',
                        sourceId: note.id,
                        label: note.title,
                        text: `${note.title}\n${note.content}`
                    }));
                }
            }

            if (chats) {
                for (const chat of chats) {
                    syncPromises.push(knowledgeService.upsertKnowledgeNode({
                        type: 'chat',
                        sourceId: chat.id,
                        label: chat.title,
                        text: chat.title
                    }));
                }
            }

            if (quizSubs) {
                for (const sub of quizSubs) {
                    const title = (sub.quiz as any)?.title || 'Quiz';
                    syncPromises.push(knowledgeService.upsertKnowledgeNode({
                        type: 'quiz',
                        sourceId: sub.id,
                        label: title,
                        text: title
                    }));
                }
            }

            if (assignmentSubs) {
                for (const sub of assignmentSubs) {
                    const title = (sub.assignment as any)?.title || 'Assignment';
                    syncPromises.push(knowledgeService.upsertKnowledgeNode({
                        type: 'assignment',
                        sourceId: sub.id,
                        label: title,
                        text: title
                    }));
                }
            }

            await Promise.all(syncPromises);
            toast.success("EduMatrix synchronized!");
            fetchKnowledgeData();
        } catch (error) {
            console.error("Sync error:", error);
            toast.error("Failed to sync history");
        } finally {
            setIsSyncing(false);
        }
    };

    const LegendItems = () => {
        const filters = [
            { id: 'all', label: 'All', icon: '✨' },
            { id: 'chat', label: 'Chats', icon: '💬' },
            { id: 'note', label: 'Notes', icon: '📝' },
            { id: 'quiz', label: 'Quizzes', icon: '🏆' },
            { id: 'assignment', label: 'Tasks', icon: '📚' }
        ];

        return (
            <div className="flex items-center p-1 bg-background/50 backdrop-blur-md rounded-2xl border border-border shadow-sm">
                {filters.map((filter) => (
                    <button
                        key={filter.id}
                        onClick={() => setActiveFilter(filter.id as any)}
                        className={cn(
                            "px-3 py-1 rounded-[10px] text-[10px] font-black transition-all flex items-center gap-1.5",
                            activeFilter === filter.id
                                ? "bg-indigo-500 text-white shadow-lg shadow-indigo-500/30"
                                : "text-muted-foreground hover:bg-accent hover:text-foreground"
                        )}
                    >
                        <span className="text-[12px] opacity-90 leading-none">{filter.icon}</span>
                        <span className="uppercase tracking-wider">{filter.label}</span>
                    </button>
                ))}
                <div className="h-4 w-[1px] bg-border mx-2" />
                <button
                    onClick={syncExistingData}
                    disabled={isSyncing || loading}
                    className="p-2 text-indigo-500 hover:bg-accent rounded-xl transition-all active:scale-95"
                    title="Sync History"
                >
                    <RefreshCw className={cn("size-4", isSyncing && "animate-spin")} />
                </button>
            </div>
        );
    };

    const getNodeColor = (node: Node) => {
        switch (node.type) {
            case 'chat': return '#6366f1'; // Indigo
            case 'note': return '#10b981'; // Emerald
            case 'quiz': return '#f59e0b'; // Amber
            case 'assignment': return '#ef4444'; // Red
            default: return '#94a3b8';
        }
    };

    return (
        <DashboardLayout fullHeight>
            <div className="flex flex-col h-[100dvh] w-full bg-background/30 md:bg-transparent overflow-hidden relative">
                {/* Premium Light Theme Pattern - Unified */}
                <div className="absolute inset-0 pointer-events-none opacity-[0.03]"
                    style={{ backgroundImage: `radial-gradient(#4f46e5 1px, transparent 1px)`, backgroundSize: '24px 24px' }}
                />

                {/* Desktop Header */}
                <div className="hidden md:flex flex-col p-6 text-foreground relative z-10">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 mb-6">
                        <div>
                            <h1 className="text-3xl font-bold flex items-center gap-3">
                                <Orbit className="size-8 text-primary" />
                                EduMatrix
                            </h1>
                            <p className="text-sm text-muted-foreground mt-1">Visualize your learning journey across time.</p>
                        </div>
                        <LegendItems />
                    </div>
                </div>

                {/* Mobile Header (Unified Style) */}
                <div className="flex md:hidden flex-col items-start pt-4 px-4 bg-background/40 backdrop-blur-sm z-20 relative">
                    <div className="w-full flex items-center justify-between mb-6">
                        <div className="flex items-center gap-2">
                            <div className="size-10 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-500/30">
                                <Orbit className="size-6 text-white" />
                            </div>
                            <h1 className="text-2xl font-black text-foreground tracking-tight">EduMatrix</h1>
                        </div>
                        <button
                            onClick={syncExistingData}
                            disabled={isSyncing || loading}
                            className="size-10 flex items-center justify-center bg-background rounded-2xl shadow-sm border border-border text-indigo-500 active:scale-95 transition-all"
                        >
                            <RefreshCw className={cn("size-5", isSyncing && "animate-spin")} />
                        </button>
                    </div>

                    <div className="w-full flex items-center p-1 bg-accent/40 rounded-[20px] mb-2 border border-border shadow-inner">
                        <button
                            onClick={() => setActiveFilter('all')}
                            className={cn(
                                "flex-1 py-2 px-1 rounded-2xl text-[10px] font-black transition-all whitespace-nowrap",
                                activeFilter === 'all' ? "bg-indigo-500 text-white shadow-md" : "text-muted-foreground hover:text-foreground"
                            )}
                        >
                            All
                        </button>
                        {[
                            { id: 'chat', label: 'Chats', icon: '💬' },
                            { id: 'note', label: 'Notes', icon: '📝' },
                            { id: 'quiz', label: 'Quizzes', icon: '🏆' },
                            { id: 'assignment', label: 'Tasks', icon: '📚' }
                        ].map((filter) => (
                            <button
                                key={filter.id}
                                onClick={() => setActiveFilter(filter.id as any)}
                                className={cn(
                                    "flex-1 py-2 px-1 rounded-2xl text-[10px] font-black transition-all whitespace-nowrap flex flex-col min-[380px]:flex-row items-center justify-center gap-0.5 min-[380px]:gap-1.5",
                                    activeFilter === filter.id ? "bg-indigo-500 text-white shadow-md" : "text-muted-foreground hover:text-foreground"
                                )}
                            >
                                <span className="text-[14px] min-[380px]:text-[12px] opacity-70 leading-none">{filter.icon}</span>
                                <span className="leading-none">{filter.label}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Graph Container */}
                <div ref={containerRef} className="flex-1 relative overflow-hidden group bg-transparent">
                    {loading ? (
                        <div className="absolute inset-0 flex flex-col p-6 space-y-8 z-10 bg-background/50 backdrop-blur-sm animate-in fade-in duration-500">
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                <Skeleton className="h-24 rounded-3xl" />
                                <Skeleton className="h-24 rounded-3xl" />
                                <Skeleton className="h-24 rounded-3xl" />
                                <Skeleton className="h-24 rounded-3xl" />
                            </div>
                            <div className="flex-1 flex items-center justify-center">
                                <div className="space-y-4 text-center">
                                    <Skeleton className="size-32 rounded-full mx-auto" />
                                    <Skeleton className="h-6 w-48 mx-auto rounded-lg" />
                                    <Skeleton className="h-4 w-64 mx-auto rounded-lg" />
                                </div>
                            </div>
                        </div>
                    ) : graphData.nodes.length === 0 ? (
                        <div className="absolute inset-0 flex flex-col items-center justify-center z-10 p-8 text-center bg-background/20 backdrop-blur-[2px]">
                            <div className="size-16 rounded-full bg-primary/10 flex items-center justify-center mb-4">
                                <Orbit className="size-8 text-primary/40" />
                            </div>
                            <h3 className="text-lg font-bold mb-2">Build Your Galaxy</h3>
                            <p className="max-w-xs text-sm text-muted-foreground mb-6">Start chatting with AI or writing notes to see your EduMatrix come to life.</p>
                            <button
                                onClick={syncExistingData}
                                className="px-6 py-2 bg-primary text-primary-foreground rounded-xl font-bold hover:scale-105 transition-all active:scale-95"
                            >
                                Sync My History
                            </button>
                        </div>
                    ) : (
                        <>
                            {/* Controls Card - Desktop Tooltip */}
                            <div className="hidden md:block absolute bottom-4 right-4 md:top-4 md:right-4 z-10 pointer-events-none md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                                <Card className="p-3 bg-white/60 dark:bg-black/60 backdrop-blur-xl border-white/10 dark:border-white/5 text-[9px] md:text-[10px] space-y-1.5 shadow-2xl rounded-2xl">
                                    <div className="flex items-center gap-2">
                                        <Info className="size-2 md:size-3 text-primary/60" />
                                        <span><b>Pinch/Scroll</b> to zoom</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Info className="size-2 md:size-3 text-primary/60" />
                                        <span><b>Drag</b> to rotate</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Info className="size-2 md:size-3 text-primary/60" />
                                        <span><b>Tap node</b> to focus</span>
                                    </div>
                                </Card>
                            </div>

                            <ForceGraph3D
                                ref={fgRef}
                                graphData={graphData}
                                width={dimensions.width}
                                height={dimensions.height}
                                nodeLabel={(node: any) => {
                                    const nodeColor = getNodeColor(node as Node);
                                    let typeIcon = '✨';
                                    if (node.type === 'chat') typeIcon = '💬';
                                    if (node.type === 'note') typeIcon = '📝';
                                    if (node.type === 'quiz') typeIcon = '🏆';
                                    if (node.type === 'assignment') typeIcon = '📚';

                                    return `
                                        <div style="font-family: inherit;" class="relative p-2 backdrop-blur-sm">
                                            <div class="absolute left-0 inset-y-0 w-0.5 rounded-full" style="background: ${nodeColor}; box-shadow: 0 0 10px ${nodeColor}80"></div>
                                            <div class="pl-4 flex flex-col gap-1">
                                                <p class="text-[9px] font-black uppercase tracking-[0.2em]" style="color: ${nodeColor}; text-shadow: 0 2px 4px rgba(0,0,0,0.5)">${node.type}</p>
                                                <h3 class="text-sm font-bold text-white leading-tight" style="text-shadow: 0 2px 4px rgba(0,0,0,0.5)">
                                                    <span class="mr-2">${typeIcon}</span>
                                                    ${node.label}
                                                </h3>
                                            </div>
                                            <div class="pl-4 mt-2 text-[8px] font-bold text-white/40 uppercase tracking-[0.2em]" style="text-shadow: 0 2px 4px rgba(0,0,0,0.5)">
                                                Click to Focus
                                            </div>
                                        </div>
                                    `;
                                }}
                                nodeThreeObject={(node: any) => {
                                    const canvas = document.createElement('canvas');
                                    canvas.width = 120;
                                    canvas.height = 120;
                                    const ctx = canvas.getContext('2d')!;
                                    const color = getNodeColor(node as Node);

                                    // Base sphere glow
                                    const gradient = ctx.createRadialGradient(60, 60, 0, 60, 60, 60);
                                    gradient.addColorStop(0, color);
                                    gradient.addColorStop(0.7, color);
                                    gradient.addColorStop(1, 'rgba(255,255,255,0)');

                                    ctx.fillStyle = gradient;
                                    ctx.beginPath();
                                    ctx.arc(60, 60, 50, 0, 2 * Math.PI);
                                    ctx.fill();

                                    // White icon inside
                                    ctx.fillStyle = 'white';
                                    ctx.font = 'bold 42px Arial';
                                    ctx.textAlign = 'center';
                                    ctx.textBaseline = 'middle';
                                    let icon = '✨';
                                    if (node.type === 'chat') icon = '💬';
                                    if (node.type === 'note') icon = '📝';
                                    if (node.type === 'quiz') icon = '🏆';
                                    if (node.type === 'assignment') icon = '📚';
                                    ctx.fillText(icon, 60, 60);

                                    const texture = new THREE.CanvasTexture(canvas);
                                    const material = new THREE.SpriteMaterial({
                                        map: texture,
                                        transparent: true,
                                        depthTest: false
                                    });
                                    const sprite = new THREE.Sprite(material);
                                    sprite.scale.set(node.val * 1.5, node.val * 1.5, 1);
                                    return sprite;
                                }}
                                nodeColor={(node: any) => getNodeColor(node as Node)}
                                nodeRelSize={7}
                                nodeVal={(node: any) => (node as Node).val}
                                linkColor={() => 'rgba(79, 70, 229, 0.15)'}
                                linkWidth={2}
                                linkOpacity={0.2}
                                backgroundColor="rgba(0,0,0,0)"
                                nodeThreeObjectExtend={false}
                                onNodeClick={(node: any) => {
                                    const distance = 40;
                                    const distRatio = 1 + distance / Math.hypot(node.x, node.y, node.z);
                                    fgRef.current.cameraPosition(
                                        { x: node.x * distRatio, y: node.y * distRatio, z: node.z * distRatio },
                                        node,
                                        1500
                                    );
                                }}
                            />

                            {/* Branded Control Bar - Now on all devices & Higher Up */}
                            <div className="absolute bottom-24 inset-x-0 flex justify-center px-4 z-30 pointer-events-none">
                                <div className="flex items-center justify-between w-full max-w-sm bg-background/80 backdrop-blur-xl border border-border shadow-2xl rounded-[32px] p-2 pointer-events-auto">
                                    <button
                                        className="flex-1 flex flex-col items-center gap-1.5 py-3 text-indigo-600 active:scale-90 transition-all"
                                        onClick={() => {
                                            const pos = fgRef.current.cameraPosition();
                                            fgRef.current.cameraPosition({ x: pos.x * 0.8, y: pos.y * 0.8, z: pos.z * 0.8 }, null, 500);
                                        }}
                                    >
                                        <div className="size-11 flex items-center justify-center bg-indigo-500/10 rounded-2xl shadow-sm border border-indigo-500/20">
                                            <Search className="size-6 text-indigo-500" />
                                        </div>
                                        <span className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Zoom</span>
                                    </button>
                                    <div className="w-[1px] h-8 bg-border" />
                                    <button
                                        className="flex-1 flex flex-col items-center gap-1.5 py-3 text-indigo-600 active:scale-90 transition-all"
                                        onClick={() => {
                                            fgRef.current.cameraPosition({ x: 0, y: 0, z: 200 }, { x: 0, y: 0, z: 0 }, 1000);
                                        }}
                                    >
                                        <div className="size-11 flex items-center justify-center bg-indigo-500/10 rounded-2xl shadow-sm border border-indigo-500/20">
                                            <Hand className="size-6 text-indigo-500" />
                                        </div>
                                        <span className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Pan</span>
                                    </button>
                                    <div className="w-[1px] h-8 bg-border" />
                                    <button
                                        className="flex-1 flex flex-col items-center gap-1.5 py-3 text-indigo-600 active:scale-90 transition-all"
                                        onClick={() => {
                                            const nodes = graphData.nodes as any[];
                                            if (nodes.length > 0) {
                                                const node = nodes[Math.floor(Math.random() * nodes.length)];
                                                const distance = 40;
                                                const distRatio = 1 + distance / Math.hypot(node.x, node.y, node.z);
                                                fgRef.current.cameraPosition(
                                                    { x: node.x * distRatio, y: node.y * distRatio, z: node.z * distRatio },
                                                    node,
                                                    1500
                                                );
                                            }
                                        }}
                                    >
                                        <div className="size-11 flex items-center justify-center bg-indigo-500/10 rounded-2xl shadow-sm border border-indigo-500/20">
                                            <Target className="size-6 text-indigo-500" />
                                        </div>
                                        <span className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Focus</span>
                                    </button>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            </div>
        </DashboardLayout>
    );
}

