import { useState, useRef, useEffect, useMemo } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import {
  Search,
  MessageSquare,
  Paperclip,
  Smile,
  Send,
  FileText,
  Download,
  Loader2,
  Trash2,
  Plus,
  X,
  Mic,
  MoreVertical,
  Filter,
  CheckCheck,
  Clock,
  LogOut,
  Pause,
  SwitchCamera,
  Terminal,
  ShieldAlert,
  CalendarCheck,
  Settings,
  User,
  Phone,
  Video,
  Copy,
  Link,
  Play,
  ArrowLeft,
  ExternalLink,
  Maximize2
} from "lucide-react";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { CallModal } from "@/components/chat/CallModal";
import { useNavigate, useLocation } from "react-router-dom";
import { cn } from "@/lib/utils";
import { useMessages } from "@/hooks/useMessages";
import { useInstructors } from "@/hooks/useInstructors";
import { useAuth } from "@/contexts/AuthContext";
import { useLongPress } from "@/hooks/useLongPress";
import { format, isToday, isYesterday, isSameDay } from "date-fns";
import { toast } from "sonner";
import { uploadToCloudinary } from "@/lib/cloudinary";
import { uploadToSupabaseStorage } from "@/lib/supastorage";
import { useEligibleStudents } from "@/hooks/useEligibleStudents";
import { useOnlinePresence } from "@/hooks/useOnlinePresence";
import { useCall } from "@/contexts/CallContext";
import { ChatSkeleton } from "@/components/skeletons/ChatSkeleton";
import { useClasses } from "@/hooks/useClasses";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { BookOpen, GraduationCap, BarChart2 } from "lucide-react";
import { PollBubble } from "@/components/chat/PollBubble";
import { CallBubble } from "@/components/chat/CallBubble";
import { ChatPollDialog } from "@/components/chat/ChatPollDialog";
import { useAudioRecorder } from "@/hooks/useAudioRecorder";
import { useStreak } from "@/contexts/StreakContext";
import { ChatProfilePopup } from "@/components/chat/ChatProfilePopup";

const formatFileSize = (bytes: number) => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

const getDateLabel = (date: Date) => {
  if (isToday(date)) return "TODAY";
  if (isYesterday(date)) return "YESTERDAY";
  return format(date, "MM/dd/yy");
};

// Message Bubble Component
interface MessageBubbleProps {
  message: any;
  setMessageToDelete: (id: string) => void;
}

const MessageBubble = ({ message, setMessageToDelete, onEdit }: {
  message: any;
  setMessageToDelete: (id: string) => void;
  onEdit: (id: string, newContent: string) => void;
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(message.content);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const audioRef = useRef<HTMLAudioElement>(null);
  const user = useAuth().user;

  const toggleRecordingPlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      const current = audioRef.current.currentTime;
      const duration = audioRef.current.duration;
      if (duration > 0) {
        setProgress((current / duration) * 100);
      }
    }
  };

  const handleAudioEnded = () => {
    setIsPlaying(false);
    setProgress(0);
  };

  const longPressHandlers = useLongPress({
    onLongPress: () => message.isOwn && setMessageToDelete(message.id),
    delay: 500,
  });

  const canEdit = message.isOwn &&
    !message.attachment &&
    (Date.now() - new Date(message.created_at_raw).getTime() < 5 * 60 * 1000) &&
    (message.edit_count || 0) < 2;

  const handleSaveEdit = () => {
    if (editContent.trim() !== message.content) {
      onEdit(message.id, editContent);
    }
    setIsEditing(false);
  };

  const handleCancelEdit = () => {
    setEditContent(message.content);
    setIsEditing(false);
  };

  return (
    <div
      className={cn(
        "flex mb-2 group/bubble",
        message.isOwn ? "justify-end" : "justify-start"
      )}
    >
      <div className={cn(
        "relative flex flex-col max-w-[85%] md:max-w-[70%] min-w-0",
        message.isOwn ? "items-end" : "items-start"
      )}>

        {/* Edit/Delete Menu Trigger for Desktop (Hover) */}
        {message.isOwn && !isEditing && (
          <div className={cn(
            "absolute top-0 opacity-0 group-hover/bubble:opacity-100 transition-opacity p-1",
            message.isOwn ? "-left-8" : "-right-8"
          )}>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="icon" className="size-6 h-6 w-6 p-0">
                  <MoreVertical className="size-4 text-slate-400" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                {canEdit && (
                  <DropdownMenuItem onClick={() => setIsEditing(true)}>
                    Edit
                  </DropdownMenuItem>
                )}
                <DropdownMenuItem onClick={() => setMessageToDelete(message.id)} className="text-red-600">
                  Delete
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        )}

        <div
          {...(message.isOwn ? longPressHandlers : {})}
          className={cn(
            "rounded-xl px-3.5 py-2 shadow-sm relative group",
            message.isOwn
              ? "bg-emerald-100 dark:bg-[#064e43] text-slate-800 dark:text-white rounded-tr-none"
              : "bg-white dark:bg-[#202c33] text-slate-800 dark:text-white rounded-tl-none border border-slate-100 dark:border-none"
          )}
        >
          {message.attachment && (
            <div className="mb-2">
              {message.attachment.type === 'poll' ? (
                <PollBubble pollId={message.attachment.url} />
              ) : message.attachment.type === 'call' ? (
                <CallBubble
                  type={message.attachment.name?.toLowerCase().includes('video') ? 'video' : 'audio'}
                  status={(message.attachment as any).status || 'ended'}
                  duration={message.attachment.size}
                  timestamp={message.timestamp}
                  isOwn={message.isOwn}
                  content={message.content}
                />
              ) : message.attachment.type === 'audio' ? (
                <div className="flex items-center gap-3 p-3 rounded-xl bg-[#1f2c34] dark:bg-[#1f2c34] min-w-[220px] max-w-full overflow-hidden">
                  <Button
                    variant="ghost"
                    size="icon"
                    className="size-10 rounded-full bg-[#00a884] hover:bg-[#008f72] flex items-center justify-center shrink-0 border-0 text-white"
                    onClick={() => {
                      if (isPlaying) {
                        audioRef.current?.pause();
                        setIsPlaying(false);
                      } else {
                        audioRef.current?.play();
                        setIsPlaying(true);
                      }
                    }}
                  >
                    {isPlaying ? <Pause className="size-5" /> : <Play className="size-5 ml-0.5" />}
                  </Button>
                  <div className="flex-1 space-y-1 min-w-0">
                    <div className="h-1.5 w-full bg-slate-700 rounded-full overflow-hidden relative">
                      <div
                        className="absolute h-full left-0 top-0 bg-[#00a884] transition-all duration-100"
                        style={{ width: `${progress}%` }}
                      />
                    </div>
                    <div className="flex justify-between items-center text-[10px] text-slate-400">
                      <span>{isPlaying ? "Playing..." : "Voice Message"}</span>
                      <span>{message.attachment.size}</span>
                    </div>
                  </div>
                  <audio
                    ref={audioRef}
                    src={message.attachment.url}
                    onTimeUpdate={handleTimeUpdate}
                    onEnded={handleAudioEnded}
                    className="hidden"
                  />
                  <Button
                    variant="ghost"
                    size="icon"
                    className="size-8 rounded-full"
                    onClick={() => window.open(message.attachment.url, '_blank')}
                  >
                    <Download className="size-4 text-muted-foreground" />
                  </Button>
                </div>
              ) : message.attachment.type?.startsWith('image/') ? (
                <div className="rounded-lg overflow-hidden mb-2">
                  <img
                    src={message.attachment.url}
                    alt="Attachment"
                    className="max-w-full max-h-64 object-cover rounded-lg cursor-pointer"
                    onClick={() => window.open(message.attachment.url, '_blank')}
                  />
                </div>
              ) : (
                <div
                  className="flex items-center gap-3 p-3 rounded-xl bg-[#1f2c34] dark:bg-[#1f2c34] cursor-pointer hover:bg-[#2a3942] transition-colors max-w-full overflow-hidden"
                  onClick={() => window.open(message.attachment.url, '_blank')}
                >
                  <div className="size-10 rounded-lg bg-emerald-500/20 flex items-center justify-center shrink-0">
                    <FileText className="size-5 text-emerald-500" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate text-slate-200">{message.attachment.name}</p>
                    <p className="text-xs text-slate-400">{message.attachment.size}</p>
                  </div>
                  <Download className="size-4 text-slate-400 shrink-0" />
                </div>
              )}
            </div>
          )}

          {isEditing ? (
            <div className="min-w-[200px]">
              <Input
                value={editContent}
                onChange={e => setEditContent(e.target.value)}
                className="mb-2 h-8 text-sm"
                autoFocus
              />
              <div className="flex justify-end gap-2">
                <Button size="sm" variant="ghost" className="h-6 text-xs" onClick={handleCancelEdit}>Cancel</Button>
                <Button size="sm" className="h-6 text-xs bg-emerald-600" onClick={handleSaveEdit}>Save</Button>
              </div>
            </div>
          ) : (
            message.content && message.attachment?.type !== 'call' && (
              <p className="text-sm shadow-none whitespace-pre-wrap [word-break:break-word] leading-relaxed py-0.5">{message.content}</p>
            )
          )}

          <div className={cn(
            "flex items-center gap-1 mt-1 justify-end",
            message.isOwn ? "text-emerald-600 dark:text-emerald-400" : "text-slate-500 dark:text-slate-400"
          )}>
            <span className="text-[10px]">
              {message.timestamp}
              {message.isEdited && <span className="italic ml-1">(edited)</span>}
            </span>
            {message.isOwn && (
              message.read_at ? (
                <CheckCheck className="size-3 text-blue-400" />
              ) : (
                <CheckCheck className="size-3 text-slate-500" />
              )
            )}
          </div>
        </div>
      </div>
    </div >
  );
};

// Date Separator Component
const DateSeparator = ({ date }: { date: string }) => (
  <div className="flex items-center justify-center my-4">
    <div className="px-4 py-1 rounded-full bg-slate-100 dark:bg-slate-800 text-xs font-medium text-muted-foreground shadow-sm">
      {date}
    </div>
  </div>
);

// Typing Indicator Component
const TypingIndicator = () => (
  <div className="flex justify-start mb-3">
    <div className="bg-white dark:bg-slate-800 rounded-2xl rounded-bl-md px-4 py-3 shadow-sm">
      <div className="flex gap-1">
        <span className="size-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
        <span className="size-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
        <span className="size-2 bg-emerald-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
      </div>
    </div>
  </div>
);

// Shared Media Drawer Component
const SharedMediaDrawer = ({ isOpen, onOpenChange, messages, otherUserName }: {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  messages: any[];
  otherUserName: string;
}) => {
  const media = useMemo(() => {
    return messages?.filter(m =>
      m.attachment_url &&
      (m.attachment_type?.startsWith('image/') || m.attachment_type?.startsWith('video/'))
    ) || [];
  }, [messages]);

  const docs = useMemo(() => {
    return messages?.filter(m =>
      m.attachment_url &&
      !m.attachment_type?.startsWith('image/') &&
      !m.attachment_type?.startsWith('video/') &&
      m.attachment_type !== 'call' &&
      m.attachment_type !== 'poll'
    ) || [];
  }, [messages]);

  const links = useMemo(() => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    return messages?.filter(m => m.content && m.content.match(urlRegex)) || [];
  }, [messages]);

  return (
    <Sheet open={isOpen} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="w-full sm:max-w-md p-0 overflow-hidden flex flex-col border-none shadow-2xl dark:bg-[#111b21]">
        <SheetHeader className="p-6 border-b border-slate-100 dark:border-slate-800 shrink-0">
          <div className="flex items-center gap-3 text-left">
            <div className="size-10 rounded-full bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center">
              <Paperclip className="size-5 text-emerald-600 dark:text-emerald-400" />
            </div>
            <div>
              <SheetTitle className="text-xl">Shared Content</SheetTitle>
              <SheetDescription className="text-slate-500">Shared with {otherUserName}</SheetDescription>
            </div>
          </div>
        </SheetHeader>

        <Tabs defaultValue="media" className="flex-1 flex flex-col overflow-hidden bg-white dark:bg-[#111b21]">
          <TabsList className="grid w-full grid-cols-3 mx-0 px-6 py-0 bg-transparent border-b border-slate-100 dark:border-slate-800 rounded-none h-14">
            <TabsTrigger value="media" className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-emerald-500 rounded-none h-full shadow-none font-semibold text-xs uppercase tracking-wider">Media</TabsTrigger>
            <TabsTrigger value="docs" className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-emerald-500 rounded-none h-full shadow-none font-semibold text-xs uppercase tracking-wider">Docs</TabsTrigger>
            <TabsTrigger value="links" className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-emerald-500 rounded-none h-full shadow-none font-semibold text-xs uppercase tracking-wider">Links</TabsTrigger>
          </TabsList>

          <TabsContent value="media" className="flex-1 overflow-y-auto p-4 focus-visible:ring-0">
            {media.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400 text-center animate-in fade-in duration-500">
                <div className="size-20 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                  <Video className="size-8 opacity-20" />
                </div>
                <p className="font-medium">No media shared yet</p>
                <p className="text-xs max-w-[180px] mt-1">Photos and videos will appear here.</p>
              </div>
            ) : (
              <div className="grid grid-cols-3 gap-2 animate-in fade-in slide-in-from-bottom-2 duration-300">
                {media.map((m, i) => (
                  <div key={i} className="aspect-square bg-slate-100 dark:bg-slate-800 rounded-xl overflow-hidden cursor-pointer hover:ring-2 hover:ring-emerald-500 transition-all group relative">
                    {m.attachment_type?.startsWith('image/') ? (
                      <img src={m.attachment_url!} className="w-full h-full object-cover" onClick={() => window.open(m.attachment_url!, '_blank')} />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center relative" onClick={() => window.open(m.attachment_url!, '_blank')}>
                        <Play className="size-6 text-white absolute z-10 drop-shadow-lg" />
                        <div className="absolute inset-0 bg-black/20 group-hover:bg-black/40 transition-colors" />
                        <img src={m.attachment_url! + "#t=0.5"} className="w-full h-full object-cover" alt="Video thumbnail" />
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </TabsContent>

          <TabsContent value="docs" className="flex-1 overflow-y-auto p-4 space-y-2 focus-visible:ring-0">
            {docs.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400 text-center animate-in fade-in duration-500">
                <div className="size-20 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                  <FileText className="size-8 opacity-20" />
                </div>
                <p className="font-medium">No documents shared yet</p>
                <p className="text-xs max-w-[180px] mt-1">PDFs and other files will appear here.</p>
              </div>
            ) : (
              <div className="space-y-2 animate-in fade-in slide-in-from-bottom-2 duration-300">
                {docs.map((m, i) => (
                  <div key={i} className="flex items-center gap-3 p-3 rounded-2xl bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-700/50 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-all" onClick={() => window.open(m.attachment_url!, '_blank')}>
                    <div className="size-12 rounded-xl bg-blue-500/10 flex items-center justify-center shrink-0">
                      <FileText className="size-6 text-blue-500" />
                    </div>
                    <div className="flex-1 min-w-0 flex flex-col">
                      <p className="text-sm font-semibold truncate">{m.attachment_name || 'Document'}</p>
                      <p className="text-[10px] text-slate-400 uppercase tracking-wider">{m.attachment_size} • {m.attachment_type?.split('/')[1] || 'FILE'}</p>
                    </div>
                    <div className="size-8 rounded-full flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors text-slate-400">
                      <Download className="size-4" />
                    </div>
                  </div>
                ))}
              </div>
            )}
          </TabsContent>

          <TabsContent value="links" className="flex-1 overflow-y-auto p-4 space-y-2 focus-visible:ring-0">
            {links.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400 text-center animate-in fade-in duration-500">
                <div className="size-20 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                  <Link className="size-8 opacity-20" />
                </div>
                <p className="font-medium">No links shared yet</p>
                <p className="text-xs max-w-[180px] mt-1">Links from your messages will appear here.</p>
              </div>
            ) : (
              <div className="space-y-2 animate-in fade-in slide-in-from-bottom-2 duration-300">
                {links.map((m, i) => {
                  const urls = m.content.match(/(https?:\/\/[^\s]+)/g);
                  return urls?.map((url: string, ui: number) => (
                    <div key={`${i}-${ui}`} className="flex items-center gap-3 p-3 rounded-2xl bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-700/50 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-all" onClick={() => window.open(url, '_blank')}>
                      <div className="size-12 rounded-xl bg-emerald-500/10 flex items-center justify-center shrink-0">
                        <Link className="size-6 text-emerald-500" />
                      </div>
                      <div className="flex-1 min-w-0 flex flex-col">
                        <p className="text-sm font-semibold truncate text-emerald-600 dark:text-emerald-400">{url}</p>
                        <p className="text-[10px] text-slate-400 uppercase tracking-wider">{format(new Date(m.created_at), 'MMM d, yyyy')}</p>
                      </div>
                      <div className="size-8 rounded-full flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors text-slate-400">
                        <ExternalLink className="size-4" />
                      </div>
                    </div>
                  ));
                })}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </SheetContent>
    </Sheet>
  );
};

export default function Messages() {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, role, profile } = useAuth();
  const {
    conversations, messages, sendMessage, deleteMessage, selectedConversationId, setSelectedConversationId,
    loading, typingUsers, sendTyping, startConversation, clearChat, deleteChat, hideChat, unhideChat,
    finalizeDeleteChat, editMessage, hasMore, loadMoreMessages, markMessagesAsRead,
    toggleAutoDelete
  } = useMessages();
  const { instructors, loading: instructorsLoading } = useInstructors();
  const { students: eligibleStudents, classGroups, loading: studentsLoading } = useEligibleStudents();
  const { onlineUsers } = useOnlinePresence();
  const { classes, loading: classesLoading } = useClasses();

  const [messageInput, setMessageInput] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [filterMode, setFilterMode] = useState<'all' | 'online' | 'students' | 'lecturers'>('all');
  const [messageToDelete, setMessageToDelete] = useState<string | null>(null);
  const [isNewChatOpen, setIsNewChatOpen] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [showClearDialog, setShowClearDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  // Add wallpaper state
  const [wallpaper, setWallpaper] = useState<string>("");
  const [messageSearchQuery, setMessageSearchQuery] = useState("");
  const [isMessageSearchOpen, setIsMessageSearchOpen] = useState(false);
  const { initiateCall, startMeeting, activeCall } = useCall();
  const activeCallRef = useRef<any>(null);

  // Meeting State
  const [joinMeetingCode, setJoinMeetingCode] = useState("");
  const [isJoinMeetingOpen, setIsJoinMeetingOpen] = useState(false);
  const [createdMeetingCode, setCreatedMeetingCode] = useState("");
  const [isCreateMeetingOpen, setIsCreateMeetingOpen] = useState(false);
  const [meetingType, setMeetingType] = useState<'audio' | 'video'>('video');
  const [isPollDialogOpen, setIsPollDialogOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMediaDrawerOpen, setIsMediaDrawerOpen] = useState(false);

  const [profilePopupOpen, setProfilePopupOpen] = useState(false);
  const [popupUserData, setPopupUserData] = useState<{ name: string; avatar: string }>({ name: "", avatar: "" });

  // Mobile View State
  const [isMobileChatOpen, setIsMobileChatOpen] = useState(false);

  // Auto-open mobile chat when conversation selected
  useEffect(() => {
    if (selectedConversationId) {
      setIsMobileChatOpen(true);
      localStorage.setItem('last_active_conversation', selectedConversationId);
    }
  }, [selectedConversationId]);

  // Restore state on mount
  useEffect(() => {
    const savedId = localStorage.getItem('last_active_conversation');
    if (savedId) {
      setSelectedConversationId(savedId);
      // We don't auto-open mobile view on refresh to prevent getting stuck if user wanted list
      // But user requirement says "Persist state". 
      // Let's check if we should auto-open based on user expectation. 
      // If we restore ID, the effect above runs and sets isMobileChatOpen(true). 
      // Ideally we might want to also save 'isMobileChatOpen' state if we want perfection.
    }
  }, []);

  const { isRecording, recordingTime, audioBlob, startRecording, stopRecording, resetRecorder } = useAudioRecorder();

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Load wallpaper on mount
  useEffect(() => {
    if (user?.id) {
      const saved = localStorage.getItem(`chat_wallpaper_${user.id}`);
      if (saved) setWallpaper(saved);
    }
  }, [user?.id]);

  const handleWallpaperChange = (value: string) => {
    setWallpaper(value);
    if (user?.id) {
      localStorage.setItem(`chat_wallpaper_${user.id}`, value);
    }
  };

  const generateMeetingCode = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let code = '';
    for (let i = 0; i < 6; i++) {
      code += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return code.substring(0, 3) + '-' + code.substring(3);
  };

  const handleCreateMeeting = (type: 'audio' | 'video') => {
    const code = generateMeetingCode();
    setCreatedMeetingCode(code);
    setMeetingType(type);
    setIsCreateMeetingOpen(true);
  };

  const startMeetingHandler = (code: string, type: 'audio' | 'video') => {
    // Record academic action (Participating in class interaction)
    if (role === 'student') {
      recordAcademicAction();
    }
    startMeeting(code, "Meeting", type);
    setIsCreateMeetingOpen(false);
    setIsJoinMeetingOpen(false);
    setJoinMeetingCode("");
  };

  const handleDirectCall = async (type: 'audio' | 'video', category: 'private' | 'meeting' = 'private') => {
    if (!selectedConversation || !user) return;

    // Record academic action
    if (role === 'student') {
      recordAcademicAction();
    }

    const otherUserId = selectedConversation.participant_1 === user.id
      ? selectedConversation.participant_2
      : selectedConversation.participant_1;

    try {
      if (category === 'private') {
        await initiateCall(
          otherUserId,
          selectedConversation.other_user_name || 'User',
          selectedConversation.other_user_avatar || '',
          type
        );
      } else {
        // Meeting Call (Jitsi)
        startMeeting(selectedConversation.id, selectedConversation.other_user_name || 'Meeting', type);

        // Send message about meeting
        await sendMessage(otherUserId, "Meeting Started", {
          type: 'call',
          name: type === 'video' ? 'Video Meeting' : 'Voice Meeting',
          status: 'started'
        });
      }
    } catch (err) {
      console.error("Failed to start call:", err);
      toast.error("Failed to start call");
    }
  };

  // Monitor call ending to send "Ended" message
  useEffect(() => {
    if (activeCall) {
      activeCallRef.current = activeCall;
    } else if (activeCallRef.current) {
      const call = activeCallRef.current;
      const durationMs = Date.now() - (call.startTime || Date.now());
      const minutes = Math.floor(durationMs / 60000);
      const seconds = Math.floor((durationMs % 60000) / 1000);
      const durationStr = `${minutes}:${seconds.toString().padStart(2, '0')}`;

      // Only send message for non-meeting direct calls (where conversationId is a UUID)
      if (!call.isMeeting && call.conversationId && call.conversationId.length > 30) {
        const conv = conversations.find(c => c.id === call.conversationId);
        if (conv && user) {
          const otherUserId = conv.participant_1 === user.id
            ? conv.participant_2
            : conv.participant_1;

          sendMessage(otherUserId, "Call Ended", {
            type: 'call',
            name: call.type === 'video' ? 'Video Call' : 'Voice Call',
            status: 'ended',
            size: durationStr
          }).catch(err => console.error("Failed to send end call message:", err));
        }
      }
      activeCallRef.current = null;
    }
  }, [activeCall, conversations, user, sendMessage]);

  const handleWallpaperUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        handleWallpaperChange(result);
      };
      reader.readAsDataURL(file);
    }
  };


  const handleDeleteMessage = async () => {
    if (!messageToDelete) return;
    try {
      await deleteMessage(messageToDelete);
      toast.success("Message deleted");
    } catch (err) {
      toast.error("Failed to delete message");
    } finally {
      setMessageToDelete(null);
    }
  };

  // Infinite Scroll & Scroll Restoration
  const [loadingMore, setLoadingMore] = useState(false);
  const scrollViewportRef = useRef<HTMLDivElement>(null);
  const prevScrollHeightRef = useRef<number>(0);

  const handleScroll = async (e: React.UIEvent<HTMLDivElement>) => {
    const target = e.currentTarget;
    // Trigger load more when near top (e.g. < 50px)
    if (target.scrollTop < 50 && hasMore && !loadingMore) {
      setLoadingMore(true);
      prevScrollHeightRef.current = target.scrollHeight;
      await loadMoreMessages();
      setLoadingMore(false);
    }
  };

  // Restore scroll position after loading more messages
  useEffect(() => {
    if (prevScrollHeightRef.current > 0 && scrollViewportRef.current) {
      const newScrollHeight = scrollViewportRef.current.scrollHeight;
      const diff = newScrollHeight - prevScrollHeightRef.current;
      if (diff > 0) {
        scrollViewportRef.current.scrollTop = diff;
      }
      prevScrollHeightRef.current = 0;
    }
  }, [messages]);

  // Mark messages as read when viewing conversation
  useEffect(() => {
    if (selectedConversationId && messages.length > 0) {
      markMessagesAsRead(selectedConversationId);
    }
  }, [selectedConversationId, messages, markMessagesAsRead]);

  // Scroll to bottom on initial load or new message (if near bottom)
  useEffect(() => {
    // Only scroll to bottom if WE send a message or it's the initial load (prevScrollHeight is 0)
    // If we just loaded old messages (prevScrollHeight > 0), DO NOT scroll to bottom.
    if (prevScrollHeightRef.current === 0) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, selectedConversationId]);

  const selectedConversation = conversations.find(c => c.id === selectedConversationId);
  const otherUserId = selectedConversation ? (selectedConversation.participant_1 === user?.id ? selectedConversation.participant_2 : selectedConversation.participant_1) : null;
  const isOtherUserOnline = otherUserId ? onlineUsers.has(otherUserId) : false;
  const isOtherUserTyping = otherUserId ? typingUsers.has(otherUserId) : false;

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 20 * 1024 * 1024) {
        toast.error("File size must be less than 20MB");
        return;
      }
      setSelectedFile(file);
    }
  };

  const clearSelectedFile = () => {
    setSelectedFile(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // Handle auto-send for audio recording
  useEffect(() => {
    if (audioBlob) {
      handleSendAudio(audioBlob);
    }
  }, [audioBlob]);

  const handleSendAudio = async (blob: Blob) => {
    if (!selectedConversation || !user) return;
    setIsUploading(true);

    const receiverId = selectedConversation.participant_1 === user.id
      ? selectedConversation.participant_2
      : selectedConversation.participant_1;

    try {
      const file = new File([blob], `audio_message_${Date.now()}.webm`, { type: 'audio/webm' });
      // Use Cloudinary for audio as well, or Supabase. Let's use Cloudinary as it handles media well.
      const uploaded = await uploadToCloudinary(file);

      const attachmentData = {
        name: 'Audio Message',
        url: uploaded.url,
        type: 'audio', // Mark as audio for proper rendering
        size: formatFileSize(blob.size)
      };

      await sendMessage(receiverId, "", attachmentData);
      resetRecorder();
    } catch (err) {
      console.error('Failed to send audio message:', err);
      toast.error("Failed to send audio message");
    } finally {
      setIsUploading(false);
    }
  };

  const toggleRecording = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      try {
        await startRecording();
      } catch (err) {
        toast.error("Could not access microphone");
      }
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const { recordAcademicAction } = useStreak();

  const handleSendMessage = async () => {
    if ((!messageInput.trim() && !selectedFile) || !selectedConversation || !user || isUploading) return;

    // Record academic action (Participating in class interaction)
    if (role === 'student') {
      recordAcademicAction();
    }

    const receiverId = selectedConversation.participant_1 === user.id
      ? selectedConversation.participant_2
      : selectedConversation.participant_1;

    try {
      let attachmentData;

      if (selectedFile) {
        setIsUploading(true);
        try {
          let uploaded;
          if (selectedFile.type === 'application/pdf') {
            uploaded = await uploadToSupabaseStorage(selectedFile);
          } else {
            uploaded = await uploadToCloudinary(selectedFile);
          }

          attachmentData = {
            name: uploaded.name,
            url: uploaded.url,
            type: uploaded.type,
            size: formatFileSize(selectedFile!.size)
          };
        } catch (uploadError: any) {
          toast.error(`Upload failed: ${uploadError.message}`);
          setIsUploading(false);
          return;
        }
        setIsUploading(false);
      }

      await sendMessage(receiverId, messageInput, attachmentData);
      setMessageInput("");
      clearSelectedFile();
    } catch (err) {
      console.error('Failed to send message:', err);
      toast.error("Failed to send message");
    } finally {
      setIsUploading(false);
    }
  };

  const handleStartNewChat = async (targetId: string) => {
    const existing = conversations.find(c =>
      (c.participant_1 === user?.id && c.participant_2 === targetId) ||
      (c.participant_1 === targetId && c.participant_2 === user?.id)
    );

    if (existing) {
      setSelectedConversationId(existing.id);
      setIsNewChatOpen(false);
      return;
    }

    try {
      const conversationId = await startConversation(targetId);
      if (conversationId) {
        setSelectedConversationId(conversationId);
      }
    } catch (e) {
      console.error('Error starting conversation:', e);
      toast.error("Failed to start conversation");
    }
    setIsNewChatOpen(false);
  };

  // Handle auto-open from navigation state
  useEffect(() => {
    const state = location.state as { contactId?: string };
    if (state?.contactId && !loading) {
      handleStartNewChat(state.contactId);
      // Clear state after handling it once
      window.history.replaceState({}, document.title);
    }
  }, [location.state, loading, conversations, handleStartNewChat]);

  const handleClearChat = async () => {
    if (!selectedConversationId) return;
    try {
      await clearChat(selectedConversationId);
      toast.success("Chat cleared");
    } catch (error) {
      console.error("Failed to clear chat:", error);
      toast.error("Failed to clear chat");
    }
  };

  const handleDeleteChat = async () => {
    if (!selectedConversationId) return;
    const previousId = selectedConversationId;

    try {
      // Step 1: Hide immediately (Soft Delete)
      await hideChat(previousId);

      // Step 2: Show Undo Toast
      toast.success("Chat deleted", {
        action: {
          label: "Undo",
          onClick: async () => {
            // Undo Logic: Unhide
            try {
              await unhideChat(previousId);
              toast.success("Chat restored");
            } catch (e) {
              console.error("Restore failed", e);
              toast.error("Failed to restore chat");
            }
          }
        },
        duration: 5000,
        // Removed auto-finalize for now to ensure reliability of restore logic first.
        // Hiding is sufficient for "Deletions". History clearing is optional step 2.
      });
    } catch (error) {
      console.error("Failed to delete chat:", error);
      toast.error("Failed to delete chat");
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Merge conversations with eligible contacts
  const existingContactIds = new Set(conversations.map(c =>
    c.participant_1 === user?.id ? c.participant_2 : c.participant_1
  ));

  const studentsWithoutChat = eligibleStudents.filter(s => !existingContactIds.has(s.id));
  const lecturersWithoutChat = instructors.filter(i => !existingContactIds.has(i.id));

  const virtualContacts = role === 'student'
    ? lecturersWithoutChat.map(i => ({
      id: `new:${i.id}`,
      participant_1: user?.id || '',
      participant_2: i.id,
      last_message: 'Start a conversation',
      last_message_at: null,
      other_user_name: i.full_name,
      other_user_avatar: i.avatar_url,
      other_user_role: 'lecturer',
      other_user_id: i.id,
      is_virtual: true
    }))
    : studentsWithoutChat.map(s => ({
      id: `new:${s.id}`,
      participant_1: user?.id || '',
      participant_2: s.id,
      last_message: 'Start a conversation',
      last_message_at: null,
      other_user_name: s.full_name,
      other_user_avatar: s.avatar_url,
      other_user_role: 'student',
      other_user_id: s.id,
      is_virtual: true
    }));

  const allItems = [...conversations, ...virtualContacts].filter((item) =>
    (item.other_user_name || '').toLowerCase().includes(searchQuery.toLowerCase())
  ).filter(item => {
    if (filterMode === 'all') return true;
    if (filterMode === 'online') {
      const realId = 'is_virtual' in item && item.is_virtual ? (item as any).other_user_id : (item.participant_1 === user?.id ? item.participant_2 : item.participant_1);
      return onlineUsers.has(realId);
    }
    // Simplistic role filtering if possible, else just ignore
    return true;
  });

  const sortedItems = allItems.sort((a, b) => {
    if (a.last_message_at && b.last_message_at) {
      return new Date(b.last_message_at).getTime() - new Date(a.last_message_at).getTime();
    }
    if (a.last_message_at) return -1;
    if (b.last_message_at) return 1;
    return (a.other_user_name || '').localeCompare(b.other_user_name || '');
  });

  // Group messages by date
  const groupedMessages: { date: string; messages: any[] }[] = [];
  let currentDateLabel = "";

  const filteredMessages = messages.filter(msg =>
    !messageSearchQuery ||
    (msg.content && msg.content.toLowerCase().includes(messageSearchQuery.toLowerCase()))
  );

  filteredMessages.forEach((msg) => {
    const msgDate = new Date(msg.created_at);
    const dateLabel = getDateLabel(msgDate);

    if (dateLabel !== currentDateLabel) {
      currentDateLabel = dateLabel;
      groupedMessages.push({ date: dateLabel, messages: [] });
    }

    groupedMessages[groupedMessages.length - 1].messages.push({
      id: msg.id,
      content: msg.content,
      timestamp: format(msgDate, 'h:mm a'),
      isOwn: msg.sender_id === user?.id,
      sender: msg.sender_name || 'Unknown',
      isEdited: msg.is_edited,
      read_at: msg.read_at,
      edit_count: msg.edit_count,
      created_at_raw: msg.created_at,
      attachment: msg.attachment_name ? {
        name: msg.attachment_name,
        size: msg.attachment_size || '',
        type: msg.attachment_type || '',
        url: msg.attachment_url || ''
      } : undefined,
    });
  });

  if (loading) {
    return (
      <DashboardLayout fullHeight={true} hideHeaderOnMobile={!!selectedConversation && isMobileChatOpen}>
        <ChatSkeleton />
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout fullHeight={true} hideHeaderOnMobile={!!selectedConversation && isMobileChatOpen}>
      <div className={cn(
        "flex h-full w-full bg-white dark:bg-[#111b21] overflow-hidden relative",
        "md:rounded-xl md:shadow-xl md:border md:border-slate-200 dark:md:border-slate-700 fade-in duration-300"
      )}>

        {/* Left Sidebar */}
        <div className={cn(
          "border-r border-slate-200 dark:border-slate-700/50 flex flex-col bg-white dark:bg-[#111b21]",
          "md:w-80 w-full shrink-0",
          selectedConversation && isMobileChatOpen ? "hidden md:flex" : "flex"
        )}>

          {/* Sidebar Header */}
          <div className="h-16 px-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-700 bg-emerald-50 dark:bg-slate-800">
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="icon"
                className="md:hidden size-8 text-slate-700 dark:text-emerald-400 hover:text-emerald-900 mr-1"
                onClick={() => window.history.back()}
              >
                <ArrowLeft className="size-5" />
              </Button>
              <div className="flex items-center gap-3">
                <Avatar className="size-7 md:size-10 ring-2 ring-emerald-500/20">
                  <AvatarImage src={profile?.avatar_url || user?.user_metadata?.avatar_url} />
                  <AvatarFallback className="bg-emerald-500 text-white font-semibold">
                    {profile?.full_name?.charAt(0) || user?.user_metadata?.full_name?.charAt(0) || 'U'}
                  </AvatarFallback>
                </Avatar>
                <div>
                  <p className="font-semibold text-sm">{profile?.full_name || user?.user_metadata?.full_name || 'User'}</p>
                  <p className="text-xs text-emerald-600 dark:text-emerald-400">Active Now</p>
                </div>
              </div>
            </div >
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="icon"
                className="size-9 text-slate-600 dark:text-slate-400 hover:text-emerald-600"
                onClick={() => navigate('/call-history')}
                title="Call History"
              >
                <Clock className="size-5" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className="size-9 text-slate-600 dark:text-slate-400 hover:text-emerald-600"
                onClick={() => setIsNewChatOpen(true)}
                title="Start New Chat"
              >
                <Plus className="size-5" />
              </Button>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" className="size-9 text-slate-600 dark:text-slate-400 hover:text-emerald-600">
                    <MoreVertical className="size-5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56">
                  <DropdownMenuLabel>Chat Settings</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  <DropdownMenuLabel className="text-xs font-normal text-muted-foreground pb-2">
                    Background Colors
                  </DropdownMenuLabel>
                  <div className="p-2 grid grid-cols-4 gap-2 mb-2">
                    {[
                      '#fecaca', // Red
                      '#fed7aa', // Orange
                      '#fde68a', // Amber
                      '#bbf7d0', // Green
                      '#a5f3fc', // Cyan
                      '#bfdbfe', // Blue
                      '#ddd6fe', // Violet
                      '#fbcfe8'  // Pink
                    ].map(c => (
                      <button
                        key={c}
                        className="size-8 rounded-lg border shadow-sm transition-transform hover:scale-110"
                        style={{ backgroundColor: c }}
                        onClick={() => handleWallpaperChange(c)}
                        title={c}
                      />
                    ))}
                  </div>
                  <DropdownMenuItem onClick={() => handleWallpaperChange('')}>
                    <span className="text-xs">Reset Default</span>
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => document.getElementById('wallpaper-upload')?.click()}>
                    <span className="text-xs">Upload Image</span>
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuLabel className="text-xs font-normal text-muted-foreground pb-2">
                    Meetings
                  </DropdownMenuLabel>
                  {role === 'lecturer' && (
                    <DropdownMenuItem onClick={() => handleCreateMeeting('video')}>
                      <Video className="size-4 mr-2" />
                      <span className="text-xs">Create Meeting</span>
                    </DropdownMenuItem>
                  )}
                  {role === 'lecturer' && (
                    <DropdownMenuItem onClick={() => setIsPollDialogOpen(true)}>
                      <BarChart2 className="size-4 mr-2" />
                      <span className="text-xs">Create Poll</span>
                    </DropdownMenuItem>
                  )}
                  <DropdownMenuItem onClick={() => setIsJoinMeetingOpen(true)}>
                    <Link className="size-4 mr-2" />
                    <span className="text-xs">Join Meeting</span>
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>

          {/* Search */}
          <div className="p-3 border-b border-slate-100 dark:border-slate-700">
            <div className="relative flex items-center gap-2">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-slate-500 dark:text-slate-400" />
                <Input
                  placeholder="Search or start new chat"
                  className="pl-9 bg-slate-100 dark:bg-slate-700 border-0 rounded-lg h-10 text-base md:text-sm"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" className={cn("size-9", filterMode !== 'all' ? "text-emerald-600 bg-emerald-50" : "text-slate-500 dark:text-slate-400")}>
                    <Filter className="size-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuLabel>Filter Chats</DropdownMenuLabel>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem onClick={() => setFilterMode('all')}>
                    All Chats
                    {filterMode === 'all' && <CheckCheck className="size-3 ml-auto text-emerald-500" />}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setFilterMode('online')}>
                    Online Only
                    {filterMode === 'online' && <CheckCheck className="size-3 ml-auto text-emerald-500" />}
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>

          {/* Conversation List */}
          <ScrollArea className="flex-1">
            {sortedItems.length === 0 ? (
              <div className="p-6 text-center">
                <MessageSquare className="size-12 mx-auto mb-3 text-slate-300" />
                <p className="text-sm text-slate-500">No conversations yet</p>
              </div>
            ) : (
              sortedItems.map((item) => {
                const isVirtual = 'is_virtual' in item && item.is_virtual;
                const realId = isVirtual ? (item as any).other_user_id : item.id;
                const otherUserIdForOnline = isVirtual ? realId : (item.participant_1 === user?.id ? item.participant_2 : item.participant_1);
                const isOnline = onlineUsers.has(otherUserIdForOnline);
                const isTyping = typingUsers.has(otherUserIdForOnline);

                return (
                  <button
                    key={item.id}
                    onClick={() => {
                      if (isVirtual) {
                        handleStartNewChat(realId);
                      } else {
                        setSelectedConversationId(item.id);
                      }
                      setIsMobileChatOpen(true);
                    }}
                    className={cn(
                      "w-full flex items-center gap-3 px-4 py-3 text-left transition-colors border-b border-slate-50 dark:border-slate-700/50",
                      selectedConversationId === item.id
                        ? "bg-emerald-50 dark:bg-emerald-900/20"
                        : "hover:bg-slate-50 dark:hover:bg-slate-700/50"
                    )}
                  >
                    <div
                      className="relative cursor-pointer hover:opacity-80 transition-opacity"
                      onClick={(e) => {
                        e.stopPropagation();
                        setPopupUserData({
                          name: item.other_user_name || 'Unknown User',
                          avatar: item.other_user_avatar || ''
                        });
                        setProfilePopupOpen(true);
                      }}
                    >
                      <Avatar className="size-12 ring-2 ring-transparent hover:ring-emerald-500/30 transition-all">
                        <AvatarImage src={item.other_user_avatar} />
                        <AvatarFallback className="bg-slate-200 dark:bg-slate-600 text-slate-600 dark:text-slate-300">
                          {(item.other_user_name || 'U').split(" ").map((n: string) => n[0]).join("")}
                        </AvatarFallback>
                      </Avatar>
                      {isOnline && (
                        <span className="absolute bottom-0 right-0 size-3 bg-emerald-500 rounded-full border-2 border-white dark:border-slate-800" />
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between gap-2">
                        <span className="font-medium text-sm truncate">{item.other_user_name || 'Unknown User'}</span>
                        <span className="text-[10px] text-emerald-600 dark:text-emerald-400 shrink-0">
                          {item.last_message_at ? format(new Date(item.last_message_at), 'h:mm a') : ''}
                        </span>
                      </div>
                      <p className={cn(
                        "text-xs truncate mt-0.5",
                        isTyping ? "text-emerald-600 dark:text-emerald-400 italic" : "text-slate-500"
                      )}>
                        {isTyping ? "typing..." : (item.last_message || 'No messages yet')}
                      </p>
                    </div>
                    {isVirtual && (
                      <div className="size-5 rounded-full bg-emerald-500 flex items-center justify-center">
                        <Plus className="size-3 text-white" />
                      </div>
                    )}
                  </button>
                );
              })
            )}
          </ScrollArea>

          {/* New Chat Button */}
          <div className="p-3 border-t border-slate-100 dark:border-slate-700">
            <Button
              className="w-full bg-emerald-500 hover:bg-emerald-600 text-white gap-2 rounded-xl h-11"
              onClick={() => setIsNewChatOpen(true)}
            >
              <MessageSquare className="size-4" />
              New Chat
            </Button>
          </div>
        </div>

        {/* Chat Area */}
        {selectedConversation ? (
          <div className={cn(
            "flex-1 min-w-0 flex flex-col bg-slate-50 dark:bg-[#0b141a] h-full relative overflow-hidden",
            (!isMobileChatOpen ? "hidden md:flex" : "flex")
          )}
            style={{
              backgroundImage: (wallpaper.startsWith('data:') || wallpaper.startsWith('http')) ? `url(${wallpaper})` : undefined,
              backgroundColor: (!wallpaper.startsWith('data:') && !wallpaper.startsWith('http')) ? wallpaper : undefined,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
              height: '100%'
            }}
          >

            {/* Chat Header */}
            <div className="h-16 px-3 md:px-6 flex items-center justify-between border-b border-slate-200 dark:border-slate-700/50 bg-slate-50 dark:bg-[#1f2c34] z-20 shrink-0 select-none">
              {isMessageSearchOpen ? (
                <div className="flex items-center gap-2 w-full animate-in fade-in slide-in-from-top-2 duration-200">
                  <Search className="size-4 text-slate-400" />
                  <Input
                    autoFocus
                    placeholder="Search in conversation..."
                    className="border-none shadow-none focus-visible:ring-0 bg-transparent h-9 px-0"
                    value={messageSearchQuery}
                    onChange={(e) => setMessageSearchQuery(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Escape') {
                        setIsMessageSearchOpen(false);
                        setMessageSearchQuery("");
                      }
                    }}
                  />
                  <Button
                    variant="ghost"
                    size="icon"
                    className="size-8 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full text-slate-600 dark:text-slate-400"
                    onClick={() => {
                      setIsMessageSearchOpen(false);
                      setMessageSearchQuery("");
                    }}
                  >
                    <X className="size-4" />
                  </Button>
                </div>
              ) : (
                <>
                  <div className="flex items-center gap-1 min-w-0 flex-1 overflow-hidden">
                    <Button
                      variant="ghost"
                      size="icon"
                      className="md:hidden text-slate-700 dark:text-white hover:bg-slate-200 dark:hover:bg-white/10 shrink-0 size-10 -ml-2"
                      onClick={() => setIsMobileChatOpen(false)}
                    >
                      <ArrowLeft className="size-6" />
                    </Button>
                    <Avatar
                      className="size-8 md:size-10 shrink-0 border border-slate-200 dark:border-slate-700/50 cursor-pointer hover:ring-2 hover:ring-emerald-500/30 transition-all"
                      onClick={() => {
                        setPopupUserData({
                          name: selectedConversation.other_user_name || 'Unknown User',
                          avatar: selectedConversation.other_user_avatar || ''
                        });
                        setProfilePopupOpen(true);
                      }}
                    >
                      <AvatarImage src={selectedConversation.other_user_avatar} />
                      <AvatarFallback className="bg-emerald-500 dark:bg-[#064e43] text-white">
                        {(selectedConversation.other_user_name || 'U').split(" ").map((n) => n[0]).join("")}
                      </AvatarFallback>
                    </Avatar>
                    <div
                      className="min-w-0 flex-1 flex flex-col justify-center ml-1 text-left cursor-pointer hover:opacity-80 transition-opacity"
                      onClick={() => setIsMediaDrawerOpen(true)}
                    >
                      <h3 className="font-bold text-sm truncate leading-tight text-slate-900 dark:text-white">{selectedConversation.other_user_name || 'Unknown User'}</h3>
                      <p className="text-[10px] text-emerald-600 dark:text-emerald-400 truncate leading-none mt-0.5">
                        {isOtherUserOnline ? 'Online' : 'Offline'}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center shrink-0 ml-1">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="size-9 min-w-[36px] text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-white shrink-0"
                        >
                          <Phone className="size-5" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => handleDirectCall('audio', 'private')}>
                          <ShieldAlert className="size-4 mr-2 text-emerald-500" />
                          <span>🔒 Private Audio Call</span>
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleDirectCall('audio', 'meeting')}>
                          <User className="size-4 mr-2 text-blue-500" />
                          <span>👥 Meeting Audio Call</span>
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>

                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="size-9 min-w-[36px] text-slate-600 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-white shrink-0"
                        >
                          <Video className="size-5" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => handleDirectCall('video', 'private')}>
                          <ShieldAlert className="size-4 mr-2 text-emerald-500" />
                          <span>🔒 Private Video Call</span>
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleDirectCall('video', 'meeting')}>
                          <User className="size-4 mr-2 text-blue-500" />
                          <span>👥 Meeting Video Call</span>
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="size-9 min-w-[36px] text-slate-500 dark:text-slate-300 hover:text-emerald-600 dark:hover:text-white shrink-0"
                      onClick={() => setIsMessageSearchOpen(true)}
                    >
                      <Search className="size-5" />
                    </Button>

                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon" className="size-9 text-slate-600 dark:text-slate-500 hover:text-emerald-600">
                          <MoreVertical className="size-5" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => setShowClearDialog(true)}>
                          <div className="flex items-center gap-2 text-slate-600 dark:text-slate-300">
                            <Trash2 className="size-4" />
                            <span>Clear Chat</span>
                          </div>
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setIsSettingsOpen(true)}>
                          <div className="flex items-center gap-2 text-slate-600 dark:text-slate-300">
                            <Settings className="size-4" />
                            <span>Chat Settings</span>
                          </div>
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setShowDeleteDialog(true)}>
                          <div className="flex items-center gap-2 text-red-600 dark:text-red-400">
                            <LogOut className="size-4" />
                            <span>Delete Chat</span>
                          </div>
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem onClick={() => document.getElementById('wallpaper-upload')?.click()}>
                          <span className="text-xs">Change Wallpaper</span>
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuLabel className="text-xs font-normal text-muted-foreground pb-2">
                          Meetings
                        </DropdownMenuLabel>
                        {role === 'lecturer' && (
                          <DropdownMenuItem onClick={() => handleCreateMeeting('video')}>
                            <Video className="size-4 mr-2" />
                            <span className="text-xs">Create Meeting</span>
                          </DropdownMenuItem>
                        )}
                        <DropdownMenuItem onClick={() => setIsJoinMeetingOpen(true)}>
                          <Link className="size-4 mr-2" />
                          <span className="text-xs">Join Meeting</span>
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>

                    <input
                      id="wallpaper-upload"
                      type="file"
                      className="hidden"
                      accept="image/*"
                      onChange={handleWallpaperUpload}
                    />
                  </div>
                </>
              )}
            </div>

            {/* Messages Area */}
            <ScrollArea
              className="flex-1 w-full"
              style={{
                overscrollBehaviorY: 'contain',
                WebkitOverflowScrolling: 'touch'
              }}
              viewportRef={scrollViewportRef}
              onScroll={handleScroll}
            >
              <div className="px-2.5 md:px-6 py-4 max-w-5xl mx-auto w-full">
                {loading && !loadingMore ? (
                  <ChatSkeleton />
                ) : (
                  <>
                    {loadingMore && (
                      <div className="flex justify-center py-2 h-8">
                        <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                      </div>
                    )}
                    {groupedMessages.map((group, groupIndex) => (
                      <div key={groupIndex}>
                        <DateSeparator date={group.date} />
                        {group.messages.map((message) => (
                          <MessageBubble
                            key={message.id}
                            message={message}
                            setMessageToDelete={setMessageToDelete}
                            onEdit={editMessage}
                          />
                        ))}
                      </div>
                    ))}
                    {isOtherUserTyping && <TypingIndicator />}
                    <div ref={messagesEndRef} />
                  </>
                )}
              </div>
            </ScrollArea>

            <div className="p-2 md:p-4 bg-white dark:bg-[#111b21] border-t border-slate-200 dark:border-slate-700 pb-[calc(env(safe-area-inset-bottom)+0.25rem)] md:pb-4 shrink-0">
              {selectedFile && (
                <div className="mb-2 p-3 bg-[#1f2c34] rounded-xl flex items-center justify-between animate-in slide-in-from-bottom-2">
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="size-10 rounded-lg bg-emerald-500/20 flex items-center justify-center">
                      <FileText className="size-5 text-emerald-600" />
                    </div>
                    <div className="min-w-0 flex-1">
                      <p className="text-sm font-medium truncate text-slate-200">{selectedFile.name}</p>
                      <p className="text-xs text-slate-400">{formatFileSize(selectedFile.size)}</p>
                    </div>
                  </div>
                  <Button variant="ghost" size="icon" className="size-8 text-slate-400" onClick={clearSelectedFile}>
                    <X className="size-4" />
                  </Button>
                </div>
              )}

              <div className="flex items-center gap-2 max-w-full mx-auto w-full">
                {/* Plus button outside */}
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="size-10 text-emerald-500 hover:bg-emerald-500/10 rounded-full shrink-0"
                    >
                      <Plus className="size-6 transition-transform hover:rotate-90 duration-200" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="start" side="top" sideOffset={12} className="w-56 rounded-2xl p-2 shadow-xl border-slate-700 bg-[#1f2c34]">
                    <DropdownMenuItem onClick={() => fileInputRef.current?.click()} className="flex items-center gap-3 p-3 rounded-xl cursor-pointer focus:bg-emerald-900/30">
                      <div className="size-10 rounded-xl bg-blue-900/30 flex items-center justify-center text-blue-400">
                        <Paperclip className="size-5" />
                      </div>
                      <div className="flex flex-col">
                        <span className="font-semibold text-sm text-slate-200">File</span>
                        <span className="text-[10px] text-slate-400">Document, image, or video</span>
                      </div>
                    </DropdownMenuItem>
                    {role === 'lecturer' && (
                      <DropdownMenuItem onClick={() => setIsPollDialogOpen(true)} className="flex items-center gap-3 p-3 rounded-xl cursor-pointer focus:bg-emerald-900/30">
                        <div className="size-10 rounded-xl bg-emerald-900/30 flex items-center justify-center text-emerald-500">
                          <BarChart2 className="size-5" />
                        </div>
                        <div className="flex flex-col">
                          <span className="font-semibold text-sm text-slate-200">Poll</span>
                          <span className="text-[10px] text-slate-400">Create a class survey</span>
                        </div>
                      </DropdownMenuItem>
                    )}
                  </DropdownMenuContent>
                </DropdownMenu>

                <input
                  type="file"
                  ref={fileInputRef}
                  className="hidden"
                  onChange={handleFileSelect}
                  accept="*"
                />

                {/* Message Pill */}
                <div className="flex-1 flex items-center bg-slate-100 dark:bg-[#2a3942] rounded-full px-4 py-1 gap-2 min-h-[44px] border border-slate-200 dark:border-none">
                  <div className="flex-1 relative flex items-center">
                    {isRecording ? (
                      <div className="flex-1 flex items-center gap-2 h-9">
                        <span className="size-2 bg-red-500 rounded-full animate-pulse shrink-0" />
                        <span className="text-sm font-medium font-mono text-slate-200">{formatTime(recordingTime)}</span>
                        <div className="flex-1 overflow-hidden flex items-center gap-0.5 opacity-40">
                          {[...Array(12)].map((_, i) => (
                            <div key={i} className="w-1 bg-emerald-500 rounded-full h-4 animate-pulse" />
                          ))}
                        </div>
                      </div>
                    ) : (
                      <Input
                        value={messageInput}
                        onChange={(e) => {
                          setMessageInput(e.target.value);
                          if (e.target.value.length % 5 === 0) sendTyping();
                        }}
                        onKeyDown={handleKeyPress}
                        placeholder="Type a message..."
                        className="bg-transparent border-0 focus-visible:ring-0 focus-visible:ring-offset-0 h-10 text-base md:text-sm w-full shadow-none text-slate-900 dark:text-slate-200 placeholder:text-slate-500 dark:placeholder:text-slate-400 px-0"
                      />
                    )}
                  </div>

                  {/* Microphone inside the pill */}
                  <Button
                    variant="ghost"
                    size="icon"
                    className={cn(
                      "size-8 shrink-0 rounded-full",
                      isRecording ? "text-red-500" : "text-slate-500 dark:text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-500"
                    )}
                    onClick={toggleRecording}
                  >
                    <Mic className={cn("size-5", isRecording && "animate-pulse")} />
                  </Button>
                </div>

                {/* Send Button separate circle */}
                <Button
                  size="icon"
                  className={cn(
                    "size-11 rounded-full shrink-0 shadow-lg transition-transform active:scale-90",
                    messageInput.trim() || selectedFile
                      ? "bg-emerald-600 dark:bg-[#00a884] hover:bg-emerald-700 dark:hover:bg-[#008f72] text-white"
                      : "bg-slate-100 dark:bg-[#2a3942] text-slate-400 cursor-not-allowed opacity-80"
                  )}
                  onClick={handleSendMessage}
                  disabled={(!messageInput.trim() && !selectedFile) || isUploading}
                >
                  {isUploading ? <Loader2 className="size-5 animate-spin" /> : <Send className="size-5 ml-0.5" />}
                </Button>
              </div>
            </div>
          </div>
        ) : (

          <div className="hidden md:flex flex-1 flex items-center justify-center bg-slate-100 dark:bg-slate-900">
            <div className="text-center max-w-md">
              <div className="size-24 mx-auto mb-6 rounded-full bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center">
                <MessageSquare className="size-12 text-emerald-500" />
              </div>
              <h3 className="text-xl font-semibold mb-2">Welcome to Messages</h3>
              <p className="text-sm text-slate-500 mb-6">
                Select a conversation from the sidebar or start a new chat to begin messaging.
              </p>
              <Button
                className="bg-emerald-500 hover:bg-emerald-600 text-white gap-2 rounded-xl"
                onClick={() => setIsNewChatOpen(true)}
              >
                <Plus className="size-4" />
                Start New Chat
              </Button>
            </div>
          </div>
        )}


        {/* Delete Confirmation Dialog */}
        <Dialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Delete Conversation</DialogTitle>
              <DialogDescription>
                This will delete the chat only for you. The other person will still have the conversation.
              </DialogDescription>
            </DialogHeader>
            <div className="flex justify-end gap-3 mt-4">
              <Button variant="outline" onClick={() => setShowDeleteDialog(false)}>Cancel</Button>
              <Button variant="destructive" onClick={() => {
                handleDeleteChat();
                setShowDeleteDialog(false);
              }}>Delete</Button>
            </div>
          </DialogContent>
        </Dialog>

        {/* Clear Confirmation Dialog */}
        <Dialog open={showClearDialog} onOpenChange={setShowClearDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Clear Chat History</DialogTitle>
              <DialogDescription>
                This will clear all messages in this viewer for you. The chat will remain in your list.
              </DialogDescription>
            </DialogHeader>
            <div className="flex justify-end gap-3 mt-4">
              <Button variant="outline" onClick={() => setShowClearDialog(false)}>Cancel</Button>
              <Button variant="destructive" onClick={() => {
                handleClearChat();
                setShowClearDialog(false);
              }}>Clear Messages</Button>
            </div>
          </DialogContent>
        </Dialog>
        <Dialog open={!!messageToDelete} onOpenChange={(open) => !open && setMessageToDelete(null)}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Delete Message?</DialogTitle>
              <DialogDescription>
                This message will be permanently deleted. This action cannot be undone.
              </DialogDescription>
            </DialogHeader>
            <div className="flex justify-end gap-2 mt-4">
              <Button variant="outline" onClick={() => setMessageToDelete(null)}>
                Cancel
              </Button>
              <Button variant="destructive" onClick={handleDeleteMessage}>
                <Trash2 className="size-4 mr-2" />
                Delete
              </Button>
            </div>
          </DialogContent>
        </Dialog>

        {/* New Chat Dialog */}
        <Dialog open={isNewChatOpen} onOpenChange={setIsNewChatOpen}>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>{role === 'lecturer' ? "New Message" : "Select a Class"}</DialogTitle>
              <DialogDescription>
                {role === 'lecturer'
                  ? "Select a student to message."
                  : "Choose a class to contact the lecturer."}
              </DialogDescription>
            </DialogHeader>
            <div className="py-4">
              {role === 'lecturer' ? (
                studentsLoading ? (
                  <div className="flex justify-center py-8">
                    <Loader2 className="size-8 animate-spin text-emerald-500" />
                  </div>
                ) : classGroups?.length === 0 ? (
                  <p className="text-center text-slate-500 py-8">No eligible students found.</p>
                ) : (
                  <ScrollArea className="h-[300px]">
                    <div className="space-y-4">
                      {classGroups?.map((group) => (
                        group.students.length > 0 && (
                          <div key={group.class_id}>
                            <h4 className="px-3 mb-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider sticky top-0 bg-white dark:bg-slate-900 z-10 py-1">
                              {group.class_name}
                            </h4>
                            <div className="space-y-1">
                              {group.students.map(student => (
                                <button
                                  key={student.id}
                                  onClick={() => handleStartNewChat(student.id)}
                                  className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-left"
                                >
                                  <Avatar className="size-10">
                                    <AvatarImage src={student.avatar_url || ''} />
                                    <AvatarFallback className="bg-emerald-100 text-emerald-600">
                                      {(student.full_name || 'S').charAt(0)}
                                    </AvatarFallback>
                                  </Avatar>
                                  <div className="flex-1 min-w-0">
                                    <p className="font-medium text-sm">{student.full_name}</p>
                                    <p className="text-xs text-slate-500 truncate">{student.email}</p>
                                  </div>
                                </button>
                              ))}
                            </div>
                          </div>
                        )
                      ))}
                    </div>
                  </ScrollArea>

                )
              ) : (
                classesLoading ? (
                  <div className="flex justify-center py-8">
                    <Loader2 className="size-8 animate-spin text-emerald-500" />
                  </div>
                ) : classes.length === 0 ? (
                  <p className="text-center text-slate-500 py-8">No enrolled classes found.</p>
                ) : (
                  <ScrollArea className="h-[300px]">
                    <div className="space-y-4">
                      {classes.map((cls) => (
                        <div key={cls.id}>
                          <h4 className="px-3 mb-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider sticky top-0 bg-white dark:bg-slate-900 z-10 py-1">
                            {cls.class_name || cls.course_code}
                          </h4>
                          <div className="space-y-1">
                            <button
                              onClick={() => handleStartNewChat(cls.lecturer_id)}
                              className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-left"
                            >
                              <Avatar className="size-10">
                                <AvatarImage src={cls.lecturer_profile_image || ''} />
                                <AvatarFallback className="bg-emerald-100 text-emerald-600">
                                  {(cls.lecturer_name || 'L').charAt(0)}
                                </AvatarFallback>
                              </Avatar>
                              <div className="flex-1 min-w-0">
                                <p className="font-medium text-sm">{cls.lecturer_name || 'Unknown Lecturer'}</p>
                                <p className="text-xs text-slate-500 truncate">Lecturer • {cls.course_code}</p>
                              </div>
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </ScrollArea>
                )
              )}
            </div>
          </DialogContent>
        </Dialog>
        {/* Create Meeting Dialog */}
        <Dialog open={isCreateMeetingOpen} onOpenChange={setIsCreateMeetingOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Meeting Created</DialogTitle>
              <DialogDescription>
                Share this code with others to join the {meetingType} meeting.
              </DialogDescription>
            </DialogHeader>
            <div className="flex flex-col items-center gap-4 py-4">
              <div className="text-3xl font-mono font-bold tracking-widest bg-slate-100 dark:bg-slate-800 px-6 py-2 rounded-lg border border-slate-200 dark:border-slate-700">
                {createdMeetingCode}
              </div>
              <Button
                variant="outline"
                size="sm"
                className="gap-2"
                onClick={() => {
                  navigator.clipboard.writeText(createdMeetingCode);
                  toast.success("Code copied to clipboard");
                }}
              >
                <Copy className="size-4" />
                Copy Code
              </Button>
            </div>
            <div className="flex justify-end gap-3 mt-4">
              <Button variant="outline" onClick={() => setIsCreateMeetingOpen(false)}>Close</Button>
              <Button
                className="bg-emerald-500 hover:bg-emerald-600 text-white"
                onClick={() => startMeetingHandler(createdMeetingCode, meetingType)}
              >
                Start Now
              </Button>
            </div>
          </DialogContent>
        </Dialog>

        {/* Join Meeting Dialog */}
        <Dialog open={isJoinMeetingOpen} onOpenChange={setIsJoinMeetingOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Join Meeting</DialogTitle>
              <DialogDescription>
                Enter the 6-character code to join a meeting.
              </DialogDescription>
            </DialogHeader>
            <div className="py-4">
              <Input
                placeholder="ABC-DEF"
                className="text-center text-2xl font-mono tracking-widest h-14"
                value={joinMeetingCode}
                onChange={(e) => setJoinMeetingCode(e.target.value.toUpperCase())}
                maxLength={7}
              />
            </div>
            <div className="flex justify-end gap-3 mt-4">
              <Button variant="outline" onClick={() => setIsJoinMeetingOpen(false)}>Cancel</Button>
              <Button
                className="bg-emerald-500 hover:bg-emerald-600 text-white"
                disabled={joinMeetingCode.length < 6}
                onClick={() => startMeetingHandler(joinMeetingCode, 'video')}
              >
                Join
              </Button>
            </div>
          </DialogContent>
        </Dialog>

        {selectedConversationId && (
          <ChatPollDialog
            isOpen={isPollDialogOpen}
            onClose={() => setIsPollDialogOpen(false)}
            conversationId={selectedConversationId}
            onSuccess={(pollId, question) => {
              const receiverId = conversations.find(c => c.id === selectedConversationId)?.participant_1 === user?.id
                ? conversations.find(c => c.id === selectedConversationId)?.participant_2
                : conversations.find(c => c.id === selectedConversationId)?.participant_1;

              if (receiverId) {
                sendMessage(receiverId, "📊 " + question, {
                  name: question,
                  url: pollId,
                  type: 'poll'
                });
              }
            }}
          />
        )}

        {/* Chat Settings Dialog */}
        <Dialog open={isSettingsOpen} onOpenChange={setIsSettingsOpen}>
          <DialogContent className="sm:max-w-[425px] rounded-2xl">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <Settings className="size-5 text-emerald-600" />
                Chat Settings
              </DialogTitle>
              <DialogDescription>
                Manage privacy and automation for this conversation.
              </DialogDescription>
            </DialogHeader>
            <div className="py-6 space-y-6">
              <div className="flex items-center justify-between space-x-4 p-4 rounded-xl bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-700">
                <div className="flex-1 space-y-1">
                  <Label htmlFor="auto-delete" className="text-base font-semibold">Auto-Delete Messages</Label>
                  <p className="text-xs text-slate-500 dark:text-slate-400 leading-relaxed">
                    When enabled, messages older than 15 days will be automatically removed from this conversation for you.
                  </p>
                </div>
                <Switch
                  id="auto-delete"
                  checked={(user?.id && selectedConversation?.auto_delete_settings?.[user.id]) || false}
                  onCheckedChange={async (checked) => {
                    try {
                      await toggleAutoDelete(selectedConversationId!, checked);
                      toast.success(checked ? "Auto-delete enabled" : "Auto-delete disabled", {
                        description: checked ? "Messages will be auto-deleted after 15 days." : "Messages will remain permanently."
                      });
                    } catch (err) {
                      toast.error("Failed to update setting");
                    }
                  }}
                />
              </div>
            </div>
          </DialogContent>
        </Dialog>
        <SharedMediaDrawer
          isOpen={isMediaDrawerOpen}
          onOpenChange={setIsMediaDrawerOpen}
          messages={messages}
          otherUserName={selectedConversation?.other_user_name || 'User'}
        />

        <ChatProfilePopup
          isOpen={profilePopupOpen}
          onOpenChange={setProfilePopupOpen}
          userName={popupUserData.name}
          userAvatar={popupUserData.avatar}
          onShowMedia={() => setIsMediaDrawerOpen(true)}
        />
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { BookOpen, Plus, Trash2, Edit2, Save, X, Search, Clock, ChevronRight } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { format } from "date-fns";
import { knowledgeService } from "@/lib/knowledgeService";
import { cn } from "@/lib/utils";

interface Note {
    id: string;
    title: string;
    content: string;
    created_at: string;
    updated_at?: string;
}

export default function Notes() {
    const { user } = useAuth();
    const [notes, setNotes] = useState<Note[]>([]);
    const [loading, setLoading] = useState(true);
    const [isEditing, setIsEditing] = useState<string | null>(null);
    const [newNoteMode, setNewNoteMode] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");

    // Form State
    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    const fetchNotes = async () => {
        if (!user) return;
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('student_notes')
                .select('*')
                .eq('user_id', user.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setNotes(data || []);
        } catch (error: any) {
            console.error("Error fetching notes:", error);
            toast.error("Failed to load notes");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (user) fetchNotes();
    }, [user]);

    const handleSave = async () => {
        if (!user || !title.trim()) return;

        try {
            if (isEditing) {
                const { error: updateError } = await supabase
                    .from('student_notes')
                    .update({ title, content })
                    .eq('id', isEditing);
                if (updateError) throw updateError;
                toast.success("Note updated");

                knowledgeService.upsertKnowledgeNode({
                    type: 'note',
                    sourceId: isEditing,
                    label: title,
                    text: `${title}\n${content}`
                });
            } else {
                const { data, error: insertError } = await supabase
                    .from('student_notes')
                    .insert({ user_id: user.id, title, content })
                    .select();
                if (insertError) throw insertError;
                toast.success("Note created");

                if (data?.[0]) {
                    knowledgeService.upsertKnowledgeNode({
                        type: 'note',
                        sourceId: data[0].id,
                        label: title,
                        text: `${title}\n${content}`
                    });
                }
            }

            resetForm();
            fetchNotes();
        } catch (error) {
            console.error("Error saving note:", error);
            toast.error("Failed to save note");
        }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const { error } = await supabase.from('student_notes').delete().eq('id', id);
        if (error) {
            toast.error("Failed to delete note");
        } else {
            toast.success("Note deleted");
            setNotes(prev => prev.filter(n => n.id !== id));
            knowledgeService.deleteKnowledgeNode(id);
        }
    };

    const startEdit = (note: Note) => {
        setIsEditing(note.id);
        setTitle(note.title);
        setContent(note.content);
        setNewNoteMode(false);
    };

    const resetForm = () => {
        setIsEditing(null);
        setNewNoteMode(false);
        setTitle("");
        setContent("");
    };

    const filteredNotes = notes.filter(n =>
        n.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        n.content.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <DashboardLayout fullHeight>
            <div className="flex flex-col h-[100dvh] lg:h-[calc(100dvh-64px)] bg-slate-50/50 dark:bg-transparent overflow-hidden pt-[var(--safe-top)]">
                {/* Header Section */}
                <div className="flex flex-col sm:flex-row sm:items-center justify-between p-4 sm:p-6 gap-4 border-b border-border/50 bg-white dark:bg-slate-900/50 backdrop-blur-sm">
                    <div className="flex items-center gap-3">
                        <div className="size-10 sm:size-12 rounded-2xl bg-indigo-500/10 flex items-center justify-center border border-indigo-500/20">
                            <BookOpen className="size-5 sm:size-6 text-indigo-500" />
                        </div>
                        <div>
                            <h1 className="text-xl sm:text-2xl font-black tracking-tight">My Notes</h1>
                            <p className="text-xs text-muted-foreground font-bold uppercase tracking-widest">{notes.length} Total Notes</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <div className="relative flex-1 sm:w-64 max-w-sm">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
                            <Input
                                placeholder="Search notes..."
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                                className="pl-9 h-11 border-border/50 bg-white/50 dark:bg-slate-800/50 rounded-xl focus-visible:ring-indigo-500/20"
                            />
                        </div>
                        <Button
                            onClick={() => setNewNoteMode(true)}
                            className="h-11 px-6 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-500/20 gap-2 shrink-0"
                        >
                            <Plus className="size-5" />
                            <span className="hidden sm:inline">New Note</span>
                        </Button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden">
                    {/* Notes Grid/List */}
                    {(newNoteMode || isEditing) ? (
                        <div className="flex-1 flex flex-col p-4 sm:p-8 animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-5xl mx-auto w-full">
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-2xl font-bold flex items-center gap-3">
                                    <Edit2 className="size-6 text-indigo-500" />
                                    {isEditing ? 'Editing Note' : 'Create New Note'}
                                </h2>
                                <Button variant="ghost" onClick={resetForm} className="rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800">
                                    <X className="mr-2 size-4" /> Cancel
                                </Button>
                            </div>

                            <div className="space-y-6 flex-1 flex flex-col">
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">Title</label>
                                    <Input
                                        placeholder="Note Title"
                                        value={title}
                                        onChange={e => setTitle(e.target.value)}
                                        className="text-xl sm:text-2xl font-black h-16 rounded-2xl border-border/50 bg-white dark:bg-slate-900 focus-visible:ring-indigo-500/20 px-6"
                                    />
                                </div>

                                <div className="space-y-2 flex-1 flex flex-col min-h-0">
                                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">Content</label>
                                    <Textarea
                                        placeholder="Start typing your thoughts here..."
                                        value={content}
                                        onChange={e => setContent(e.target.value)}
                                        className="flex-1 resize-none rounded-2xl border-border/50 bg-white dark:bg-slate-900 p-6 text-lg focus-visible:ring-indigo-500/20 leading-relaxed overflow-y-auto"
                                    />
                                </div>

                                <div className="flex justify-end pt-4 gap-4 pb-4">
                                    <Button
                                        onClick={handleSave}
                                        disabled={!title.trim()}
                                        size="lg"
                                        className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-xl shadow-indigo-600/30 font-black rounded-2xl px-12 h-14 text-lg"
                                    >
                                        <Save className="h-5 w-5 mr-3" /> Save Changes
                                    </Button>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <ScrollArea className="flex-1 px-4 sm:px-8 py-6">
                            {loading ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in duration-500">
                                    {[1, 2, 3, 4, 5, 6].map(i => (
                                        <div key={i} className="bg-white dark:bg-slate-900 border border-border/50 rounded-3xl p-6 space-y-4">
                                            <div className="space-y-2">
                                                <Skeleton className="h-4 w-24 rounded-lg" />
                                                <Skeleton className="h-7 w-3/4 rounded-lg" />
                                            </div>
                                            <div className="space-y-2">
                                                <Skeleton className="h-4 w-full rounded-md" />
                                                <Skeleton className="h-4 w-full rounded-md" />
                                                <Skeleton className="h-4 w-[60%] rounded-md" />
                                            </div>
                                            <div className="pt-4 border-t border-border/10 flex justify-between items-center">
                                                <Skeleton className="h-3 w-20 rounded-md" />
                                                <Skeleton className="size-4 rounded-full" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : filteredNotes.length > 0 ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-12">
                                    {filteredNotes.map(note => (
                                        <div
                                            key={note.id}
                                            onClick={() => startEdit(note)}
                                            className="group bg-white dark:bg-slate-900 border border-border/50 rounded-3xl p-6 hover:shadow-2xl hover:shadow-indigo-500/10 hover:border-indigo-500/30 transition-all duration-300 cursor-pointer flex flex-col relative overflow-hidden active:scale-[0.98]"
                                        >
                                            <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    onClick={(e) => handleDelete(note.id, e)}
                                                    className="size-10 rounded-xl bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white transition-all shadow-sm"
                                                >
                                                    <Trash2 className="size-4" />
                                                </Button>
                                            </div>

                                            <div className="mb-4">
                                                <div className="flex items-center gap-2 text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-1.5 opacity-60">
                                                    <Clock className="size-3" />
                                                    {format(new Date(note.created_at), "MMM d, yyyy")}
                                                </div>
                                                <h3 className="text-xl font-black text-slate-900 dark:text-white line-clamp-1 group-hover:text-indigo-500 transition-colors">
                                                    {note.title}
                                                </h3>
                                            </div>

                                            <p className="text-slate-500 dark:text-slate-400 text-sm leading-relaxed line-clamp-4 flex-1">
                                                {note.content || "Empty Note"}
                                            </p>

                                            <div className="mt-6 pt-4 border-t border-border/10 flex items-center justify-between text-indigo-500">
                                                <span className="text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all transform translate-x-[-10px] group-hover:translate-x-0">View Details</span>
                                                <ChevronRight className="size-4 group-hover:translate-x-1 transition-transform" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center py-24 text-center">
                                    <div className="size-20 bg-indigo-500/10 rounded-[40px] flex items-center justify-center mb-6">
                                        <BookOpen className="size-10 text-indigo-500/40" />
                                    </div>
                                    <h3 className="text-2xl font-black text-slate-400">No notes found</h3>
                                    <p className="text-slate-500 max-w-xs mx-auto mt-2 mb-8 font-medium">Capture your thoughts, ideas, and lecture highlights in one place.</p>
                                    <Button
                                        onClick={() => setNewNoteMode(true)}
                                        className="bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl px-8 h-12"
                                    >
                                        <Plus className="size-5 mr-2" /> Start Writing
                                    </Button>
                                </div>
                            )}
                        </ScrollArea>
                    )}
                </div>
            </div>
        </DashboardLayout>
    );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Bell,
  BookOpen,
  FileText,
  MessageSquare,
  Calendar,
  CheckCircle,
  Info,
  Trash2,
  Check,
  Settings,
  MoreHorizontal,
  Loader2,
  Clock,
  GraduationCap,
} from "lucide-react";
import { cn } from "@/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { useNotifications } from "@/hooks/useNotifications";
import { useAccessRequests } from "@/hooks/useAccessRequests";
import { AccessRequestCard } from "@/components/student/AccessRequestCard";
import { JoinRequestModal } from "@/components/student/JoinRequestModal";
import { useStudentOnboarding } from "@/hooks/useStudentOnboarding";
import { toast } from "sonner";
import { NotificationSkeleton } from "@/components/skeletons/NotificationSkeleton";

type NotificationType = 'assignment' | 'schedule' | 'message' | 'grade' | 'announcement' | 'general' | 'access_request';

interface NotificationData {
  id: string;
  user_id?: string;
  title: string;
  message: string;
  type: string;
  related_id?: string | null;
  class_id?: string | null;
  action_type?: string | null;
  is_read: boolean;
  created_at: string;
  link?: string;
  metadata?: any;
}

const getNotificationIcon = (type: string) => {
  switch (type) {
    case "assignment":
      return FileText;
    case "course":
      return BookOpen;
    case "message":
      return MessageSquare;
    case "announcement":
      return Bell;
    case "grade":
      return CheckCircle;
    case "schedule":
      return Calendar;
    case "access_request":
      return GraduationCap;
    default:
      return Info;
  }
};

const getNotificationColor = (type: string) => {
  switch (type) {
    case "assignment":
      return "bg-blue-500";
    case "course":
      return "bg-purple-500";
    case "message":
      return "bg-green-500";
    case "announcement":
      return "bg-orange-500";
    case "grade":
      return "bg-emerald-500";
    case "schedule":
      return "bg-pink-500";
    case "access_request":
      return "bg-indigo-500";
    default:
      return "bg-gray-500";
  }
};

export default function Notifications() {
  const navigate = useNavigate();
  const { notifications, unreadCount, loading, markAsRead, markAllAsRead, clearAllNotifications } = useNotifications();
  const { getMyAccessRequests } = useAccessRequests();
  const {
    pendingInvitations,
    showModal,
    dismissModal,
    refreshInvitations,
    reopenModalForRequest,
    markRequestAsHandled
  } = useStudentOnboarding();
  const [activeTab, setActiveTab] = useState("all");
  const [selectedNotification, setSelectedNotification] = useState<NotificationData | null>(null);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [accessRequests, setAccessRequests] = useState<any[]>([]);
  const [loadingRequests, setLoadingRequests] = useState(true);

  useEffect(() => {
    loadAccessRequests();
  }, []);

  const loadAccessRequests = async () => {
    try {
      setLoadingRequests(true);
      const requests = await getMyAccessRequests();
      setAccessRequests(requests || []);
    } catch (error) {
      console.error("Error loading access requests:", error);
    } finally {
      setLoadingRequests(false);
    }
  };

  const handleClearAll = async () => {
    await clearAllNotifications();
    setShowClearConfirm(false);
    toast.success("All notifications cleared");
  };

  const filteredNotifications = notifications.filter((notification) => {
    if (activeTab === "all") return true;
    if (activeTab === "unread") return !notification.is_read;
    if (activeTab === "access_requests") return notification.type === "access_request";
    return notification.type === activeTab;
  });

  if (loading && loadingRequests) {
    return (
      <DashboardLayout>
        <NotificationSkeleton />
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold">Notifications</h1>
              {unreadCount > 0 && (
                <Badge variant="default">{unreadCount} new</Badge>
              )}
            </div>
            <p className="text-muted-foreground">
              Stay updated with your courses, assignments, and messages
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" onClick={markAllAsRead} disabled={unreadCount === 0}>
              <Check className="size-4 mr-2" />
              Mark all as read
            </Button>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="icon">
                  <MoreHorizontal className="size-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem
                  onClick={() => setShowClearConfirm(true)}
                  disabled={notifications.length === 0}
                >
                  <Trash2 className="size-4 mr-2" />
                  Clear all notifications
                </DropdownMenuItem>
                <DropdownMenuItem onClick={() => navigate('/profile?tab=notifications')}>
                  <Settings className="size-4 mr-2" />
                  Notification settings
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>

        {/* Access Requests Section */}
        {accessRequests.length > 0 && (
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <GraduationCap className="size-5 text-primary" />
              <h2 className="text-lg font-semibold">Pending Class Invitations</h2>
              <Badge variant="secondary">{accessRequests.length}</Badge>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
              {accessRequests.map((request) => (
                <AccessRequestCard
                  key={request.id}
                  request={request}
                  onRespond={loadAccessRequests}
                />
              ))}
            </div>
          </div>
        )}

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="w-full justify-start overflow-x-auto">
            <TabsTrigger value="all" className="gap-2">
              All
              <Badge variant="secondary" className="ml-1">{notifications.length}</Badge>
            </TabsTrigger>
            <TabsTrigger value="unread" className="gap-2">
              Unread
              {unreadCount > 0 && <Badge className="ml-1">{unreadCount}</Badge>}
            </TabsTrigger>
            <TabsTrigger value="access_requests">Class Invitations</TabsTrigger>
            <TabsTrigger value="assignment">Assignments</TabsTrigger>
            <TabsTrigger value="course">Courses</TabsTrigger>
            <TabsTrigger value="message">Messages</TabsTrigger>
            <TabsTrigger value="announcement">Announcements</TabsTrigger>
          </TabsList>

          <TabsContent value={activeTab} className="mt-4">
            {filteredNotifications.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-16 text-center bg-surface rounded-xl border border-border">
                <div className="size-16 rounded-full bg-secondary flex items-center justify-center mb-4">
                  <Bell className="size-8 text-muted-foreground" />
                </div>
                <h3 className="text-lg font-semibold">No notifications</h3>
                <p className="text-muted-foreground text-sm mt-1">
                  {activeTab === "unread"
                    ? "You're all caught up!"
                    : "You don't have any notifications yet."}
                </p>
              </div>
            ) : (
              <ScrollArea className="h-[calc(100vh-24rem)]">
                <div className="space-y-2">
                  {filteredNotifications.map((notification) => {
                    const Icon = getNotificationIcon(notification.type);
                    return (
                      <div
                        key={notification.id}
                        className={cn(
                          "flex items-start gap-4 p-4 rounded-lg border transition-all hover:bg-secondary/50 cursor-pointer group",
                          notification.is_read
                            ? "bg-surface border-border"
                            : "bg-primary/5 border-primary/20"
                        )}
                        onClick={() => {
                          // Handle access_request notifications differently
                          if (notification.type === 'access_request' && notification.related_id) {
                            // Reopen modal for this specific request
                            reopenModalForRequest(notification.related_id);
                            // Mark as read
                            if (!notification.is_read) {
                              markAsRead(notification.id);
                            }
                          } else {
                            setSelectedNotification(notification);
                            if (!notification.is_read) {
                              markAsRead(notification.id);
                            }
                          }
                        }}
                      >
                        {/* Icon */}
                        <div
                          className={cn(
                            "size-10 rounded-full flex items-center justify-center shrink-0 text-white",
                            getNotificationColor(notification.type)
                          )}
                        >
                          <Icon className="size-5" />
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                          <div className="flex items-start justify-between gap-2">
                            <div>
                              <div className="flex items-center gap-2">
                                <h4
                                  className={cn(
                                    "font-medium",
                                    !notification.is_read && "text-foreground"
                                  )}
                                >
                                  {notification.title}
                                </h4>
                                {!notification.is_read && (
                                  <span className="size-2 rounded-full bg-primary shrink-0" />
                                )}
                              </div>
                              <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                                {notification.message}
                              </p>
                              <p className="text-xs text-muted-foreground mt-2">
                                {new Date(notification.created_at).toLocaleString()}
                              </p>
                            </div>
                          </div>
                        </div>

                        {/* Actions */}
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          {!notification.is_read && (
                            <Button
                              variant="ghost"
                              size="icon"
                              className="size-8"
                              onClick={(e) => {
                                e.stopPropagation();
                                markAsRead(notification.id);
                              }}
                            >
                              <Check className="size-4" />
                            </Button>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </ScrollArea>
            )}
          </TabsContent>
        </Tabs>

        {/* Notification Detail Modal */}
        <Dialog open={!!selectedNotification} onOpenChange={(open) => !open && setSelectedNotification(null)}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-3">
                {selectedNotification && (() => {
                  const Icon = getNotificationIcon(selectedNotification.type);
                  return (
                    <>
                      <div className={cn(
                        "size-10 rounded-full flex items-center justify-center text-white",
                        getNotificationColor(selectedNotification.type)
                      )}>
                        <Icon className="size-5" />
                      </div>
                      <span>{selectedNotification.title}</span>
                    </>
                  );
                })()}
              </DialogTitle>
            </DialogHeader>

            {selectedNotification && (
              <div className="space-y-4">
                {/* Type Badge */}
                <div>
                  <Badge variant="outline" className="capitalize">
                    {selectedNotification.type.replace('_', ' ')}
                  </Badge>
                </div>

                {/* Full Message */}
                <div className="bg-muted/50 rounded-lg p-4">
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">
                    {selectedNotification.message}
                  </p>
                </div>

                {/* Timestamp */}
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <Clock className="size-4" />
                  <span>
                    {new Date(selectedNotification.created_at).toLocaleString('en-US', {
                      weekday: 'long',
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </span>
                </div>

                {/* Actions */}
                <div className="flex justify-end gap-2 pt-4 border-t">
                  <Button variant="outline" onClick={() => setSelectedNotification(null)}>
                    Close
                  </Button>
                  <Button onClick={() => {
                    const n = selectedNotification;
                    if (!n) return;

                    let targetUrl = '/notifications';

                    switch (n.type) {
                      case 'announcement':
                        // Class feed announcements
                        targetUrl = '/class-feed';
                        break;
                      case 'message':
                        targetUrl = n.related_id ? `/messages?conversation=${n.related_id}` : '/messages';
                        break;
                      case 'assignment':
                        targetUrl = '/student/assignments';
                        break;
                      case 'grade':
                        targetUrl = '/student/assignments';
                        break;
                      case 'schedule':
                        targetUrl = '/schedule';
                        break;
                      case 'access_request':
                        targetUrl = '/notifications';
                        break;
                      default:
                        targetUrl = '/notifications';
                    }

                    // Handle submission notifications for lecturers  
                    if (n.action_type === 'submitted' && n.class_id && n.related_id) {
                      targetUrl = `/lecturer/assignments/${n.class_id}/${n.related_id}/submissions`;
                    }
                    if (n.action_type === 'quiz_submitted' && n.class_id && n.related_id) {
                      targetUrl = `/lecturer/quizzes/${n.class_id}/${n.related_id}/results`;
                    }

                    setSelectedNotification(null);
                    navigate(targetUrl);
                  }}>
                    View Details
                  </Button>
                </div>
              </div>
            )}
          </DialogContent>
        </Dialog>

        {/* Clear All Confirmation Dialog */}
        <Dialog open={showClearConfirm} onOpenChange={setShowClearConfirm}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Clear All Notifications?</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <p className="text-sm text-muted-foreground">
                This will permanently delete all {notifications.length} notification{notifications.length !== 1 ? 's' : ''}.
                This action cannot be undone.
              </p>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setShowClearConfirm(false)}>
                  Cancel
                </Button>
                <Button variant="destructive" onClick={handleClearAll}>
                  <Trash2 className="size-4 mr-2" />
                  Clear All
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* Join Request Modal */}
        <JoinRequestModal
          open={showModal}
          onOpenChange={dismissModal}
          pendingInvitations={pendingInvitations}
          onRequestHandled={refreshInvitations}
          onRequestMarkedAsHandled={markRequestAsHandled}
        />
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { useAuth, Profile as ProfileType } from "@/contexts/AuthContext";
import { useTheme } from "@/contexts/ThemeContext"; // Added for theme management
import { ThemeSelector } from "@/components/theme/ThemeSelector";
import { LanguageSelector } from "@/components/language/LanguageSelector";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  User,
  GraduationCap,
  Shield,
  Bell,
  Settings,
  Mail,
  Phone,
  Calendar,
  CheckCircle,
  Camera,
  Save,
  BookOpen,
  Award,
  Clock,
  Eye,
  EyeOff,
  Lock,
  Smartphone,
  Globe,
  Palette,
  Loader2,
  Upload,
  Trash2,
  QrCode,
  Share2,
  Linkedin,
  Github,
  Twitter,
  Copy,
  Link as LinkIcon,
  ExternalLink,
  Download,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { uploadToCloudinary } from "@/lib/cloudinary";
import { ProfileSkeleton } from "@/components/skeletons/ProfileSkeleton";
import { ProfileNotificationSettings } from "@/components/ProfileNotificationSettings";
import SEO from "@/components/SEO";

const profileTabs = [
  { id: "personal", label: "Personal Info", icon: User },
  { id: "academic", label: "Academic Details", icon: GraduationCap },
  { id: "social", label: "Social Links", icon: Share2 },
  { id: "security", label: "Security", icon: Shield },
  { id: "notifications", label: "Notifications", icon: Bell },
  { id: "preferences", label: "Preferences", icon: Settings },
];

export default function Profile() {
  const { user, profile, isAuthenticated, isLoading: authLoading, updateProfile, role } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState("personal");
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isUploadingImage, setIsUploadingImage] = useState(false);
  const [isUploadingBanner, setIsUploadingBanner] = useState(false);
  const [showPublicProfile, setShowPublicProfile] = useState(false);
  const [showQRCode, setShowQRCode] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const bannerInputRef = useRef<HTMLInputElement>(null);

  // Form state
  const [formData, setFormData] = useState({
    full_name: "",
    email: "",
    phone: "",
    date_of_birth: "",
    bio: "",
    street: "",
    city: "",
    state: "",
    zip_code: "",
    country: "United States",
    // Academic
    student_id: "",
    program: "",
    year: "",
    department: "",
    gpa: "",
    credits_completed: "",
    credits_required: "",
    advisor: "",
    enrollment_date: "",
    expected_graduation: "",
    // Notifications
    notifications_enabled: true,
    // Preferences
    language: "en",
    timezone: "America/New_York",
    theme: "system",
    batch: "",
    hod_name: "",
    // Social
    linkedin_url: "",
    github_url: "",
    twitter_url: "",
    portfolio_url: "",
  });

  // Password change state
  const [passwordData, setPasswordData] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });
  const [showPasswords, setShowPasswords] = useState({
    current: false,
    new: false,
    confirm: false,
  });

  useEffect(() => {
    if (profile) {
      setFormData({
        full_name: profile.full_name || "",
        email: profile.email || "",
        phone: profile.phone || "",
        date_of_birth: profile.date_of_birth || "",
        bio: profile.bio || "",
        street: profile.street || "",
        city: profile.city || "",
        state: profile.state || "",
        zip_code: profile.zip_code || "",
        country: profile.country || "United States",
        student_id: profile.student_id || "",
        program: profile.program || "",
        year: profile.year || "",
        department: profile.department || "",
        gpa: profile.gpa?.toString() || "",
        credits_completed: profile.credits_completed?.toString() || "",
        credits_required: profile.credits_required?.toString() || "",
        advisor: profile.advisor || "",
        enrollment_date: profile.enrollment_date || "",
        expected_graduation: profile.expected_graduation || "",
        notifications_enabled: profile.notifications_enabled ?? true,
        language: profile.language || "en",
        timezone: profile.timezone || "America/New_York",
        theme: profile.theme || "system",
        batch: profile.batch || "",
        hod_name: profile.hod_name || "",
        linkedin_url: profile.linkedin_url || "",
        github_url: profile.github_url || "",
        twitter_url: profile.twitter_url || "",
        portfolio_url: profile.portfolio_url || "",
      });
    }
  }, [profile]);

  // Redirect if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      navigate("/login");
    }
  }, [authLoading, isAuthenticated, navigate]);

  const handleImageUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      toast.error('Please select an image file');
      return;
    }

    // Validate file size (max 10MB)
    if (file.size > 10 * 1024 * 1024) {
      toast.error('Image size should be less than 10MB');
      return;
    }

    setIsUploadingImage(true);

    try {
      // Upload to Cloudinary
      const uploaded = await uploadToCloudinary(file);
      console.log('Image uploaded to Cloudinary:', uploaded.url);

      const result = await updateProfile({ avatar_url: uploaded.url } as Partial<ProfileType>);

      if (result.success) {
        toast.success('Profile image updated successfully!');
      } else {
        throw new Error(result.error || 'Failed to update profile');
      }

      setIsUploadingImage(false);

      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }

    } catch (error: unknown) {
      console.error('Error uploading image:', error);
      const errorMessage = error instanceof Error ? error.message : 'Failed to upload image';
      toast.error(errorMessage);
      setIsUploadingImage(false);

      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const handleBannerUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      toast.error('Please select an image file');
      return;
    }

    // Validate file size (max 10MB)
    if (file.size > 10 * 1024 * 1024) {
      toast.error('Banner size should be less than 10MB');
      return;
    }

    setIsUploadingBanner(true);

    try {
      // Upload to Cloudinary
      const uploaded = await uploadToCloudinary(file);
      const result = await updateProfile({ cover_url: uploaded.url } as Partial<ProfileType>);

      if (result.success) {
        toast.success('Cover photo updated successfully!');
      } else {
        throw new Error(result.error || 'Failed to update cover photo');
      }

      setIsUploadingBanner(false);

      if (bannerInputRef.current) {
        bannerInputRef.current.value = '';
      }

    } catch (error: unknown) {
      console.error('Error uploading banner:', error);
      const errorMessage = error instanceof Error ? error.message : 'Failed to upload banner';
      toast.error(errorMessage);
      setIsUploadingBanner(false);

      if (bannerInputRef.current) {
        bannerInputRef.current.value = '';
      }
    }
  };

  const calculateProfileCompleteness = () => {
    if (!profile) return 0;

    const fieldsToTrack = [
      'full_name', 'email', 'phone', 'date_of_birth', 'bio',
      'street', 'city', 'state', 'zip_code', 'country',
      'avatar_url', 'cover_url', 'student_id', 'program',
      'linkedin_url', 'github_url', 'twitter_url', 'portfolio_url'
    ];

    const completedFields = fieldsToTrack.filter(field => {
      const value = (profile as any)[field];
      return value && value !== "" && value !== null;
    });

    return Math.round((completedFields.length / fieldsToTrack.length) * 100);
  };

  const completeness = calculateProfileCompleteness();

  if (authLoading) {
    return (
      <DashboardLayout>
        <ProfileSkeleton />
      </DashboardLayout>
    );
  }

  if (!isAuthenticated) {
    return null;
  }

  const handleInputChange = async (field: string, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));

    // Auto-save notification preferences
    if (typeof value === 'boolean') {
      const result = await updateProfile({ [field]: value } as Partial<ProfileType>);
      if (result.success) {
        toast.success("Preference saved");
      } else {
        toast.error("Failed to save preference");
        // Revert on failure
        setFormData((prev) => ({ ...prev, [field]: !value }));
      }
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    const result = await updateProfile({
      full_name: formData.full_name,
      email: formData.email,
      phone: formData.phone,
      date_of_birth: formData.date_of_birth || null,
      bio: formData.bio,
      street: formData.street,
      city: formData.city,
      state: formData.state,
      zip_code: formData.zip_code,
      country: formData.country,
      student_id: formData.student_id,
      program: formData.program,
      year: formData.year,
      department: formData.department,
      gpa: formData.gpa ? parseFloat(formData.gpa) : null,
      credits_completed: formData.credits_completed ? parseInt(formData.credits_completed) : null,
      credits_required: formData.credits_required ? parseInt(formData.credits_required) : null,
      advisor: formData.advisor,
      enrollment_date: formData.enrollment_date || null,
      expected_graduation: formData.expected_graduation || null,
      notifications_enabled: formData.notifications_enabled,
      language: formData.language,
      timezone: formData.timezone,
      theme: formData.theme,
      batch: formData.batch,
      hod_name: formData.hod_name,
      linkedin_url: formData.linkedin_url,
      github_url: formData.github_url,
      twitter_url: formData.twitter_url,
      portfolio_url: formData.portfolio_url,
    } as Partial<ProfileType>);

    if (result.success) {
      toast.success("Profile updated successfully!");
      setIsEditing(false);
    } else {
      toast.error(result.error || "Failed to update profile");
    }
    setIsSaving(false);
  };

  const handleShare = async () => {
    if (!profile?.user_id) {
      toast.error("Profile ID not found. Please refresh and try again.");
      return;
    }
    const profileUrl = `https://eduspaceacademy.online/p/${profile.user_id}`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `${formData.full_name}'s Profile | EduSpace`,
          text: `Check out my academic profile on EduSpace!`,
          url: profileUrl,
        });
        toast.success("Shared successfully");
      } catch (err) {
        if ((err as Error).name !== 'AbortError') {
          console.error('Error sharing:', err);
          copyToClipboard(profileUrl);
        }
      }
    } else {
      copyToClipboard(profileUrl);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text).then(() => {
      toast.success("Link copied to clipboard");
    }).catch((err) => {
      console.error('Could not copy text: ', err);
      toast.error("Failed to copy link");
    });
  };

  const handlePasswordChange = async () => {
    if (passwordData.newPassword !== passwordData.confirmPassword) {
      toast.error("New passwords do not match");
      return;
    }
    if (passwordData.newPassword.length < 6) {
      toast.error("Password must be at least 6 characters");
      return;
    }

    setIsSaving(true);

    try {
      // Update password using Supabase auth
      const { error } = await supabase.auth.updateUser({
        password: passwordData.newPassword
      });

      if (error) {
        toast.error(error.message || "Failed to update password");
      } else {
        toast.success("Password updated successfully!");
        setPasswordData({ currentPassword: "", newPassword: "", confirmPassword: "" });
      }
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "An unexpected error occurred";
      toast.error(errorMessage);
    } finally {
      setIsSaving(false);
    }
  };

  const bioMaxLength = 250;
  const bioRemaining = bioMaxLength - (formData.bio?.length || 0);
  const initials = formData.full_name?.split(" ").map((n) => n[0]).join("") || "U";

  return (
    <DashboardLayout>
      <SEO
        title="Your Profile"
        description="Manage your academic and personal information, notification preferences, and account settings."
      />
      <div className="flex flex-col xl:flex-row gap-8 w-full animate-in fade-in duration-500 pb-24 xl:pb-0">
        {/* Left Sidebar - Profile Navigation (Desktop Only) */}
        <div className="hidden xl:block w-80 shrink-0">
          <div className="bg-surface border border-border rounded-xl p-4 sticky top-4">
            {/* User Quick Info */}
            <div className="flex items-center gap-3 pb-4 border-b border-border mb-4">
              <Avatar className="size-12">
                <AvatarImage src={profile?.avatar_url || ""} />
                <AvatarFallback className="bg-primary/10 text-primary font-semibold">
                  {initials}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 min-w-0">
                <h3 className="font-semibold text-foreground truncate">{formData.full_name || "User"}</h3>
                <p className="text-xs text-muted-foreground">
                  {role === "lecturer" ? `Lecturer ID: ${formData.student_id || "N/A"}` : `Student ID: ${formData.student_id || "N/A"}`}
                </p>
              </div>
            </div>

            {/* Verified Badge */}
            {profile?.verified && (
              <div className="flex items-center gap-2 text-sm text-green-600 mb-4">
                <CheckCircle className="size-4" />
                <span>Account Verified</span>
              </div>
            )}

            {/* Navigation Tabs */}
            <nav className="flex flex-col gap-1">
              {profileTabs.map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={cn(
                    "flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all text-left",
                    activeTab === tab.id
                      ? "bg-primary/10 text-primary"
                      : "text-muted-foreground hover:bg-secondary hover:text-foreground"
                  )}
                >
                  <tab.icon className="size-5" />
                  <span>{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 space-y-6">
          {/* Profile Header Card */}
          <div className="bg-surface border border-border rounded-xl overflow-hidden">
            {/* Banner Section */}
            <div className="relative h-32 sm:h-48 w-full group">
              {profile?.cover_url ? (
                <img
                  src={profile.cover_url}
                  alt="Profile Banner"
                  className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                />
              ) : (
                <div className="w-full h-full bg-gradient-to-r from-primary/20 via-primary/10 to-surface" />
              )}

              {/* Banner Upload Button */}
              <div className="absolute top-4 right-4">
                <input
                  ref={bannerInputRef}
                  type="file"
                  accept="image/*"
                  onChange={handleBannerUpload}
                  className="hidden"
                />
                <Button
                  variant="secondary"
                  size="sm"
                  onClick={() => bannerInputRef.current?.click()}
                  disabled={isUploadingBanner}
                  className="bg-black/20 hover:bg-black/40 text-white border-white/20 backdrop-blur-md transition-all opacity-0 group-hover:opacity-100"
                >
                  {isUploadingBanner ? (
                    <Loader2 className="size-4 animate-spin mr-2" />
                  ) : (
                    <Camera className="size-4 mr-2" />
                  )}
                  {profile?.cover_url ? "Change Cover" : "Add Cover"}
                </Button>
              </div>
            </div>

            <div className="p-4 sm:p-6 sm:pt-0 relative z-10">
              <div className="flex flex-col sm:flex-row items-center sm:items-end gap-6 text-center sm:text-left">
                {/* Avatar with Edit */}
                <div className="relative shrink-0 -mt-12 sm:-mt-16">
                  <Avatar className="size-24 sm:size-32 border-4 border-surface shadow-xl">
                    <AvatarImage src={profile?.avatar_url || ""} />
                    <AvatarFallback className="bg-primary/10 text-primary text-2xl font-semibold">
                      {initials}
                    </AvatarFallback>
                  </Avatar>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="hidden"
                  />
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    disabled={isUploadingImage}
                    className="absolute bottom-2 right-2 size-8 bg-primary text-primary-foreground rounded-full flex items-center justify-center shadow-lg hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed border-2 border-surface"
                    title="Upload profile image"
                  >
                    {isUploadingImage ? (
                      <Loader2 className="size-4 animate-spin" />
                    ) : (
                      <Camera className="size-4" />
                    )}
                  </button>
                </div>

                {/* User Info & Actions */}
                <div className="flex-1 w-full pt-2 flex flex-col items-center sm:items-start min-w-0">
                  <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 w-full">
                    <div className="min-w-0 flex-1">
                      <h1 className="text-2xl sm:text-3xl font-bold text-foreground flex items-center justify-center sm:justify-start gap-2 truncate">
                        {formData.full_name || "User"}
                        {profile?.verified && (
                          <CheckCircle className="size-5 text-primary fill-primary/10 shrink-0" />
                        )}
                      </h1>
                      <p className="text-muted-foreground truncate">
                        {formData.program || "No program set"} {formData.year && `• ${formData.year}`}
                      </p>
                    </div>

                    <div className="flex items-center gap-2 w-full sm:w-auto overflow-x-auto no-scrollbar pb-1 sm:pb-0 shrink-0">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setShowPublicProfile(true)}
                        className="bg-surface/50 backdrop-blur-sm whitespace-nowrap shrink-0 border-border/50"
                      >
                        <Eye className="size-4 mr-2" />
                        Public Profile
                      </Button>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => setShowQRCode(true)}
                        className="h-9 w-9 rounded-full text-muted-foreground hover:text-primary hover:bg-primary/10 shrink-0"
                        title="Digital Business Card"
                      >
                        <QrCode className="size-4" />
                      </Button>
                      <Button
                        size="icon"
                        variant="ghost"
                        className="h-9 w-9 rounded-full text-muted-foreground hover:text-primary hover:bg-primary/10 shrink-0"
                        onClick={() => handleShare()}
                      >
                        <Share2 className="size-4" />
                      </Button>
                    </div>
                  </div>

                  {/* Profile Completeness Tracker */}
                  <div className="mt-4 sm:mt-2 space-y-1.5 w-full sm:max-w-md">
                    <div className="flex items-center justify-between text-[10px] sm:text-[11px]">
                      <span className="text-muted-foreground font-medium uppercase tracking-widest">Completeness</span>
                      <span className="text-primary font-black">{completeness}%</span>
                    </div>
                    <div className="h-2 w-full bg-secondary/50 rounded-full overflow-hidden shadow-inner border border-border/30">
                      <div
                        className="h-full bg-gradient-to-r from-primary/80 to-primary transition-all duration-1000 ease-out rounded-full shadow-[0_0_8px_rgba(var(--primary),0.3)]"
                        style={{ width: `${completeness}%` }}
                      />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Personal Information Section */}
          {activeTab === "personal" && (
            <>
              <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-lg font-semibold text-foreground">Personal Information</h2>
                  <button
                    onClick={() => setIsEditing(!isEditing)}
                    className="text-sm font-medium text-primary hover:underline"
                  >
                    {isEditing ? "Cancel" : "Edit Info"}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Full Name */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Full Name</label>
                    <div className="relative">
                      <User className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        value={formData.full_name}
                        onChange={(e) => handleInputChange("full_name", e.target.value)}
                        disabled={!isEditing}
                        className="pl-10"
                      />
                    </div>
                  </div>

                  {/* Email */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Email Address</label>
                    <div className="relative">
                      <Mail className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        value={formData.email}
                        disabled
                        className="pl-10 bg-muted/50"
                      />
                    </div>
                  </div>

                  {/* Phone */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Phone Number</label>
                    <div className="relative">
                      <Phone className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        value={formData.phone}
                        onChange={(e) => handleInputChange("phone", e.target.value)}
                        disabled={!isEditing}
                        className="pl-10"
                      />
                    </div>
                  </div>

                  {/* Date of Birth */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Date of Birth</label>
                    <div className="relative">
                      <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        type="date"
                        value={formData.date_of_birth}
                        onChange={(e) => handleInputChange("date_of_birth", e.target.value)}
                        disabled={!isEditing}
                        className="pl-10"
                      />
                    </div>
                  </div>
                </div>

                {/* Bio */}
                <div className="mt-4 space-y-2">
                  <label className="text-sm font-medium text-foreground">Bio</label>
                  <Textarea
                    value={formData.bio}
                    onChange={(e) => handleInputChange("bio", e.target.value.slice(0, bioMaxLength))}
                    disabled={!isEditing}
                    rows={4}
                    placeholder="Tell us about yourself..."
                    className="resize-none"
                  />
                  <p className="text-xs text-muted-foreground text-right">
                    {bioRemaining} characters left
                  </p>
                </div>
              </div>

              {/* Address Section */}
              <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
                <h2 className="text-lg font-semibold text-foreground mb-6">Address Details</h2>

                <div className="space-y-4">
                  {/* Street Address */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Street Address</label>
                    <Input
                      value={formData.street}
                      onChange={(e) => handleInputChange("street", e.target.value)}
                      disabled={!isEditing}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* City */}
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">City</label>
                      <Input
                        value={formData.city}
                        onChange={(e) => handleInputChange("city", e.target.value)}
                        disabled={!isEditing}
                      />
                    </div>

                    {/* State */}
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">State / Province</label>
                      <Input
                        value={formData.state}
                        onChange={(e) => handleInputChange("state", e.target.value)}
                        disabled={!isEditing}
                      />
                    </div>

                    {/* Zip Code */}
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">Zip Code</label>
                      <Input
                        value={formData.zip_code}
                        onChange={(e) => handleInputChange("zip_code", e.target.value)}
                        disabled={!isEditing}
                      />
                    </div>

                    {/* Country */}
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">Country</label>
                      <Select
                        value={formData.country}
                        onValueChange={(value) => handleInputChange("country", value)}
                        disabled={!isEditing}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Select country" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="United States">United States</SelectItem>
                          <SelectItem value="Canada">Canada</SelectItem>
                          <SelectItem value="United Kingdom">United Kingdom</SelectItem>
                          <SelectItem value="Australia">Australia</SelectItem>
                          <SelectItem value="Germany">Germany</SelectItem>
                          <SelectItem value="France">France</SelectItem>
                          <SelectItem value="India">India</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                </div>
              </div>

            </>
          )}

          {/* Social Links Section */}
          {activeTab === "social" && (
            <div className="bg-surface border border-border rounded-xl p-4 sm:p-6 mb-8">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-lg font-semibold text-foreground flex items-center gap-2">
                  <Share2 className="size-5 text-primary" />
                  Social & Professional Links
                </h2>
                <button
                  onClick={() => setIsEditing(!isEditing)}
                  className="text-sm font-medium text-primary hover:underline"
                >
                  {isEditing ? "Cancel" : "Edit Info"}
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* LinkedIn */}
                <div className="space-y-2">
                  <label className="text-sm font-medium text-foreground flex items-center gap-2">
                    <Linkedin className="size-4 text-[#0077b5]" />
                    LinkedIn Profile
                  </label>
                  <Input
                    placeholder="https://linkedin.com/in/username"
                    value={formData.linkedin_url}
                    onChange={(e) => handleInputChange("linkedin_url", e.target.value)}
                    disabled={!isEditing}
                    className="bg-surface/50 transition-all focus:ring-primary/20"
                  />
                </div>

                {/* GitHub */}
                <div className="space-y-2">
                  <label className="text-sm font-medium text-foreground flex items-center gap-2">
                    <Github className="size-4 text-[#333]" />
                    GitHub Profile
                  </label>
                  <Input
                    placeholder="https://github.com/username"
                    value={formData.github_url}
                    onChange={(e) => handleInputChange("github_url", e.target.value)}
                    disabled={!isEditing}
                    className="bg-surface/50 transition-all focus:ring-primary/20"
                  />
                </div>

                {/* Twitter / X */}
                <div className="space-y-2">
                  <label className="text-sm font-medium text-foreground flex items-center gap-2">
                    <Twitter className="size-4 text-[#1DA1F2]" />
                    Twitter / X
                  </label>
                  <Input
                    placeholder="https://twitter.com/username"
                    value={formData.twitter_url}
                    onChange={(e) => handleInputChange("twitter_url", e.target.value)}
                    disabled={!isEditing}
                    className="bg-surface/50 transition-all focus:ring-primary/20"
                  />
                </div>

                {/* Portfolio */}
                <div className="space-y-2">
                  <label className="text-sm font-medium text-foreground flex items-center gap-2">
                    <Globe className="size-4 text-primary" />
                    Personal Portfolio
                  </label>
                  <Input
                    placeholder="https://yourportfolio.com"
                    value={formData.portfolio_url}
                    onChange={(e) => handleInputChange("portfolio_url", e.target.value)}
                    disabled={!isEditing}
                    className="bg-surface/50 transition-all focus:ring-primary/20"
                  />
                </div>
              </div>

              {/* Glassmorphism Social Preview (Only if not editing) */}
              {!isEditing && (
                <div className="mt-8 pt-6 border-t border-border/50">
                  <p className="text-sm text-muted-foreground mb-4">Quick Connect</p>
                  <div className="flex flex-wrap gap-3">
                    {formData.linkedin_url && (
                      <a href={formData.linkedin_url} target="_blank" rel="noopener noreferrer"
                        className="flex items-center gap-2 px-4 py-2 rounded-full bg-primary/5 hover:bg-primary/10 border border-primary/10 transition-all text-sm font-medium text-primary backdrop-blur-sm">
                        <Linkedin className="size-4" /> LinkedIn
                      </a>
                    )}
                    {formData.github_url && (
                      <a href={formData.github_url} target="_blank" rel="noopener noreferrer"
                        className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-500/5 hover:bg-slate-500/10 border border-slate-500/10 transition-all text-sm font-medium text-foreground backdrop-blur-sm">
                        <Github className="size-4" /> GitHub
                      </a>
                    )}
                    {formData.twitter_url && (
                      <a href={formData.twitter_url} target="_blank" rel="noopener noreferrer"
                        className="flex items-center gap-2 px-4 py-2 rounded-full bg-blue-400/5 hover:bg-blue-400/10 border border-blue-400/10 transition-all text-sm font-medium text-[#1DA1F2] backdrop-blur-sm">
                        <Twitter className="size-4" /> Twitter
                      </a>
                    )}
                    {formData.portfolio_url && (
                      <a href={formData.portfolio_url} target="_blank" rel="noopener noreferrer"
                        className="flex items-center gap-2 px-4 py-2 rounded-full bg-primary/5 hover:bg-primary/10 border border-primary/10 transition-all text-sm font-medium text-primary backdrop-blur-sm">
                        <Globe className="size-4" /> Portfolio
                      </a>
                    )}
                    {!formData.linkedin_url && !formData.github_url && !formData.twitter_url && !formData.portfolio_url && (
                      <p className="text-xs text-muted-foreground italic">No social links added yet.</p>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Academic Details Section */}
          {activeTab === "academic" && (
            <>
              <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-lg font-semibold text-foreground">Academic Information</h2>
                  <button
                    onClick={() => setIsEditing(!isEditing)}
                    className="text-sm font-medium text-primary hover:underline"
                  >
                    {isEditing ? "Cancel" : "Edit Info"}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Student/Lecturer ID - Moved outside to be top level first item maybe? Or keep in grid */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">
                      {role === "lecturer" ? "Lecturer ID" : "Student ID"}
                    </label>
                    <div className="relative">
                      <Award className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        value={formData.student_id}
                        onChange={(e) => handleInputChange("student_id", e.target.value)}
                        disabled={!isEditing}
                        className="pl-10"
                      />
                    </div>
                  </div>

                  {/* Program */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Program</label>
                    <div className="relative">
                      <BookOpen className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        value={formData.program}
                        onChange={(e) => handleInputChange("program", e.target.value)}
                        disabled={!isEditing}
                        className="pl-10"
                        placeholder="e.g., B.Sc. Computer Science"
                      />
                    </div>
                  </div>

                  {/* Additional Lecturer Fields */}
                  {role === "lecturer" && (
                    <>
                      {/* Batch */}
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Batch</label>
                        <Select
                          value={formData.batch}
                          onValueChange={(value) => handleInputChange("batch", value)}
                          disabled={!isEditing}
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select batch" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="2022-2026">2022–2026</SelectItem>
                            <SelectItem value="2023-2027">2023–2027</SelectItem>
                            <SelectItem value="2024-2028">2024–2028</SelectItem>
                            <SelectItem value="2025-2029">2025–2029</SelectItem>
                            <SelectItem value="2026-2030">2026–2030</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>

                      {/* HOD Name */}
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">HOD Name</label>
                        <div className="relative">
                          <User className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                          <Input
                            value={formData.hod_name}
                            onChange={(e) => handleInputChange("hod_name", e.target.value)}
                            disabled={!isEditing}
                            className="pl-10"
                            placeholder="e.g., Dr. Head of Dept"
                          />
                        </div>
                      </div>
                    </>
                  )}

                  {/* Student Specific Fields */}
                  {role !== "lecturer" && (
                    <>
                      {/* Year */}
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Year</label>
                        <Select
                          value={formData.year}
                          onValueChange={(value) => handleInputChange("year", value)}
                          disabled={!isEditing}
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select year" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="1st Year">1st Year</SelectItem>
                            <SelectItem value="2nd Year">2nd Year</SelectItem>
                            <SelectItem value="3rd Year">3rd Year</SelectItem>
                            <SelectItem value="4th Year">4th Year</SelectItem>
                            <SelectItem value="Graduate">Graduate</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>

                      {/* GPA */}
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">GPA</label>
                        <Input
                          type="number"
                          step="0.01"
                          min="0"
                          max="4"
                          value={formData.gpa}
                          onChange={(e) => handleInputChange("gpa", e.target.value)}
                          disabled={!isEditing}
                          placeholder="e.g., 3.75"
                        />
                      </div>

                      {/* Advisor */}
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-foreground">Academic Advisor</label>
                        <Input
                          value={formData.advisor}
                          onChange={(e) => handleInputChange("advisor", e.target.value)}
                          disabled={!isEditing}
                          placeholder="e.g., Dr. Smith"
                        />
                      </div>
                    </>
                  )}
                </div>
              </div>

              {/* Only show Important Dates for Students */}
              {role !== "lecturer" && (
                <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
                  <h2 className="text-lg font-semibold text-foreground mb-6">Important Dates</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">Enrollment Date</label>
                      <div className="relative">
                        <Clock className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                        <Input
                          type="date"
                          value={formData.enrollment_date}
                          onChange={(e) => handleInputChange("enrollment_date", e.target.value)}
                          disabled={!isEditing}
                          className="pl-10"
                        />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-foreground">Expected Graduation</label>
                      <div className="relative">
                        <GraduationCap className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                        <Input
                          type="date"
                          value={formData.expected_graduation}
                          onChange={(e) => handleInputChange("expected_graduation", e.target.value)}
                          disabled={!isEditing}
                          className="pl-10"
                        />
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </>
          )}

          {/* Security Section */}
          {activeTab === "security" && (
            <>
              <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
                <h2 className="text-lg font-semibold text-foreground mb-6">Change Password</h2>

                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Current Password</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        type={showPasswords.current ? "text" : "password"}
                        value={passwordData.currentPassword}
                        onChange={(e) =>
                          setPasswordData((prev) => ({ ...prev, currentPassword: e.target.value }))
                        }
                        className="pl-10 pr-10"
                        placeholder="Enter current password"
                      />
                      <button
                        type="button"
                        onClick={() =>
                          setShowPasswords((prev) => ({ ...prev, current: !prev.current }))
                        }
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                      >
                        {showPasswords.current ? <EyeOff className="size-5" /> : <Eye className="size-5" />}
                      </button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">New Password</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        type={showPasswords.new ? "text" : "password"}
                        value={passwordData.newPassword}
                        onChange={(e) =>
                          setPasswordData((prev) => ({ ...prev, newPassword: e.target.value }))
                        }
                        className="pl-10 pr-10"
                        placeholder="Enter new password"
                      />
                      <button
                        type="button"
                        onClick={() => setShowPasswords((prev) => ({ ...prev, new: !prev.new }))}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                      >
                        {showPasswords.new ? <EyeOff className="size-5" /> : <Eye className="size-5" />}
                      </button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-foreground">Confirm New Password</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 size-5 text-muted-foreground" />
                      <Input
                        type={showPasswords.confirm ? "text" : "password"}
                        value={passwordData.confirmPassword}
                        onChange={(e) =>
                          setPasswordData((prev) => ({ ...prev, confirmPassword: e.target.value }))
                        }
                        className="pl-10 pr-10"
                        placeholder="Confirm new password"
                      />
                      <button
                        type="button"
                        onClick={() =>
                          setShowPasswords((prev) => ({ ...prev, confirm: !prev.confirm }))
                        }
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                      >
                        {showPasswords.confirm ? <EyeOff className="size-5" /> : <Eye className="size-5" />}
                      </button>
                    </div>
                  </div>

                  <Button onClick={handlePasswordChange} disabled={isSaving} className="mt-2">
                    {isSaving ? (
                      <>
                        <Loader2 className="size-4 mr-2 animate-spin" />
                        Updating...
                      </>
                    ) : (
                      "Update Password"
                    )}
                  </Button>
                </div>
              </div>
            </>
          )}

          {/* Notifications Section */}
          {activeTab === "notifications" && (
            <ProfileNotificationSettings />
          )}

          {/* Preferences Section */}
          {activeTab === "preferences" && (
            <div className="bg-surface border border-border rounded-xl p-4 sm:p-6">
              <h2 className="text-lg font-semibold text-foreground mb-6">App Preferences</h2>

              <div className="space-y-6">
                {/* Theme */}
                <div className="space-y-2">
                  <label className="text-sm font-medium text-foreground flex items-center gap-2">
                    <Palette className="size-4" />
                    Theme
                  </label>
                  <ThemeSelector />
                  <p className="text-xs text-muted-foreground">
                    Choose your preferred theme. System will follow your device settings.
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Action Buttons */}
          {(activeTab === "personal" || activeTab === "academic" || activeTab === "social" || activeTab === "notifications" || activeTab === "preferences") && (
            <div className="flex justify-end gap-3">
              <Button variant="outline" onClick={() => setIsEditing(false)}>
                Cancel
              </Button>
              <Button onClick={handleSave} disabled={isSaving}>
                {isSaving ? (
                  <>
                    <Loader2 className="size-4 mr-2 animate-spin" />
                    Saving...
                  </>
                ) : (
                  <>
                    <Save className="size-4 mr-2" />
                    Save Changes
                  </>
                )}
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Public Profile Modal */}
      <Dialog open={showPublicProfile} onOpenChange={setShowPublicProfile}>
        <DialogContent className="max-w-2xl">
          <DialogHeader className="pb-4 border-b">
            <DialogTitle>Public Profile View</DialogTitle>
          </DialogHeader>

          {/* Academic Profile Preview */}
          <div className="bg-slate-50 dark:bg-[#050b14] text-slate-900 dark:text-white rounded-xl overflow-hidden shadow-2xl font-sans selection:bg-blue-500/30 transition-colors duration-300">

            {/* Top Header */}
            <div className="pt-8 pb-4 text-center">
              <h2 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-400 uppercase">Academic Profile</h2>
            </div>

            <div className="max-w-md mx-auto px-6 pb-12 relative z-10">
              <div className="flex flex-col items-center text-center mt-4">
                {/* Avatar with Glow */}
                <div className="relative mb-6 group">
                  <div className="absolute -inset-0.5 bg-gradient-to-b from-blue-500 to-blue-600 rounded-full opacity-75 blur"></div>
                  <div className="relative">
                    <Avatar className="size-24 border-4 border-white dark:border-[#050b14] shadow-2xl">
                      <AvatarImage src={profile?.avatar_url || ""} className="object-cover" />
                      <AvatarFallback className="bg-slate-100 dark:bg-slate-800 text-2xl font-bold text-blue-500">
                        {initials}
                      </AvatarFallback>
                    </Avatar>
                    {profile?.verified && (
                      <div className="absolute bottom-1 right-1 bg-blue-500 text-white p-1 rounded-full border-4 border-white dark:border-[#050b14]">
                        <CheckCircle className="size-3" fill="currentColor" />
                      </div>
                    )}
                  </div>
                </div>

                {/* Name */}
                <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-3">
                  {formData.full_name || "User Name"}
                </h1>

                {/* Badges */}
                <div className="flex flex-wrap justify-center gap-2 mb-6 items-center">
                  <Badge className="bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border border-blue-200 dark:border-blue-800/50 px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-full">
                    Academic Portal
                  </Badge>
                  <Badge variant="outline" className="bg-primary/5 text-primary border-primary/20 px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-full">
                    {role === "lecturer" ? "Lecturer" : "Student"}
                  </Badge>
                  {profile?.verified && (
                    <Badge className="bg-slate-100 dark:bg-slate-800/50 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50 px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-full">
                      Verified Identity
                    </Badge>
                  )}
                  <Button
                    size="icon"
                    variant="ghost"
                    className="h-6 w-6 rounded-full text-slate-400 hover:text-slate-900 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-white/10 ml-1"
                    onClick={() => {
                      const url = `${window.location.origin}/p/${user?.id}`;
                      navigator.clipboard.writeText(url);
                      toast.success("Public profile link copied!");
                    }}
                    title="Share Profile"
                  >
                    <Share2 className="size-3.5" />
                  </Button>
                </div>

                {/* Info Row */}
                <div className="flex flex-col items-center gap-2 text-sm text-slate-500 dark:text-slate-400 mb-8 font-medium">
                  <div className="flex items-center gap-2">
                    <Mail className="size-3.5 text-blue-500" />
                    <span>{profile?.email}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Calendar className="size-3.5 text-blue-500" />
                    <span>Updated {new Date().toLocaleDateString()}</span>
                  </div>
                </div>

                {/* Personal Statement */}
                {formData.bio && (
                  <div className="w-full text-left mb-8">
                    <div className="flex items-center gap-2 mb-4">
                      <div className="h-1 w-6 bg-blue-600 rounded-full"></div>
                      <h3 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-500 uppercase">Personal Statement</h3>
                    </div>
                    <p className="text-base text-slate-600 dark:text-slate-200 italic font-medium leading-relaxed">
                      "{formData.bio}"
                    </p>
                  </div>
                )}

                {/* Connectivity */}
                <div className="w-full text-left mb-8">
                  <div className="flex items-center gap-2 mb-4">
                    <div className="h-1 w-6 bg-blue-600 rounded-full"></div>
                    <h3 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-400 uppercase">Connectivity</h3>
                  </div>

                  <div
                    className="bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-xl p-4 flex items-center justify-between group hover:border-blue-500/20 transition-all cursor-pointer shadow-sm dark:shadow-none mb-3"
                    onClick={() => {
                      const url = `${window.location.origin}/p/${user?.id}`;
                      navigator.clipboard.writeText(url);
                      toast.success("Profile link copied!");
                    }}
                  >
                    <div className="flex items-center gap-3 overflow-hidden">
                      <Globe className="size-4 text-slate-400 shrink-0" />
                      <span className="text-xs font-semibold text-slate-700 dark:text-slate-300 truncate tracking-tight">
                        eduspaceacademy.online/p/{formData.full_name?.toLowerCase().replace(/\s+/g, '')}
                      </span>
                    </div>
                    <Copy className="size-3.5 text-slate-500" />
                  </div>

                  {formData.portfolio_url && (
                    <a
                      href={formData.portfolio_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-xl p-4 flex items-center justify-between group hover:border-blue-500/20 transition-all cursor-pointer shadow-sm dark:shadow-none mb-3"
                    >
                      <div className="flex items-center gap-3 overflow-hidden">
                        <LinkIcon className="size-4 text-blue-500 shrink-0" />
                        <span className="text-xs font-semibold text-slate-700 dark:text-slate-300 truncate tracking-tight">
                          {formData.portfolio_url.replace(/^https?:\/\/(www\.)?/, '')}
                        </span>
                      </div>
                      <ExternalLink className="size-3.5 text-slate-500" />
                    </a>
                  )}

                  {/* Social Presence Links */}
                  {(formData.linkedin_url || formData.github_url || formData.twitter_url) && (
                    <div className="flex flex-wrap gap-2">
                      {formData.linkedin_url && (
                        <a
                          href={formData.linkedin_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 hover:border-blue-500/20 transition-all shadow-sm group/social"
                        >
                          <Linkedin className="size-3.5 text-[#0077b5] group-hover/social:scale-110 transition-transform" />
                          <span className="text-[10px] font-bold text-slate-600 dark:text-slate-400">LinkedIn</span>
                        </a>
                      )}
                      {formData.github_url && (
                        <a
                          href={formData.github_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 hover:border-blue-500/20 transition-all shadow-sm group/social"
                        >
                          <Github className="size-3.5 text-slate-900 dark:text-white group-hover/social:scale-110 transition-transform" />
                          <span className="text-[10px] font-bold text-slate-600 dark:text-slate-400">GitHub</span>
                        </a>
                      )}
                      {formData.twitter_url && (
                        <a
                          href={formData.twitter_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 hover:border-blue-500/20 transition-all shadow-sm group/social"
                        >
                          <Twitter className="size-3.5 text-[#1DA1F2] group-hover/social:scale-110 transition-transform" />
                          <span className="text-[10px] font-bold text-slate-600 dark:text-slate-400">X</span>
                        </a>
                      )}
                    </div>
                  )}
                </div>

                {/* Footer E-Record Card */}
                <div className="w-full bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-2xl p-4 flex items-center justify-between shadow-xl shadow-slate-200/50 dark:shadow-blue-900/5">
                  <div className="flex items-center gap-3">
                    <div className="size-10 rounded-full border-2 border-blue-500/20 flex items-center justify-center bg-blue-500/5 text-blue-500">
                      <Shield className="size-5" />
                    </div>
                    <div className="text-left">
                      <p className="text-[10px] font-bold text-slate-900 dark:text-white leading-tight mb-0.5">Official Academic E-Record</p>
                      <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">ID: PREVIEW-MODE</p>
                    </div>
                  </div>
                  <div className="bg-blue-600 text-[8px] font-black px-3 py-1.5 rounded-lg text-white tracking-wider">
                    VERIFIED
                  </div>
                </div>

                <div className="mt-6 w-full pb-2 flex justify-center">
                  <Button
                    className="w-full max-w-sm bg-slate-900 dark:bg-white hover:bg-slate-800 dark:hover:bg-slate-200 text-white dark:text-slate-900 rounded-full py-6 shadow-xl shadow-slate-900/10 transition-all active:scale-[0.98] border border-white/10"
                    onClick={() => {
                      toast.info("This is a preview. Download functionality is available on the public profile page.");
                    }}
                  >
                    <Download className="size-4 mr-2" />
                    <span className="font-bold tracking-wide text-xs uppercase">Download Official PDF</span>
                  </Button>
                </div>

                {/* Visit Public Profile Link */}
                <div className="mt-4 text-center">
                  <button
                    onClick={() => {
                      setShowPublicProfile(false);
                      setTimeout(() => {
                        navigate(`/p/${user?.id}`);
                      }, 100);
                    }}
                    className="text-blue-600 hover:text-blue-700 dark:text-blue-400 dark:hover:text-blue-300 font-medium text-sm transition-colors underline-offset-2 hover:underline"
                  >
                    Visit Public Profile
                  </button>
                </div>
              </div>
            </div>
          </div>

        </DialogContent>
      </Dialog>

      {/* Digital Business Card (QR Code) Modal */}
      <Dialog open={showQRCode} onOpenChange={setShowQRCode}>
        <DialogContent className="max-w-sm rounded-3xl overflow-hidden p-0 border-none bg-transparent">
          <div className="bg-white dark:bg-[#050b14] p-8 text-center relative overflow-hidden">
            {/* Decorative backgrounds */}
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 via-purple-500 to-primary" />
            <div className="absolute -top-24 -right-24 size-48 bg-primary/10 rounded-full blur-3xl" />
            <div className="absolute -bottom-24 -left-24 size-48 bg-blue-500/10 rounded-full blur-3xl" />

            <div className="relative z-10 flex flex-col items-center">
              <div className="mb-6">
                <div className="size-20 bg-primary/10 rounded-2xl flex items-center justify-center mb-4 mx-auto">
                  <QrCode className="size-10 text-primary" />
                </div>
                <h2 className="text-xl font-bold text-slate-900 dark:text-white">Digital Business Card</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">Scan to connect with {formData.full_name?.split(' ')[0]}</p>
              </div>

              {/* QR Code Frame */}
              <div className="p-4 bg-white rounded-2xl shadow-2xl shadow-primary/10 border border-slate-100 mb-8 aspect-square flex items-center justify-center">
                <img
                  src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(`https://eduspaceacademy.online/p/${user?.id}`)}`}
                  alt="QR Code"
                  className="size-48 object-contain"
                />
              </div>

              <div className="w-full space-y-3">
                <Button
                  className="w-full rounded-xl bg-primary hover:bg-primary/90 text-white shadow-lg shadow-primary/20 py-6"
                  onClick={() => {
                    const profileUrl = `https://eduspaceacademy.online/p/${user?.id}`;
                    navigator.clipboard.writeText(profileUrl);
                    toast.success("Profile link copied!");
                  }}
                >
                  <Copy className="size-4 mr-2" />
                  Copy Profile Link
                </Button>
                <Button
                  variant="outline"
                  className="w-full rounded-xl border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-300 py-6"
                  onClick={() => setShowQRCode(false)}
                >
                  Close
                </Button>
              </div>

              <div className="mt-8 flex items-center gap-2 text-[10px] font-black tracking-widest text-slate-400 uppercase">
                <Shield className="size-3" />
                Eduspace Verified Student
              </div>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Mobile Bottom Navigation for Profile Tabs */}
      <div className="fixed bottom-0 left-0 right-0 z-50 bg-background/80 backdrop-blur-lg border-t border-border xl:hidden pb-safe">
        <nav className="flex items-center justify-around h-16 px-2 overflow-x-auto no-scrollbar">
          {profileTabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => {
                setActiveTab(tab.id);
                window.scrollTo({ top: 0, behavior: "smooth" });
              }}
              className={cn(
                "flex flex-col items-center justify-center gap-1 min-w-[64px] h-full text-[10px] font-medium transition-colors my-1",
                activeTab === tab.id
                  ? "text-primary"
                  : "text-muted-foreground hover:text-foreground"
              )}
            >
              <div
                className={cn(
                  "p-1.5 rounded-xl transition-all",
                  activeTab === tab.id && "bg-primary/10"
                )}
              >
                <tab.icon
                  className={cn("size-5 transition-all", activeTab === tab.id ? "text-primary" : "text-muted-foreground")}
                  strokeWidth={activeTab === tab.id ? 2.5 : 2}
                />
              </div>
              <span className={cn("hidden xs:block scale-0 transition-all duration-200", activeTab === tab.id && "scale-100")}>
                {tab.label.split(" ")[0]}
              </span>
            </button>
          ))}
        </nav>
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { useParams, useNavigate, useSearchParams } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { X, Trophy, Mail, Calendar, CheckCircle, Copy, ChevronLeft, Loader2, User, Globe, Shield, Printer, Sparkles, Star, Medal, Award, Zap, Crown, Sword, Gem, GraduationCap, Infinity as InfinityIcon, Link as LinkIcon, ExternalLink, Linkedin, Github, Twitter } from "lucide-react";
import { toast } from "sonner";
import { motion, AnimatePresence } from "framer-motion";
import { BadgeType, BADGE_DETAILS } from "@/services/streakService";
import { StreakBadgeDetailModal } from "@/components/streak/StreakBadgeDetailModal";
import SEO from "@/components/SEO";

const IconMap: Record<string, any> = {
    Trophy, Medal, Award, Zap, Crown, Sparkles, Shield, Sword, Gem, Infinity: InfinityIcon
};

interface ProfileData extends Record<string, any> {
    avatar_url?: string;
    full_name?: string;
    bio?: string;
    email?: string;
    updated_at?: string;
}

export default function PublicProfile() {
    const { id } = useParams();
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const badgeType = searchParams.get("badge") as BadgeType | null;
    const badgeDetails = badgeType ? BADGE_DETAILS[badgeType] : null;
    const BadgeIcon = badgeDetails ? (IconMap[badgeDetails.icon] || Trophy) : null;
    const [profile, setProfile] = useState<ProfileData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [showBadge, setShowBadge] = useState(true);

    useEffect(() => {
        async function fetchProfile() {
            if (!id) return;
            try {
                setLoading(true);
                const { data: publicData, error: publicError } = await supabase
                    .from("public_profiles")
                    .select("*")
                    .eq("user_id", id)
                    .single();

                let finalData: any = publicData;

                // If public profile missing or missing avatar, try getting from main profiles
                if (publicError || !publicData?.avatar_url) {
                    const { data: mainData, error: mainError } = await supabase
                        .from("profiles")
                        .select("*")
                        .eq("user_id", id)
                        .single();

                    if (!mainError && mainData) {
                        if (!finalData) {
                            finalData = mainData as any;
                        } else {
                            // Merge missing avatar from main profile
                            finalData = {
                                ...finalData,
                                avatar_url: finalData.avatar_url || (mainData as any).avatar_url,
                                full_name: finalData.full_name || (mainData as any).full_name,
                                bio: finalData.bio || (mainData as any).bio
                            };
                        }
                    }

                    // Explicit fallback: Check student_profiles for image if still missing
                    if (!finalData?.avatar_url) {
                        const { data: studentData } = await supabase
                            .from("student_profiles")
                            .select("profile_image")
                            .eq("user_id", id)
                            .maybeSingle();

                        if (studentData?.profile_image) {
                            if (!finalData) finalData = {}; // Initialize if null
                            finalData.avatar_url = studentData.profile_image;
                        }
                    }
                }

                setProfile(finalData);
            } catch (err: any) {
                console.error("Error fetching public profile:", err);
                setError(err.message);
            } finally {
                setLoading(false);
            }
        }

        fetchProfile();
    }, [id]);

    const copyLink = () => {
        const url = window.location.href;
        navigator.clipboard.writeText(url);
    };



    const isBadgeView = window.location.pathname.includes('/badge/');

    if (loading) {
        return (
            <div className="flex h-screen w-full items-center justify-center bg-[#050b14]">
                <div className="flex flex-col items-center gap-4">
                    <Loader2 className="h-10 w-10 animate-spin text-blue-500" />
                    <p className="text-slate-400 font-medium animate-pulse">
                        {isBadgeView ? 'Retrieving Achievement...' : 'Loading Profile...'}
                    </p>
                </div>
            </div>
        );
    }

    if (error || !profile) {
        return (
            <div className="flex min-h-screen w-full flex-col items-center justify-center bg-[#050b14] p-6 text-center text-white">
                <User className="size-16 text-slate-700 mb-6" />
                <h1 className="text-2xl font-bold mb-2">Profile Not Found</h1>
                <Button onClick={() => navigate("/")} variant="outline" className="rounded-full mt-4 border-slate-700 text-slate-300 hover:bg-slate-800 hover:text-white">
                    Return to Portal
                </Button>
            </div>
        );
    }

    const initials = profile.full_name
        ? profile.full_name.split(" ").map((n: string) => n[0]).join("").toUpperCase()
        : "U";

    return (
        <div className="h-screen w-full overflow-hidden bg-slate-50 dark:bg-[#050b14] text-slate-900 dark:text-white font-sans selection:bg-blue-500/30 transition-colors duration-300 flex flex-col items-center">
            <SEO
                title={profile ? `${profile.full_name} | Academic Profile` : "Public Profile"}
                description={profile?.bio || "View this student's academic profile and achievements on Eduspace Academy."}
                ogImage={profile?.avatar_url || "/og-image.png"}
                keywords={["Student Profile", "Academic Portfolio", "Eduspace Profile", "Student Achievements"]}
                structuredData={profile ? {
                    "@context": "https://schema.org",
                    "@type": "Person",
                    "name": profile.full_name,
                    "description": profile.bio,
                    "image": profile.avatar_url,
                    "url": window.location.href
                } : undefined}
            />

            {/* Background spotlight for badge view */}
            {isBadgeView && (
                <div className="absolute inset-0 pointer-events-none z-0">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-[radial-gradient(circle_at_center,rgba(59,130,246,0.15),transparent_70%)]" />
                </div>
            )}

            {/* Main Content - Centered */}
            <main className="flex-1 w-full max-w-md px-6 relative z-10 overflow-y-auto nav-scroll flex flex-col justify-center">
                {/* The Full Streak Badge Modal for Live Sharing */}
                <StreakBadgeDetailModal
                    type={badgeType}
                    isOpen={showBadge && !!badgeType}
                    hideShare={isBadgeView}
                    hideClose={isBadgeView}
                    hideGenerate={isBadgeView}
                    externalProfile={profile}
                    onClose={() => {
                        setShowBadge(false);
                        // Clean up URL parameter after closing
                        const newUrl = window.location.pathname;
                        window.history.replaceState({}, '', newUrl);
                    }}
                />

                {/* Profile Card - Hidden in Badge View */}
                {!isBadgeView && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ duration: 0.4 }}
                        className="flex flex-col items-center text-center pb-24 pt-8 bg-slate-50 dark:bg-[#050b14] text-slate-900 dark:text-white"
                    >

                        {/* Academic Profile Header */}
                        <div className="mb-6 text-center">
                            <h2 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-400 uppercase">
                                {badgeDetails ? 'Profile of Achiever' : 'Academic Profile'}
                            </h2>
                        </div>

                        {/* Avatar with Glow */}
                        <div className="relative mb-4 md:mb-6 group">
                            <div className="absolute -inset-0.5 bg-gradient-to-b from-blue-500 to-blue-600 rounded-full opacity-75 blur group-hover:opacity-100 transition duration-1000 group-hover:duration-200 animate-tilt"></div>
                            <div className="relative">
                                <Avatar className="size-24 md:size-32 border-4 border-white dark:border-[#050b14] shadow-2xl">
                                    <AvatarImage src={profile.avatar_url || ""} className="object-cover" />
                                    <AvatarFallback className="bg-slate-100 dark:bg-slate-800 text-3xl font-bold text-blue-500">
                                        {initials}
                                    </AvatarFallback>
                                </Avatar>
                                {profile.verified && (
                                    <div className="absolute bottom-1 right-1 bg-blue-500 text-white p-1 rounded-full border-4 border-white dark:border-[#050b14]">
                                        <CheckCircle className="size-4" fill="currentColor" />
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Name */}
                        <h1 className="text-2xl md:text-3xl font-bold tracking-tight text-slate-900 dark:text-white mb-2 md:mb-3">
                            {profile.full_name}
                        </h1>

                        {/* Badges */}
                        <div className="flex flex-wrap justify-center gap-2 mb-6">
                            <Badge className="bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 hover:bg-blue-200 dark:hover:bg-blue-900/50 border border-blue-200 dark:border-blue-800/50 px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-full">
                                Academic Portal
                            </Badge>
                            {profile.verified && (
                                <Badge className="bg-slate-100 dark:bg-slate-800/50 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 border border-slate-200 dark:border-slate-700/50 px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-full">
                                    Verified Identity
                                </Badge>
                            )}
                        </div>

                        {/* Info Row */}
                        <div className="flex flex-col items-center gap-1.5 md:gap-2 text-sm text-slate-500 dark:text-slate-400 mb-8 md:mb-12 font-medium">
                            <div className="flex items-center gap-2">
                                <Mail className="size-4 text-blue-500" />
                                <span>{profile.email}</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <Calendar className="size-4 text-blue-500" />
                                <span>Updated {new Date(profile.updated_at || new Date()).toLocaleDateString()}</span>
                            </div>
                        </div>

                        {/* Personal Statement */}
                        {profile.bio && (
                            <div className="w-full text-left mb-10">
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="h-1 w-6 bg-blue-600 rounded-full"></div>
                                    <h3 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-500 uppercase">Personal Statement</h3>
                                </div>
                                <p className="text-lg text-slate-600 dark:text-slate-200 italic font-medium leading-relaxed">
                                    "{profile.bio}"
                                </p>
                            </div>
                        )}

                        {/* Connectivity */}
                        <div className="w-full text-left mb-12">
                            <div className="flex items-center gap-2 mb-4">
                                <div className="h-1 w-6 bg-blue-600 rounded-full"></div>
                                <h3 className="text-[10px] font-black tracking-[0.2em] text-slate-500 dark:text-slate-500 uppercase">Connectivity</h3>
                            </div>

                            <div className="bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-xl p-4 flex items-center justify-between group hover:border-blue-500/20 transition-all cursor-pointer shadow-sm dark:shadow-none mb-3" onClick={copyLink}>
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <Globe className="size-5 text-slate-400 shrink-0" />
                                    <span className="text-sm font-semibold text-slate-700 dark:text-slate-300 truncate tracking-tight">
                                        eduspaceacademy.online/p/{profile.full_name?.toLowerCase().replace(/\s+/g, '')}
                                    </span>
                                </div>
                                <Copy className="size-4 text-slate-400 dark:text-slate-500 group-hover:text-blue-500 transition-colors" />
                            </div>

                            {profile.portfolio_url && (
                                <a
                                    href={profile.portfolio_url}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-xl p-4 flex items-center justify-between group hover:border-blue-500/20 transition-all cursor-pointer shadow-sm dark:shadow-none mb-3"
                                >
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <LinkIcon className="size-5 text-blue-500 shrink-0" />
                                        <span className="text-sm font-semibold text-slate-700 dark:text-slate-300 truncate tracking-tight">
                                            {profile.portfolio_url.replace(/^https?:\/\/(www\.)?/, '')}
                                        </span>
                                    </div>
                                    <ExternalLink className="size-4 text-slate-400 dark:text-slate-500 group-hover:text-blue-500 transition-colors" />
