                        </div>

                        {/* Footer E-Record Card */}
                        <div className="w-full bg-white dark:bg-[#0f1623] border border-slate-200 dark:border-white/5 rounded-2xl p-5 flex items-center justify-between shadow-xl shadow-slate-200/50 dark:shadow-blue-900/5 mb-8">
                            <div className="flex items-center gap-4">
                                <div className="size-12 rounded-full border-2 border-blue-500/20 flex items-center justify-center bg-blue-500/5 text-blue-500">
                                    <Shield className="size-6" />
                                </div>
                                <div className="text-left">
                                    <p className="text-xs font-bold text-slate-900 dark:text-white leading-tight mb-1">Official Academic E-Record</p>
                                    <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">ID: {id?.slice(0, 8).toUpperCase()}</p>
                                </div>
                            </div>
                            <div className="bg-blue-600 text-[10px] font-black px-4 py-2 rounded-lg text-white shadow-lg shadow-blue-600/20 tracking-wider">
                                VERIFIED
                            </div>
                        </div>

                    </motion.div>
                )}

            </main>

            {/* Floating Action Buttons - Hidden in Badge View */}
            {!isBadgeView && (
                <div className="fixed bottom-6 z-20 w-full px-6 flex justify-center pointer-events-none">
                    <Button
                        className="w-full max-w-sm bg-slate-900 dark:bg-white hover:bg-slate-800 dark:hover:bg-slate-200 text-white dark:text-slate-900 rounded-full py-6 shadow-2xl shadow-slate-900/20 transition-all active:scale-[0.98] pointer-events-auto border border-white/10"
                        onClick={() => window.print()}
                    >
                        <Printer className="size-5 mr-3" />
                        <span className="font-bold tracking-wide text-sm uppercase">Print Profile</span>
                    </Button>
                </div>
            )}

            {/* Nav Back Button (Top Left) */}
            <Button
                variant="ghost"
                size="icon"
                className="fixed top-4 left-4 z-20 text-slate-500 hover:text-slate-900 dark:hover:text-white bg-white/50 dark:bg-black/20 backdrop-blur-sm rounded-full"
                onClick={() => navigate('/')}
            >
                <ChevronLeft className="size-5" />
            </Button>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import {
    Loader2,
    CheckCircle,
    XCircle,
    Clock,
    Check,
    Download,
    Menu,
    Home,
    Search,
    LayoutDashboard,
    ChevronLeft,
    ChevronRight,
    Info
} from 'lucide-react';
import {
    Sheet,
    SheetContent,
    SheetHeader,
    SheetTitle,
    SheetTrigger,
} from "@/components/ui/sheet";
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { Skeleton } from '@/components/ui/skeleton';
import { toast } from 'sonner';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

export default function QuizAttemptDetails() {
    const { quizId } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [quiz, setQuiz] = useState<any>(null);
    const [questions, setQuestions] = useState<any[]>([]);
    const [answers, setAnswers] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(true);
    const [result, setResult] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);
    const [currentIndex, setCurrentIndex] = useState(0);

    useEffect(() => {
        const fetchDetails = async () => {
            if (!quizId || !user) return;
            try {
                setLoading(true);
                setError(null);

                const { data: quizData, error: quizError } = await supabase
                    .from('quizzes')
                    .select('*, classes(class_name)')
                    .eq('id', quizId)
                    .single();

                if (quizError) throw quizError;
                setQuiz(quizData);

                const { data: submission, error: submissionError } = await supabase
                    .from('quiz_submissions')
                    .select('*')
                    .eq('quiz_id', quizId)
                    .eq('student_id', user.id)
                    .order('submitted_at', { ascending: false })
                    .limit(1)
                    .maybeSingle();

                if (submissionError) throw submissionError;

                if (!submission) {
                    setError(`No submission record found`);
                } else {
                    setResult(submission);
                }

                const { data: questionsData, error: questionsError } = await supabase
                    .from('quiz_questions')
                    .select('*')
                    .eq('quiz_id', quizId)
                    .order('order_index');

                if (questionsError) throw questionsError;
                setQuestions(questionsData || []);

                const { data: existingAnswers } = await supabase
                    .from('quiz_answers')
                    .select('question_id, selected_option')
                    .eq('submission_id', submission?.id);

                if (existingAnswers) {
                    const loadedAnswers: Record<string, string> = {};
                    existingAnswers.forEach((a: any) => {
                        loadedAnswers[a.question_id] = a.selected_option;
                    });
                    setAnswers(loadedAnswers);
                }

            } catch (error: any) {
                console.error('Error loading quiz details:', error);
                setError(error.message || 'Failed to load details');
            } finally {
                setLoading(false);
            }
        };

        fetchDetails();
    }, [quizId, user]);

    const formatTimeFull = (seconds: number) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${h.toString().padStart(2, '0')} : ${m.toString().padStart(2, '0')} : ${s.toString().padStart(2, '0')}`;
    };

    const scrollToQuestion = (idx: number) => {
        const element = document.getElementById(`mobile-question-${idx}`);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'start' });
            setCurrentIndex(idx);
        } else {
            setCurrentIndex(idx);
        }
    };

    const generatePDF = () => {
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.text("Quiz Result Summary", 20, 20);
        doc.setFontSize(16);
        doc.text(`Quiz: ${quiz.title}`, 20, 35);
        doc.text(`Student ID: ${user?.id.slice(0, 8)}`, 20, 45);
        doc.text(`Score: ${result.total_obtained}/${quiz.total_marks}`, 20, 55);

        const tableData = questions.map((q, idx) => [
            idx + 1,
            q.question_text,
            answers[q.id] === q.correct_answer ? "Correct" : (answers[q.id] ? "Incorrect" : "Skipped"),
            answers[q.id] === q.correct_answer ? q.marks : 0
        ]);

        autoTable(doc, {
            startY: 70,
            head: [['#', 'Question', 'Result', 'Points']],
            body: tableData,
        });

        doc.save(`${quiz.title}_Result.pdf`);
        toast.success("Download successful");
    };

    const SidebarContent = () => (
        <div className="flex flex-col h-full">
            <h2 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] mb-6 shrink-0">Review Questions</h2>

            {/* Scrollable Question Grid */}
            <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar mb-6 -mx-2 px-2">
                <div className="grid grid-cols-5 gap-4 py-4 px-2">
                    {questions.map((q, idx) => {
                        const ansId = answers[q.id];
                        const isCorrectQ = ansId === q.correct_answer;
                        const isSkippedQ = !ansId;
                        const isActive = currentIndex === idx;

                        return (
                            <div key={q.id} className="flex items-center justify-center">
                                <button
                                    onClick={() => scrollToQuestion(idx)}
                                    className={cn(
                                        "size-10 rounded-lg flex items-center justify-center font-bold text-sm transition-all border-2",
                                        isActive
