                                            </div>
                                        </div>
                                        <div className="text-center pt-2 sm:pt-4">
                                            <h4 className="text-xs sm:text-xl font-black text-slate-900 dark:text-white truncate max-w-[100px] sm:max-w-[160px] mb-1">
