        </div>

        {/* Mobile FAB for Schedule */}
        {!isStudent && selectedClassId && (
          <div className="fixed bottom-6 right-6 sm:hidden z-40 animate-in fade-in slide-in-from-bottom-4 duration-300">
            <Button
              onClick={() => {
                resetForm();
                setIsAddEventOpen(true);
