            setEventToDelete(null);
          }
        }}
        title="Delete Schedule Entry?"
        description="This will remove the event from the class timetable. Students will no longer see this in their schedule."
      />
    </DashboardLayout>
  );
}

import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { deleteUserAccount } from "@/lib/accountService";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Trash2,
  AlertTriangle,
  Loader2,
} from "lucide-react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

export default function Settings() {
  const { toast } = useToast();
  const { user, profile, signOut } = useAuth();
  const navigate = useNavigate();
  const [isDeleting, setIsDeleting] = useState(false);
  const [password, setPassword] = useState("");
  const [confirmText, setConfirmText] = useState("");
  const [isConfirming, setIsConfirming] = useState(false);


  const handleDeleteAccount = async () => {
    if (!user || !user.email) return;

    if (!password || confirmText !== "DELETE") {
      toast({
        title: "Validation Failed",
        description: "Please enter your password and type 'DELETE' to confirm.",
        variant: "destructive",
      });
      return;
    }

    setIsDeleting(true);
    try {
      // 1. Verify password by attempting to sign in
      const { error: authError } = await supabase.auth.signInWithPassword({
        email: user.email,
        password: password,
      });

      if (authError) {
        throw new Error("Invalid password. Please try again.");
      }

      // 2. Proceed with deletion
      const { success, error } = await deleteUserAccount(user.id);

      if (success) {
        toast({
          title: "Account Deleted",
          description: "Your account has been successfully reset. You will be signed out.",
        });

        // Clear state
        setPassword("");
        setConfirmText("");
        setIsConfirming(false);

        // Wait briefly for the toast to be visible
        setTimeout(async () => {
          await signOut();
          navigate("/login");
        }, 1500);
      } else {
        throw new Error(error || "Failed to delete account");
      }
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
      setIsDeleting(false);
    }
  };

  return (
    <DashboardLayout>
      <div className="space-y-6 max-w-2xl mx-auto">
        {/* Header */}
        <div>
          <h1 className="text-2xl font-bold">Account Settings</h1>
          <p className="text-muted-foreground">
            Manage your account security and preferences
          </p>
        </div>



        {/* Danger Zone */}
        <Card className="border-destructive/20 bg-destructive/5">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-destructive">
              <AlertTriangle className="size-5" />
              Danger Zone
            </CardTitle>
            <CardDescription className="text-destructive/80">
              Irreversible account actions
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <h4 className="font-medium">Delete Account</h4>
              <p className="text-sm text-muted-foreground">
                Once you delete your account, there is no going back. Please be certain.
                This action will:
              </p>
              <ul className="list-disc list-inside text-sm text-muted-foreground ml-2 space-y-1">
                <li>Permanently delete your profile information</li>
                <li>Remove you from all enrolled courses</li>
                <li>Delete your submission history and grades</li>
                <li>Remove your access to the platform immediately</li>
              </ul>
            </div>

            <div className="pt-2">
              <AlertDialog open={isConfirming} onOpenChange={setIsConfirming}>
                <AlertDialogTrigger asChild>
                  <Button variant="destructive" className="w-full sm:w-auto">
                    <Trash2 className="size-4 mr-2" />
                    Delete My Account
                  </Button>
                </AlertDialogTrigger>
                <AlertDialogContent className="sm:max-w-md">
                  <AlertDialogHeader>
                    <AlertDialogTitle className="text-xl font-bold text-destructive">Are you absolutely sure?</AlertDialogTitle>
                    <AlertDialogDescription className="text-base">
                      This action cannot be undone. This will permanently delete your
                      account data and remove your data from our servers.
                    </AlertDialogDescription>
                  </AlertDialogHeader>

                  <div className="py-6 space-y-5">
                    <div className="space-y-2">
                      <Label htmlFor="password">1. Enter your password</Label>
                      <Input
                        id="password"
                        type="password"
                        placeholder="Current password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        className="bg-muted/50"
                        autoComplete="current-password"
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="confirm-text">
                        2. Type <span className="font-bold text-foreground">DELETE</span> to confirm
                      </Label>
                      <Input
                        id="confirm-text"
                        type="text"
                        placeholder="Type DELETE"
                        value={confirmText}
                        onChange={(e) => setConfirmText(e.target.value)}
                        className="bg-muted/50 font-mono"
                      />
                    </div>

                    <div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 text-xs text-destructive flex gap-2 items-start">
                      <AlertTriangle className="size-4 shrink-0 mt-0.5" />
                      <span>This dual-verification ensures you are certain about scrubbing your data permanently.</span>
                    </div>
                  </div>

                  <AlertDialogFooter className="gap-2 sm:gap-0">
                    <AlertDialogCancel
                      disabled={isDeleting}
                      onClick={() => {
                        setPassword("");
                        setConfirmText("");
                      }}
                    >
                      Cancel
                    </AlertDialogCancel>
                    <AlertDialogAction
                      onClick={(e) => {
                        e.preventDefault();
                        handleDeleteAccount();
                      }}
                      className="bg-destructive hover:bg-destructive/90 text-white min-w-[120px]"
                      disabled={isDeleting || !password || confirmText !== "DELETE"}
                    >
                      {isDeleting ? (
                        <>
                          <Loader2 className="size-4 mr-2 animate-spin" />
                          Deleting...
                        </>
                      ) : (
                        "Delete Account"
                      )}
                    </AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            </div>
          </CardContent>
        </Card>
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { aiChatService, AIConversation, AIChatMessage } from "@/lib/aiChatService";
import { AIMessage } from "@/components/student/ai-chat/AIMessage";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Loader2, MessageCircle, ChevronLeft, Share2, ShieldCheck } from "lucide-react";
import { motion } from "framer-motion";

export default function SharedAIChat() {
    const { token } = useParams<{ token: string }>();
    const navigate = useNavigate();
    const [conversation, setConversation] = useState<AIConversation | null>(null);
    const [messages, setMessages] = useState<AIChatMessage[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (token) {
            loadSharedChat(token);
        }
    }, [token]);

    const loadSharedChat = async (shareToken: string) => {
        setIsLoading(true);
        try {
            const data = await aiChatService.getSharedConversation(shareToken);
            setConversation(data.conversation);
            setMessages(data.messages);
        } catch (err: any) {
            console.error("Failed to load shared chat:", err);
            setError(err.message || "This chat is no longer available or the link is invalid.");
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex h-screen w-full flex-col items-center justify-center gap-4 bg-background">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
                <p className="text-sm font-medium text-muted-foreground">Loading shared conversation...</p>
            </div>
        );
    }

    if (error || !conversation) {
        return (
            <div className="flex h-screen w-full flex-col items-center justify-center p-8 text-center bg-background">
                <div className="size-16 rounded-2xl bg-destructive/10 flex items-center justify-center mb-6">
                    <Share2 className="h-8 w-8 text-destructive" />
                </div>
                <h1 className="text-2xl font-bold mb-2">Unavailable Chat</h1>
                <p className="text-muted-foreground max-w-md mb-8">{error}</p>
                <Button onClick={() => navigate("/")} variant="outline">
                    Go Home
                </Button>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-screen bg-background overflow-hidden">
            {/* Header */}
            <header className="h-16 shrink-0 border-b border-border/40 bg-background/50 backdrop-blur-md flex items-center justify-between px-4 md:px-6 z-30">
                <div className="flex items-center gap-3">
                    <Button variant="ghost" size="icon" onClick={() => navigate(-1)} className="rounded-xl">
                        <ChevronLeft className="h-5 w-5" />
                    </Button>
                    <div className="size-8 md:size-9 rounded-xl overflow-hidden border border-border/40 shadow-lg shrink-0">
                        <img src="/favicon.png" alt="Eduspace Logo" className="size-full object-cover" />
                    </div>
                    <div>
                        <h2 className="text-xs md:text-sm font-bold tracking-tight text-foreground/90 truncate max-w-[200px] md:max-w-none leading-none">
                            {conversation.title}
                        </h2>
                        <div className="flex items-center gap-1.5 mt-1 leading-none">
                            <ShieldCheck className="h-2.5 w-2.5 text-emerald-500" />
                            <span className="text-[10px] text-emerald-500/80 font-bold uppercase tracking-wider">Shared View (Read Only)</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <div className="hidden sm:flex items-center gap-1.5 px-3 py-1 rounded-full bg-primary/10 border border-primary/20">
                        <MessageCircle className="h-3 w-3 text-primary" />
                        <span className="text-[10px] font-bold text-primary uppercase tracking-wider">AI Conversation</span>
                    </div>
                </div>
            </header>

            {/* Content */}
            <main className="flex-1 overflow-hidden relative">
                <div className="absolute inset-x-0 bottom-0 h-32 bg-gradient-to-t from-background to-transparent z-10 pointer-events-none" />

                <ScrollArea className="h-full">
                    <div className="max-w-4xl mx-auto w-full px-4 pt-8 pb-32">
                        <div className="space-y-8">
                            {messages.map((msg, i) => (
                                <motion.div
                                    key={msg.id}
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: i * 0.05 }}
                                >
                                    <AIMessage
                                        messageId={msg.id}
                                        role={msg.role}
                                        content={msg.content}
                                        profile={(conversation as any).profiles}
                                        isReadOnly
                                    />
                                </motion.div>
                            ))}
                        </div>

                        <div className="mt-12 p-8 rounded-3xl border border-dashed border-border/60 bg-muted/5 text-center">
                            <h3 className="text-lg font-bold mb-2">Want to ask your own questions?</h3>
                            <p className="text-sm text-muted-foreground mb-6">Join Eduspace to start your own AI-powered learning journey.</p>
                            <Button onClick={() => navigate("/register")} className="rounded-2xl px-8 shadow-lg shadow-primary/20">
                                Get Started Free
                            </Button>
                        </div>
                    </div>
                </ScrollArea>
            </main>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import {
    ArrowLeft,
    Calendar,
    Clock,
    FileText,
    Download,
    User,
    BookOpen,
    CheckCircle,
    AlertCircle,
    Loader2,
    Upload,
    ExternalLink,
    Trophy,
    Sparkles,
    MessageSquare,
    Eye
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { format } from "date-fns";
import { SubmitAssignmentDialog } from "@/components/assignments/SubmitAssignmentDialog";
import { useAssignments } from "@/hooks/useAssignments";
import { formatFileSize, getFileTypeDisplay, getFileExtension } from "@/lib/fileUtils";
import { useStreak } from "@/contexts/StreakContext";

import { Skeleton } from "@/components/ui/skeleton";

interface AssignmentDetail {
    id: string;
    title: string;
    description: string | null;
    instructions: string | null;
    due_date: string | null;
    max_points: number;
    attachment_url: string | null;
    attachment_name: string | null;
    status: string;
    created_at: string;
    class_id: string | null;
    subject_id: string | null;
    lecturer_id: string;
    class_name?: string;
    subject_name?: string;
    lecturer_name?: string;
}

interface Submission {
    id: string;
    submitted_at: string;
    attachment_url: string | null;
    attachment_name: string | null;
    file_type: string | null;
    file_size: number | null;
    submission_text: string | null;
    grade: number | null;
    feedback: string | null;
    status: string;
}

export default function StudentAssignmentDetail() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();
    const { submitAssignment } = useAssignments();
    const { recordAcademicAction } = useStreak();

    const [assignment, setAssignment] = useState<AssignmentDetail | null>(null);
    const [submission, setSubmission] = useState<Submission | null>(null);
    const [loading, setLoading] = useState(true);
    const [isSubmitOpen, setIsSubmitOpen] = useState(false);

    useEffect(() => {
        if (!id || !user) return;

        const fetchAssignmentDetails = async () => {
            setLoading(true);
            try {
                // Record academic action
                recordAcademicAction();

                // Fetch assignment
                const { data: assignmentData, error: assignmentError } = await supabase
                    .from('assignments')
                    .select('*')
                    .eq('id', id)
                    .single();

                if (assignmentError) throw assignmentError;

                // Fetch related data
                let className = null;
                let subjectName = null;
                let lecturerName = null;

                if (assignmentData.class_id) {
                    const { data: classData } = await supabase
                        .from('classes')
                        .select('class_name')
                        .eq('id', assignmentData.class_id)
                        .single();
                    className = classData?.class_name;
                }

                if (assignmentData.subject_id) {
                    const { data: subjectData } = await supabase
                        .from('subjects')
                        .select('name')
                        .eq('id', assignmentData.subject_id)
                        .single();
                    subjectName = subjectData?.name;
                }

                if (assignmentData.lecturer_id) {
                    const { data: lecturerData } = await supabase
                        .from('profiles')
                        .select('full_name')
                        .eq('user_id', assignmentData.lecturer_id)
                        .single();
                    lecturerName = lecturerData?.full_name;
                }

                setAssignment({
                    ...assignmentData,
                    class_name: className,
                    subject_name: subjectName,
                    lecturer_name: lecturerName,
                });

                // Fetch student's submission
                const { data: submissionData } = await supabase
                    .from('assignment_submissions')
                    .select('*, file_type, file_size')
                    .eq('assignment_id', id)
                    .eq('student_id', user.id)
                    .single();

                setSubmission(submissionData || null);
            } catch (err) {
                console.error('Error fetching assignment details:', err);
            } finally {
                setLoading(false);
            }
        };

        fetchAssignmentDetails();

        // Real-time subscription for submission updates
        const submissionSubscription = supabase
            .channel(`submission_${id}_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'assignment_submissions',
                    filter: `assignment_id=eq.${id}`,
                },
                async (payload: any) => {
                    console.log('[StudentAssignmentDetail] Submission update:', payload);
                    if (payload.new && 'student_id' in payload.new && payload.new.student_id === user.id) {
                        setSubmission(payload.new as Submission);
                    }
                }
            )
            .subscribe();

        return () => {
            submissionSubscription.unsubscribe();
        };
    }, [id, user, recordAcademicAction]);

    const getStatusConfig = () => {
        if (submission) {
            if (submission.status === 'graded') {
                return {
                    label: 'Graded',
                    color: 'bg-green-500/10 text-green-600 dark:text-green-400 border-green-200 dark:border-green-800',
                    icon: CheckCircle
                };
            }
            return {
                label: 'Submitted',
                color: 'bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-800',
                icon: CheckCircle
            };
        }

        const isOverdue = assignment?.due_date && new Date(assignment.due_date) < new Date();
        if (isOverdue) {
            return {
                label: 'Overdue',
                color: 'bg-red-500/10 text-red-600 dark:text-red-400 border-red-200 dark:border-red-800',
                icon: AlertCircle
            };
        }

        return {
            label: 'Pending',
            color: 'bg-amber-500/10 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-800',
            icon: Clock
        };
    };

    if (loading) {
        return (
            <DashboardLayout>
                <div className="min-h-full bg-slate-50/50 dark:bg-slate-950/20 p-0 lg:p-4">
                    <div className="max-w-7xl mx-auto space-y-8 p-4 lg:p-6">
                        <div className="flex items-center justify-between">
                            <Skeleton className="size-10 rounded-full" />
                            <Skeleton className="h-8 w-24 rounded-full" />
                        </div>
                        <div className="space-y-3">
                            <Skeleton className="h-10 w-3/4 max-w-lg" />
                            <Skeleton className="h-5 w-40" />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                            <Skeleton className="h-32 rounded-3xl" />
                            <Skeleton className="h-32 rounded-3xl" />
                            <Skeleton className="h-32 rounded-3xl" />
                        </div>
                        <Card className="border-none shadow-xl shadow-slate-200/50 dark:shadow-none rounded-3xl overflow-hidden">
                            <CardContent className="p-8 space-y-6">
                                <Skeleton className="h-10 w-full" />
                                <Skeleton className="h-24 w-full" />
                            </CardContent>
                        </Card>
                    </div>
                </div>
            </DashboardLayout>
        );
    }

    if (!assignment) {
        return (
            <DashboardLayout>
                <div className="flex flex-col items-center justify-center py-20">
                    <AlertCircle className="size-16 text-muted-foreground mb-4" />
                    <h1 className="text-2xl font-bold text-foreground">Assignment Not Found</h1>
                    <p className="text-muted-foreground mt-2">The assignment you're looking for doesn't exist.</p>
                    <Link to="/student/assignments" className="mt-4">
                        <Button>Back to Assignments</Button>
                    </Link>
                </div>
            </DashboardLayout>
        );
    }

    const statusConfig = getStatusConfig();
    const StatusIcon = statusConfig.icon;

    return (
        <DashboardLayout>
            <div className="min-h-full bg-slate-50/50 dark:bg-slate-950/20 p-0 sm:p-4 animate-in fade-in duration-500">
                <div className="max-w-7xl mx-auto space-y-4 sm:space-y-6 p-4 sm:p-6">
                    {/* Header Navigation */}
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate('/student/assignments')}
                            className="w-fit h-9 px-3 rounded-xl hover:bg-white dark:hover:bg-slate-900 shadow-sm gap-2"
                        >
                            <ArrowLeft className="size-4" />
                            <span className="text-xs font-bold uppercase tracking-wider">Back</span>
                        </Button>
                        <Badge variant="outline" className={cn("w-fit px-4 py-1.5 rounded-full font-bold text-[10px] sm:text-xs border-none shadow-sm capitalize", statusConfig.color)}>
                            <div className="size-1.5 sm:size-2 rounded-full bg-current mr-2 animate-pulse" />
                            {statusConfig.label}
                        </Badge>
                    </div>

                    {/* Title Section */}
                    <div className="space-y-1.5">
                        <h1 className="text-2xl sm:text-3xl lg:text-4xl font-black text-slate-900 dark:text-white tracking-tight leading-tight">
                            {assignment.title}
                        </h1>
                        {assignment.lecturer_name && (
                            <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400 font-bold text-xs sm:text-sm">
                                <User className="size-3.5 sm:size-4" />
                                <span>Prof. {assignment.lecturer_name}</span>
                            </div>
                        )}
                    </div>

                    {/* Key Info Grid */}
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 sm:gap-5">
                        <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-2xl sm:rounded-3xl overflow-hidden group">
                            <CardContent className="p-3 sm:p-4 flex items-center gap-3 sm:gap-4">
                                <div className="size-10 sm:size-12 rounded-xl sm:rounded-2xl bg-blue-500/10 flex items-center justify-center text-blue-600 dark:text-blue-400 group-hover:scale-110 transition-transform duration-300">
                                    <Calendar className="size-5 sm:size-6" />
                                </div>
                                <div className="min-w-0">
                                    <p className="text-[9px] sm:text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">Due Date</p>
                                    <p className="text-sm sm:text-lg font-black text-slate-900 dark:text-white truncate">
                                        {assignment.due_date ? format(new Date(assignment.due_date), "MMM d") : "No date"}
                                    </p>
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-2xl sm:rounded-3xl overflow-hidden group">
                            <CardContent className="p-3 sm:p-4 flex items-center gap-3 sm:gap-4">
                                <div className="size-10 sm:size-12 rounded-xl sm:rounded-2xl bg-purple-500/10 flex items-center justify-center text-purple-600 dark:text-purple-400 group-hover:scale-110 transition-transform duration-300">
                                    <Clock className="size-5 sm:size-6" />
                                </div>
                                <div className="min-w-0">
                                    <p className="text-[9px] sm:text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">Time</p>
                                    <p className="text-sm sm:text-lg font-black text-slate-900 dark:text-white truncate">
                                        {assignment.due_date ? format(new Date(assignment.due_date), "h:mm a") : "N/A"}
                                    </p>
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-2xl sm:rounded-3xl overflow-hidden group col-span-2 sm:col-span-1">
                            <CardContent className="p-3 sm:p-4 flex items-center gap-3 sm:gap-4 justify-center sm:justify-start">
                                <div className="size-10 sm:size-12 rounded-xl sm:rounded-2xl bg-orange-500/10 flex items-center justify-center text-orange-600 dark:text-orange-400 group-hover:scale-110 transition-transform duration-300">
                                    <Trophy className="size-5 sm:size-6" />
                                </div>
                                <div className="min-w-0">
                                    <p className="text-[9px] sm:text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5 text-center sm:text-left">Max Score</p>
                                    <p className="text-sm sm:text-lg font-black text-slate-900 dark:text-white">
                                        {assignment.max_points} pts
                                    </p>
                                </div>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Assignment Details */}
                    <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-3xl overflow-hidden">
                        <CardHeader className="p-5 sm:p-6 pb-2">
                            <CardTitle className="flex items-center gap-3 text-base sm:text-lg font-black">
                                <FileText className="size-5 text-blue-500" />
                                Assignment Details
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="p-5 sm:p-6 pt-0 space-y-5">
                            {assignment.description && (
                                <div className="space-y-2">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Description</p>
                                    <p className="text-slate-600 dark:text-slate-300 text-base sm:text-lg leading-relaxed whitespace-pre-wrap">
                                        {assignment.description}
                                    </p>
                                </div>
                            )}

                            {assignment.attachment_url && (
                                <div className="space-y-4 pt-5 border-t border-slate-100 dark:border-slate-800">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Resource Material</p>
                                    <div className="flex flex-col sm:flex-row items-center gap-4 p-4 rounded-2xl bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-800 group transition-all">
                                        <div className="size-10 sm:size-12 rounded-xl bg-white dark:bg-slate-900 flex items-center justify-center text-blue-500 shadow-sm border border-slate-100 dark:border-slate-800">
                                            <FileText className="size-5 sm:size-6" />
                                        </div>
                                        <div className="flex-1 text-center sm:text-left min-w-0">
                                            <p className="font-bold text-sm sm:text-base text-slate-900 dark:text-white truncate">
                                                {assignment.attachment_name || 'Instructions.pdf'}
                                            </p>
                                            <p className="text-xs text-slate-500 font-bold uppercase tracking-tight">Support Resource</p>
                                        </div>
                                        <Button
                                            onClick={() => window.open(assignment.attachment_url!, '_blank')}
                                            className="w-full sm:w-auto bg-slate-900 hover:bg-black text-white px-5 h-10 rounded-xl font-bold gap-2 text-xs"
                                        >
                                            <Download className="size-3.5" />
                                            Download
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* Submission Section */}
                    {submission ? (
                        <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-3xl overflow-hidden">
                            <CardHeader className="p-5 sm:p-6 pb-2">
                                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                                    <CardTitle className="flex items-center gap-3 text-base sm:text-lg font-black text-emerald-600 dark:text-emerald-400">
                                        <CheckCircle className="size-5" />
                                        Your Submission
                                    </CardTitle>
                                    {new Date(submission.submitted_at) <= new Date(assignment.due_date || submission.submitted_at) && (
                                        <Badge className="w-fit bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-none font-black text-[9px] px-3">
                                            ON TIME
                                        </Badge>
                                    )}
                                </div>
                                <p className="text-slate-400 text-xs sm:text-sm font-bold mt-1 uppercase tracking-tight">
                                    Submitted {format(new Date(submission.submitted_at), "MMM d, h:mm a")}
                                </p>
                            </CardHeader>
                            <CardContent className="p-5 sm:p-6 pt-2 space-y-5">
                                <div className="space-y-4">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Submitted File</p>
                                    <div className="flex flex-col sm:flex-row items-center gap-4 p-4 rounded-2xl bg-emerald-50/50 dark:bg-emerald-500/5 border border-emerald-100 dark:border-emerald-500/10 group transition-all">
                                        <div className="size-10 sm:size-12 rounded-xl bg-white dark:bg-slate-900 flex items-center justify-center text-emerald-600 shadow-sm border border-emerald-100 dark:border-emerald-800">
                                            <FileText className="size-5 sm:size-6" />
                                        </div>
                                        <div className="flex-1 text-center sm:text-left min-w-0">
                                            <p className="font-bold text-sm sm:text-base text-slate-900 dark:text-white truncate">
                                                {submission.attachment_name || 'My_Submission.pdf'}
                                            </p>
                                            <div className="flex items-center justify-center sm:justify-start gap-2 mt-1">
                                                <Badge variant="outline" className="text-[9px] font-bold uppercase tracking-wider py-0 px-2 bg-slate-900 text-white border-none">
                                                    {getFileTypeDisplay(submission.file_type) || "PDF"}
                                                </Badge>
                                                {submission.file_size && (
                                                    <span className="text-[10px] text-slate-400 font-bold uppercase">
                                                        {formatFileSize(submission.file_size)}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                        <div className="flex gap-2 w-full sm:w-auto">
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => window.open(submission.attachment_url!, '_blank')}
                                                className="flex-1 sm:flex-none border-slate-200 dark:border-slate-800 rounded-xl font-bold gap-2 h-10 px-4 text-xs"
                                            >
                                                <Eye className="size-3.5" />
                                                View
                                            </Button>
                                            <Button
                                                asChild
                                                size="sm"
                                                className="flex-1 sm:flex-none bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold gap-2 shadow-lg shadow-emerald-500/20 h-10 px-4 text-xs"
                                            >
                                                <a href={submission.attachment_url!} target="_blank" rel="noreferrer" download>
                                                    <Download className="size-3.5" />
                                                    Download
                                                </a>
                                            </Button>
                                        </div>
                                    </div>
                                </div>

                                {submission.submission_text && (
                                    <div className="space-y-4 pt-6 border-t border-slate-100 dark:border-slate-800">
                                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Your Notes</p>
                                        <div className="p-6 rounded-2xl bg-slate-50 dark:bg-slate-800/80 border border-slate-200 dark:border-slate-800 italic text-slate-600 dark:text-slate-300">
                                            "{submission.submission_text}"
                                        </div>
                                    </div>
                                )}

                                {submission.status === 'graded' && (
                                    <div className="pt-8 space-y-8 border-t border-slate-100 dark:border-slate-800">
                                        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
                                            <div className="flex items-center gap-4">
                                                <div className="size-16 rounded-2xl bg-blue-600 flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
                                                    <Sparkles className="size-8" />
                                                </div>
                                                <div>
                                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Assignment Grade</p>
                                                    <p className="text-3xl font-black text-slate-900 dark:text-white">
                                                        {submission.grade} <span className="text-lg text-slate-400 font-bold">/ {assignment.max_points}</span>
                                                    </p>
                                                </div>
                                            </div>

                                            {submission.feedback && (
                                                <div className="flex items-center gap-2 text-emerald-500 font-bold text-sm bg-emerald-500/10 px-4 py-2 rounded-full">
                                                    <CheckCircle className="size-4" />
                                                    Graded & Reviewed
                                                </div>
                                            )}
                                        </div>

                                        {submission.feedback && (
                                            <div className="p-5 sm:p-8 rounded-2xl sm:rounded-3xl bg-blue-50/50 dark:bg-blue-500/5 border border-blue-100 dark:border-blue-500/10 relative overflow-hidden group">
                                                <div className="absolute top-0 right-0 p-4 opacity-[0.03] group-hover:opacity-[0.05] transition-opacity">
                                                    <MessageSquare className="size-20 sm:size-32" />
                                                </div>
                                                <div className="flex items-center gap-2 mb-3 text-blue-600 dark:text-blue-400 relative z-10">
                                                    <MessageSquare className="size-3.5 sm:size-4" />
                                                    <span className="text-[10px] font-bold uppercase tracking-widest">Instructor Feedback</span>
                                                </div>
                                                <p className="text-slate-600 dark:text-slate-300 text-base sm:text-lg leading-relaxed italic relative z-10">
                                                    "{submission.feedback}"
                                                </p>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    ) : (
                        <Card className="border-none bg-white dark:bg-slate-900 shadow-xl shadow-slate-200/50 dark:shadow-none rounded-3xl overflow-hidden text-center p-8 sm:p-12 lg:p-20">
                            <div className="size-16 sm:size-24 rounded-2xl sm:rounded-3xl bg-blue-500/10 flex items-center justify-center text-blue-600 mx-auto mb-6 sm:mb-8 animate-bounce">
                                <Upload className="size-8 sm:size-10" />
                            </div>
                            <h2 className="text-2xl sm:text-3xl font-black text-slate-900 dark:text-white mb-3 sm:mb-4">Ready to submit?</h2>
                            <p className="text-slate-500 dark:text-slate-400 font-bold max-w-md mx-auto mb-8 sm:mb-10 text-sm sm:text-lg">
                                Upload your assignment file to submit your work. Review all instructions before finalizing.
                            </p>
                            <Button
                                size="lg"
                                onClick={() => setIsSubmitOpen(true)}
                                className={cn(
                                    "w-full sm:w-auto h-14 sm:h-16 px-10 sm:px-12 rounded-2xl font-black text-base sm:text-lg gap-3 transition-all active:scale-95 shadow-2xl",
                                    assignment.due_date && new Date(assignment.due_date) < new Date()
                                        ? "bg-red-500 hover:bg-red-600 shadow-red-500/20"
                                        : "bg-blue-600 hover:bg-blue-700 shadow-blue-600/20"
                                )}
                            >
                                <Upload className="size-5 sm:size-6" />
                                {assignment.due_date && new Date(assignment.due_date) < new Date()
                                    ? "Submit Late"
                                    : "Submit Now"}
                            </Button>
                        </Card>
                    )}

                </div>
            </div>

            {/* Submit Dialog */}
            <SubmitAssignmentDialog
                isOpen={isSubmitOpen}
                onClose={() => setIsSubmitOpen(false)}
                assignment={assignment}
                onSubmit={submitAssignment}
            />
        </DashboardLayout>
    );
}

import { useState, useEffect } from "react";
import { useNavigate } from 'react-router-dom';
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { AssignmentCard } from '@/components/assignments/AssignmentCard';
import { PremiumStatsCard } from "@/components/dashboard/PremiumStatsCard";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Calendar, Clock, FileText, CheckCircle, AlertCircle, TrendingUp, BookOpen, CheckCircle2, GraduationCap, Search, LayoutGrid, List, Filter } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuRadioGroup,
    DropdownMenuRadioItem,
    DropdownMenuTrigger
} from "@/components/ui/dropdown-menu";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useAssignments } from "@/hooks/useAssignments";
import { SubmitAssignmentDialog } from "@/components/assignments/SubmitAssignmentDialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Skeleton } from "@/components/ui/skeleton";
import { PremiumCardSkeleton } from "@/components/skeletons/PremiumCardSkeleton";

type FilterType = "all" | "pending" | "submitted" | "overdue" | "graded";

export default function StudentAssignments() {
    const navigate = useNavigate();
    const { role, profile, updateProfile: syncProfile } = useAuth();
    const [selectedClassId, setSelectedClassId] = useState<string>("");

    const {
        assignments,
        loading,
        submitAssignment,
        deleteSubmission,
        refreshAssignments,
        stats,
        enrolledClasses
    } = useAssignments(selectedClassId);

    const [filter, setFilter] = useState<FilterType>("all");
    const [selectedAssignment, setSelectedAssignment] = useState<any | null>(null);
    const [isSubmitOpen, setIsSubmitOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [isDeleting, setIsDeleting] = useState(false);

    // Initial load: Set class from profile or first available
    useEffect(() => {
        if (enrolledClasses && enrolledClasses.length > 0 && !selectedClassId) {
            const lastId = profile?.last_selected_class_id;
            const isValid = lastId && enrolledClasses.some(c => c.id === lastId);

            if (isValid) {
                setSelectedClassId(lastId);
            } else {
                setSelectedClassId(enrolledClasses[0].id);
            }
        }
    }, [enrolledClasses, profile, selectedClassId]);

    const handleClassChange = (newVal: string) => {
        setSelectedClassId(newVal);
        syncProfile({ last_selected_class_id: newVal });
    };

    const filteredAssignments = assignments.filter((assignment) => {
        if (filter === "all") return true;
        if (filter === "submitted" && (assignment.studentStatus === "submitted" || assignment.studentStatus === "graded")) return true;
        return assignment.studentStatus === filter;
    }).filter(assignment =>
        assignment.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        assignment.course_code?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const handleSubmitClick = (assignment: any) => {
        setSelectedAssignment(assignment);
        setIsSubmitOpen(true);
    };

    const getStatusVariant = (status: string) => {
        switch (status) {
            case 'graded':
                return 'success';
            case 'submitted':
                return 'default';
            case 'overdue':
                return 'destructive';
            default:
                return 'secondary';
        }
    };

    // Use the stored assignment for the dialog, but sync it with latest data if available
    const activeAssignment = assignments.find(a => a.id === selectedAssignment?.id) || selectedAssignment;

    return (
        <DashboardLayout>
            <div className="w-full flex flex-col gap-0 animate-in fade-in duration-500">
                <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
                    <div>
                        <h1 className="text-4xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-slate-900 to-slate-700 dark:from-white dark:to-slate-300">
                            Assignments
                        </h1>
                        <p className="text-muted-foreground text-lg mt-2">
                            Stay on top of your coursework and deadlines
                        </p>
                    </div>

                </div>

                {/* Premium Stats Cards */}
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 sm:gap-4 mt-4 sm:mt-6">
                    <PremiumStatsCard
                        title="TOTAL"
                        value={stats.total}
                        subtitle="Active assignments"
                        icon={BookOpen}
                        backgroundColor="bg-gradient-to-br from-blue-600 to-indigo-700"
                        iconBackgroundColor="bg-white/10"
                    />
                    <PremiumStatsCard
                        title="COMPLETED"
                        value={stats.completed}
                        subtitle="Tasks finished"
                        icon={CheckCircle2}
                        backgroundColor="bg-gradient-to-br from-green-600 to-emerald-700"
                        iconBackgroundColor="bg-white/10"
                    />
                    <PremiumStatsCard
                        title="PENDING"
                        value={stats.pending}
                        subtitle="Require attention"
                        icon={Clock}
                        backgroundColor="bg-gradient-to-br from-amber-500 to-orange-600"
                        iconBackgroundColor="bg-white/10"
                        className="col-span-2 sm:col-span-1"
                    />
                </div>

                {loading && (enrolledClasses?.length === 0) ? (
                    <div className={cn(
                        viewMode === 'grid'
                            ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                            : "flex flex-col gap-3 max-w-4xl mx-auto"
                    )}>
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <PremiumCardSkeleton key={i} viewMode={viewMode} />
                        ))}
                    </div>
                ) : enrolledClasses && enrolledClasses.length > 0 ? (
                    <Tabs value={selectedClassId} onValueChange={handleClassChange} className="w-full mt-8">
                        <div className="w-full overflow-hidden">
                            <TabsList className="bg-transparent h-auto w-full justify-start gap-3 p-1 overflow-x-auto pb-4 snap-x pr-20 no-scrollbar">
                                {enrolledClasses.map((cls) => (
                                    <TabsTrigger
                                        key={cls.id}
                                        value={cls.id}
                                        className={cn(
                                            "relative flex items-center gap-2 sm:gap-3 pl-1 sm:pl-2 pr-3 sm:pr-6 py-1.5 sm:py-2 rounded-full border transition-all duration-300 min-w-0 sm:min-w-[160px] snap-start",
                                            "data-[state=active]:bg-blue-600 data-[state=active]:text-white data-[state=active]:border-blue-500 data-[state=active]:shadow-lg data-[state=active]:shadow-blue-500/20",
                                            "data-[state=inactive]:bg-white dark:data-[state=inactive]:bg-slate-800/80 data-[state=inactive]:hover:bg-slate-50 dark:data-[state=inactive]:hover:bg-slate-800 data-[state=inactive]:border-slate-200 dark:data-[state=inactive]:border-slate-700 data-[state=inactive]:text-slate-600 dark:data-[state=inactive]:text-slate-400",
                                            "group overflow-hidden tap-highlight-transparent"
                                        )}
                                    >
                                        <div className={cn(
                                            "flex items-center justify-center w-7 h-7 sm:w-10 sm:h-10 rounded-full font-bold text-[10px] sm:text-xs shrink-0 transition-colors",
                                            selectedClassId === cls.id
                                                ? "bg-white/20 text-white"
                                                : "bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-400 group-hover:bg-slate-200 dark:group-hover:bg-slate-700"
                                        )}>
                                            {cls.course_code.slice(0, 2).toUpperCase()}
                                        </div>
                                        <div className="flex flex-col items-start text-left truncate min-w-0 flex-1">
                                            <span className={cn(
                                                "font-bold text-[7px] sm:text-[10px] uppercase tracking-wider mb-0 sm:mb-0.5 opacity-70",
                                            )}>
                                                {cls.course_code}
                                            </span>
                                            <span className="font-bold text-[10px] sm:text-sm truncate w-full sm:max-w-[120px] leading-none">
                                                {cls.class_name}
                                            </span>
                                        </div>
                                    </TabsTrigger>
                                ))}
                            </TabsList>
                        </div>

                        {/* Content Area - Direct Render */}
                        <div className="mt-2 space-y-6">
                            {(assignments.length > 0 || loading) && (
                                <div className="flex flex-col xl:flex-row gap-4 items-center justify-between p-1">
                                    <div className="grid grid-cols-5 sm:hidden items-center gap-1 sm:gap-2 w-full sm:w-auto p-1 bg-slate-100/50 dark:bg-slate-800/50 rounded-xl shrink-0">
                                        {(['all', 'pending', 'submitted', 'graded', 'overdue'] as FilterType[]).map((f) => (
                                            <Button
                                                key={f}
                                                variant={filter === f ? "default" : "ghost"}
                                                size="sm"
                                                onClick={() => setFilter(f)}
                                                className={cn(
                                                    "capitalize whitespace-nowrap rounded-lg px-0.5 sm:px-4 text-[10px] sm:text-sm font-black transition-all h-8 flex-1 sm:flex-none",
                                                    filter === f
                                                        ? "bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-indigo-400"
                                                        : "text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100"
                                                )}
                                            >
                                                {f}
                                            </Button>
                                        ))}
                                    </div>

                                    <div className="flex items-center gap-3 w-full xl:flex-1 overflow-hidden">
                                        <div className="hidden sm:block">
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        className="h-9 shrink-0 gap-2 border-slate-200 dark:border-white/5 bg-white dark:bg-slate-900 rounded-xl font-bold text-slate-600 dark:text-slate-300"
                                                    >
                                                        <Filter className="size-4" />
                                                        <span className="hidden lg:inline capitalize">{filter}</span>
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align="start" className="w-48 rounded-xl p-2 bg-white dark:bg-slate-900 border-slate-200 dark:border-white/10">
                                                    <div className="px-2 py-1.5 text-xs font-black text-slate-400 uppercase tracking-widest">Filter Status</div>
                                                    <DropdownMenuRadioGroup value={filter} onValueChange={(val) => setFilter(val as FilterType)}>
                                                        {(['all', 'pending', 'submitted', 'graded', 'overdue'] as FilterType[]).map((f) => (
                                                            <DropdownMenuRadioItem
                                                                key={f}
                                                                value={f}
                                                                className="capitalize rounded-lg focus:bg-blue-500/10 focus:text-blue-500 cursor-pointer font-bold"
                                                            >
                                                                {f}
                                                            </DropdownMenuRadioItem>
                                                        ))}
                                                    </DropdownMenuRadioGroup>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        </div>

                                        <div className="relative flex-1">
                                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                            <Input
                                                placeholder="Search assignments..."
                                                className="pl-9 h-9 bg-background border-border/60 focus-visible:ring-1"
                                                value={searchQuery}
                                                onChange={(e: any) => setSearchQuery(e.target.value)}
                                            />
                                        </div>

                                        <div className="flex sm:hidden items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shrink-0">
                                            <Button
                                                variant={viewMode === 'grid' ? 'default' : 'ghost'}
                                                size="sm"
                                                onClick={() => setViewMode('grid')}
                                                className={cn("h-8 w-10 px-0 rounded-lg transition-all", viewMode === 'grid' ? "bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400" : "text-slate-500")}
                                            >
                                                <LayoutGrid className="size-4" />
                                            </Button>
                                            <Button
                                                variant={viewMode === 'list' ? 'default' : 'ghost'}
                                                size="sm"
                                                onClick={() => setViewMode('list')}
                                                className={cn("h-8 w-10 px-0 rounded-lg transition-all", viewMode === 'list' ? "bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400" : "text-slate-500")}
                                            >
                                                <List className="size-4" />
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {(loading || isDeleting) ? (
                                <div className={cn(
                                    viewMode === 'grid'
                                        ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                                        : "flex flex-col gap-3 max-w-4xl mx-auto"
                                )}>
                                    {[1, 2, 3, 4, 5, 6].map((i) => (
                                        <PremiumCardSkeleton key={i} viewMode={viewMode} />
                                    ))}
                                </div>
                            ) : filteredAssignments.length === 0 ? (
                                <Card className="border-dashed">
                                    <CardContent className="flex flex-col items-center justify-center py-16 text-center">
                                        <div className="p-4 rounded-full bg-muted mb-4">
                                            <BookOpen className="w-8 h-8 text-muted-foreground" />
                                        </div>
                                        <h3 className="text-xl font-semibold mb-2">No assignments found</h3>
                                        <p className="text-muted-foreground max-w-sm mb-6">
                                            {filter === 'all' && !searchQuery
                                                ? "You don't have any assignments for this class yet."
                                                : "Try adjusting your filters or search query."}
                                        </p>
                                        {(filter !== 'all' || searchQuery) && (
                                            <Button variant="outline" onClick={() => { setFilter('all'); setSearchQuery(''); }}>
                                                Clear Filters
                                            </Button>
                                        )}
                                    </CardContent>
                                </Card>
                            ) : (
                                <div className={cn(
                                    viewMode === 'grid'
                                        ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                                        : "flex flex-col gap-3 max-w-4xl mx-auto"
                                )}>
                                    {filteredAssignments.map((assignment) => (
                                        <AssignmentCard
                                            key={assignment.id}
                                            assignment={{
                                                ...assignment,
                                                status: (assignment.studentStatus || assignment.status || 'pending') as any,
                                                points: assignment.max_points,
                                            }}
                                            role="student"
                                            viewMode={viewMode}
                                            onView={(id) => navigate(`/student/assignments/${id}`)}
                                            onSubmit={handleSubmitClick}
                                            onDelete={assignment.studentStatus === 'submitted' ? async (id) => {
                                                const submission = assignment.submission;
                                                if (submission?.id) {
                                                    setIsDeleting(true);
                                                    const result = await deleteSubmission(submission.id);
                                                    if (result.success) {
                                                        toast.success("Submission deleted successfully");
                                                        // Manually refresh to ensure UI updates
                                                        await refreshAssignments(true);
                                                    } else {
                                                        toast.error(result.error || "Failed to delete submission");
                                                    }
                                                    setIsDeleting(false);
                                                }
                                            } : undefined}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>
                    </Tabs>
                ) : (
                    <Card className="border-dashed border-2 bg-muted/20 rounded-3xl">
                        <CardContent className="flex flex-col items-center justify-center py-24 text-center">
                            <div className="p-6 rounded-full bg-primary/10 mb-6">
                                <BookOpen className="size-16 text-primary" />
                            </div>
                            <h3 className="text-2xl font-bold mb-3">No Classes Enrolled!</h3>
                            <p className="text-muted-foreground text-lg max-w-md mx-auto">
                                You need to join a class before you can see any assignments.
                            </p>
                        </CardContent>
                    </Card>
                )}
            </div>

            {activeAssignment && (
                <SubmitAssignmentDialog
                    isOpen={isSubmitOpen && !!activeAssignment}
                    onClose={() => setIsSubmitOpen(false)}
                    assignment={activeAssignment}
                    onSubmit={submitAssignment}
                    onDelete={async (submissionId) => {
                        setIsDeleting(true);
                        const result = await deleteSubmission(submissionId);
                        if (result.success) {
                            toast.success("Submission deleted successfully");
                            setIsSubmitOpen(false);
                            // Manually refresh to ensure UI updates
                            await refreshAssignments(true);
                        } else {
                            toast.error(result.error || "Failed to delete submission");
                        }
                        setIsDeleting(false);
                    }}
                />
            )}

        </DashboardLayout>
    );
}

import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent } from '@/components/ui/card';
import { QuizCard } from '@/components/student/QuizCard';
import { Button } from '@/components/ui/button';
import { FileText, LayoutGrid, List, Search, Filter } from 'lucide-react';
import { cn } from "@/lib/utils";
import { Input } from "@/components/ui/input";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuRadioGroup,
    DropdownMenuRadioItem,
    DropdownMenuTrigger
} from "@/components/ui/dropdown-menu";
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStudentQuizzes } from '@/hooks/useStudentQuizzes';
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Skeleton } from "@/components/ui/skeleton";
import { PremiumCardSkeleton } from "@/components/skeletons/PremiumCardSkeleton";
import { useAuth } from '@/contexts/AuthContext';

export default function StudentQuizzes() {
    const navigate = useNavigate();
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [selectedClassId, setSelectedClassId] = useState<string>('');
    const [searchQuery, setSearchQuery] = useState("");
    const [filter, setFilter] = useState<"all" | "pending" | "submitted">("all");
    const { profile, updateProfile: syncProfile } = useAuth();
    const { quizzes, loading, enrolledClasses } = useStudentQuizzes(selectedClassId);

    const filteredQuizzes = quizzes.filter((quiz) => {
        const submissionStatus = quiz.my_submission?.status;
        if (filter === "all") return true;
        if (filter === "pending") return submissionStatus === "pending";
        if (filter === "submitted") return submissionStatus === "passed" || submissionStatus === "failed";
        return true;
    }).filter(quiz =>
        quiz.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        quiz.classes?.course_code?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Initial load: Set class from profile or first available
    useEffect(() => {
        if (enrolledClasses.length > 0 && !selectedClassId) {
            const lastId = profile?.last_selected_class_id;
            const isValid = lastId && enrolledClasses.some(c => c.id === lastId);

            if (isValid) {
                setSelectedClassId(lastId);
            } else {
                setSelectedClassId(enrolledClasses[0].id);
            }
        }
    }, [enrolledClasses, profile, selectedClassId]);

    const handleClassChange = (newVal: string) => {
        setSelectedClassId(newVal);
        syncProfile({ last_selected_class_id: newVal });
    };

    const handleAttempt = (quizId: string) => {
        navigate(`/student/quizzes/${quizId}`);
    };

    return (
        <DashboardLayout>
            <div className="w-full h-full flex flex-col gap-6 animate-in fade-in duration-500 overflow-y-auto">
                <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 px-4 pt-4">
                    <div className="flex items-center gap-3">
                        <div className="size-12 rounded-2xl bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-600/20 shrink-0">
                            <FileText className="size-6 text-white" />
                        </div>
                        <div>
                            <span className="text-[10px] font-black tracking-[0.2em] text-indigo-500 uppercase">Assessment</span>
                            <h1 className="text-2xl font-black text-slate-800 dark:text-white">Active Quizzes</h1>
                        </div>
                    </div>
                </div>

                {loading && enrolledClasses.length === 0 ? (
                    <div className={cn(
                        viewMode === 'grid'
                            ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                            : "flex flex-col gap-3 max-w-4xl mx-auto"
                    )}>
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <PremiumCardSkeleton key={i} viewMode={viewMode} />
                        ))}
                    </div>
                ) : enrolledClasses.length > 0 ? (
                    <Tabs value={selectedClassId} onValueChange={handleClassChange} className="w-full">
                        <div className="w-full overflow-hidden">
                            <TabsList className="bg-transparent h-auto w-full justify-start gap-3 p-1 overflow-x-auto pb-4 snap-x pr-20 no-scrollbar">
                                {enrolledClasses.map((cls) => (
                                    <TabsTrigger
                                        key={cls.id}
                                        value={cls.id}
                                        className={cn(
                                            "relative flex items-center gap-2 sm:gap-3 pl-1 sm:pl-2 pr-3 sm:pr-6 py-1.5 sm:py-2 rounded-full border transition-all duration-300 min-w-0 sm:min-w-[160px] snap-start",
                                            "data-[state=active]:bg-blue-600 data-[state=active]:text-white data-[state=active]:border-blue-500 data-[state=active]:shadow-lg data-[state=active]:shadow-blue-500/20",
                                            "data-[state=inactive]:bg-white dark:data-[state=inactive]:bg-slate-800/80 data-[state=inactive]:hover:bg-slate-50 dark:data-[state=inactive]:hover:bg-slate-800 data-[state=inactive]:border-slate-200 dark:data-[state=inactive]:border-slate-700 data-[state=inactive]:text-slate-600 dark:data-[state=inactive]:text-slate-400",
                                            "group overflow-hidden tap-highlight-transparent"
                                        )}
                                    >
                                        <div className={cn(
                                            "flex items-center justify-center w-7 h-7 sm:w-10 sm:h-10 rounded-full font-bold text-[10px] sm:text-xs shrink-0 transition-colors",
                                            selectedClassId === cls.id
                                                ? "bg-white/20 text-white"
                                                : "bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-400 group-hover:bg-slate-200 dark:group-hover:bg-slate-700"
                                        )}>
                                            {cls.course_code.slice(0, 2).toUpperCase()}
                                        </div>
                                        <div className="flex flex-col items-start text-left truncate min-w-0 flex-1">
                                            <span className={cn(
                                                "font-bold text-[7px] sm:text-[10px] uppercase tracking-wider mb-0 sm:mb-0.5 opacity-70",
                                            )}>
                                                {cls.course_code}
                                            </span>
                                            <span className="font-bold text-[10px] sm:text-sm truncate w-full sm:max-w-[120px] leading-none">
                                                {cls.class_name}
                                            </span>
                                        </div>
                                    </TabsTrigger>
                                ))}
                            </TabsList>
                        </div>

                        <div className="mt-4 flex flex-col xl:flex-row gap-4 items-center justify-between p-1">
                            <div className="flex items-center gap-3 w-full xl:flex-1 overflow-hidden">
                                <div className="hidden sm:block">
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                className="h-9 shrink-0 gap-2 border-slate-200 dark:border-white/5 bg-white dark:bg-slate-900 rounded-xl font-bold text-slate-600 dark:text-slate-300"
                                            >
                                                <Filter className="size-4" />
                                                <span className="hidden lg:inline capitalize">{filter}</span>
                                            </Button>
                                        </DropdownMenuTrigger>
                                        <DropdownMenuContent align="start" className="w-48 rounded-xl p-2 bg-white dark:bg-slate-900 border-slate-200 dark:border-white/10">
                                            <div className="px-2 py-1.5 text-xs font-black text-slate-400 uppercase tracking-widest">Filter Status</div>
                                            <DropdownMenuRadioGroup value={filter} onValueChange={(val) => setFilter(val as any)}>
                                                {['all', 'pending', 'submitted'].map((f) => (
                                                    <DropdownMenuRadioItem
                                                        key={f}
                                                        value={f}
                                                        className="capitalize rounded-lg focus:bg-indigo-500/10 focus:text-indigo-500 cursor-pointer font-bold"
                                                    >
                                                        {f}
                                                    </DropdownMenuRadioItem>
                                                ))}
                                            </DropdownMenuRadioGroup>
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </div>

                                <div className="relative flex-1">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                    <Input
                                        placeholder="Search quizzes..."
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        className="pl-10 h-10 bg-white/50 dark:bg-slate-800/50 border-none shadow-sm focus-visible:ring-2 focus-visible:ring-indigo-500/20 text-sm rounded-xl"
                                    />
                                </div>

                                <div className="flex sm:hidden items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shrink-0">
                                    <Button
                                        variant={viewMode === 'grid' ? 'default' : 'ghost'}
                                        size="sm"
                                        onClick={() => setViewMode('grid')}
                                        className={cn("h-8 w-10 px-0 rounded-lg transition-all", viewMode === 'grid' ? "bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400" : "text-slate-500")}
                                    >
                                        <LayoutGrid className="size-4" />
                                    </Button>
                                    <Button
                                        variant={viewMode === 'list' ? 'default' : 'ghost'}
                                        size="sm"
                                        onClick={() => setViewMode('list')}
                                        className={cn("h-8 w-10 px-0 rounded-lg transition-all", viewMode === 'list' ? "bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400" : "text-slate-500")}
                                    >
                                        <List className="size-4" />
                                    </Button>
                                </div>
                            </div>
                        </div>

                        {/* Content Area - Rendered directly based on selection, not inside TabsContent to ensure updates */}
                        <div className="mt-4">
                            {loading ? (
                                <div className={cn(
                                    viewMode === 'grid'
                                        ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                                        : "flex flex-col gap-3 max-w-4xl mx-auto"
                                )}>
                                    {[1, 2, 3, 4, 5, 6].map((i) => (
                                        <PremiumCardSkeleton key={i} viewMode={viewMode} />
                                    ))}
                                </div>
                            ) : filteredQuizzes.length === 0 ? (
                                <Card className="border-dashed border-2 bg-muted/20 rounded-3xl">
                                    <CardContent className="flex flex-col items-center justify-center py-24 text-center">
                                        <div className="p-6 rounded-full bg-primary/10 mb-6">
                                            <FileText className="size-16 text-primary" />
                                        </div>
                                        <h3 className="text-2xl font-bold mb-3">No Quizzes Available</h3>
                                        <p className="text-muted-foreground text-lg max-w-md mx-auto">
                                            There are no published quizzes for this class yet. Check back later!
                                        </p>
                                    </CardContent>
                                </Card>
                            ) : (
                                <div className={cn(
                                    viewMode === 'grid'
                                        ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6 gap-4"
                                        : "flex flex-col gap-3 max-w-4xl mx-auto"
                                )}>
                                    {filteredQuizzes.map((quiz) => (
                                        <QuizCard
                                            key={quiz.id}
                                            quiz={quiz}
                                            viewMode={viewMode}
                                            onAttempt={handleAttempt}
                                            onViewDetails={(id) => navigate(`/student/quizzes/${id}/details`)}
                                            onViewLeaderboard={(quizId, classId) => navigate(`/student/quizzes/${classId}/${quizId}/results`)}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>
                    </Tabs>
                ) : (
                    <Card className="border-dashed border-2 bg-muted/20 rounded-3xl">
                        <CardContent className="flex flex-col items-center justify-center py-24 text-center">
                            <div className="p-6 rounded-full bg-primary/10 mb-6">
                                <FileText className="size-16 text-primary" />
                            </div>
                            <h3 className="text-2xl font-bold mb-3">No Classes Enrolled!</h3>
                            <p className="text-muted-foreground text-lg max-w-md mx-auto">
                                You need to join a class before you can see any quizzes.
                            </p>
                        </CardContent>
                    </Card>
                )}
            </div>
        </DashboardLayout>
    );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { Loader2, CheckCircle, XCircle, FileText, ChevronLeft, ChevronRight, Clock, Trophy, Target, ArrowLeft, Save, Download } from 'lucide-react';
import { DeleteConfirmDialog } from '@/components/layout/DeleteConfirmDialog';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { format } from 'date-fns';
import { QuizSkeleton } from '@/components/skeletons/QuizSkeleton';
import { notifyQuizSubmission } from '@/lib/notificationService';
import { useStreak } from '@/contexts/StreakContext';
import { knowledgeService } from '@/lib/knowledgeService';

export default function TakeQuiz() {
    const { quizId } = useParams();
    const navigate = useNavigate();
    const { user, profile } = useAuth();

    const [quiz, setQuiz] = useState<any>(null);
    const [questions, setQuestions] = useState<any[]>([]);
    const [answers, setAnswers] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [result, setResult] = useState<any>(null);
    const [submissionId, setSubmissionId] = useState<string | null>(null);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [rank, setRank] = useState<{ position: number, total: number } | null>(null);
    const [elapsedTime, setElapsedTime] = useState<number>(0);
    const [isConfirmSubmitOpen, setIsConfirmSubmitOpen] = useState(false);
    const timerRef = useRef<NodeJS.Timeout | null>(null);
    const startTimeRef = useRef<number>(Date.now());

    // LocalStorage keys for persistence
    const getStorageKey = (key: string) => `quiz_${quizId}_${key}`;

    // Load saved quiz state from localStorage on mount
    useEffect(() => {
        if (!quizId) return;

        const savedIndex = localStorage.getItem(getStorageKey('currentIndex'));
        const savedStartTime = localStorage.getItem(getStorageKey('startTime'));

        if (savedIndex !== null) {
            setCurrentIndex(parseInt(savedIndex, 10));
        }

        // Initialize start time if not exists
        const startTimestamp = savedStartTime ? parseInt(savedStartTime, 10) : Date.now();
        startTimeRef.current = startTimestamp;
        if (!savedStartTime) {
            localStorage.setItem(getStorageKey('startTime'), startTimestamp.toString());
        }

        // Start timer — reads from ref so it can be reset mid-session
        timerRef.current = setInterval(() => {
            const elapsed = Math.floor((Date.now() - startTimeRef.current) / 1000);
            setElapsedTime(elapsed);
        }, 1000);

        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, [quizId]);

    // Save currentIndex to localStorage when it changes
    useEffect(() => {
        if (quizId && !result) {
            localStorage.setItem(getStorageKey('currentIndex'), currentIndex.toString());
        }
    }, [currentIndex, quizId, result]);

    // Clear localStorage when quiz is submitted
    const clearQuizStorage = () => {
        if (quizId) {
            localStorage.removeItem(getStorageKey('currentIndex'));
            localStorage.removeItem(getStorageKey('startTime'));
        }
    };

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    };

    useEffect(() => {
        const fetchQuizData = async () => {
            if (!quizId || !user) return;
            try {
                setLoading(true);
                const { data: quizData, error: quizError } = await supabase
                    .from('quizzes')
                    .select('*, classes(class_name)')
                    .eq('id', quizId)
                    .single();

                if (quizError) throw quizError;
                setQuiz(quizData);

                // Record academic action (Attempting a quiz)
                recordAcademicAction();

                // Check for existing ACTIVE submission (pending or completed, but not archived)
                // This is the SINGLE SOURCE OF TRUTH for preventing reattempts
                let { data: submission } = await supabase
                    .from('quiz_submissions')
                    .select('*')
                    .eq('quiz_id', quizId)
                    .eq('student_id', user.id)
                    .eq('is_archived', false) // Use active submissions only
                    .order('submitted_at', { ascending: false })
                    .limit(1)
                    .maybeSingle();

                // If submission exists and is completed, load answers and show result view
                if (submission && submission.status !== 'pending') {
                    console.log('Quiz already completed. Loading answers for result view.');

                    // Fetch the student's saved answers so the review section works
                    const { data: savedAnswers } = await supabase
                        .from('quiz_answers')
                        .select('question_id, selected_option')
                        .eq('submission_id', submission.id);

                    if (savedAnswers) {
                        const loadedAnswers: Record<string, string> = {};
                        savedAnswers.forEach((a: any) => {
                            loadedAnswers[a.question_id] = a.selected_option;
                        });
                        setAnswers(loadedAnswers);
                    }

                    // Also fetch questions so the review section can render
                    const { data: questionsData } = await supabase
                        .from('quiz_questions')
                        .select('*')
                        .eq('quiz_id', quizId)
                        .order('order_index');

                    if (questionsData) setQuestions(questionsData);

                    setResult(submission);
                    setLoading(false);
                    return;
                }

                // Check for version mismatch (Re-attempt Logic)
                if (submission && (submission.quiz_version || 1) < (quizData.version || 1)) {
                    console.log("Found outdated active submission. Archiving to allow re-take.");
                    // Archive the old submission
                    await supabase
                        .from('quiz_submissions')
                        .update({ is_archived: true })
                        .eq('id', submission.id);

                    // Clear saved quiz state and reset timer to 0
                    clearQuizStorage();
                    startTimeRef.current = Date.now();
                    localStorage.setItem(getStorageKey('startTime'), startTimeRef.current.toString());
                    setElapsedTime(0);
                    setCurrentIndex(0);

                    // Reset submission variable to trigger new creation
                    submission = null;
                }

                if (submission) {
                    setSubmissionId(submission.id);
                    if (submission.status === 'pending') {
                        setResult(null);
                        const { data: existingAnswers } = await supabase
                            .from('quiz_answers')
                            .select('question_id, selected_option')
                            .eq('submission_id', submission.id);

                        if (existingAnswers) {
                            const loadedAnswers: Record<string, string> = {};
                            existingAnswers.forEach((a: any) => {
                                loadedAnswers[a.question_id] = a.selected_option;
                            });
                            setAnswers(loadedAnswers);
                            toast.info('Resuming your quiz attempt');
                        }
                    } else {
                        // Submission is already completed (passed/failed) - REDIRECT TO RESULTS
                        console.log('Quiz already completed. Redirecting to results page.');
                        navigate(`/student/quizzes/${quizId}/details`);
                        return;
                    }
                }

                // Create new submission if none exists (or if we just archived the outdated one)
                if (!submission) {
                    // Try to create only if we didn't find one
                    const { data: newSubmission, error: createError } = await supabase
                        .from('quiz_submissions')
                        .insert({
                            quiz_id: quizId,
                            student_id: user.id,
                            total_obtained: 0,
                            status: 'pending',
                            quiz_version: quizData.version,
                            started_at: new Date().toISOString()
                        })
                        .select()
                        .single();

                    if (createError) {
                        // Handle unique constraint violation (race condition or filter mismatch)
                        if (createError.code === '23505') {
                            console.log('Found existing submission via uniqueness constraint, recovering...');
                            const { data: recoveredSub } = await supabase
                                .from('quiz_submissions')
                                .select('*')
                                .eq('quiz_id', quizId)
                                .eq('student_id', user.id)
                                .eq('status', 'pending')
                                .maybeSingle();

                            if (recoveredSub) {
                                setSubmissionId(recoveredSub.id);
                                // Should load answers here too technically, but usually new/empty
                            }
                        } else {
                            console.error('Error creating pending submission', createError);
                        }
                    } else if (newSubmission) {
                        setSubmissionId(newSubmission.id);
                    }
                }

                const { data: questionsData, error: questionsError } = await supabase
                    .from('quiz_questions')
                    .select('*')
                    .eq('quiz_id', quizId)
                    .order('order_index');

                if (questionsError) throw questionsError;
                setQuestions(questionsData || []);

            } catch (error: any) {
                console.error('Error loading quiz:', JSON.stringify(error, null, 2));
                toast.error(`Failed to load quiz: ${error.message || 'Unknown error'}`);
                navigate('/student/quizzes');
            } finally {
                setLoading(false);
            }
        };

        fetchQuizData();
    }, [quizId, user, navigate]);

    useEffect(() => {
        if (result && quizId) {
            const fetchRank = async () => {
                try {
                    const { count: higherScoresCount } = await supabase
                        .from('quiz_submissions')
                        .select('*', { count: 'exact', head: true })
                        .eq('quiz_id', quizId)
                        .gt('total_obtained', result.total_obtained);

                    const { count: totalSubmissions } = await supabase
                        .from('quiz_submissions')
                        .select('*', { count: 'exact', head: true })
                        .eq('quiz_id', quizId);

                    if (higherScoresCount !== null && totalSubmissions !== null) {
                        setRank({
                            position: higherScoresCount + 1,
                            total: totalSubmissions
                        });
                    }
                } catch (e) {
                    console.error("Error fetching rank", e);
                }
            };
            fetchRank();
        }
    }, [result, quizId]);

    const handleAnswerChange = async (questionId: string, optionId: string) => {
        setAnswers(prev => ({ ...prev, [questionId]: optionId }));

        if (submissionId) {
            const { error } = await supabase.from('quiz_answers').upsert({
                submission_id: submissionId,
                question_id: questionId,
                selected_option: optionId
            }, { onConflict: 'submission_id,question_id' } as any);

            if (error) console.error("Error auto-saving answer", error);
        }
    };

    const clearAnswer = () => {
        const currentQuestion = questions[currentIndex];
        if (currentQuestion) {
            setAnswers(prev => {
                const newAnswers = { ...prev };
                delete newAnswers[currentQuestion.id];
                return newAnswers;
            });
        }
    };

    const { recordAcademicAction } = useStreak();

    const handleSubmit = async () => {
        if (!user || !quiz) return;
        setIsConfirmSubmitOpen(false);

        // Record academic action (Submitting a quiz)
        await recordAcademicAction();
        if (result || (submissionId && !answers)) {
            toast.error("You have already submitted this quiz.");
            navigate(`/student/quizzes/${quizId}/details`);
            return;
        }

        setSubmitting(true);
        try {
            // Ensure submissionId exists
            let activeSubmissionId = submissionId;

            if (!activeSubmissionId) {
                console.log("No active submission ID, checking for existing pending submission...");

                // 1. Check for existing pending submission first
                const { data: existingSub } = await supabase
                    .from('quiz_submissions')
                    .select('id')
                    .eq('quiz_id', quizId)
                    .eq('student_id', user.id)
                    .eq('status', 'pending')
                    .maybeSingle();

                if (existingSub) {
                    console.log("Found existing pending submission:", existingSub.id);
                    activeSubmissionId = existingSub.id;
                    setSubmissionId(existingSub.id);
                } else {
                    // 2. Only create if no pending submission exists
                    console.log("No pending submission found, creating new one...");
                    const { data: newSub, error: createError } = await supabase
                        .from('quiz_submissions')
                        .insert({
                            quiz_id: quizId,
                            student_id: user.id,
                            total_obtained: 0,
                            status: 'pending'
                        })
                        .select()
                        .single();

                    if (createError) {
                        if (createError.code === '23505' || createError.message?.includes('duplicate key')) { // Unique violation code or message check
                            console.log('Duplicate key error detected. Attempting recovery via RPC...', { quizId, userId: user.id });

                            // Use RPC to bypass RLS and find the exact active submission
                            const { data: rpcResult, error: rpcError } = await supabase
                                .rpc('get_active_student_submission', {
                                    p_quiz_id: quizId,
                                    p_student_id: user.id
                                });

                            console.log('RPC Recovery Query Result:', { rpcResult, rpcError });

                            const retrySub = rpcResult as any;

                            if (retrySub) {
                                if (retrySub.status !== 'pending') {
                                    setResult(retrySub);
                                    toast.info('Quiz already submitted');
                                    return;
                                }
                                activeSubmissionId = retrySub.id;
                                setSubmissionId(retrySub.id);
                            } else {
                                console.error('Recovery failed: Active submission not found via RPC', rpcResult);
                                throw new Error(`Failed to create submission: Duplicate detected but active submission not found via RPC. IDs: Q=${quizId}, U=${user.id}`);
                            }
                        } else {
                            throw new Error(`Failed to create submission: ${createError.message}`);
                        }
                    } else {
                        activeSubmissionId = newSub.id;
                        setSubmissionId(newSub.id);
                    }
                }
            }

            let score = 0;
            const answersToInsert: any[] = [];

            questions.forEach(q => {
                const selected = answers[q.id];
                const isCorrect = selected === q.correct_answer;
                if (isCorrect) score += q.marks;

                answersToInsert.push({
                    submission_id: activeSubmissionId,
                    question_id: q.id,
                    selected_option: selected || 'skipped',
                    correct_option_id: q.correct_answer,
                    is_correct: isCorrect
                });
            });

            const percentage = (score / quiz.total_marks) * 100;
            const status = percentage >= quiz.pass_percentage ? 'passed' : 'failed';

            // Delete old answers and insert new ones
            const { error: deleteError } = await supabase.from('quiz_answers').delete().eq('submission_id', activeSubmissionId);
            if (deleteError) throw deleteError;

            const { error: insertError } = await supabase.from('quiz_answers').insert(answersToInsert);
            if (insertError) throw insertError;

            // Update submission status
            const { data: submissionData, error: subError } = await supabase
                .from('quiz_submissions')
                .update({
                    total_obtained: score,
                    status: status,
                    submitted_at: new Date().toISOString(),
                    time_taken: elapsedTime,
                    quiz_version: quiz.version || 1
                })
                .eq('id', activeSubmissionId)
                .select()
                .single();

            if (subError) throw subError;

            // Clear localStorage on successful submission
            clearQuizStorage();

            setResult(submissionData);
            if (timerRef.current) clearInterval(timerRef.current);
            toast.success('Quiz submitted successfully!');

            // Add to Knowledge Map
            knowledgeService.upsertKnowledgeNode({
                type: 'quiz',
                sourceId: submissionData.id,
                label: quiz.title,
                text: quiz.title
            });

            // Notify Lecturer
            if (quiz.created_by && profile?.full_name) {
                notifyQuizSubmission(
                    quiz.created_by,
                    profile.full_name,
                    quiz.title,
                    quiz.id,
                    quiz.class_id,
                    user.id
                ).catch(err => console.error("Failed to notify lecturer:", err));
            }

        } catch (error: any) {
            console.error('Error submitting quiz:', error);
            toast.error(error.message || 'Failed to submit quiz');
        } finally {
            setSubmitting(false);
        }
    };

    const handleAttemptSubmit = () => {
        const unansweredCount = questions.length - Object.keys(answers).length;
        if (unansweredCount > 0) {
            setIsConfirmSubmitOpen(true);
        } else {
            handleSubmit();
        }
    };


    if (loading) {
        return (
            <DashboardLayout fullHeight>
                <QuizSkeleton />
            </DashboardLayout>
        );
    }

    if (!quiz) {
        return (
            <DashboardLayout>
                <div className="flex flex-col items-center justify-center py-20 gap-4">
                    <XCircle className="size-16 text-destructive" />
                    <h2 className="text-2xl font-bold">Quiz Not Found</h2>
                    <Button onClick={() => navigate('/student/quizzes')}>Back to Quizzes</Button>
                </div>
            </DashboardLayout>
        );
    }

    // ==================== RESULT VIEW ====================
    if (result) {
        const percentage = Math.round((result.total_obtained / quiz.total_marks) * 100);
        const isPassed = result.status === 'passed';
        const correctCount = questions.filter(q => answers[q.id] === q.correct_answer).length;

        return (
            <DashboardLayout fullHeight>
                <div className="h-full bg-[#0A0C14] text-white overflow-y-auto selection:bg-blue-500/30">
                    <div className="max-w-6xl mx-auto p-4 lg:p-10 space-y-10 pb-20">

                        {/* 1. Results Header */}
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className="size-12 rounded-2xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-600/20">
                                    <Trophy className="size-6 text-white" />
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-[10px] font-black tracking-[0.2em] text-blue-400 uppercase">Results</span>
                                    </div>
                                    <h1 className="text-xl font-bold text-slate-100">{quiz.title}</h1>
                                </div>
                            </div>
                            <Button
                                variant="outline"
                                onClick={() => navigate('/student/quizzes')}
                                className="bg-slate-900/50 border-slate-800 text-slate-300 hover:bg-slate-800 hover:text-white rounded-xl gap-2 font-bold"
                            >
                                <XCircle className="size-4" />
                                Exit
                            </Button>
                        </div>

                        {/* 2. Main Performance Card */}
                        <div className="relative group">
                            <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-600/20 to-purple-600/20 rounded-[32px] blur opacity-75 group-hover:opacity-100 transition duration-1000"></div>
                            <div className="relative bg-[#111420] border border-white/5 rounded-[32px] p-8 lg:p-12 overflow-hidden">
                                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-center">
                                    {/* Left: Score Gauge */}
                                    <div className="lg:col-span-4 flex justify-center">
                                        <div className="relative size-56">
                                            <svg className="size-full -rotate-90 transform" viewBox="0 0 100 100">
                                                <circle
                                                    className="text-slate-800"
                                                    strokeWidth="8"
                                                    stroke="currentColor"
                                                    fill="transparent"
                                                    r="42"
                                                    cx="50"
                                                    cy="50"
                                                />
                                                <circle
                                                    className="text-blue-500 transition-all duration-1000 ease-out"
                                                    strokeWidth="8"
                                                    strokeDasharray={264}
                                                    strokeDashoffset={264 - (264 * percentage) / 100}
                                                    strokeLinecap="round"
                                                    stroke="currentColor"
                                                    fill="transparent"
                                                    r="42"
                                                    cx="50"
                                                    cy="50"
                                                />
                                            </svg>
                                            <div className="absolute inset-0 flex flex-col items-center justify-center">
                                                <span className="text-6xl font-black tracking-tighter text-white">{percentage}<span className="text-2xl text-blue-400">%</span></span>
                                                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">Final Score</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Middle: Stats Grid */}
                                    <div className="lg:col-span-8 space-y-8">
                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                            <div>
                                                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Accuracy</p>
                                                <p className="text-3xl font-black text-white">{correctCount} <span className="text-lg text-slate-600 font-bold ml-1">/ {questions.length}</span></p>
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Global Rank</p>
                                                {rank ? (
                                                    <p className="text-3xl font-black text-white">#{rank.position} <span className="text-lg text-slate-600 font-bold ml-1">/ {rank.total}</span></p>
                                                ) : (
                                                    <Loader2 className="animate-spin size-6 text-slate-600 mt-1" />
                                                )}
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Time Spent</p>
                                                <p className="text-3xl font-black text-white">{formatTime(result.time_taken || elapsedTime)} <span className="text-lg text-slate-600 font-bold ml-1">min</span></p>
                                            </div>
                                        </div>


                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* 3. Question Review Section */}
                        <div className="space-y-6">
                            <div className="flex items-center justify-between border-b border-white/5 pb-4">
                                <h2 className="text-2xl font-black tracking-tight text-white">Question Review</h2>
                                <div className="flex gap-6">
                                    <div className="flex items-center gap-2">
                                        <div className="size-2 rounded-full bg-emerald-500"></div>
                                        <span className="text-[10px] font-black uppercase tracking-widest text-emerald-500/80">Correct</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <div className="size-2 rounded-full bg-red-500"></div>
                                        <span className="text-[10px] font-black uppercase tracking-widest text-red-500/80">Incorrect</span>
                                    </div>
                                </div>
                            </div>

                            <div className="grid gap-8">
                                {questions.map((q, idx) => {
                                    const userAnswerId = answers[q.id];
                                    const isCorrect = userAnswerId === q.correct_answer;
                                    const isSkipped = !userAnswerId || userAnswerId === 'skipped';

                                    return (
                                        <div
                                            key={q.id}
                                            className={cn(
                                                "relative bg-[#111420] rounded-[24px] overflow-hidden border transition-all duration-300",
                                                isCorrect ? "border-emerald-500/10" : "border-red-500/10"
                                            )}
                                        >
                                            {/* Top Bar */}
                                            <div className="bg-black/20 px-8 py-5 flex items-center justify-between">
                                                <div className="flex items-center gap-4">
                                                    <div className={cn(
                                                        "size-10 rounded-xl flex items-center justify-center font-black text-sm",
                                                        isCorrect ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"
                                                    )}>
                                                        {idx + 1 < 10 ? `0${idx + 1}` : idx + 1}
                                                    </div>
                                                    <h3 className="text-lg font-bold text-slate-200">{q.question_text}</h3>
                                                </div>
                                                <Badge variant="outline" className="bg-slate-900/50 border-slate-700 text-slate-400 font-black text-[10px] px-3 py-1">
                                                    {isCorrect ? q.marks : 0}.0 POINTS
                                                </Badge>
                                            </div>

                                            {/* Options */}
                                            <div className="p-8 space-y-3">
                                                {q.options.map((option: any) => {
                                                    const isSelected = userAnswerId === option.id;
                                                    const isTheCorrectAnswer = q.correct_answer === option.id;

                                                    return (
                                                        <div
                                                            key={option.id}
                                                            className={cn(
                                                                "group flex items-center gap-4 p-4 rounded-xl border transition-all",
                                                                isTheCorrectAnswer
                                                                    ? "bg-emerald-500/5 border-emerald-500/20"
                                                                    : isSelected
                                                                        ? "bg-red-500/5 border-red-500/20"
                                                                        : "bg-slate-900/30 border-white/5 opacity-60"
                                                            )}
                                                        >
                                                            <div className={cn(
                                                                "size-10 rounded-full flex items-center justify-center transition-colors",
                                                                isTheCorrectAnswer
                                                                    ? "bg-emerald-500 text-white"
                                                                    : isSelected
                                                                        ? "bg-red-500 text-white"
                                                                        : "bg-slate-800 text-slate-500"
                                                            )}>
                                                                {isTheCorrectAnswer ? <CheckCircle className="size-5" /> : isSelected ? <XCircle className="size-5" /> : <div className="size-2 rounded-full bg-current" />}
                                                            </div>
                                                            <span className={cn(
                                                                "flex-1 font-bold text-sm",
                                                                isTheCorrectAnswer ? "text-emerald-400" : isSelected ? "text-red-400" : "text-slate-400"
                                                            )}>
                                                                {option.text}
                                                            </span>
                                                            {isTheCorrectAnswer && (
                                                                <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest bg-emerald-500/10 px-3 py-1 rounded-full">Correct Answer</span>
                                                            )}
                                                            {isSelected && !isTheCorrectAnswer && (
                                                                <span className="text-[10px] font-black text-red-500 uppercase tracking-widest bg-red-500/10 px-3 py-1 rounded-full">Your Choice</span>
                                                            )}
                                                        </div>
                                                    );
                                                })}

                                                {/* Explanation Section */}
                                                {q.explanation && (
                                                    <div className="mt-8 p-5 rounded-2xl bg-blue-500/5 border border-blue-500/10 flex gap-4 items-start">
                                                        <div className="size-8 rounded-full bg-blue-500/10 flex items-center justify-center shrink-0">
                                                            <Target className="size-4 text-blue-400" />
                                                        </div>
                                                        <p className="text-xs text-slate-400 leading-relaxed italic">
                                                            <span className="text-blue-400 font-bold uppercase tracking-wider block mb-1">Explanation:</span>
                                                            {q.explanation}
                                                        </p>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>



                    </div>
                </div>
            </DashboardLayout>
        );
    }

    if (questions.length === 0) {
        return (
            <DashboardLayout>
                <div className="flex flex-col items-center justify-center py-20 gap-4">
                    <FileText className="size-16 text-muted-foreground" />
                    <h2 className="text-2xl font-bold">No Questions Available</h2>
                    <Button onClick={() => navigate('/student/quizzes')}>Back to Quizzes</Button>
                </div>
            </DashboardLayout>
        );
    }

    const progress = (Object.keys(answers).length / questions.length) * 100;
    const currentQuestion = questions[currentIndex];

    if (!currentQuestion) {
        setCurrentIndex(0);
        return null;
    }

    // ==================== QUIZ TAKING VIEW ====================
    return (
        <DashboardLayout fullHeight>
            <div className="h-full flex flex-col overflow-hidden bg-[#f8fafc] dark:bg-slate-950">
                {/* Top Header Bar */}
                <header className="shrink-0 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 lg:px-6 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="flex items-center justify-center size-10 rounded-xl bg-blue-500 text-white">
                        </div>
                        <h1 className="font-bold text-lg">{quiz.title}</h1>
                    </div>

                    {/* Progress */}
                    <div className="hidden md:flex items-center gap-3">
                        <span className="text-sm text-muted-foreground font-medium">PROGRESS</span>
                        <div className="w-40 h-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-blue-500 rounded-full transition-all duration-300"
                                style={{ width: `${progress}%` }}
                            />
                        </div>
                        <span className="text-sm font-bold text-blue-600">{Math.round(progress)}%</span>
                    </div>

                    {/* Timer */}
                    <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 px-4 py-2 rounded-xl">
                        <Clock className="size-5 text-blue-500" />
                        <span className="font-mono font-bold text-lg tracking-wider">{formatTime(elapsedTime)}</span>
                    </div>
                </header>

                <div className="flex-1 flex overflow-hidden">
                    {/* Left Sidebar - Question Navigator */}
                    <aside className="hidden lg:flex flex-col w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-5">
                        <h3 className="text-xs font-bold uppercase tracking-wider text-muted-foreground mb-4">Question Navigator</h3>

                        {/* Question Grid */}
                        <div className="grid grid-cols-5 gap-2 mb-6">
                            {questions.map((q, i) => {
                                const isAnswered = !!answers[q.id];
                                const isCurrent = i === currentIndex;

                                let className = "flex items-center justify-center size-10 rounded-lg font-bold text-sm transition-all cursor-pointer ";
                                if (isCurrent) {
                                    className += "bg-blue-500 text-white shadow-lg";
                                } else if (isAnswered) {
                                    className += "bg-emerald-500 text-white";
                                } else {
                                    className += "bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700";
                                }

                                return (
                                    <button
                                        key={i}
                                        onClick={() => setCurrentIndex(i)}
                                        className={className}
                                    >
                                        {i + 1}
                                    </button>
                                );
                            })}
                        </div>

                        <div className="flex-1" />

                        {/* Legend */}
                        <div className="space-y-3 pt-4 border-t border-slate-200 dark:border-slate-700">
                            <p className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Legend</p>
                            <div className="flex items-center gap-2 text-sm">
                                <div className="size-4 rounded bg-blue-500" />
                                <span>Current Question</span>
                            </div>
                            <div className="flex items-center gap-2 text-sm">
                                <div className="size-4 rounded bg-emerald-500" />
                                <span>Answered</span>
                            </div>
                            <div className="flex items-center gap-2 text-sm">
                                <div className="size-4 rounded bg-slate-200 dark:bg-slate-700" />
                                <span>Unanswered</span>
                            </div>
                        </div>

                        {/* Submit Button */}
                        <Button
                            onClick={handleAttemptSubmit}
                            disabled={submitting}
                            className="mt-6 w-full h-12 bg-blue-500 hover:bg-blue-600 text-white font-bold text-base"
                        >
                            {submitting ? <Loader2 className="animate-spin" /> : <>Submit Exam <ChevronRight className="size-4 ml-1" /></>}
                        </Button>
                    </aside>

                    {/* Main Content Area */}
                    <main className="flex-1 overflow-y-auto bg-[#f8fafc] dark:bg-slate-950">
                        <div className="max-w-3xl mx-auto px-6 py-8">
                            {/* Question Header Row */}
                            <div className="flex items-center gap-3 mb-6">
                                <span className="text-3xl font-bold text-[#3b82f6]">Q{currentIndex + 1}</span>
                                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Multiple Choice</span>
                            </div>

                            {/* Question Box */}
                            <div className="mb-8 p-6 rounded-lg border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
                                <p className="text-lg font-medium leading-relaxed text-slate-700 dark:text-slate-200">
                                    {currentQuestion.question_text}
                                </p>
                            </div>

                            {/* Answer Options */}
                            <div className="space-y-3 mb-10">
                                {(currentQuestion.options || []).map((option: any, idx: number) => {
                                    const optionLetter = String.fromCharCode(65 + idx);
                                    const isSelected = answers[currentQuestion.id] === option.id;

                                    return (
                                        <button
                                            key={option.id}
                                            onClick={() => handleAnswerChange(currentQuestion.id, option.id)}
                                            className={`w-full flex items-center gap-4 p-4 rounded-lg border text-left transition-all ${isSelected
                                                ? 'border-[#3b82f6] bg-blue-50/50 dark:bg-blue-500/10'
                                                : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 hover:border-slate-300'
                                                }`}
                                        >
                                            {/* Letter Badge */}
                                            <span className={`flex items-center justify-center w-10 h-10 rounded-full font-semibold text-sm shrink-0 ${isSelected
                                                ? 'bg-[#3b82f6] text-white'
                                                : 'bg-slate-100 dark:bg-slate-800 text-slate-500'
                                                }`}>
                                                {optionLetter}
                                            </span>
                                            {/* Option Text */}
                                            <span className={`flex-1 text-[15px] ${isSelected ? 'text-slate-800 dark:text-slate-100' : 'text-slate-600 dark:text-slate-300'}`}>
                                                {option.text}
                                            </span>
                                            {/* Checkmark */}
                                            {isSelected && (
                                                <div className="shrink-0 flex items-center justify-center w-6 h-6 rounded-full bg-[#3b82f6]">
                                                    <CheckCircle className="size-4 text-white" />
                                                </div>
                                            )}
                                        </button>
                                    );
                                })}
                            </div>

                            {/* Bottom Navigation */}
                            <div className="flex items-center justify-between gap-4">
                                <Button
                                    variant="outline"
                                    onClick={() => setCurrentIndex(prev => Math.max(0, prev - 1))}
                                    disabled={currentIndex === 0}
                                    className="h-11 px-5 font-medium gap-2 border-slate-300 dark:border-slate-600"
                                >
                                    <ChevronLeft className="size-4" /> Previous
                                </Button>

                                <button
                                    onClick={clearAnswer}
                                    disabled={!answers[currentQuestion.id]}
                                    className="h-11 px-5 font-medium text-slate-500 hover:text-slate-700 disabled:opacity-40"
                                >
                                    Clear Answer
                                </button>

                                <Button
                                    onClick={() => setCurrentIndex(prev => Math.min(questions.length - 1, prev + 1))}
                                    disabled={currentIndex === questions.length - 1}
                                    className="h-11 px-6 font-medium gap-2 bg-[#3b82f6] hover:bg-blue-600 text-white"
                                >
                                    Next Question <ChevronRight className="size-4" />
                                </Button>
                            </div>
                        </div>
                    </main>
                </div>

                {/* Mobile Bottom Nav */}
                <div className="lg:hidden shrink-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4">
                    <div className="flex items-center justify-between gap-2">
                        <Button
                            variant="outline"
                            onClick={() => setCurrentIndex(prev => Math.max(0, prev - 1))}
                            disabled={currentIndex === 0}
                            className="flex-1 h-12"
                        >
                            <ChevronLeft className="size-4" /> Prev
                        </Button>
                        <Button
                            onClick={handleAttemptSubmit}
                            disabled={submitting}
                            className="flex-1 h-12 bg-blue-500"
                        >
                            {submitting ? <Loader2 className="animate-spin" /> : 'Submit'}
                        </Button>
                        <Button
                            onClick={() => setCurrentIndex(prev => Math.min(questions.length - 1, prev + 1))}
                            disabled={currentIndex === questions.length - 1}
                            className="flex-1 h-12 bg-blue-500"
                        >
                            Next <ChevronRight className="size-4" />
                        </Button>
                    </div>
                </div>
            </div>
            <DeleteConfirmDialog
                open={isConfirmSubmitOpen}
                onOpenChange={setIsConfirmSubmitOpen}
                onConfirm={handleSubmit}
                title="Submit Quiz?"
                description={`You have ${questions.length - Object.keys(answers).length} unanswered questions. Are you sure you want to submit your quiz now?`}
            />
        </DashboardLayout>
    );
}

import { useState, useEffect } from "react";
import { Lock, Eye, EyeOff, CheckCircle, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { AuthHeader } from "@/components/layout/AuthHeader";
import { BackgroundDecoration } from "@/components/auth/BackgroundDecoration";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";

export default function UpdatePassword() {
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);
    const navigate = useNavigate();
    const { toast } = useToast();

    useEffect(() => {
        const checkSession = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) {
                toast({
                    title: "Session Expired",
                    description: "Please request a new password reset link.",
                    variant: "destructive",
                });
                navigate("/forgot-password");
            }
        };
        checkSession();
    }, [navigate, toast]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (password !== confirmPassword) {
            toast({
                title: "Passwords Don't Match",
                description: "Please make sure both passwords are the same",
                variant: "destructive",
            });
            return;
        }

        if (password.length < 6) {
            toast({
                title: "Password Too Short",
                description: "Password must be at least 6 characters long",
                variant: "destructive",
            });
            return;
        }

        setIsLoading(true);

        try {
            const { error } = await supabase.auth.updateUser({
                password: password,
            });

            if (error) {
                throw error;
            }

            setIsSuccess(true);
            toast({
                title: "Password Updated",
                description: "Your password has been successfully updated",
            });

            // Redirect to login after 2 seconds
            setTimeout(() => {
                navigate("/login", { replace: true });
            }, 2000);
        } catch (error: any) {
            console.error("Password update error:", error);
            toast({
                title: "Error",
                description: error.message || "Failed to update password. Please try again.",
                variant: "destructive",
            });
        } finally {
            setIsLoading(false);
        }
    };

    if (isSuccess) {
        return (
            <div className="min-h-screen flex flex-col overflow-x-hidden">
                <AuthHeader />
                <main className="flex-1 flex flex-col justify-center py-10 px-4 sm:px-6 lg:px-8">
                    <div className="w-full max-w-[480px] mx-auto flex flex-col gap-6">
                        <div className="bg-surface rounded-xl shadow-[0_0_15px_rgba(0,0,0,0.05)] dark:shadow-none border border-border p-6 sm:p-8 flex flex-col items-center gap-6 text-center animate-fade-in">
                            <div className="size-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
                                <CheckCircle className="size-8 text-green-600 dark:text-green-400" />
                            </div>
                            <div className="flex flex-col gap-2">
                                <h2 className="text-foreground text-2xl font-bold">Password Updated!</h2>
                                <p className="text-muted-foreground text-sm leading-relaxed">
                                    Your password has been successfully updated. Redirecting to login...
                                </p>
                            </div>
                        </div>
                    </div>
                </main>
                <BackgroundDecoration />
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col overflow-x-hidden">
            <AuthHeader />

            <main className="flex-1 flex flex-col justify-center py-10 px-4 sm:px-6 lg:px-8">
                <div className="w-full max-w-[480px] mx-auto flex flex-col gap-6">
                    {/* Page Heading */}
                    <div className="flex flex-col gap-2 text-center sm:text-left animate-fade-in">
                        <h1 className="text-foreground text-3xl sm:text-4xl font-black leading-tight tracking-[-0.033em]">
                            Update Password
                        </h1>
                        <p className="text-muted-foreground text-base font-normal leading-normal">
                            Enter your new password below
                        </p>
                    </div>

                    {/* Form Card */}
                    <div className="bg-surface rounded-xl shadow-[0_0_15px_rgba(0,0,0,0.05)] dark:shadow-none border border-border p-6 sm:p-8 flex flex-col gap-6 animate-fade-in">
                        <form className="flex flex-col gap-5" onSubmit={handleSubmit}>
                            {/* New Password Field */}
                            <label className="flex flex-col gap-2">
                                <span className="text-foreground text-sm font-medium leading-normal">
                                    New Password
                                </span>
                                <div className="relative flex items-center">
                                    <Input
                                        type={showPassword ? "text" : "password"}
                                        placeholder="Enter new password"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        className="pr-20"
                                        disabled={isLoading}
                                        required
                                    />
                                    <div className="absolute right-3 flex items-center gap-2">
                                        <Lock className="size-5 text-muted-foreground" />
                                        <button
                                            type="button"
                                            onClick={() => setShowPassword(!showPassword)}
                                            className="text-muted-foreground hover:text-foreground transition-colors"
                                        >
                                            {showPassword ? (
                                                <EyeOff className="size-5" />
                                            ) : (
                                                <Eye className="size-5" />
                                            )}
                                        </button>
                                    </div>
                                </div>
                            </label>

                            {/* Confirm Password Field */}
                            <label className="flex flex-col gap-2">
                                <span className="text-foreground text-sm font-medium leading-normal">
                                    Confirm Password
                                </span>
                                <div className="relative flex items-center">
                                    <Input
                                        type={showConfirmPassword ? "text" : "password"}
                                        placeholder="Confirm new password"
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        className="pr-20"
                                        disabled={isLoading}
                                        required
                                    />
                                    <div className="absolute right-3 flex items-center gap-2">
                                        <Lock className="size-5 text-muted-foreground" />
                                        <button
                                            type="button"
                                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                            className="text-muted-foreground hover:text-foreground transition-colors"
                                        >
                                            {showConfirmPassword ? (
                                                <EyeOff className="size-5" />
                                            ) : (
                                                <Eye className="size-5" />
                                            )}
                                        </button>
                                    </div>
                                </div>
                            </label>

                            {/* Submit Button */}
                            <Button type="submit" className="w-full" disabled={isLoading}>
                                {isLoading ? (
                                    <>
                                        <Loader2 className="size-4 mr-2 animate-spin" />
                                        Updating...
                                    </>
                                ) : (
                                    "Update Password"
                                )}
                            </Button>
                        </form>
                    </div>
                </div>
            </main>

            <BackgroundDecoration />
        </div>
    );
}

import { supabase } from "@/integrations/supabase/client";
import { format, subDays } from "date-fns";

export type BadgeType = 'novice' | 'learner' | 'scholar' | 'prodigy' | 'warrior' | 'elite' | 'master' | 'grandmaster' | 'titan' | 'immortal';

export interface UserStreak {
    user_id: string;
    current_streak: number;
    longest_streak: number;
    total_days: number;
    last_action_date: string | null;
    updated_at: string;
}

export interface UserBadge {
    id: string;
    user_id: string;
    badge_type: BadgeType;
    unlocked_at: string;
    streak_count: number;
}

export const STREAK_LEVELS: Record<number, BadgeType> = {
